-- Poems batch 111
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('9057de38-6b6a-43a7-a377-5fd31d8d6880','上黄端明壽詩以竚期三入後一品見玄孫爲韻  其一○','李呂','宋','宋诗','song-poetry','','[]','阻陪稱壽席，想見醉芳樽。',24,'全唐诗/poet.song.125000.json','["阻陪稱壽席，想見醉芳樽。", "嘉慶宜圖畫，簪紳徧子孫。"]'),
('960481ef-3a18-48a8-9a4e-be9159221a5f','瑩心泉','李呂','宋','宋诗','song-poetry','','[]','修綆何妨汲，羸瓶不自任。',24,'全唐诗/poet.song.125000.json','["修綆何妨汲，羸瓶不自任。", "從渠清徹底，伴我歲寒心。"]'),
('e066f9de-0783-4b87-829e-870f94df89e6','漁艇','李呂','宋','宋诗','song-poetry','','[]','撇烈非爲魚，流行本處山。',24,'全唐诗/poet.song.125000.json','["撇烈非爲魚，流行本處山。", "白鷗正得意，相逐過前灣。"]'),
('8933cdeb-66dc-4595-a789-a25decf40d91','自警三首  其一','李呂','宋','宋诗','song-poetry','','[]','愛之能勿勞，忠焉能勿誨。',24,'全唐诗/poet.song.125000.json','["愛之能勿勞，忠焉能勿誨。", "彼有不受者，善意翻成累。"]'),
('d900f32b-ff27-4dfa-a333-19cfe691f989','自警三首  其二','李呂','宋','宋诗','song-poetry','','[]','當仁貴不讓，見義忌無勇。',24,'全唐诗/poet.song.125000.json','["當仁貴不讓，見義忌無勇。", "今人無魏顆，勿望渠形夢。"]'),
('87c0026a-c37a-406f-9ed4-1bb1089c0c9a','自警三首  其三','李呂','宋','宋诗','song-poetry','','[]','嬖人排孟子，通國誚匡章。',24,'全唐诗/poet.song.125000.json','["嬖人排孟子，通國誚匡章。", "內省倘不疚，青蠅徒自忙。"]'),
('8332f55e-ce7c-479b-b618-e2a44584526e','椿逕','李呂','宋','宋诗','song-poetry','','[]','栽培護靈根，夾道若車蓋。',24,'全唐诗/poet.song.125000.json','["栽培護靈根，夾道若車蓋。", "坐待八千歲，儼立風雨外。"]'),
('5064cbde-301f-4219-a15a-b6db253f726c','題破石鋪','李呂','宋','宋诗','song-poetry','','[]','往返數百里，上下幾重山。',24,'全唐诗/poet.song.125000.json','["往返數百里，上下幾重山。", "僕僕利名客，不知行路難。"]'),
('2d7bf6e0-a4ba-42a7-9787-f677ab08a16d','茶竈','李呂','宋','宋诗','song-poetry','','[]','中坻出盤陀，曲突非刻畫。',24,'全唐诗/poet.song.125000.json','["中坻出盤陀，曲突非刻畫。", "仙翁碾玉塵，盈甌試春色。"]'),
('e6531754-b048-4915-bbd3-d69d49c3e04a','溫泉  其一','李呂','宋','宋诗','song-poetry','','[]','陰陽分二氣，鈞播立萬物。',24,'全唐诗/poet.song.125000.json','["陰陽分二氣，鈞播立萬物。", "泉脈或寒溫，初非擇地出。"]'),
('6a8e317a-e3d6-4952-9833-483589101582','溫泉  其二','李呂','宋','宋诗','song-poetry','','[]','太樸一已散，人僞日滋彰。',24,'全唐诗/poet.song.125000.json','["太樸一已散，人僞日滋彰。", "持彼炎凉態，指目爲溫湯。"]'),
('b5a41503-fbc4-45ec-8016-cfd096f631ef','溫泉  其三','李呂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬發源初，絕景迺如許。',24,'全唐诗/poet.song.125000.json','["匡廬發源初，絕景迺如許。", "尤幸遠市朝，不遭豪右取。"]'),
('698e0a4c-2a1d-466d-93e2-a06b9090645e','溫泉  其四','李呂','宋','宋诗','song-poetry','','[]','懷哉經始心，與世共遊賞。',24,'全唐诗/poet.song.125000.json','["懷哉經始心，與世共遊賞。", "爲語往來人，莫起驪山想。"]'),
('a75afdb7-e688-4802-bd23-672662c5e42d','題吳仲微常齋','李呂','宋','宋诗','song-poetry','','[]','達石情忘倦，移山志必通。',24,'全唐诗/poet.song.125000.json','["達石情忘倦，移山志必通。", "朝朝勤甓運，井井策新功。"]'),
('ec698147-86e3-41de-a759-5915b9045845','和吳微明疏影橫斜水清淺七詠韻  其一','李呂','宋','宋诗','song-poetry','','[]','深叢茉莉香有餘，穠李爭春俗不除。',32,'全唐诗/poet.song.125000.json','["深叢茉莉香有餘，穠李爭春俗不除。", "借箸推排風味勝，尖新莫向小梅疏。"]'),
('373e19b7-fde8-4d5a-b0b3-96e2b826b771','和吳微明疏影橫斜水清淺七詠韻  其二','李呂','宋','宋诗','song-poetry','','[]','避俗淵明心會景，祇詠孤松秀冬嶺。',32,'全唐诗/poet.song.125000.json','["避俗淵明心會景，祇詠孤松秀冬嶺。", "爭識槎牙竹外枝，月上空階間金影。"]'),
('c750e299-8243-4b17-a9fb-13be921010c4','和吳微明疏影橫斜水清淺七詠韻  其三','李呂','宋','宋诗','song-poetry','','[]','倚竹風神不勝情，裁雲刻月鬭輕明。',32,'全唐诗/poet.song.125000.json','["倚竹風神不勝情，裁雲刻月鬭輕明。", "澄鮮祇合騷人惜，懶對紅塵肉眼橫。"]'),
('f30469ed-e4a1-41eb-91cf-9d81c8f80692','和吳微明疏影橫斜水清淺七詠韻  其四','李呂','宋','宋诗','song-poetry','','[]','嶺上休將貝闕誇，江頭聊比玉川家。',32,'全唐诗/poet.song.125000.json','["嶺上休將貝闕誇，江頭聊比玉川家。", "箇中真趣誰能會，獨對回風雪陣斜。"]'),
('0f1a2c52-371b-4f57-b347-66e3a5659da9','和吳微明疏影橫斜水清淺七詠韻  其五','李呂','宋','宋诗','song-poetry','','[]','碧澗潺潺暮山紫，閉關危坐心如水。',32,'全唐诗/poet.song.125000.json','["碧澗潺潺暮山紫，閉關危坐心如水。", "窗間微見一枝橫，鼻觀得香尤可喜。"]'),
('aa8cfa41-b933-41c9-a488-a2655294fc85','和吳微明疏影橫斜水清淺七詠韻  其六','李呂','宋','宋诗','song-poetry','','[]','勝賞須傾竹葉青，此花元自聖之清。',32,'全唐诗/poet.song.125000.json','["勝賞須傾竹葉青，此花元自聖之清。", "翻思杜老尤躭翫，野水橫吹當酒行。"]'),
('99cf30c0-db60-4807-acd0-627d4acc65ed','和吳微明疏影橫斜水清淺七詠韻  其七','李呂','宋','宋诗','song-poetry','','[]','斜入茅簷如有恨，高情每頼吟題遣。',32,'全唐诗/poet.song.125000.json','["斜入茅簷如有恨，高情每頼吟題遣。", "要知調鼎會有時，且占寒溪照清淺。"]'),
('1b311f3e-3a83-41f6-b631-6e84bb65e57e','秋旱','李呂','宋','宋诗','song-poetry','','[]','天公作意雨垂垂，風伯顛狂散萬絲。',32,'全唐诗/poet.song.125000.json','["天公作意雨垂垂，風伯顛狂散萬絲。", "執法若能誅首惡，更將京觀築鯨鯢。"]'),
('bf05d4f6-3c2f-4f13-8de2-0e3996236d0d','伏承伯丈人待制侍郎九重渙號三聘鼎來促裝戒道即膺爰立謹吟成送行詩五絕句繕寫拜呈  其一','李呂','宋','宋诗','song-poetry','','[]','漢庭得謝久縣車，松竹蕭疏護葺廬。',32,'全唐诗/poet.song.125000.json','["漢庭得謝久縣車，松竹蕭疏護葺廬。", "爭奈蒼生待霖雨，未容安石愛幽居。"]'),
('dd3f9bd3-3f31-4954-a070-3f25c9549b29','伏承伯丈人待制侍郎九重渙號三聘鼎來促裝戒道即膺爰立謹吟成送行詩五絕句繕寫拜呈  其二','李呂','宋','宋诗','song-poetry','','[]','嘉謨豈但國蓍龜，舊學端爲帝者師。',32,'全唐诗/poet.song.125000.json','["嘉謨豈但國蓍龜，舊學端爲帝者師。", "聖世欲收仁義效，行看平步鳳凰池。"]'),
('4b1051a7-4951-40e1-92af-d7c2f2a861e0','伏承伯丈人待制侍郎九重渙號三聘鼎來促裝戒道即膺爰立謹吟成送行詩五絕句繕寫拜呈  其三','李呂','宋','宋诗','song-poetry','','[]','孟子正心邪說息，昌黎首唱六經明。',32,'全唐诗/poet.song.125000.json','["孟子正心邪說息，昌黎首唱六經明。", "可憐後學多趨末，重振斯文藉主盟。"]'),
('cb1d86d0-c673-4fa6-a047-8acb45d37c51','伏承伯丈人待制侍郎九重渙號三聘鼎來促裝戒道即膺爰立謹吟成送行詩五絕句繕寫拜呈  其四','李呂','宋','宋诗','song-poetry','','[]','膴膴周原二百州，欲圖恢復豈難求。',32,'全唐诗/poet.song.125000.json','["膴膴周原二百州，欲圖恢復豈難求。", "既煩元老爲時出，但願宣王益內修。"]'),
('19a4b821-6644-41a5-836d-9cdeded9a9ce','伏承伯丈人待制侍郎九重渙號三聘鼎來促裝戒道即膺爰立謹吟成送行詩五絕句繕寫拜呈  其五','李呂','宋','宋诗','song-poetry','','[]','梅花映雪送征鞍，要伴先生耐歲寒。',32,'全唐诗/poet.song.125000.json','["梅花映雪送征鞍，要伴先生耐歲寒。", "收拾好歸調鼎用，春來枝上已含酸。"]'),
('29d80a87-707a-4bda-b6f2-c429f087041b','送千二十姪五首  其一','李呂','宋','宋诗','song-poetry','','[]','江頭片片玉梅飛，嶺路迢遥雪正迷。',32,'全唐诗/poet.song.125000.json','["江頭片片玉梅飛，嶺路迢遥雪正迷。", "乘興爲誰騎馬去，不辭迎凍散雙蹄。"]'),
('8b5aed85-7fa2-42d4-99a8-ed3bcb6db675','送千二十姪五首  其二','李呂','宋','宋诗','song-poetry','','[]','賢哉東道世崇儒，愛子尤專擇楷模。',32,'全唐诗/poet.song.125000.json','["賢哉東道世崇儒，愛子尤專擇楷模。", "責望要須精舉業，未應道義略唐虞。"]'),
('9395a4ad-ea33-494d-855a-07edddbc5beb','送千二十姪五首  其三','李呂','宋','宋诗','song-poetry','','[]','紛紛世態利爲言，此道誰人識正傳。',32,'全唐诗/poet.song.125000.json','["紛紛世態利爲言，此道誰人識正傳。", "爲己爲人宜兩盡，莫教渠笑舍其田。"]'),
('99699104-da13-46fd-a352-ccbb1c316049','送千二十姪五首  其四','李呂','宋','宋诗','song-poetry','','[]','江左風流久擅名，成章擲地作金聲。',32,'全唐诗/poet.song.125000.json','["江左風流久擅名，成章擲地作金聲。", "清新俊逸俱難及，若比前賢更老成。"]'),
('e6f4f5fb-b7d4-416e-84e3-a1a469dd8bf9','送千二十姪五首  其五','李呂','宋','宋诗','song-poetry','','[]','却喜君知取友端，詩情遊戲志睎顔。',32,'全唐诗/poet.song.125000.json','["却喜君知取友端，詩情遊戲志睎顔。", "更煩爲說開三逕，安得斯人數往還。"]'),
('4657f582-df06-4c99-89da-331ad2287c48','和感懷韻','李呂','宋','宋诗','song-poetry','','[]','四時迭運春復冬，莫把窮愁蹙兩峰。',32,'全唐诗/poet.song.125000.json','["四時迭運春復冬，莫把窮愁蹙兩峰。", "牢掣鼻繩休放却，鏡中已失舊時容。"]'),
('95174bbd-518d-4dd0-9fbc-5c37dec2493b','象之晚坐有感次韻','李呂','宋','宋诗','song-poetry','','[]','丈夫不作宋玉悲，珍重陶潛菊一枝。',32,'全唐诗/poet.song.125000.json','["丈夫不作宋玉悲，珍重陶潛菊一枝。", "寄傲北窗緣底事，只應真趣少人知。"]'),
('390d7bc8-91bf-41f2-832f-22d50b0737d9','題長灘鋪','李呂','宋','宋诗','song-poetry','','[]','一丘一壑吾臭味，真是真非孰有無。',32,'全唐诗/poet.song.125000.json','["一丘一壑吾臭味，真是真非孰有無。", "月笛煙蓑秋正好，急須歸釣渚溪魚。"]'),
('f1465861-50d9-4cac-a33e-ac75e322f554','千四一姪見贈筇竹杖以詩謝之','李呂','宋','宋诗','song-poetry','','[]','常瞻南極畫圖中，壽相偏宜九節筇。',32,'全唐诗/poet.song.125000.json','["常瞻南極畫圖中，壽相偏宜九節筇。", "珍重阿戎來寄我，慚無林下老仙風。"]'),
('8ea811b0-f11e-4323-afca-858c0b080424','澹軒','李呂','宋','宋诗','song-poetry','','[]','窮耽世味不期驕，安得羹牆暫見堯。',32,'全唐诗/poet.song.125000.json','["窮耽世味不期驕，安得羹牆暫見堯。", "未到聞韶飽三月，且求陋巷樂簞瓢。"]'),
('bcafde75-ff10-4ea0-b329-ec764b959f04','代人上建守四首  其一','李呂','宋','宋诗','song-poetry','','[]','潛藩雄鎮七閩頭，親覩賢侯利澤周。',32,'全唐诗/poet.song.125000.json','["潛藩雄鎮七閩頭，親覩賢侯利澤周。", "不借寇恂留潁尾，却教郭伋再并州。"]'),
('40f28d8d-09f2-4e4f-a163-08e2c99b1866','代人上建守四首  其二','李呂','宋','宋诗','song-poetry','','[]','可怪鄉風最不情，生兒不舉世相仍。',32,'全唐诗/poet.song.125000.json','["可怪鄉風最不情，生兒不舉世相仍。", "自從節省歸新歷，添得王民幾萬丁。"]'),
('fe83bcbc-0d87-490f-82e7-36f09700049d','代人上建守四首  其三','李呂','宋','宋诗','song-poetry','','[]','鄂渚纔來便救焚，富沙拯溺濟饑民。',32,'全唐诗/poet.song.125000.json','["鄂渚纔來便救焚，富沙拯溺濟饑民。", "從容妙得調元手，好轉洪鈞拱帝宸。"]'),
('f6d68de8-1fa5-45ad-aba5-3bbfd7a719e3','代人上建守四首  其四','李呂','宋','宋诗','song-poetry','','[]','悵懷往事我何知，作興重來觸緒非。',32,'全唐诗/poet.song.125000.json','["悵懷往事我何知，作興重來觸緒非。", "無地可畦家十口，蕭然相對欲誰歸。"]'),
('c63a11a5-4715-4035-aa5a-f9698a6625b0','題君山愛松軒','李呂','宋','宋诗','song-poetry','','[]','嘗愛山間老喬松，棲煙宿雨盤虬龍。',32,'全唐诗/poet.song.125000.json','["嘗愛山間老喬松，棲煙宿雨盤虬龍。", "道人所愛偶相似，許我來此聽松風。"]'),
('e2b4a743-d847-4533-b2c8-04e3b0794799','辨義豐老人師傅聞疑大乾事迹','李呂','宋','宋诗','song-poetry','','[]','義寧欲末隋鼎遷，解符西泝心悠然。',32,'全唐诗/poet.song.125000.json','["義寧欲末隋鼎遷，解符西泝心悠然。", "沉舟甘作夷齊鬼，不與宇文同戴天。"]'),
('60bec33e-0675-4dbd-a8b0-0d57a433f931','游鉛山石井','李呂','宋','宋诗','song-poetry','','[]','碧玉罅中仙洞府，玻瓈無底涵煙雨。',32,'全唐诗/poet.song.125000.json','["碧玉罅中仙洞府，玻瓈無底涵煙雨。", "好將潤澤天下施，沾溉寧論數千畝。"]'),
('079fd7e6-2114-4b9c-81f9-681872b342b1','次蕪徽明諸公韻三首  其一','李呂','宋','宋诗','song-poetry','','[]','鏡中已失舊時容，懶問春來白與紅。',32,'全唐诗/poet.song.125000.json','["鏡中已失舊時容，懶問春來白與紅。", "君爲花愁成獨醉，餘醅何惜命鄰翁。"]'),
('3bf13b74-70e5-454e-bfbb-f48341215177','次蕪徽明諸公韻三首  其二','李呂','宋','宋诗','song-poetry','','[]','未許酴醿浪得香，殿春時出一枝芳。',32,'全唐诗/poet.song.125000.json','["未許酴醿浪得香，殿春時出一枝芳。", "從他百卉隨風舞，獨立晴天試艷粧。"]'),
('c68a72fe-395e-40e5-b330-e01fe8a299bf','次蕪徽明諸公韻三首  其三','李呂','宋','宋诗','song-poetry','','[]','黄雲看即變成秋，春事餘寒得少留。',32,'全唐诗/poet.song.125000.json','["黄雲看即變成秋，春事餘寒得少留。", "此去浣花猶遠在，誰人能爲作遨頭。"]'),
('5ee85c14-97fd-4a72-b4a7-ad5e3d279c43','過孝義亭作詩寄歸代書','李呂','宋','宋诗','song-poetry','','[]','經夕離家行百里，山椒一上一回頭。',32,'全唐诗/poet.song.125000.json','["經夕離家行百里，山椒一上一回頭。", "此來頗快疑陰相，寄語妻兒勿過憂。"]'),
('13113818-4dec-441f-a1ff-13ef74474387','登徐孺子亭','李呂','宋','宋诗','song-poetry','','[]','昔賢久矣埋黄土，獨有清風翳環堵。',32,'全唐诗/poet.song.125000.json','["昔賢久矣埋黄土，獨有清風翳環堵。", "曾將一束奠生芻，今與遊人閙歌舞。"]'),
('600a87fc-3a68-4a1f-894e-b83bc1f731ec','簡龔令望','李呂','宋','宋诗','song-poetry','','[]','乘興來尋老樹村，接談才祇敘寒溫。',32,'全唐诗/poet.song.125000.json','["乘興來尋老樹村，接談才祇敘寒溫。", "翻然掉臂凌風去，何似王猷不及門。"]'),
('df263cde-5e3a-4b0d-8ba4-889d6323e0b5','南康道上','李呂','宋','宋诗','song-poetry','','[]','穿山深徑如行巷，拱道喬枝欲化龍。',32,'全唐诗/poet.song.125000.json','["穿山深徑如行巷，拱道喬枝欲化龍。", "開闢從來年代遠，不知過盡幾人蹤。"]'),
('fbc05b37-7629-4e92-8a34-708d47e80582','復聞杜鵑','李呂','宋','宋诗','song-poetry','','[]','憶到旴江聞子規，五更自在勸人歸。',32,'全唐诗/poet.song.125000.json','["憶到旴江聞子規，五更自在勸人歸。", "而今俄起蓴鱸念，不爲山禽說是非。"]'),
('dfd95568-ace5-45bf-a165-00e8b215ed12','宿洪氏南軒','李呂','宋','宋诗','song-poetry','','[]','馬乳龍鬚方壓架，玉簪羅蓋漸平堤。',32,'全唐诗/poet.song.125000.json','["馬乳龍鬚方壓架，玉簪羅蓋漸平堤。", "朅來頗釋塵勞念，况有清風入枕幃。"]'),
('311a3961-80d9-43bf-8fae-16fff8548e77','懷烏山柏庭僧宗文','李呂','宋','宋诗','song-poetry','','[]','清風明月休論景，翠竹黄花不離禪。',32,'全唐诗/poet.song.125000.json','["清風明月休論景，翠竹黄花不離禪。", "好箇趙州關捩子，陶潛欲辯已忘言。"]'),
('2a4b50d0-e492-44a3-b59b-411e16a2652a','遣興','李呂','宋','宋诗','song-poetry','','[]','一身欲著自無處，萬事不疑心始閒。',32,'全唐诗/poet.song.125000.json','["一身欲著自無處，萬事不疑心始閒。", "僕僕紅塵皆苦相，何時挾策過東山。"]'),
('1344c1fb-65b6-48ac-a9fa-3f51e88558a7','贈朱少南別二首  其一','李呂','宋','宋诗','song-poetry','','[]','外貌休尋餖座梨，應知石裏藴瓌奇。',32,'全唐诗/poet.song.125000.json','["外貌休尋餖座梨，應知石裏藴瓌奇。", "從來善相書前史，爲識英雄未遇時。"]'),
('74a0cefb-27bb-4bea-9cd0-df5bfca5a3d8','贈朱少南別二首  其二','李呂','宋','宋诗','song-poetry','','[]','朱君精到古人趣，踏遍東南稱獨步。',32,'全唐诗/poet.song.125000.json','["朱君精到古人趣，踏遍東南稱獨步。", "祇今應詔非乏材，預煩拈出棟梁具。"]'),
('646b3e5d-3d50-4eb1-b07d-c0ffa6cc8d60','己亥出南康宮伯稱以詩贈行次韻三首  其一','李呂','宋','宋诗','song-poetry','','[]','誰憐甲子混泥塗，老鈍何能展壯圖。',32,'全唐诗/poet.song.125000.json','["誰憐甲子混泥塗，老鈍何能展壯圖。", "方恨此行垂橐去，辱君贈句當駢珠。"]'),
('045e7b76-2e9c-436f-a146-db0a16f3834d','己亥出南康宮伯稱以詩贈行次韻三首  其二','李呂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','丹楓攝攝挂晨霜，笑指匡廬路許長。',32,'全唐诗/poet.song.125000.json','["丹楓攝攝挂晨霜，笑指匡廬路許長。", "且喜眼中無逐臭，自然心地發清香。"]'),
('544d1b52-b2aa-4151-9a25-69e71e256400','己亥出南康宮伯稱以詩贈行次韻三首  其三','李呂','宋','宋诗','song-poetry','','[]','君才端可用於時，努力行將徹主知。',32,'全唐诗/poet.song.125000.json','["君才端可用於時，努力行將徹主知。", "出處到頭皆分定，相期於道不須離。"]'),
('64c976aa-2726-42e2-8b08-538e7a9b8e5b','跋晦翁遊大隠屏詩','李呂','宋','宋诗','song-poetry','','[]','晦公詞翰妙天下，可見元無一點塵。',32,'全唐诗/poet.song.125000.json','["晦公詞翰妙天下，可見元無一點塵。", "爲問爭珠誰得者，須還趯倒浄瓶人。"]'),
('801da337-bd26-4be3-b924-64cb4b7718d2','以油煙贈許尉因賦長篇','李呂','宋','宋诗','song-poetry','','[]','我有堅玉黝而澤，嘗從十八公處得。',240,'全唐诗/poet.song.125000.json','["我有堅玉黝而澤，嘗從十八公處得。", "蘭膠麝篆積甚勞，佛帳書燈掃何益。", "江南務官骨已朽，潘仙久矣尋李白。", "誰歟獲此古膠法，持贈茅齋輕尺璧。", "我非其人弗忍磨，緘藏夜光侵几格。", "換鵝右軍肯輕示，五日京兆無人識。", "臨池學書水爲黑，不救晉家清談厄。", "風流解物遠山長，才輕未免遭刻責。", "神仙中人許玉斧，手持補天筆五色。", "效官一尉聊復爾，礨磈胸襟盡珠瓅。", "張顛落筆謾如雲，曹植波瀾翻逼窄。", "逢時騰踔不作難，定冠蓬山文字職。", "是物胡爲送乞君，要與銛鋒勢相敵。", "誅姦發潛蓋餘事，吾道豈容邪學塞。", "不然黄屋求正言，願染當今治安策。"]'),
('9bca341e-c6b8-4c46-8d40-969cd46b32a8','清友堂爲呂賓峰題','李呂','宋','宋诗','song-poetry','','[]','惡草不可近，惡蟲不可逢。',180,'全唐诗/poet.song.125000.json','["惡草不可近，惡蟲不可逢。", "草有有鈎吻，入口裂其胸。", "蟲中有細腰，蠆尾猶銛鋒。", "人生涉世故，得不戒遊從。", "澡心三峽浪，對面九疑峰。", "相須濟吾事，醖釀如酒醲。", "一朝臨利害，暗捷同機舂。", "箇中本無物，薄俗誰我容。", "眷彼冰雪姿，氣格天所鍾。", "蟠根便水石，作配宜竹松。", "相看世味薄，清坐真意濃。", "今時無膠漆，安得如駏蛩。", "永結歲寒伴，馨香滿蒙茸。", "願爲管鮑友，莫繼耳餘蹤。", "可能闢三徑，吾亦欲携筇。"]'),
('82560112-3db9-4811-9efc-9540179ef3df','雲際嶺','李呂','宋','宋诗','song-poetry','','[]','凌空石磴三千丈，匝地瑶林百萬花。',32,'全唐诗/poet.song.125000.json','["凌空石磴三千丈，匝地瑶林百萬花。", "自有眼來方見此，直疑身已到仙家。"]'),
('33c0b047-e59b-4df9-852b-5cbec6eb6b1c','壽鞏守','劉季裴','宋','宋诗','song-poetry','','[]','正月從來號履端，那堪生日遇天官。',64,'全唐诗/poet.song.125000.json','["正月從來號履端，那堪生日遇天官。", "萬尋山嶽才名重，千里江湖德量寬。", "菩薩像前開錦繡，老人星下爇旃檀。", "區區祝頌無他意，願見靈椿度歲寒。"]'),
('17538f72-348d-4faa-9aa0-627603f913bb','壽朱守','劉季裴','宋','宋诗','song-poetry','','[]','康鼎談經世少雙，一時文物動虞庠。',64,'全唐诗/poet.song.125000.json','["康鼎談經世少雙，一時文物動虞庠。", "江湖雖隔金閨籍，衣袖仍聞玉案香。", "墨客幾年陪畫隼，板輿平日到蘐堂。", "時清身健堪行樂，未見荆榛老鳳凰。"]'),
('00a168cd-4f93-401e-8b5e-ba846e984b0f','句','蹇駒','宋','宋诗','song-poetry','','[]','連山橫截展一臂，爲我障斷西南夷。',16,'全唐诗/poet.song.125000.json','["連山橫截展一臂，爲我障斷西南夷。"]'),
('40cbcaf7-1aea-4f85-a87e-e32976fd91e5','登更好堂同景思少卿表丈韻','王嵎','宋','宋诗','song-poetry','','[]','萬里同行一瘦筇，尋山問水有先容。',64,'全唐诗/poet.song.125000.json','["萬里同行一瘦筇，尋山問水有先容。", "更窮天姥投南路，已過台山第幾峰。", "從此又隨雙澗月，不妨曾聽五峰鐘。", "却從更好堂前望，滿眼詩材思不供。"]'),
('261347f3-61ca-4244-bc9a-12103c4ad39f','留藍溪驛','羅時用','宋','宋诗','song-poetry','','[]','寂寥孤館白日靜，酣睡有魔那得降。',64,'全唐诗/poet.song.125000.json','["寂寥孤館白日靜，酣睡有魔那得降。", "扣戶故人風動竹，齕萁羸馬浪翻江。", "飛殘蝙蝠燈留壁，啼盡栖鴉日到窗。", "堪笑浪遊成住此，一秋贏得鬢絲霜。"]'),
('3e18a3f0-631c-438e-a2e1-54fe246cc6fe','南源寺','范季隨','宋','宋诗','song-poetry','','[]','嬾逐兒曹載酒行，朅來蕭寺作清明。',64,'全唐诗/poet.song.125000.json','["嬾逐兒曹載酒行，朅來蕭寺作清明。", "江湖萬里此身健，風雨一春今日晴。", "露地野花雙戲蝶，並湖煙樹獨啼鶑。", "挂冠神武何時見，只合深藏諱姓名。"]'),
('5411069b-4e10-4cde-bd70-60fd04ac26e2','句  其一','胡溫彥','宋','宋诗','song-poetry','','[]','南朝欲相風方上，北敵聞風骨已寒。',16,'全唐诗/poet.song.125000.json','["南朝欲相風方上，北敵聞風骨已寒。"]'),
('dbd4d7ea-0f24-4d70-b157-9613bef7f0a0','句  其二','胡溫彥','宋','宋诗','song-poetry','','[]','已聽恩波生茗椀，更看皇澤下雞竿。',16,'全唐诗/poet.song.125000.json','["已聽恩波生茗椀，更看皇澤下雞竿。"]'),
('4b277076-65a6-4dd6-b238-78e59cd83304','句  其三','胡溫彥','宋','宋诗','song-poetry','','[]','難甘不是唐工部，竊效猶堪豔繡鞍。',16,'全唐诗/poet.song.125000.json','["難甘不是唐工部，竊效猶堪豔繡鞍。"]'),
('24574abd-02c3-4d2b-9c56-1740c9a4f2a6','題來安縣興國寺','遇僧','宋','宋诗','song-poetry','','[]','三千里地孤寒客，七十年前富貴家。',32,'全唐诗/poet.song.125000.json','["三千里地孤寒客，七十年前富貴家。", "泛海玉龍駕雪浪，權藏頭角混泥沙。"]'),
('513a6eb1-a2bf-4fbd-a6d0-d519d0f3425a','示江子我','朱昱','宋','宋诗','song-poetry','','[]','蠅營狗苟祇貽羞，萬事何能著意求。',64,'全唐诗/poet.song.125000.json','["蠅營狗苟祇貽羞，萬事何能著意求。", "自此閉門從所好，不妨高枕得無憂。", "經年不濯子春足，半月纔梳叔夜頭。", "此味肯教兒輩覺，誦書聲裏卧黄紬。"]'),
('92c9bb9c-17bb-4fbe-9cae-6817c11256e1','示羅教授楚知監','朱昱','宋','宋诗','song-poetry','','[]','半世交遊無遠信，一時賓客有新知。',64,'全唐诗/poet.song.125000.json','["半世交遊無遠信，一時賓客有新知。", "泮宮官冷宜談妙，圜府錢流不廢詩。", "封水占山爲久客，合樽促席及佳時。", "盆山突兀清泉滿，中有三江萬里思。"]'),
('0dce6785-d753-4115-b85e-03020db58c81','示張子昭','朱昱','宋','宋诗','song-poetry','','[]','西日未收東雨來，南軒相對北窗開。',64,'全唐诗/poet.song.125000.json','["西日未收東雨來，南軒相對北窗開。", "茫茫移穴蟻旋磨，擾擾出簷蚊聚雷。", "三宿定成桑下戀，一篇聊向雨中催。", "忘形頼有張公子，信手圍棋到夜回。"]'),
('aebf2c49-441a-4115-923d-6097feeae592','中秋示潘子賤','朱昱','宋','宋诗','song-poetry','','[]','雲徹通明殿，風涵白玉樓。',48,'全唐诗/poet.song.125000.json','["雲徹通明殿，風涵白玉樓。", "幽人當此夜，滿意作中秋。", "念念何曾問，塵塵自不收。", "覊懷忽冰釋，天地一虛舟。"]'),
('3601884c-8e50-46fa-a9ba-e89f23aa4ca5','競秀閣二首  其一','朱昱','宋','宋诗','song-poetry','','[]','輞川遥展右丞圖，盤谷中藏李愿居。',64,'全唐诗/poet.song.125000.json','["輞川遥展右丞圖，盤谷中藏李愿居。", "龍睡潭深飛客棹，鳳鳴枝老結吾廬。", "但令蠟屐去前齒，安用鴟夷託後車。", "西望子陵三十里，烟雲來往問何如。"]'),
('0e90d26e-483d-4ea7-8e39-69cddd79f9e7','競秀閣二首  其二','朱昱','宋','宋诗','song-poetry','','[]','客槎飛過小金山，畫棟參差杳靄間。',64,'全唐诗/poet.song.125000.json','["客槎飛過小金山，畫棟參差杳靄間。", "隠踏鼇頭歸月府，側騎龍背出塵寰。", "秋生弱水烟霞冷，春至蓬壺日月閒。", "遥望嚴陵釣魚處，十分全似落星灣。"]'),
('d740b0d0-e6d4-4177-b095-f3b3858a7951','一經堂','鄭裕','宋','宋诗','song-poetry','','[]','莆之甲姓，實維大方。',240,'全唐诗/poet.song.125000.json','["莆之甲姓，實維大方。", "紫囊錦帳，閥閲膏粱。", "有子盈之，乃其最良。", "心志乎道，視之如忘。", "博究六藝，并包五常。", "東家尼父，北窗羲皇。", "日相討論，兼收并藏。", "五經在笥，一經名堂。", "謙以自牧，雖晦而光。", "實浮于名，雖抑而揚。", "伊昔孟氏，排墨與楊。", "斯文羽翼，吾道棟梁。", "豈特詩書，獨稱其長。", "諸儒之說，于孟何傷。", "吾子命名，既擇而詳。", "通而貫之，輝涵汪茫。", "剖破藩籬，無門無旁。", "默契韶頀，能宮能商。", "正蒙析滯，起廢鍼肓。", "以一知萬，名實孔彰。", "人知同好，絺句繪章。", "玄酒太羹，子獨先嘗。", "經術之門，驥騁康莊。", "典謨之文，鳳鳴朝陽。"]'),
('448a9ea6-3efe-4145-a542-b5192bf1d332','偈頌二十一首  其一','釋堅璧','宋','宋诗','song-poetry','','[]','日月如彈丸，頑心似堅石。',60,'全唐诗/poet.song.125000.json','["日月如彈丸，頑心似堅石。", "堅石不可融，彈丸易跳擲。", "始見踏青行，相將年又極。", "誰將後夜霜，換我雙鬢黑。", "有箇不老方，諸人識不識。"]'),
('47ad9baf-0a35-43bc-9b44-8233ea4d5071','偈頌二十一首  其二','釋堅璧','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',24,'全唐诗/poet.song.125000.json','["晷運推移，日南長至。", "一夜東海烏龜，吞却南山鱉鼻。"]'),
('53b3d230-6901-4d52-900c-7ead2539c6eb','偈頌二十一首  其三','釋堅璧','宋','宋诗','song-poetry','','[]','大用全提作者知，爍迦眼活電光遲。',32,'全唐诗/poet.song.125000.json','["大用全提作者知，爍迦眼活電光遲。", "大悲院裏翻身處，臨濟甘爲小廝兒。"]'),
('84b91a57-a3dd-4940-ae0b-14b13ef1cbb1','偈頌二十一首  其四','釋堅璧','宋','宋诗','song-poetry','','[]','今朝六月中，嘉田雨沾足。',60,'全唐诗/poet.song.125000.json','["今朝六月中，嘉田雨沾足。", "山房冷似冰，千山擁寒玉。", "祖意不西來，法身無展縮。", "水上掛燈毬，鎮州出蘿蔔。", "三盞不沾脣，百味皆具足。"]'),
('c9cf573b-58bc-4906-b73f-3a112a95d458','偈頌二十一首  其五','釋堅璧','宋','宋诗','song-poetry','','[]','寰中獨照萬機息，壼外分權六國清。',32,'全唐诗/poet.song.125000.json','["寰中獨照萬機息，壼外分權六國清。", "四海晏然王化裏，不須當道話昇平。"]'),
('19b1e367-36d0-4a56-9524-b29f40bf186e','偈頌二十一首  其六','釋堅璧','宋','宋诗','song-poetry','','[]','釋迦慳，迦葉富。',68,'全唐诗/poet.song.125000.json','["釋迦慳，迦葉富。", "欺負乎人，誇張莽鹵。", "五天不納到支那，塞壑填溝無避處。", "無避處，不遮護，汲興相逢，如塗毒鼓。", "直須親切一回來，莫似邯鄲學唐步。"]'),
('044e21ef-c370-4121-ac0f-4bbce13b499c','偈頌二十一首  其七','釋堅璧','宋','宋诗','song-poetry','','[]','玉象吞獅子，泥牛上綉鞍。',24,'全唐诗/poet.song.125000.json','["玉象吞獅子，泥牛上綉鞍。", "御樓觀射獵，不是刈茆田。"]'),
('6d2ea957-2ea8-47f7-b228-bd7f2b2a8a4f','偈頌二十一首  其八','釋堅璧','宋','宋诗','song-poetry','','[]','仲冬嚴寒，一陽長至。',41,'全唐诗/poet.song.125000.json','["仲冬嚴寒，一陽長至。", "佛祖有機關，俱落第二義。", "豈不見溈山寂子與香嚴，未免將泥土裏洗。"]'),
('f769a209-3f4c-427d-902e-4b61dc1bbeec','偈頌二十一首  其九','釋堅璧','宋','宋诗','song-poetry','','[]','園林宿雨不勝清，巖谷舂撞萬杵鳴。',32,'全唐诗/poet.song.125000.json','["園林宿雨不勝清，巖谷舂撞萬杵鳴。", "箇裏豁開千聖眼，不閑弓矢賀昇平。"]'),
('42240072-43bb-414b-8ee8-37f1c8cad836','偈頌二十一首  其一○','釋堅璧','宋','宋诗','song-poetry','','[]','皓月當空，寒江不動。',60,'全唐诗/poet.song.125000.json','["皓月當空，寒江不動。", "萬里清光，曾非別共。", "蚌孕珠而無從，兔懷胎而非種。", "萬別千差，波騰海湧。", "卷舒只在一毫端，不用渾家生奉重。"]'),
('4bcfdaf2-1802-4444-8613-4d893425c61c','偈頌二十一首  其一一','釋堅璧','宋','宋诗','song-poetry','','[]','十日梅天曉未晴，千巖俱作偃溪聲。',32,'全唐诗/poet.song.125000.json','["十日梅天曉未晴，千巖俱作偃溪聲。", "直饒透出威音外，猶較曹山半月程。"]'),
('cfc5991c-d854-44a1-bcdb-d748e10a4813','偈頌二十一首  其一二','釋堅璧','宋','宋诗','song-poetry','','[]','及時陽燄欲燒空，中有清凉一徑通。',32,'全唐诗/poet.song.125000.json','["及時陽燄欲燒空，中有清凉一徑通。", "衆苦不來寒暑盡，鐵崑崙卧水晶宮。"]'),
('38633fbe-0407-4fd4-b4d1-68ed90cafb95','偈頌二十一首  其一三','釋堅璧','宋','宋诗','song-poetry','','[]','空手把鋤頭，步行騎水牛。',24,'全唐诗/poet.song.125000.json','["空手把鋤頭，步行騎水牛。", "憑茲陪睿算，垂拱億千秋。"]'),
('88ec0666-68e7-4392-a16a-83da15c2f26e','偈頌二十一首  其一四','釋堅璧','宋','宋诗','song-poetry','','[]','法法不隠藏，古今常獨露。',52,'全唐诗/poet.song.125000.json','["法法不隠藏，古今常獨露。", "槐影轉清陰，風催巖下雨。", "厨庫對僧堂，燈籠挂露柱。", "只有一處最誵訛，半夜泥蛇吞石虎。"]'),
('2bfe3466-5f24-4537-bb6a-7c07356985f9','偈頌二十一首  其一五','釋堅璧','宋','宋诗','song-poetry','','[]','樹凋葉落，體露金風。',58,'全唐诗/poet.song.125000.json','["樹凋葉落，體露金風。", "堯眉八字，舜目重瞳。", "機如掣電者，難尋蹤跡。", "口似磉盤者，驀地相逢。", "翻地揭天休作解，新羅元在海門東。"]'),
('c25ecfa4-f6cb-4554-bac4-6581c4d5a9ad','偈頌二十一首  其一六','釋堅璧','宋','宋诗','song-poetry','','[]','木人夜半穿靴，難尋蹤跡。',60,'全唐诗/poet.song.125000.json','["木人夜半穿靴，難尋蹤跡。", "石女天明不露，誰辨親疎。", "枯木上一點春回，古渡頭千尋寒雪。", "同門出入不來還憶渠，同氣相求回來劫無說。"]'),
('e528fa57-b473-4abe-afa3-842c75e82d3f','偈頌二十一首  其一七','釋堅璧','宋','宋诗','song-poetry','','[]','金葉銀莖報有秋，明珠萬斛堂中收。',32,'全唐诗/poet.song.125000.json','["金葉銀莖報有秋，明珠萬斛堂中收。", "自從一飽家田飯，不用埋頭向外求。"]'),
('74b2978c-a1e8-4eac-9829-0a8ee81200a1','偈頌二十一首  其一八','釋堅璧','宋','宋诗','song-poetry','','[]','漚澄巨浸無蹤跡，月轉層巒顯大功。',32,'全唐诗/poet.song.125000.json','["漚澄巨浸無蹤跡，月轉層巒顯大功。", "剎海毫芒無欠剩，空山和月撼松風。"]'),
('dca28622-ffab-41f4-9a4d-ed1aa6257652','偈頌二十一首  其一九','釋堅璧','宋','宋诗','song-poetry','','[]','陰極俄驚一線回，石人嶺上笑咍咍。',32,'全唐诗/poet.song.125000.json','["陰極俄驚一線回，石人嶺上笑咍咍。", "摧殘枯木非枯木，今日花從冷處開。"]'),
('e7ca246e-ce1c-45d1-a15b-b97cd19bfa11','偈頌二十一首  其二○','釋堅璧','宋','宋诗','song-poetry','','[]','相隨步步見還難，墨刷驊騮錦綉鞍。',32,'全唐诗/poet.song.125000.json','["相隨步步見還難，墨刷驊騮錦綉鞍。", "一夜遍行南贍部，天明依舊立江干。"]'),
('0266bb8a-85c1-433e-b80e-412f9dcf7a5a','偈頌二十一首  其二一','釋堅璧','宋','宋诗','song-poetry','','[]','參禪須是鐵漢，著手心頭便判。',28,'全唐诗/poet.song.125000.json','["參禪須是鐵漢，著手心頭便判。", "直趣無上菩提，一切是非莫管。"]'),
('555e3c35-efb6-4769-bd34-e8d53d02e540','仰山見東寺索珠','釋堅璧','宋','宋诗','song-poetry','','[]','無言可對輝天地，無理堪伸奪夜光。',32,'全唐诗/poet.song.125000.json','["無言可對輝天地，無理堪伸奪夜光。", "離相離名言語道，潑天高價不尋常。"]'),
('031a2d62-8ef0-4609-ad75-842f4162aec1','洞山喫果子','釋堅璧','宋','宋诗','song-poetry','','[]','盡力提來不等閒，要尋知己驗來端。',32,'全唐诗/poet.song.125000.json','["盡力提來不等閒，要尋知己驗來端。", "可憐臨水探紅尾，依舊茫茫失釣竿。"]'),
('c13c0327-f656-41ca-9a11-69850bd19435','化胡椒','釋堅璧','宋','宋诗','song-poetry','','[]','異國傳來種性殊，圓陀陀似蚌中珠。',32,'全唐诗/poet.song.125000.json','["異國傳來種性殊，圓陀陀似蚌中珠。", "不□□艷照明月，自有辛香壓五湖。"]'),
('940060ca-e3de-4306-9778-4007853db1d9','送人','釋堅璧','宋','宋诗','song-poetry','','[]','千尋老幹無寒暑，百鍊精金有變遷。',32,'全唐诗/poet.song.125000.json','["千尋老幹無寒暑，百鍊精金有變遷。", "脫盡皮毛空索索，不妨重結弟兄緣。"]'),
('30ae9f4f-81f9-4a29-9165-9254d3bc7117','送堅知庫','釋堅璧','宋','宋诗','song-poetry','','[]','埽盡法中病，生憎佛是塵。',24,'全唐诗/poet.song.125000.json','["埽盡法中病，生憎佛是塵。", "堂堂一堅密，春至百花新。"]'),
('ac01c0b4-018a-4df7-8d81-46dc9a22ccbb','送泉州僧','釋堅璧','宋','宋诗','song-poetry','','[]','洛陽橋下千尋水，象骨峰前萬疊山。',32,'全唐诗/poet.song.125000.json','["洛陽橋下千尋水，象骨峰前萬疊山。", "一口爲渠吞却了，更無蹤跡在人間。"]'),
('a298147e-217a-40d1-8fac-5933978f50f3','送人','釋堅璧','宋','宋诗','song-poetry','','[]','六窗不著閒光景，七處休尋古佛心。',32,'全唐诗/poet.song.125000.json','["六窗不著閒光景，七處休尋古佛心。", "放下不行凡聖路，敢將黄葉當黄金。"]'),
('b80c25d5-bbed-4c73-ac72-f030944e605f','義副寺求','釋堅璧','宋','宋诗','song-poetry','','[]','拈却義，除却法，過現未來，不消一劄。',66,'全唐诗/poet.song.125000.json','["拈却義，除却法，過現未來，不消一劄。", "大海波騰河四流，激湍衮衮吞三峽。", "須彌山王拊掌笑，江神河神俱𨁝跳。", "留得珊瑚對月寒，九曲明珠無孔竅。"]'),
('e2352fea-fb0c-41f5-8176-df170dd4d47b','山居二首  其一','釋堅璧','宋','宋诗','song-poetry','','[]','瓶盂古澗冷相依，雲淡山寒月色微。',64,'全唐诗/poet.song.125000.json','["瓶盂古澗冷相依，雲淡山寒月色微。", "眼底賓朋聊自足，屋頭猿鳥恰忘機。", "山園茶笋疎疎有，世路人情漸漸稀。", "不記化權前後際，卷簾移榻看斜暉。"]'),
('26050167-c9b1-43f6-b792-7d19a0c92ec1','山居二首  其二','釋堅璧','宋','宋诗','song-poetry','','[]','平生湖海竟何依，選得佳山賦式微。',64,'全唐诗/poet.song.125000.json','["平生湖海竟何依，選得佳山賦式微。", "茗椀爐熏同宿學，蒲團禪板接初機。", "陂城水滿芹尤滑，瓦缽肩挨粥未稀。", "睡起烏藤清興在，不知老木掛殘暉。"]'),
('457638f7-9645-40a6-967c-e7ee92dc02f0','贊真覺','釋堅璧','宋','宋诗','song-poetry','','[]','三回九度，見神見鬼。',46,'全唐诗/poet.song.125000.json','["三回九度，見神見鬼。", "德山一棒，痛徹骨髓。", "敲老觀門，潑瓦官水。", "而今冷坐眼麻眉，錯認東瓜作碓觜。"]'),
('b6671797-0b5e-452f-8edd-d3892c3aa463','贊卿老真','釋堅璧','宋','宋诗','song-poetry','','[]','風蕭蕭，天空四壁。',52,'全唐诗/poet.song.125000.json','["風蕭蕭，天空四壁。", "雨疎疎，巖花狼藉。", "乾剝剝，白浪滔天。", "寂寥寥，徧界荆棘。", "漾在栖雲草莽中，堪嗟大地無人識。"]'),
('608a4920-49d8-4b5d-90c0-e110b8cca0c3','自贊三首  其一','釋堅璧','宋','宋诗','song-poetry','','[]','三際斷，一亙空。',44,'全唐诗/poet.song.125000.json','["三際斷，一亙空。", "轉不轉，功不功。", "迢迢物外像，矯矯巖間松。", "密密處不堪親近，荒林裏得意相逢。"]'),
('62183131-2a7f-43ae-aba5-a290e6576285','自贊三首  其二','釋堅璧','宋','宋诗','song-poetry','','[]','癡不自揆，老不知休。',48,'全唐诗/poet.song.125000.json','["癡不自揆，老不知休。", "提真覺雀觜杖，用曹山死貓頭。", "乾剝剝，冷湫湫。", "炙地熏天無氣息，拋沙撒土覓冤讐。"]'),
('f0b56745-3f85-454d-812f-6dbdc59d93c7','自贊三首  其三','釋堅璧','宋','宋诗','song-poetry','','[]','喻指喻馬，何勞真假。',90,'全唐诗/poet.song.125000.json','["喻指喻馬，何勞真假。", "說性說心，轉見病深。", "靈山拈花，不曾動著。", "少林冷坐，徒自沈吟。", "良工欲寫莫可寫，汝曹敬之隔千林。", "山陰陰，水沈沈。", "蒼苔雪徑冷不徹，花鳥夕陽閒古今。", "真兮真兮，胡得而臨。"]'),
('d211c059-cb8d-4349-8985-8f5db3dbc468','金瀨弔貞女','王端朝','宋','宋诗','song-poetry','','[]','嗟彼戰國秋，風俗日以漓。',204,'全唐诗/poet.song.125000.json','["嗟彼戰國秋，風俗日以漓。", "卓哉史氏女，粲粲蘭蕙姿。", "守貞奉慈母，克盡烏鳥私。", "業貧不辭苦，擊漂臨清漪。", "適爾遇丈夫，失路良可悲。", "惻然爲發筥，振彼窮途饑。", "振窮乃所愿，越禮非所宜。", "滅口葬魚腹，此心天地知。", "丈夫既得志，雪恥鞭平屍。", "念此一日恩，仗節遠來茲。", "百金報無地，立馬空嗟咨。", "俛仰易陳跡，屈指萬古期。", "誰招地下魂，惟遺道旁碑。", "雄辭吐激烈，粲若星貝垂。", "吾生後謫仙，況乃駑鈍資。", "捧心學西子，取笑將奚爲。", "留題表貞義，庶幾薄俗移。"]'),
('124e3110-510f-4832-a6d7-752f6ef75279','華勝寺題壁','翁蒙之','宋','宋诗','song-poetry','','[]','高閣登臨佛國春，逍遥聊復話前因。',64,'全唐诗/poet.song.125000.json','["高閣登臨佛國春，逍遥聊復話前因。", "老來白業漸欲近，興到青山相與新。", "擾擾簿書拋舊夢，迢迢鐘磬著閑身。", "笑他車馬臨官道，不及朝耕暮讀人。"]'),
('5182c63d-f5ba-4cf8-9244-2cc31f1c7fa1','贈別','李流謙','宋','宋诗','song-poetry','','[]','水火氣類感，草木臭味親。',156,'全唐诗/poet.song.125000.json','["水火氣類感，草木臭味親。", "君看金石交，分篤均天倫。", "朅來東川游，結友輕雷陳。", "諸君盡豪俊，著我漫浪身。", "酒斟約無算，詩妙各有神。", "人事不可知，變態生逡巡。", "一代韓荆州，大木卧龍鱗。", "客禽失危巢，翩翩傍叢榛。", "斗升何細碎，朱絲恐生塵。", "知己淚再滴，離羣恨方新。", "去茲勝社難，胸腹傷人神。", "臨岐欲何語，一味唯酸辛。", "歲晚念裘褐，幸勿忘騷人。"]'),
('83f05007-3d7f-4b09-a4b7-f7503ee86392','送羅制參','李流謙','宋','宋诗','song-poetry','','[]','平生願識韓，一見屣履迎。',156,'全唐诗/poet.song.125000.json','["平生願識韓，一見屣履迎。", "自揣何所持，徒有汗背驚。", "下士公盛德，事賢我真情。", "西南大幕府，控制七十城。", "自公歸奏功，泰階夜光明。", "上前論賓客，豈但丞冰衡。", "况公天人學，根本敬與誠。", "么麽見事功，萬物待生成。", "三月漲桃花，鏡面江流平。", "若爲化檣烏，親送帆檝行。", "臨風嘿悽然，一紙聊寄聲。", "上有字加餐，意重千金輕。", "勿言暫暌闊，四海如弟兄。"]'),
('226fbb03-c515-408e-9dab-8af2ee61daae','戲貽秋泉子','李流謙','宋','宋诗','song-poetry','','[]','桂椒發芳辛，水泉佐澄潔。',168,'全唐诗/poet.song.125000.json','["桂椒發芳辛，水泉佐澄潔。", "風味可人哉，醖藉固佳客。", "清非伯夷隘，和異柳惠褻。", "壺子與俱來，表裏清徹骨。", "素魄吸沆瀣，枯腸濯埃𡏖。", "東家欲毋我，漆園强齊物。", "物我儻未融，平地森劍㦸。", "非秦亦非越，有國名建德。", "恬流不須航，坦逕無轍迹。", "笑渠秉周禮，况復用蕭律。", "聚糧適千里，叱馭履九折。", "勸君反爾轅，神尻徐而疾。", "伯倫駕予車，元亮脂我轄。", "胚渾未兆前，羲軒乃叔末。"]'),
('57beb02f-ab71-439b-8c95-47a0656b18eb','病中作此','李流謙','宋','宋诗','song-poetry','','[]','苦熱日念秋，秋至轉多病。',156,'全唐诗/poet.song.125000.json','["苦熱日念秋，秋至轉多病。", "枯藤不得力，小室同械禁。", "形骸老翁然，但未雪繞鬢。", "秋山疊翠嶂，秋月掛冰鏡。", "朝躋閑屐齒，夜語閣麈柄。", "妻孥生悵望，煮藥勸屢進。", "故人尚記存，折簡時一問。", "年來識真妄，水月空萬境。", "鬭蟻非實響，杯蛇亦幻影。", "誰于炯炯中，屑金作塵眚。", "酒盞行欲謝，雲窗豈復近。", "唯有妙蓮華，勝味方雋永。", "誰來炷爐熏，佩子法王印。"]'),
('25623d10-413c-4b8c-a360-d4eec20de96c','秋懷','李流謙','宋','宋诗','song-poetry','','[]','悠悠感愁運，肅肅勵素節。',204,'全唐诗/poet.song.125000.json','["悠悠感愁運，肅肅勵素節。", "蟾華度疎櫺，蘭吹出叢薄。", "幽蟲泣煙莎，微螢映露葉。", "百哀攻予衷，感此重忉怛。", "庭闈餘斑衣，荒壠已白骨。", "苟生尚何聊，從死恐亡益。", "鞠凶天未悔，風急鴈序拆。", "女須冰玉質，眼看沒荒域。", "山鬼不足鄰，何年反爾魄。", "危腸盡一哭，六月霜凜烈。", "自從奪所怙，殘魂慨零落。", "虛弦已折翮，况此百中鏑。", "人生寄一世，常苦不滿百。", "血氣如微流，豈禁沸鼎涸。", "隠憂誰復訴，任理寬萬一。", "貝葉了諸妄，一真無悅戚。", "香火有昔緣，從茲事朝夕。"]'),
('f113f038-30df-4cac-a57b-07af5c4ede57','浴罷','李流謙','宋','宋诗','song-poetry','','[]','性懶如嵇康，不沐已三歲。',144,'全唐诗/poet.song.125000.json','["性懶如嵇康，不沐已三歲。", "蟣虱擅封域，汙垢爲之地。", "譬之大諸侯，父死輒子繼。", "納汙固云久，用鉞豈得已。", "朝來湯沐具，縞素雪危涕。", "决河卷塵泥，崩風刮氛翳。", "弛擔坐茂樹，未足當快意。", "晚日瀝餘潤，寸櫛導積氣。", "蓬根入風露，浮爽到肝肺。", "却憂見斑毛，引鏡不敢對。", "彈冠一趺坐，茹連豈吾事。", "置之勿復道，我醉欲眠爾。"]'),
('9c12a428-bd1b-4ede-afd5-b1f0beb2fc9f','鄴守以石刻屈平昭君像見惠因思大夫之忠貫白日而凌秋霜在所不論而昭君以傾國之豔擅天下之色乃不肯自同衆姬貨畫師以求媚此尤爲可感者爲賦此篇','李流謙','宋','宋诗','song-poetry','','[]','璇題朝曦麗，椒殿春風香。',264,'全唐诗/poet.song.125000.json','["璇題朝曦麗，椒殿春風香。", "带日羨寒鴉，灑鹽引癡羊。", "那知韶葩妍，有此秋節剛。", "千金非我愛，所重在行藏。", "奮然斬畫史，低頭笑君王。", "呈身由諂壬，百態恐不當。", "照影見冠佩，豈不羞帷房。", "自從到北庭，幾閲紫塞霜。", "年年鴻鴈歸，不寄一字將。", "却悲降將軍，高臺望故鄉。", "至今青塚上，沙草不肯黄。", "吾觀嬌色兒，睥睨此濫觴。", "孽閹擅國辟，天地爲低昂。", "眼前殺師傅，但有涕淋浪。", "區區一女子，去留係毫芒。", "我行桃李村，高髻餘舊粧。", "負薪行汲泉，不願同康莊。", "爲計盍不爾，乃以美自戕。", "初心豈其然，薄命遭彼狂。", "離騷照白日，至今祖文章。", "婉孌古稱士，後先出寒鄉。", "遺刻共想像，再歌重慨慷。"]'),
('6be5c811-1406-490b-a9c4-577fafdd4687','即事','李流謙','宋','宋诗','song-poetry','','[]','畏熱客不來，習懶我倦出。',48,'全唐诗/poet.song.125000.json','["畏熱客不來，習懶我倦出。", "愛閑閑不徹，一日如兩日。", "晚風生微凉，佳月挂西壁。", "誰爲無事人，共此可憐夕。"]'),
('65d18a9e-5796-42e5-bd21-17184e885f10','得小麑因戲作','李流謙','宋','宋诗','song-poetry','','[]','傾江釀斗秫，未啻俗之醨。',204,'全唐诗/poet.song.125000.json','["傾江釀斗秫，未啻俗之醨。", "向來故疎慵，重此百憂罹。", "杜門不復出，出亦將從誰。", "山氓過予言，刈樵得雛麑。", "適我藪澤念，亟買不論貲。", "斷乳無幾日，疎毳未傅皮。", "檻牢異林壑，恐作南冠纍。", "解縛非予靳，弱質叵自持。", "罦羅竹節稠，失脚悔可追。", "泠泠溪流甘，蔚蔚庭草肥。", "人生一飽耳，八荒吾庭幃。", "我自不亂羣，爾能忘土思。", "馴狎不違性，長大儻有期。", "充庖斷勿憂，巾車薄勞之。", "南山與北澗，伴我歌紫芝。", "張陳慨中畫，管鮑謬己知。", "新交不更添，歲寒端自茲。"]'),
('b92ed724-1808-4da8-a1de-6edc762688ef','數醉','李流謙','宋','宋诗','song-poetry','','[]','清秋無所爲，遇酒時一醉。',96,'全唐诗/poet.song.125000.json','["清秋無所爲，遇酒時一醉。", "醉則遺形骸，兀然外天地。", "塵世多得失，古事有興廢。", "更復不快飲，徒爲亂人意。", "屈原貴獨醒，賈誼每流涕。", "二子竟中夭，惜哉且自棄。", "蒼苔晚雨濕，紅葉北風厲。", "樂鄉聊可謀，悲秋豈吾志。"]'),
('c302db2f-8161-431b-975a-28fed8f8ba4c','病中','李流謙','宋','宋诗','song-poetry','','[]','稟生拙以疎，俯仰人事勞。',72,'全唐诗/poet.song.125000.json','["稟生拙以疎，俯仰人事勞。", "煩疾乘秋至，幽憂安能逃。", "閉閤無餘欣，西風晚蕭騷。", "乃悟揚子居，未曾損一毛。", "流光背人馳，歲暮不自聊。", "安得七發賢，相從觀海濤。"]'),
('1595430f-5e4c-4913-940a-f378b513326a','黄思忠病起作此寄之','李流謙','宋','宋诗','song-poetry','','[]','巖巖千丈松，大厦不收拾。',204,'全唐诗/poet.song.125000.json','["巖巖千丈松，大厦不收拾。", "已作澗壑卧，更困螻蟻穴。", "天果無意哉，問龜龜不食。", "悲歌氣填膺，白虹爲貫日。", "向來亡公子，後日九州伯。", "奈何蕞爾曹，乃敢觀裸浴。", "士窮有如此，於君更心惻。", "平生治國手，僅脫在陳厄。", "三彭捃細故，二豎侮明德。", "聞之投袂起，此士豈易得。", "可無不貲藥，粉珠屑白玉。", "奮髯呵不祥，有神嘿操㦸。", "欻然蛙腹裂，還我蒼玉璧。", "一尊欲壽君，悵念風雨隔。", "平吳固奇烈，更謹盤水執。", "君身則千金，斯文但一髮。", "勉矣加餐飯，吾道係損益。"]'),
('2dc4cf68-14a0-4ef2-be3e-f4d10a5403d6','予游潼川將訪魏城令君李仲明而不果作此寄之','李流謙','宋','宋诗','song-poetry','','[]','骨肉纏恩愛，友朋綴情義。',120,'全唐诗/poet.song.125000.json','["骨肉纏恩愛，友朋綴情義。", "於君若兼之，何生結此契。", "朅來東川游，咫尺桃李縣。", "引車意甚决，牽衣事輒挽。", "我如空中雲，隨風出巖岫。", "又如波上舟，東西聽水手。", "有心不能酬，富貴那可必。", "富貴吾不願，此見未宜失。", "裁詩說相思，過鴈或堪託。", "鴈能見君子，嗟予鴈不若。"]'),
('50bbf54f-85a1-4d1e-86d8-4b75c1775aed','送臺石甫出關','李流謙','宋','宋诗','song-poetry','','[]','臺君少年時，盛氣不可蓋。',168,'全唐诗/poet.song.125000.json','["臺君少年時，盛氣不可蓋。", "冀北駒墮地，過都如歷塊。", "未說兩石弓，談詩亦堅對。", "十年憂患繞，玄螭伏淺瀨。", "寶劍夜韜光，蒼鷹秋折翅。", "飄風詎終朝，否極理則泰。", "秋高氣益肅，匹馬指絕塞。", "酒闌奮袂起，曉色風雨晦。", "關頭飛將軍，久矣側席待。", "解鞍握手語，意合琥珀芥。", "去去未可知，建侯萬里外。", "兩耳熟高名，邇方揖英槩。", "頗知倜儻士，別意殊憒憒。", "贈行敢他言，忠義福所介。"]'),
('f455ede3-8b56-4e6d-aa1a-72ca36b60946','送覺華巖歸中巖','李流謙','宋','宋诗','song-poetry','','[]','世故翻巨浪，是身如孤舟。',168,'全唐诗/poet.song.125000.json','["世故翻巨浪，是身如孤舟。", "黑風半夜來，掀簸卒未休。", "誰能洶涌間，輕飛逐浮鷗。", "稽首大導師，覺海名善泅。", "請下一轉語，爲度歷劫憂。", "師笑了無言，此問難爾酬。", "未可檝迎汝，子歸當內求。", "堅忍作維纜，巨防截橫流。", "中有不動者，東西聽漂浮。", "師今念故山，翩然去難留。", "相送城東隅，黄葉堆別愁。", "歸來閉閣坐，念念期自修。", "精進儻不懈，針芥或有投。", "西風白蓮開，束包隨勝游。"]'),
('3bd6404b-019b-43ad-a96a-af799f4de60d','元日泛舟分韻得大字','李流謙','宋','宋诗','song-poetry','','[]','春從沙際生，白石映淺瀨。',180,'全唐诗/poet.song.125000.json','["春從沙際生，白石映淺瀨。", "一舟何自橫，玄寄倏與會。", "今日是何朝，亦恐魚鳥怪。", "曉暾破宿雨，換歲無此快。", "柁工貌閑暇，一篙有三昧。", "夷猶我無心，上下聽汝輩。", "斷崖舂濤波，千古意不改。", "中流浸玻璃，綠浄吾苦愛。", "林深故疎密，山遠自明晦。", "隔江見人家，短籬護畦菜。", "蓑笠弄晚色，真樂在牛背。", "稍能薄輸征，武陵豈天外。", "吾曹二三子，勿作碌碌待。", "濤戎嘆山河，塵凡累纓佩。", "人生富貴哉，固有一事大。"]'),
('37c82335-3dd4-4b82-a350-af2965859f6c','月夜泛舟','李流謙','宋','宋诗','song-poetry','','[]','苦雨連日夜，佳月遭薄蝕。',192,'全唐诗/poet.song.125000.json','["苦雨連日夜，佳月遭薄蝕。", "晚風散積靄，水天忽改碧。", "江臯放幽步，露下襟袂濕。", "劃然湖海興，如驥不受勒。", "扁舟繫枯柳，漁子眠已熟。", "喚起勿作難，解纜破秋色。", "移我坐空曠，四顧竦毛骨。", "山空木葉脫，岸斷石脚出。", "舍舟訪鄰叟，醉卧不納客。", "何必見安道，意行無適莫。", "書生亦底事，忍凍犯蛟窟。", "可憐窮事業，坐恐清景失。", "歸來定何得，索酒更深酌。", "上士不言喻，下士笑局局。", "太白下羌江，蘇仙遊赤壁。", "風流共一時，作詩記今夕。"]'),
('4750ee1a-2406-4ccb-9f8e-ae2598c77342','東巖施頭陀所隠也頭陀唐人初居郡之奉聖寺太守獨孤見之頭陀不加敬獨孤怒既去遣吏捕之頭陀以笠涉江至此山吏隨焉頭陀隠巖間兩虎守之吏駭退即其地爲院昔律今禪予昔侍親守簡數來游再到賦此詩','李流謙','宋','宋诗','song-poetry','','[]','勝地憶屢到，變革非昔年。',144,'全唐诗/poet.song.125000.json','["勝地憶屢到，變革非昔年。", "律居掃積陋，禪房侈舊觀。", "老衲不可見，遺事故老傳。", "使君擅一壑，憑愚妄自賢。", "定心初不摇，蚊虻卒飛前。", "赫然漲蛙腹，欲以火燎天。", "一笠渡清波，絕壁守兩斑。", "游戲出小異，褫駭飛殘魂。", "慢敬汝則勞，道力屹如山。", "一笑置勿問，爐薰裊輕煙。", "洗盞酌石溜，吻頰冰雪寒。", "却憶飛泉句，泫然思老仙。"]'),
('01047285-a89b-41b8-813b-4948d1d18dec','從馮黎州飲梅林以山谷舊時愛酒陶彭澤今日梅花樹下僧分韻賦詩得時字','李流謙','宋','宋诗','song-poetry','','[]','巾冠墮城府，桔槔無休時。',228,'全唐诗/poet.song.125000.json','["巾冠墮城府，桔槔無休時。", "胸脾貯黄埃，非復林壑姿。", "涎流方外勝，秦人望軒羲。", "萬金買閑日，駕言一紓眉。", "冒踏衆俊塲，更從百代師。", "食魚得河魴，熊蹯佐其滋。", "靉靉煙雨村，霜條出冰蕤。", "烏鵲噪寒暝，玉立山差差。", "置樽扶疎下，壽幹虬蛟馳。", "落蘂不動塵，初無犀駭雞。", "深酌起自勸，非族不在斯。", "公行對宣溫，雲霧生攀躋。", "能來玩墟落，匹馬却蓋麾。", "蟠胸萬螮蝀，區寰眇毫絲。", "以茲接羣動，白羽坐指揮。", "笑彼豢外者，組紱爲之鞿。", "他年駟馬還，梅花當十圍。", "記此黄公壚，下車挽客衣。", "未覺邈山河，一醉固大奇。"]'),
('54ff1ac2-b85c-42be-ac37-5c5b40efa8bc','用山谷上東坡韻與馮黎州  其一','李流謙','宋','宋诗','song-poetry','','[]','賜履聖賢地，專征翰墨塲。',96,'全唐诗/poet.song.125000.json','["賜履聖賢地，專征翰墨塲。", "藜然本非照，昏幽自蒙光。", "醍醐有真液，薝蔔無別香。", "座當百尺樓，餘子但廡廊。", "譽毀不可劫，造物能雌黄。", "簡編熟古人，見公蓋未嘗。", "彭黥非韓敵，或可噪其旁。", "公有八紘罝，就獵庸何傷。"]'),
('8c7d0428-2b9d-4a06-9f43-ff7af155e421','用山谷上東坡韻與馮黎州  其二','李流謙','宋','宋诗','song-poetry','','[]','鼓鏞作宮庭，缶盎不能聲。',84,'全唐诗/poet.song.125000.json','["鼓鏞作宮庭，缶盎不能聲。", "僊圓起瀕死，乃欲進豨苓。", "淫書有痼疾，展卷自弱齡。", "俗學或攘之，正憂荆棘生。", "孔顔共一世，餘事不芥蔕。", "跪求直指處，遂了不朽計。", "自今面其真，向來獨喜似。"]'),
('cda696fb-9569-42e3-8c5d-b7ba9683b66a','送孫隆州','李流謙','宋','宋诗','song-poetry','','[]','萬里對明光，真實一字字。',168,'全唐诗/poet.song.125000.json','["萬里對明光，真實一字字。", "九陛元不隔，是亦父子爾。", "我讀公車牘，再拜甚歡喜。", "玉色近昕夕，王度日完粹。", "再析山中符，可以覘胸次。", "道行國無小，意甘食則旨。", "平生熟窺覘，步步聖賢地。", "造物寶其人，華皓表斯世。", "從軍落窮塞，愁破覿清峙。", "蝸廬僅纏軀，鼓鐘日在耳。", "何以充淹留，白日不可繫。", "長年慕道德，師友別匪易。", "躑躅南城隅，竚立渺無涘。", "不見兩朱輪，但見嘉陵水。"]'),
('cd963e22-ef39-4467-b28a-9e7d6486a13a','上費邛州','李流謙','宋','宋诗','song-poetry','','[]','疏茅裂萬戶，百戰未易得。',264,'全唐诗/poet.song.125000.json','["疏茅裂萬戶，百戰未易得。", "一識荆州面，不作半錢直。", "朝曦明生東，夜斗光炯北。", "皎皎羣目用，餘影到盆隙。", "共在一世間，能無一世傑。", "要渠兩眼青，洞此寸心赤。", "使君絕不凡，白璧生徑尺。", "龔黄漢循吏，阮謝晉人物。", "稍稽一節趨，戯從五府辟。", "端知付兩轓，乃用倡九牧。", "春風長桑柘，豚犢飽柵櫪。", "遺秉利寡婦，負戴無斑白。", "靈河貫中國，寸地沾滴瀝。", "三公乃故事，企踵榮晝接。", "慕用吾已夙，願見憂不亟。", "聊欲寫我心，敢幸康而色。", "賓庖月照俎，談閣風滿席。", "秋霜濕征衣，行李驚遽迫。", "戀軒寄悲嘯，孤恨繞華㦸。", "權輿置身地，大冶天地窄。", "相馬不相肉，剖玉莫剖石。", "狗盜何足言，囊錐有奇客。"]'),
('8002ded5-c9d5-444b-9c06-a6aba1975c2b','馬德駿微恙既平作此勞之','李流謙','宋','宋诗','song-poetry','','[]','內寇非陰陽，窮愁因緣之。',144,'全唐诗/poet.song.125000.json','["內寇非陰陽，窮愁因緣之。", "堅壘自却走，不藥亦不龜。", "夫子樂唐虞，短褐蔭茅茨。", "塵不上几闥，何物作伺窺。", "或丐愈風檄，豈邀遣瘧詩。", "朝來就清爽，梳髮修竹墀。", "買酒約相過，勝地相扶携。", "人生踰四十，浸與衰苶期。", "君壯尚俘劫，我怯重嗟咨。", "問丹勾漏迂，訪道弱水疲。", "綿綿抱谷神，閉門有餘師。", "鶴病無死骨，松瘦有老枝。"]'),
('b5b8ecf4-d82d-4a68-9205-06e02fc6e87b','同游公玉伯氏季氏遊水陸院濯纓閣以清斯濯纓分韻賦詩得斯字','李流謙','宋','宋诗','song-poetry','','[]','積雨泥斷道，扶筇將何之。',204,'全唐诗/poet.song.125000.json','["積雨泥斷道，扶筇將何之。", "愁蹲寡情味，竄壁如蠅癡。", "朝暾惠新晴，僊風起衰萎。", "振衣欲有詣，扣扉適相期。", "百步得精廬，一丈清泠池。", "老木圍蕭森，回風影差差。", "向來赫然者，挾冰誦昔非。", "晤言意能消，真適神不疲。", "鱗游鳥空翔，趣舍各不知。", "我閑苦枵餒，吏奪君嗟咨。", "拙巧自殊用，靜躁亦異宜。", "能來共幽曠，合處或在斯。", "夜光栖重囦，草木生光輝。", "抵鵲者誰子，而况彈病鴟。", "我有飛霞裾，雲旗駕靈螭。", "舉頭叫閶闔，九萬風反低。", "敬以贈美人，嘉惠無時衰。"]'),
('f044448a-96ab-438c-9ca5-eb863fe05e2f','送劉文潛司業江西漕二首  其一','李流謙','宋','宋诗','song-poetry','','[]','百爲自叢拏，至理在綿眇。',48,'全唐诗/poet.song.125000.json','["百爲自叢拏，至理在綿眇。", "刀硎閟新穎，鏡像蓄遺照。", "吾心又不然，一士欲矯矯。", "目送雲端禽，舉觴可以了。"]'),
('64668002-47d0-4f2b-a017-ee60fb71e875','送劉文潛司業江西漕二首  其二','李流謙','宋','宋诗','song-poetry','','[]','始作想澄清，歊暑不敢毒。',48,'全唐诗/poet.song.125000.json','["始作想澄清，歊暑不敢毒。", "以茲壽慈母，吾鼎愧半菽。", "恨我如宛童，失此百圍木。", "豁然心光動，千里尚相燭。"]'),
('5bb7ce2b-04a1-473a-bde2-b12e466a62d8','清明日同宋才夫王子友游秦氏園分韻得一字','李流謙','宋','宋诗','song-poetry','','[]','誰澆無邊春，釀成此天色。',192,'全唐诗/poet.song.125000.json','["誰澆無邊春，釀成此天色。", "文章祇引睡，茗椀不著力。", "雖無田父邀，欲到野人宅。", "日萼鬭深妍，風條舞柔碧。", "數峯極藴藉，未到輒目逆。", "人心有同然，一樣寄岑寂。", "茅茨破不補，吾意嘿有適。", "置樽小軒戶，雲氣手闔闢。", "蒼蒼萬檀欒，晚吹自蕭瑟。", "穿荒取微逕，便曠從短策。", "忽與幽興會，照我兩尺璧。", "白虹潤山木，取友固多益。", "談深近迂怪，理奧煩探索。", "鯨杯不足吞，馬肝無用食。", "玉虬蟠蜿蜒，萬鱗寒縮澀。", "餞春春未闌，尚及三之一。"]'),
('cd53b868-547b-4f9b-bb0a-f3aa4fd69617','觀畫文氏園小酌而歸','李流謙','宋','宋诗','song-poetry','','[]','衝暑去何之，城南水竹園。',132,'全唐诗/poet.song.125000.json','["衝暑去何之，城南水竹園。", "發篋得祕畫，筆老不見痕。", "作者非俗士，噞喁不能名。", "王郎眼如月，指點見本根。", "解衣而盤礴，主人固可人。", "虛齋坐修竹，一面當暑煩。", "斜陽送暮色，無數烏鳥喧。", "漠漠芳樹暗，涓涓流水渾。", "星斗掛簷端，餘影到清樽。", "行觴令不虐，捉麈語不繁。", "不知聊爾耳，佳處正難言。"]'),
('a488e54c-362a-4cab-8ded-7d0fa6e45045','劉林夫以諸公送行詩軸見示作此','李流謙','宋','宋诗','song-poetry','','[]','我思在何許，却立望高丘。',120,'全唐诗/poet.song.125000.json','["我思在何許，却立望高丘。", "手持金錯刀，美人不可求。", "此意恐蹉跎，悵然生百憂。", "嘉魚樂循渚，潑潑不受鈎。", "燥濕各天性，萬生難其儔。", "喬木懷故家，日星藻皇猷。", "吾欲徵文獻，庶以充淹留。", "鼓鐘侑大烹，其樂有此不。", "江黄預壇坫，齋明盛陽秋。", "義合在一朝，如新嗤白頭。"]'),
('b7f064cc-307d-4b57-bb5d-82ea69de4722','和林夫讀老泉先生上歐陽公書韻','李流謙','宋','宋诗','song-poetry','','[]','倚門抹青紅，過者必反顧。',96,'全唐诗/poet.song.125000.json','["倚門抹青紅，過者必反顧。", "風雨不足憑，零落汙黄土。", "斯文有正色，神指亦難數。", "兩漢僅自支，崔蔡已衰暮。", "老龍破風雷，一躍空萬古。", "賈胡貧失真，而况逢其富。", "堅車行大逵，往往初必忤。", "要知論賢愚，豈在遇不遇。"]'),
('2f8eb6da-d6b1-44fa-bfb1-4f907910c86d','送李德明解綿竹尉','李流謙','宋','宋诗','song-poetry','','[]','嚴生起寒瀨，至今漁釣尊。',120,'全唐诗/poet.song.125000.json','["嚴生起寒瀨，至今漁釣尊。", "董賢尉三公，冕黻蒙垢塵。", "榮瘁視所挾，誰以通塞論。", "吾宗老筆墨，健力河漢翻。", "蛟蜃著甕盎，鬰律氣屢吞。", "顯名在操踐，一尉衡宰輕。", "幽求在朝邑，碌碌羣兒奔。", "一朝定大策，談笑搴翳氛。", "書生喜高論，我言布帛溫。", "別語不多吐，春波銷客魂。"]'),
('355ea54e-f9b6-437b-a827-036154e29366','送楊文起尉溫江','李流謙','宋','宋诗','song-poetry','','[]','學海不可窮，一葦子利涉。',96,'全唐诗/poet.song.125000.json','["學海不可窮，一葦子利涉。", "宦海海更深，破浪初鼓檝。", "波濤惡氣勢，鼉蜃毒吻頰。", "帆檣託忠信，維纜倚定力。", "晏然袵席坐，扣舷歌傲兀。", "是中有神仙，樓觀琢白璧。", "羣仙謁帝罷，霞佩粲成列。", "行矣從之游，贈子兩黄鵠。"]'),
('468a4fa8-d1b1-4fc0-8f95-c61476e73b17','六月十四日大雨少頃月如晝','李流謙','宋','宋诗','song-poetry','','[]','火雲忽改色，大雨卷地來。',84,'全唐诗/poet.song.125000.json','["火雲忽改色，大雨卷地來。", "淝水萬貔貅，一戰山嶽摧。", "須臾天宇霽，刮掃無纖埃。", "佳月流清輝，瓊瑶碎六街。", "薄泥阻微步，庭除重徘徊。", "清坐對石友，晤語修竹齋。", "惜無名酒耳，孤詠暢沖懷。"]'),
('095962e6-77ba-49e4-bc26-0787aae710f1','送宣孺攝邑古郫','李流謙','宋','宋诗','song-poetry','','[]','已作來遲遲，又爲去猝猝。',120,'全唐诗/poet.song.125000.json','["已作來遲遲，又爲去猝猝。", "奪我佳友生，悵念鬢毛白。", "投閑如我宜，君則任繁劇。", "臺府有聞知，使子固選擇。", "子男古所尊，而此萬家邑。", "郵筒即詩筒，簿書有閑日。", "迎門爛桃李，畫餠不可食。", "况欲分其餘，豈捄饞吻濕。", "留爲別後哂，聊用破孤寂。", "數期還魯疆，指日返趙璧。"]'),
('302b9f1b-9b22-46ca-ab65-61fca2e0a158','送宇文德濟解綿竹丞','李流謙','宋','宋诗','song-poetry','','[]','陋哉紈綺習，染人甚脂膏。',240,'全唐诗/poet.song.125000.json','["陋哉紈綺習，染人甚脂膏。", "傾五湖三江，未易濯穢臊。", "冰霜竹林游，糞土戎與濤。", "富貴比貧賤，所去寧一毛。", "公家全盛時，束带轄百寮。", "朱輪照華欀，龜紫映翠貂。", "綠幘走童奴，清彈沸娥媌。", "連牀不同夢，君乎吾願交。", "一覘鸞鶴姿，頗疑出衡茅。", "神駒足萬里，威鳳心九臯。", "夜窗四壁空，抱卷燈屢挑。", "往往出妙語，遺音叶咸韶。", "於此定不凡，舉步即扶摇。", "朅來署紙尾，丞哉嘆徒勞。", "官事竟何如，亦似是馬曹。", "置之勿復問，朝爽西山高。", "北風送征驂，擾我心鬰陶。", "判此別袂難，愧彼漆與膠。", "君去千仞岡，我歸一枝巢。", "升沉何必恨，書來慰蕭條。"]'),
('d9fe9f03-6da7-4c2b-830f-5e534fff20c5','從人借馬鈍甚戲作','李流謙','宋','宋诗','song-poetry','','[]','一馬如坎蛙，爬沙鈍無比。',60,'全唐诗/poet.song.125000.json','["一馬如坎蛙，爬沙鈍無比。", "長繩掣欲斷，大箠折三四。", "郵亭只數尺，對面不能至。", "我聞穆天子，八駿日千里。", "邀汝託後車，笑云勿相戲。"]'),
('5776762c-945d-41ec-957a-0f18986188c0','挽家夫人','李流謙','宋','宋诗','song-poetry','','[]','雷風畫羲文，藻蘋冠周篇。',108,'全唐诗/poet.song.125000.json','["雷風畫羲文，藻蘋冠周篇。", "房帷預何事，聖賢論本原。", "婉彼淑靜姿，濯濯出水蓮。", "擇歸令德配，映世高名懸。", "己子與他子，義在亦乳然。", "簞食或見色，千乘塵泥捐。", "裙裾具此見，生子豈不賢。", "鬼神發潛光，慈母令問傳。", "當留千斛米，買酒澆青山。"]'),
('4ac714aa-38ff-4bb5-a8d2-f8e265395efc','挽程子山侍講','李流謙','宋','宋诗','song-poetry','','[]','我昔先君子，爲公義林引。',132,'全唐诗/poet.song.125000.json','["我昔先君子，爲公義林引。", "論儒摘寡要，太史固坐井。", "期公非苟知，力行福黎蠢。", "螭坳千載逢，鳳池一跬近。", "獨妍當衆媸，隠憂觸羣慍。", "頗覺游梁倦，終成弔湘恨。", "聲名出寒餓，圭組憎薄命。", "綸言表厄陳，衮札囊束筍。", "傳家侈榮渥，尚足破孤憤。", "腸折八哀詩，涕墮五君詠。", "長歌餞公歸，木脫西風勁。"]'),
('3471186f-ce13-45b0-9cde-b645ad1c7cc8','挽黄思忠','李流謙','宋','宋诗','song-poetry','','[]','千章擇一木，工竟不善斲。',48,'全唐诗/poet.song.125000.json','["千章擇一木，工竟不善斲。", "不如路傍棘，藩圃盜可却。", "故友心破碎，真宰竟錯莫。", "門生有侯芭，灑涕傳絕學。"]'),
('9c19ed0c-0708-49d5-8296-9e07d63800b7','挽沈夫人','李流謙','宋','宋诗','song-poetry','','[]','人道孝爲大，斯言俗之砭。',84,'全唐诗/poet.song.125000.json','["人道孝爲大，斯言俗之砭。", "簪緌顙猶泚，乃能出閨簾。", "逶迤竟潛通，姑慈霽霜嚴。", "老禪入宵夢，薄雲爲之殲。", "浄心正覺成，妙解脫妄粘。", "寶蓮託浄質，此理遥已占。", "君看數珠輪，此句吾爲拈。"]'),
('fd725d79-7b67-4731-bfcc-b3a24c997937','元質偶招客飲爲賦此篇','李流謙','宋','宋诗','song-poetry','','[]','曉風吹花枝，曉雨濯花色。',120,'全唐诗/poet.song.125000.json','["曉風吹花枝，曉雨濯花色。", "裁綴爲好春，天公不遺力。", "啼禽彊領解，對花語移日。", "世事豈易料，搔首鬢毛白。", "名園適幽爽，韶序屬芳淑。", "主人雅好客，力能管風物。", "酒如瀉江波，紫翠映華席。", "我友不可揀，一一如珪璧。", "遠者渺雲海，近者接肘腋。", "能來共一醉，我亦有行役。"]'),
('ee0a7d1b-7677-4781-9b10-25ab41d4dd21','道中逢牧童跨牛者','李流謙','宋','宋诗','song-poetry','','[]','田空已不耕，草瘦尚可齕。',48,'全唐诗/poet.song.125000.json','["田空已不耕，草瘦尚可齕。", "搰搰一歲勞，得此休頃刻。", "阿童拍腹卧，短箠聽驅策。", "早晚穡事動，努力進芻粒。"]'),
('957630ab-2aaa-4fc2-8360-1077d5fd8570','予舊服朮迂其效棄去比過臨邛蒙李丈分惠并副以詩次其韻以自警','李流謙','宋','宋诗','song-poetry','','[]','是身如芭蕉，敢保金石固。',216,'全唐诗/poet.song.125000.json','["是身如芭蕉，敢保金石固。", "得生况尪陋，愧彼碩且武。", "百萬護一喘，人自疑竊斧。", "靈根著異效，嘗資一溉助。", "苦邀旦夕驗，棄去悔昔誤。", "那知百破衣，豈易一線補。", "滄溟稱微溜，九仞亦拳土。", "見彈思炙美，拊手鴞未許。", "九州作秦鼎，萬生入燖煮。", "赫然一炊頃，衆忿久已貯。", "碑方嶧山夸，骨作驪山腐。", "初心欲速耳，竟不守門戶。", "吾宗活人手，一諾輕季布。", "緘詩遣分送，愛我骨肉似。", "恐爲石髓凝，亦防山鬼妬。", "汲汲事服餌，長謠記所自。", "願求必世仁，借秦諭其故。", "解牛得養生，持問子莊子。"]'),
('ddc42ace-7035-405d-abc6-2211d7102f09','游護聖寺分韻得共字','李流謙','宋','宋诗','song-poetry','','[]','散員繩檢寬，暇日得放縱。',144,'全唐诗/poet.song.125000.json','["散員繩檢寬，暇日得放縱。", "天明風發屋，飛蓋怯掀弄。", "朋簪諾已宿，駕言盍不勇。", "幽禪遠城郭，伉壯塔廟涌。", "華鯨三擊罷，僧衆肅如拱。", "香秔撩鼻觀，饞沫出流湩。", "三生石上歌，浩劫幾丘冢。", "失脚今悔深，彈指昔緣重。", "聯裾玉連環，談端豁煩壅。", "草木自臭味，雨露元一壠。", "摩挲老瓦盆，此酌宜數共。", "已無繫日繩，但有思家夢。"]'),
('cf3f1774-ae50-4905-8fe6-72a3b51a18b6','旅中','李流謙','宋','宋诗','song-poetry','','[]','客舍供朝餔，旅食不知旨。',48,'全唐诗/poet.song.125000.json','["客舍供朝餔，旅食不知旨。", "取酒澆餓腸，乞火伸凍指。", "萍根託江流，江自不能止。", "傳舍貪閲人，風雨亦閲爾。"]'),
('ecedf762-5579-4ac2-bf55-bc08cec22ba0','過彌牟有携魚過者買而放之因志以詩','李流謙','宋','宋诗','song-poetry','','[]','行役道荒戍，馬行何徐徐。',288,'全唐诗/poet.song.125000.json','["行役道荒戍，馬行何徐徐。", "市人捉筠籃，偃然數尾魚。", "始疑失清波，殘息憊不蘇。", "俄掉尾與鬐，示之尚可圖。", "殺戒宿所持，堅盟敢渝初。", "爾命如丘山，我金若錙銖。", "敢靳百錢惠，坐視甘醢葅。", "空籃俱置之，漣漪縱縲俘。", "旋收褫駭魄，亟反清泠居。", "僕夫亦欣然，毋疑校人誣。", "爲龍未可知，風雷躍雲衢。", "田文出函關，子卿反荒區。", "骨肉一笑粲，樂哉定何如。", "人心如面然，賢鄙異所趨。", "放者尚反顧，捕者已縱罦。", "爲德懲不竟，護以西竺書。", "世事豈易料，聊欲明區區。", "人羊互吞啄，佛語深切膚。", "聞聲戒肉食，孟軻遠庖厨。", "孔釋喜交戈，好生理則符。", "浪言物與人，貴賤越與胡。", "人貴當食物，物固供人須。", "此語實魔語，地獄正爲渠。", "炯炯一靈光，彼此亡欠餘。"]'),
('6080db88-52c6-454e-812b-dc267ce896b7','自離蕪湖多阻風是日早次鴈汊風順亟駕帆以行既而稍駛落帆之半晚次雷口舟人以貪風曛暮不得泊幾危','李流謙','宋','宋诗','song-poetry','','[]','九牛可倒曳，兼旬逆風裏。',180,'全唐诗/poet.song.125000.json','["九牛可倒曳，兼旬逆風裏。", "老來硯筆衰，文思每如此。", "篙兒疲晚牽，赤日汗流趾。", "峻阪有疾圓，禿羽無縱矢。", "朝來日初亮，旗脚忽西指。", "豎帆沸羣呼，劈浪輕一葦。", "路經百家村，鷄豚不敢市。", "有客訪江滸，疾談幸其起。", "過目不留瞬，倏忽洲渚異。", "一日三日程，長年抃而喜。", "敏者貴乘便，拙者拱以竢。", "齊人誚軻迂，秦亦毒鞅駛。", "吾嘗爲此論，誰肯味無味。", "使帆勿盡風，如食勿盡美。", "君看赤手人，重負亦俱至。"]'),
('9f004434-d755-4098-a018-d3c8f84b2b67','過大信口憶西歸錄載大江渺渺忽二石山如伏猊引出水面東西對峙江形若瓢然而山乃其口然相距猶三四里則江之廣狹可見視之信然妙哉寫物之功感而賦此篇','李流謙','宋','宋诗','song-poetry','','[]','兩山如伏猊，波面忽引首。',96,'全唐诗/poet.song.125000.json','["兩山如伏猊，波面忽引首。", "江形若瓢然，此山乃其口。", "往讀西歸志，一一未深剖。", "及茲親見之，語巧極雕鏤。", "妙哉寫物功，萬像不藏覆。", "當時偶然書，信在三紀後。", "臨流重吁嘆，有涕泫襟袖。", "君看連城璞，豈但今不售。"]'),
('5747c011-b69c-4021-afd9-681936443423','游無爲寺','李流謙','宋','宋诗','song-poetry','','[]','導師生何年，人猶記此日。',252,'全唐诗/poet.song.125000.json','["導師生何年，人猶記此日。", "香火緇俗會，風雨神鬼集。", "我來恰秋深，迥迥原野闊。", "羣山勢愈壯，老木氣不折。", "拄筇踏危磴，小憩馬與僕。", "屢休才及門，到寺已曛黑。", "車從如沸羹，無地可插脚。", "闍黎揖客坐，意象頗猝猝。", "弛擔得禪房，持鉢叩香積。", "倒牀不復醒，夢與仙梵接。", "明朝沒階趨，燎香望玉色。", "丐福吾未能，修敬敢不肅。", "是身如芭蕉，危脆不堅實。", "綠髮俄素絲，赭顔倏枯腊。", "百年已長久，大抵俱化易。", "稽首不動尊，向來何證得。", "衲衣坐蒙頭，萬古一交睫。", "儻非定慧力，枯骨已瓦礫。", "物物具茲妙，抱寶訴空乏。", "伐柯則不遠，內照無別法。", "一鉢寄空巖，定當擲此幘。"]'),
('491d6787-90a6-4efa-8168-249f1769a4d9','林夫有詩趣歸期次其韻答之','李流謙','宋','宋诗','song-poetry','','[]','乾坤大逆旅，日月兩行客。',120,'全唐诗/poet.song.125000.json','["乾坤大逆旅，日月兩行客。", "江頭垂楊樹，折盡供馬策。", "學舍如冰壑，遠與簿書隔。", "天風吹我去，自哂殊役役。", "英英君子僚，妙響協竽瑟。", "詩來促還期，珠琲瑩巾帙。", "久枵渴嘉饌，積陰跂白日。", "談爲無底囊，剪燭期竟夕。", "但恐又西東，搥車歎寂寂。", "盍不歌歸來，已痼烟霞疾。"]'),
('919da2bb-9241-4eba-aef3-093e79915974','還家','李流謙','宋','宋诗','song-poetry','','[]','吾家在何許，水泉修竹林。',48,'全唐诗/poet.song.125000.json','["吾家在何許，水泉修竹林。", "鷗鶴失閑伴，跂予有遐心。", "窗前小梅花，耐霜笑吟吟。", "小待新酒熟，冷蘂勸清斟。"]'),
('3de448bf-dc2c-479f-a031-ce498cb84ff3','送李司戶之官臨邛','李流謙','宋','宋诗','song-poetry','','[]','威鳳翔九霄，千百但一遇。',120,'全唐诗/poet.song.125000.json','["威鳳翔九霄，千百但一遇。", "蒼蠅何所來，滿盤揮不去。", "吾人一肝腸，未可捨跬步。", "摻裾輒經年，把臂速炊黍。", "譬如枝上花，風裏得暫聚。", "天果何意哉，未易測其故。", "安得三間茅，藜莧同旦暮。", "秋色如行色，別語不得吐。", "鶴峯得佳句，尚足慰延佇。", "從今夜夜月，伴我照庭戶。"]'),
('bfbe7ce8-000e-4052-9e72-502d41c2517d','中秋翫月分韻得一字','李流謙','宋','宋诗','song-poetry','','[]','向來高樓月，人境居第一。',120,'全唐诗/poet.song.125000.json','["向來高樓月，人境居第一。", "天福不得再，天意亦叵測。", "濁河幸一澄，威鳳乃屢出。", "過日惜清玩，草具成勝集。", "共詠昔年詩，仍是昔年客。", "酒闌感存沒，悲歡異今昔。", "懷我盤谷翁，蘂宮此何夕。", "仰瞻雲漢章，正恐翁手緝。", "躡雲侍琅輿，頗恨無此骨。", "拭淚罷清酌，覽鏡有華髮。"]'),
('74c95432-7be0-49b6-8b5a-4fbb66adfbd3','累年中秋無月今年凡數夕有之十五日尤佳','李流謙','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','境濁常鮮愜，事難獲易欣。',168,'全唐诗/poet.song.125000.json','["境濁常鮮愜，事難獲易欣。", "皎月當中秋，覘候每倦勤。", "扁舟泊沙岸，是夕無纖雲。", "冷侵碧琉璃，又如爛鎔銀。", "十年五年無，千里萬里明。", "對此欲不飲，恐觸蟾兔嗔。", "尊空更重看，徐步長江濱。", "大魚時撥剌，宿鷺聯拳驚。", "可無橫吹者，或有琵琶人。", "領覽此奇絕，但怕添愁新。", "頗欲從冰娥，暫陪白玉輪。", "載我到廣寒，一醉羅襪塵。", "歸來閉閣卧，耿耿雞未晨。", "顧瞻篷窗間，尚餘半金盆。"]'),
('6d23f1a9-f9a4-4096-b9c7-46e0a5efea58','蝨嘆','李流謙','宋','宋诗','song-poetry','','[]','得生固么陋，宅體仍穢卑。',288,'全唐诗/poet.song.125000.json','["得生固么陋，宅體仍穢卑。", "巢穴我襟裾，食飲吾膚肌。", "毒比蚤蚊熾，類兼蚋蟻微。", "陰幽巧相傳，不知來何時。", "殄馘未掩戈，遺妖復蕃滋。", "觀處初若無，掇之或如遺。", "捷走欲違禍，深藏殆知幾。", "竄壁尤惡啄，潛沙更危機。", "處頭與物化，遂使白變緇。", "稱臣託疵賤，名官慙素尸。", "捫摸傲逆溫，梳爬厭懶嵇。", "吉凶陋巫占，彼豈能先知。", "殊快勇夫射，寧辱達士譏。", "蚩兒厭膏粱，兀坐如瓠肥。", "屠門飫雄餐，亦足飽汝饑。", "我身如枯株，但有骨附皮。", "嘬嚙竟何得，饞吻亦及之。", "夜眠輟佳夢，晝坐傷沉思。", "往往暴醜形，或爲潔者嗤。", "抑搔兩甲折，掩捕雙目疲。", "期我犯不校，責人所難爲。", "湯沐猶寬恩，磔裂乃所宜。", "吏貪摩其牙，巨力猶足支。", "舐糠及小家，此豈禁鞭笞。"]'),
('24c24228-9b20-4bd0-b851-f20ef97e3385','贈聽聲上官術士','李流謙','宋','宋诗','song-poetry','','[]','造化祕密藏，凝然大狙宅。',192,'全唐诗/poet.song.125000.json','["造化祕密藏，凝然大狙宅。", "操縱掌握間，殆似不容測。", "惟人號最靈，研窮深探賾。", "支干究生旺，更以形骸索。", "摸骨與聽聲，箇中更奇特。", "無煩覿面知，禍福悉已白。", "至理非口傳，妙處從心得。", "官君持此術，行盡山水國。", "所歷多巧中，一醉天地窄。", "祇今天下士，何啻累千百。", "紛紛肉食鄙，正須囊錐客。", "僕僕塵埃中，豈無鳳毛翮。", "勿以朝野殊，窮通理不隔。", "上方勞夢想，胡弗爲指摘。", "致君堯舜上，爾術光史冊。", "若共俗人言，懷抱真可惜。"]'),
('f4c0e454-ccb9-4bc6-8eb2-37b5f028b88c','送張時擇從楊茂州之招','李流謙','宋','宋诗','song-poetry','','[]','州閭我知君，楚璞未剖初。',204,'全唐诗/poet.song.125000.json','["州閭我知君，楚璞未剖初。", "家無兩錢錐，腹有萬卷書。", "閉門飽葵莧，撫几咏唐虞。", "兒乳腥未濯，才能辨之乎。", "巍科似拾遺，却走我不如。", "流俗校成敗，往往遭揶揄。", "豈知磻溪叟，空釣寧在魚。", "窮途有知己，一笑肝膽輸。", "羔鴈朝在門，挽我不得徐。", "鯨鯤依洪波，鳳凰集修梧。", "士貴得所託，往矣膏子車。", "忠信行蠻貊，九夷聖肯居。", "使君况儒將，奧學窺盤謨。", "小詩迺餘瀾，已足吞五湖。", "老羌弛弓刀，玉帳一事無。", "舉杯哦新篇，主賓興不孤。", "明日思君處，一千里平蕪。"]'),
('be2eeee5-d96c-4733-8e79-8a450c329644','送無害弟之官并呈使君蹇丈一笑','李流謙','宋','宋诗','song-poetry','','[]','人生一飲啄，大似有夙緣。',180,'全唐诗/poet.song.125000.json','["人生一飲啄，大似有夙緣。", "蔡蒙窮坤陬，宦游自吾先。", "哦松千尺下，剖竹羌水邊。", "泮宮擷芹藻，我歸才一年。", "子又盧奴去，妙指按五絃。", "識人舊魚鳥，入眼昔山川。", "子才如干將，當屠橫海鱣。", "纖鱗拾沮洳，人怪我輾然。", "火宿用彌壯，鷙伏飛無前。", "弟兄立分拆，門戶同仔肩。", "老僊泉下責，豈但冕與蟬。", "別離不須悲，使君直二天。", "不敢祝翁歸，冰鏡自高懸。", "夢想五賢堂，囊貯白雪篇。", "何時見華築，琬琰行當鎸。"]'),
('f78349ea-ac81-4e60-a3f1-7547b286b3e7','一春無日不飲遂作肺嗽效樂天體','李流謙','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生與酒俱生，長與酒俱長。',288,'全唐诗/poet.song.125000.json','["生與酒俱生，長與酒俱長。", "行時酒在樽，坐時酒在盎。", "一日不舉酒，一日眉不放。", "春來身無事，結客鏖勝賞。", "南山步新堤，西湖撐彩舫。", "或飛名園蓋，或祖都門帳。", "大酌須淋漓，小酌猶酣暢。", "家山忽入夢，江頭問兩槳。", "友社惜我去，共和驪駒唱。", "劇飲連晝夜，大似灌鼠壤。", "不往慍眉須，好意難棄忘。", "平生無肺病，因茲作微恙。", "終夕勞喘呀，如吹竹筒樣。", "積痰動盈缶，嚥吐不停吭。", "童奴更謁諫，浸恐傷府藏。", "萬里寄一身，節宣豈宜爽。", "蒭蕘不可遺，予心默云當。", "飲食著聖經，觀頤識爻象。", "慣習未易奪，剛制乃所尚。", "初如鍵弩牙，又類遏溪漲。", "稍稍撤觴斝，久之絕悵望。", "腸枯與吻燥，但當吸瀣沆。", "宵枕遂小康，其效疾影響。", "遽言終止之，未敢保其往。"]'),
('7cb80da4-dcd0-4956-9d93-692480ca87e6','送樂季和','李流謙','宋','宋诗','song-poetry','','[]','袖有禮神璧，橫夭射螮蝀。',156,'全唐诗/poet.song.125000.json','["袖有禮神璧，橫夭射螮蝀。", "携持易羊皮，賢士銜隠痛。", "短檠風雪窗，鼎鐘入宵夢。", "出門雀適羿，挽弓不再中。", "九折生庭除，欹輪失嚴鞚。", "事固不可知，淺者發嘲鬨。", "磨以百艱虞，吾覺此意寵。", "蠅棘芟根株，織文徹機綜。", "如簧祇囂煩，戰勝屬陰拱。", "詰朝烏帽斜，瘦馬霜鬣聳。", "行世心愈老，轉物身自重。", "解鞍澆客垢，先撥床頭甕。", "君歸我送之，我歸欲誰送。"]'),
('66cfd568-9253-4c40-a4e0-de39b64c144c','送李仲信','李流謙','宋','宋诗','song-poetry','','[]','鳳巢無鵂鶹，虎穴不生狸。',108,'全唐诗/poet.song.125000.json','["鳳巢無鵂鶹，虎穴不生狸。", "巽巖四十年，名聲兒童知。", "黄流出崑崙，筆力子似之。", "嚴兵鏖殘敵，往往輒偃麾。", "廉頗用趙人，戰勝地有宜。", "一吸空湖江，茲行定英奇。", "事功出邂逅，道德爲根基。", "儻踐鐘鼎盟，毋爽藜藿期。", "請因問安際，訂我言是非。"]'),
('a96f7c27-34d9-42d6-9521-9531759e3ba3','送仲明赴舉','李流謙','宋','宋诗','song-poetry','','[]','進退士所重，視天爲鼓鉦。',180,'全唐诗/poet.song.125000.json','["進退士所重，視天爲鼓鉦。", "採薇北山曲，濯足南澗濱。", "高風豈不偉，奈何萬蒼黔。", "道可濟天下，不必丘園尊。", "先生一世士，抱寶三家村。", "蚤日湖海興，攪鬚見霜根。", "我嘗嘆洄洑，再拜願有言。", "釣魚須遠去，沮洳無鯨鯤。", "北風折羣木，嚴駕夙在門。", "萬里著掌間，一舸氣已吞。", "岷峩頼君重，努力答山靈。", "造物飽閲駿，眼未見此人。", "小却猶玉堂，尚堪託斯文。", "賤子惜此別，贈送慙空樽。", "唯有清夜夢，相逐東南奔。"]'),
('d9ea56a6-7632-46b2-ae02-77c8c5b309d4','送呂義甫','李流謙','宋','宋诗','song-poetry','','[]','河伯矜秋浸，望洋始一嘆。',144,'全唐诗/poet.song.125000.json','["河伯矜秋浸，望洋始一嘆。", "是以太史公，身行天下半。", "可憐據坎者，寸尺盡霄漢。", "我友故英發，驤首輕皂棧。", "結束萬里游，是行吾所贊。", "榮途聽其遇，丈人教不倦。", "向來開說易，一語無疏傳。", "曰爲可用者，此本同世患。", "停舟佳山水，心目有奇觀。", "更接摇麈談，中夜光赫煥。", "我方墮吏罝，沮洳雜鰍蜆。", "眼看飛鴻翔，別樽恨不滿。"]'),
('6d6a7e44-a65b-490d-b408-523ea2281799','憶樂季和','李流謙','宋','宋诗','song-poetry','','[]','理邃不可商，造極會其天。',180,'全唐诗/poet.song.125000.json','["理邃不可商，造極會其天。", "因黥乃南面，挾璧顧屢歎。", "安有鬼一車，藴疑在目前。", "劃然解積凍，澌泮千丈淵。", "吾嘗賞淮陰，能錄惡少年。", "大勝答溪媼，奇勛此輿權。", "水激可沃焦，酖毒懷與安。", "夫君珍所持，射市吞煩冤。", "束袂甘冥冥，一穴栖鰍鱣。", "真宰技自癢，駕以風無邊。", "背水得衆無，失駒約羣還。", "三月春已深，穩下三峽船。", "夔門有巨艦，談嬉障百川。", "金華客五侯，氣力足由緣。", "爲君誦伐木，三扣臨江舷。"]'),
('486d1558-8b1e-4fc0-adb8-0b62f3274476','食藕','李流謙','宋','宋诗','song-poetry','','[]','芙渠固佳産，其末亦奇絕。',144,'全唐诗/poet.song.125000.json','["芙渠固佳産，其末亦奇絕。", "此土乃物宜，厥包比柚橘。", "蔓引莖自遂，泥蟠體仍潔。", "一絲戲傀儡，衆竅殞鯈忽。", "七月陂塘秋，千蓋偃寒碧。", "俚語名带花，脆嫩若無骨。", "如船近誑誕，似玉孰追削。", "瞿曇况真理，穢浄本同出。", "花實根相連，因果非兩法。", "君看入口處，一片疑嚼雪。", "溽暑肌如熏，毒酲肺欲裂。", "只應蕭爽時，便是清凉國。"]'),
('f5dccbf4-fabb-4c85-8821-4a07be3fe0fc','送孫賓老宰丹稜','李流謙','宋','宋诗','song-poetry','','[]','回也真賢哉，陋巷一簞食。',240,'全唐诗/poet.song.125000.json','["回也真賢哉，陋巷一簞食。", "卒然問爲邦，所告王者事。", "軻亦印微言，曰可禹稷配。", "學道則愛人，偃昔嘗有志。", "他時武城絃，嘿與聖意會。", "聊寄莞爾笑，汲深孰知底。", "欲令誦所聞，姑以割鷄戲。", "聖賢存心處，萬類宅生地。", "先生爲己功，及物乃糠粃。", "十室有忠信，百里吾敢鄙。", "六經作縣譜，趙張不到此。", "春風七條絲，可以馴桑雉。", "堯舜治天下，乃與治射比。", "一朝坐廊廟，用有大小爾。", "我昔從公游，頑璞不受砥。", "經時去函丈，榛棘撐腎胃。", "朅聞衛返魯，倦馬始休轡。", "欲申趨隅問，已作橫策起。", "人生楦宇宙，孰爲不朽計。", "著書有存亡，德業亙千祀。"]'),
('7fd8a16b-9d38-48fa-b367-2614f87e5875','苦熱','李流謙','宋','宋诗','song-poetry','','[]','祝融職司南，憑寵不遺力。',180,'全唐诗/poet.song.125000.json','["祝融職司南，憑寵不遺力。", "呀呀三足禽，敗羽懸枯腊。", "釜鬵糜碎鱗，無地此身著。", "楚炬方烘秦，湯征未自亳。", "夢想千丈冰，快踏赤兩脚。", "少憩修竹林，泉水鳴㶁㶁。", "岸巾對颯爽，汙垢亦小濯。", "蒯通據鼎耳，反唇乃幸脫。", "叩頭祝西風，駕言馬可秣。", "危喘已强支，旦夕恐不續。", "俗情傲寒灰，赴熱犬爭骨。", "灼肌豈暇顧，甘作蛾殞燭。", "君看孟嘗客，乃笑翟公雀。", "呼兒進胡床，佳月可人白。", "一醉無渭涇，舉盞新酒滑。"]'),
('dba821a4-381d-4bfb-9cb0-68e1a006810a','遊水陸院','李流謙','宋','宋诗','song-poetry','','[]','深居毒歊煩，沸鼎遊羣魚。',180,'全唐诗/poet.song.125000.json','["深居毒歊煩，沸鼎遊羣魚。", "金凉念何許，頗欲膏吾車。", "行行有佳處，舍南得精廬。", "方塘水泠泠，嘉樹陰疎疎。", "寒光四圍之，氣象豁以舒。", "清濁本相形，暑去不待除。", "赤脚踏潺湲，褫带凌空虛。", "杯盤固草草，言歸且徐徐。", "山僧擅幽勝，意輕南面孤。", "久矣不復貴，厭棄同污渠。", "貴人便宴安，大第如清都。", "華堂貯窈窕，高門列車徒。", "往往慕閒曠，偶此樂有餘。", "蛇蚿漫相憐，鵬鷃端異趨。", "不如聽鳴禽，勸我提胡盧。"]'),
('57402aff-d599-424d-8543-cdd4ccdd763c','游安樂道院','李流謙','宋','宋诗','song-poetry','','[]','美璞出叢阜，徑寸藏尺水。',120,'全唐诗/poet.song.125000.json','["美璞出叢阜，徑寸藏尺水。", "堂堂大導師，鍾靈此其地。", "荒坑名老君，故老說遺事。", "仙佛勢不敵，北面昔所試。", "烟雲龍蛇窟，風雨鬼神會。", "珍重住山人，浄觀愜幽邃。", "半偈起冥晦，徑欲裂冠袂。", "同行一微囅，落日姑整轡。", "在家固出家，象服何必異。", "君看童其顛，已落第二義。"]'),
('806bca85-0857-4f2a-b4e4-ede8a2d0aa0d','袁季海別駕以所藏靈壁石詩軸見示爲此篇','李流謙','宋','宋诗','song-poetry','','[]','諸天享備福，宮殿常隨之。',168,'全唐诗/poet.song.125000.json','["諸天享備福，宮殿常隨之。", "驕王擅雄富，鐘鼓具不移。", "巨細無實相，一種生幻師。", "君家數尺峯，在處供娛嬉。", "衡嵩接几闥，岷峨入提携。", "只作如是解，天地皆目瑿。", "君言勿作劇，丐我瓊琚詞。", "援毫不能奇，永愧嶄絕姿。", "烹茶炷爐薰，𡷾崒繚輕絲。", "如雲出澗壑，頃暫萬國滋。", "請以小喻大，人才亦如斯。", "我無適俗韻，夢想懷崟𡼭。", "借渠琳琅響，和我蘭荃詩。", "明朝謝冠服，雲根有茅茨。"]'),
('2fc83a42-a041-491d-812f-a1e67c64a4ab','峽中賦百韻','李流謙','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','振奇欲何夸，頗疑造物者。',288,'全唐诗/poet.song.125000.json','["振奇欲何夸，頗疑造物者。", "兩山擘其間，放此江東瀉。", "不知太古前，宇宙孰坏冶。", "疏鑿著夏書，固自人力假。", "巨崖切漢起，入眼驚見乍。", "影臨數州迥，根插九地隘。", "積鐵老風雹，巨焰莫鎔化。", "面惡駭夔魖，姿妍悅美奼。", "城郭巧刻劃，屏障工組畫。", "髻鬟直高綰，劍槊寒可□。", "抗立擬分庭，孤撐獨稱霸。", "駢羅紛兒孫，拱揖儼賓介。", "盤空矯鸞鵠，飲溪走牛馬。", "裂絞貫鈎鏁，翠項披絳帕。", "碎礫星宿稠，亂石豹熊跨。", "錢疊蘚暈重，鱗坼樹皮撦。", "萬甓累如甃，一桉平若砑。", "寬博敞壇墠，斜傾覆簷庌。", "懸空疑崩欹，叢密苦蒙絓。", "中斷路已盡，合處天無罅。", "周遭窘漢圍，赤露經秦赭。", "怒觜忽橫出，狂湍助喧駡。", "突展壯士臂，交鋒報睚眥。", "飛瀑綀垂素，響溜鍾調啞。"]'),
('95f5cf88-ab7d-47c7-9332-0c486c6a8bd5','中秋月色甚佳病不及觀','李流謙','宋','宋诗','song-poetry','','[]','斲月如冰輪，不知幾玉斧。',108,'全唐诗/poet.song.125000.json','["斲月如冰輪，不知幾玉斧。", "寒光十萬里，餘影到牖戶。", "我病欲强出，瘦骨怯風露。", "技癢時不禁，窗隙窺皓素。", "年年到中秋，此夕日夜數。", "酒熟客不至，景勝人或負。", "燕鴻初何心，亦作不相遇。", "拊几但悲嘯，看劍欲狂舞。", "幽蟲不相干，空階自言語。"]'),
('a2d8e349-829d-4093-b9d0-0f6458473b8d','失題','李流謙','宋','宋诗','song-poetry','','[]','學者一大事，最重出與處。',252,'全唐诗/poet.song.125000.json','["學者一大事，最重出與處。", "用行舍之藏，孔顔獨相許。", "參賜地位高，窺牖不得覩。", "而况未見聖，一曲株守兔。", "入林恐不密，狷者或拒戶。", "如蝸護一殻，槁死竟何補。", "營營夸毗子，意常在腐鼠。", "鐘鳴尚遲回，顛沛慙末路。", "細評誰失得，未易較吳楚。", "聖賢具成體，以道爲鉦鼓。", "適時不俟駕，枉己一揖去。", "而我本來心，湛如太空故。", "先生平生學，此理超聖處。", "浮沉四十年，夷險隨其遇。", "初無周南恨，內樂侈圭組。", "名高天不掩，舜聰徹幽阻。", "門前裹輪車，急急戒徒御。", "企首洙泗上，進退綽有裕。", "富貴調兒童，嗔喜狙賦芧。", "此同伐國問，何乃至君子。", "願出有用學，不朽在斯舉。"]'),
('ce7d7b1e-14d0-4c83-9b56-8b99729b2d24','勾龍元應以詩送王子友從譙綿竹之招語多見及次韻奉酬','李流謙','宋','宋诗','song-poetry','','[]','取友須四方，不去誰汝縶。',156,'全唐诗/poet.song.125000.json','["取友須四方，不去誰汝縶。", "君慙棧豆戀，自了非駿骨。", "王郎惠然來，車從暖寒寂。", "鸞鵠照清泚，餘子可廝役。", "手把一紙書，髯兄我重客。", "白虹貫襟袖，新詩玉剖石。", "女須翁絕憐，茂苑蘭所宅。", "殷勤記君意，倚頼耕寸筆。", "一朝存沒異，悵恨頭欲白。", "慰眼君自足，有兒况英物。", "盤谷宗斯文，向來指正脈。", "遺藁敬相授，補亡綴離析。", "此翁不可見，此婿未易得。"]'),
('36738684-5dda-44c7-97ef-489e43940d14','獻萬佛圖爲張雅州壽','李流謙','宋','宋诗','song-poetry','','[]','博大真人哉，妙諦形而上。',168,'全唐诗/poet.song.125000.json','["博大真人哉，妙諦形而上。", "林林總雛嬰，萬生同負襁。", "赴者不可數，百川納溟漲。", "隨取即隨給，孰識無盡藏。", "勝報如所證，豈特妙好相。", "龍天至幽嚴，窺覘輒稽顙。", "開圖萬名字，只作一佛想。", "風影可捕耶，變現自惚恍。", "俛應區中緣，茲願固深廣。", "君看朱兩轓，非真亦非妄。", "化身元宰官，台符更兩兩。", "祕言出寶笈，其品名壽量。", "一絲起爐薰，洗耳鐘磬響。", "搢笏爲公讀，萬劫一俯仰。"]'),
('87ef56a0-4bca-4e0b-a2de-20a1977ec03c','代上閬中章使君','李流謙','宋','宋诗','song-poetry','','[]','九區混軌文，正宁垂衣裳。',228,'全唐诗/poet.song.125000.json','["九區混軌文，正宁垂衣裳。", "公家轉洪鈞，一氣斡混茫。", "蠻夷奉琛貢，月窟東扶桑。", "至今有遺黎，盛德登樂章。", "溢慶久愈衍，丹穴俱鸞凰。", "祖烈肖挺挺，德音續琅琅。", "尊彜琢璠璵，薦廟流中黄。", "銅符專城居，健翼翕不張。", "黼座錄故家，雲路登方將。", "省寺窺步武，禁闥覘翱翔。", "相門出鼎槐，八葉有前芳。", "一樗無所材，擁腫蔽道傍。", "門戶岌重大，俛首慙肯堂。", "得邑萬山間，晝夜鞭跛䍧。", "斗升頼急養，山海祈深藏。", "古人重己知，漆炭固未償。", "靴板庭趨初，躔宿望煌煌。", "委身大爐冶，正懼呵不祥。", "丹鼎儻可舐，鷄犬同飛揚。"]'),
('88f74302-10b0-4ac9-94d7-bd1b2475bbdb','鷄冠','李流謙','宋','宋诗','song-poetry','','[]','雄鷄鬭不解，血濺頭上冠。',48,'全唐诗/poet.song.125000.json','["雄鷄鬭不解，血濺頭上冠。", "强顔配二妙，並樹栖梟鸞。", "絳侯資少文，禮樂責所難。", "物生宇宙內，故自安其安。"]'),
('3660f0cb-3a63-4a0a-8925-c2db9e2eae73','憫農','李流謙','宋','宋诗','song-poetry','','[]','秋苗掃地盡，春苗破土出。',48,'全唐诗/poet.song.125000.json','["秋苗掃地盡，春苗破土出。", "尚當積陳陳，那得有菜色。", "不知終年耕，未了一日食。", "守令民父母，賤士但俛嘿。"]'),
('92370b61-9724-45a6-ad55-ad26961e85c9','木芙蓉','李流謙','宋','宋诗','song-poetry','','[]','秋光冷如冰，秋花淡無色。',48,'全唐诗/poet.song.125000.json','["秋光冷如冰，秋花淡無色。", "偶見此粲者，濃艷照孤寂。", "天寒翠袖薄，那得在空谷。", "東風嬖桃李，倚樹三嘆息。"]'),
('31280f4b-3b49-46e8-b91f-eb06bd95ba48','送薛司直赴行在所供職','李流謙','宋','宋诗','song-poetry','','[]','公家樞近公，名在太史氏。',180,'全唐诗/poet.song.125000.json','["公家樞近公，名在太史氏。", "天方濬其源，沃日勢未止。", "郎君萬金産，落筆粲珠琲。", "尚當戰韋布，未可議紈綺。", "朝家錄世舊，往往收瑣尾。", "而况用才升，進擢不止此。", "邦刑託平反，哀矜蓋天意。", "持此博親懽，五鼎但口體。", "富貴君勿疑，信手著囊底。", "別君行十年，再見頹髮齒。", "眼看上雲天，歸耕慰憔悴。", "猝猝萬里別，念當一把臂。", "風雪隔異縣，跛馬不就轡。", "安得凌風翰，空齋坐歔欷。", "短章說殷勤，聊用篤友義。"]'),
('5fe52073-4cd0-4fe4-9fec-91ba6a80a125','送勾龍伯秋出幕守三榮得出字','李流謙','宋','宋诗','song-poetry','','[]','雅故非今朝，兩門自金石。',216,'全唐诗/poet.song.125000.json','["雅故非今朝，兩門自金石。", "山頭墮淚碑，宰木共蕭瑟。", "幕府蓋寶府，球琳琅玕璧。", "一一不可揀，於君况夙昔。", "常愧礫與瓦，照映乏顔色。", "於菟生則斑，窺牛乳尚濕。", "其傳祗斯文，餘事博懸擲。", "嘗覘賦千字，誦之當搢笏。", "戎索贊斗樞，殺氣掩劍㦸。", "舂容凝香地，功用闃無迹。", "忽驅兩轓去，驚鴻眇南北。", "專城豈不樂，所樂在母側。", "扶輿度春風，霜毛未上幘。", "更著摩挲手，一起窮山瘠。", "中年每患別，連日足悵惜。", "方酌江上杯，送君又郊陌。", "熟思令人老，只有加餐食。", "尚餘黄髮期，好語爲再出。"]'),
('9e8450c7-bed4-41dd-9954-d4da307634b0','題宇文叔昭閲齋齋名予所榜也有王正卿畫四時小景','李流謙','宋','宋诗','song-poetry','','[]','乾坤萍在江，日月蟻旋磨。',276,'全唐诗/poet.song.125000.json','["乾坤萍在江，日月蟻旋磨。", "吾生與化俱，反照若觀火。", "蠻觸鏖兩鬭，臼圈聽一簸。", "射鈎仍相國，嬖者死於餓。", "種瓜乃故侯，蹶張終上佐。", "支離竟能賢，青黄未足賀。", "炷香閲茲理，萬事一笑可。", "城南有豪士，豈但雄于貨。", "麒麟夢不到，林沼計未左。", "便齋愜清閟，憑几了衆夥。", "胸中大水鏡，月皎雲破墮。", "世故自起伏，一瞬奔馬過。", "金石波空流，檜杉老不挫。", "他年觀河性，依然等髫鬌。", "我友王郎子，筆墨出笑唾。", "酒酣洒素壁，埃𡏖不敢涴。", "春梢有餘妍，秋林氣磊砢。", "彈指四時具，轉物子亦頗。", "此機與我同，妙出一關鎖。", "予生拙行世，泥塗笑鼈跛。", "但存閲世眼，空花已成果。", "從今識沉冥，甘作枯株坐。", "要知無所閲，到岸乃旋柁。"]'),
('7f0189c9-d885-49fc-83a0-9f125aad831e','吾友黄仲秉讀枚乘七發至所謂洞房清宮命曰寒熱之媒皓齒蛾眉命曰伐性之斧感而作詩以示予予謂乘嘗事吳已而去之梁斯言也殆爲兩君發歟賢司馬長卿長門遠矣因次韻以申其意','李流謙','宋','宋诗','song-poetry','','[]','讀書必知書，枯枿不足斧。',204,'全唐诗/poet.song.125000.json','["讀書必知書，枯枿不足斧。", "隻詞詣微隠，連軸皆剩語。", "枚生老賓客，筆力散雹雨。", "吳梁兩驕王，橫甚鬫哮虎。", "編須笑直前，調度豈兒女。", "刈蕭培芳蓀，遠鄭進韶舞。", "斯文豈徒然，丹石起病窳。", "操瑟走齊門，託身恐非所。", "老濞竟斧砧，埋骨無塊土。", "梁亦殞牛禍，廟社幾奪主。", "至今存遺編，快讀氣屢鼓。", "長卿素佞人，清芬愧蘭杜。", "長門賦淫僻，主心侈莫禦。", "百年校賢鄙，何啻跖與禹。", "黄郎眼如月，妙義窺肺腑。", "拈出標雅箴，霏屑紛落鋸。", "枚生其伯仲，犬子但牧圉。"]'),
('9accba31-2efb-40f1-84ed-06e0a8c793ae','彥博爲偷兒妄意作詩見貽次韻奉呈','李流謙','宋','宋诗','song-poetry','','[]','士窮百不諧，所向輒牆壁。',252,'全唐诗/poet.song.125000.json','["士窮百不諧，所向輒牆壁。", "堂堂百代師，往往遭削跡。", "閭閻侮出胯，逆旅或爭席。", "雖然炯炯心，未易屈此膝。", "閉門師唐虞，清風入吾室。", "千古閲頃暫，八荒在几榻。", "從教厭藜莧，筆端有冰雪。", "出處雲行天，得喪駒過隙。", "元龍吾畏友，萬卷破丘索。", "抱耒耕莽蒼，天民所先覺。", "平生湖海氣，脊梁硬如鐵。", "方其抵掌時，南山虎可縛。", "向來三年淹，聊以六月息。", "自予得此士，不作肝膽隔。", "隠然當一面，堅壘雄屹屹。", "偷兒妄窺瞰，不用苦笞掠。", "與之塵生甑，定自驚失色。", "不知破衣中，照人一尺玉。", "開門恭執贄，政恐子不欲。", "因成一笑粲，莫放百憂集。", "子敬愛氈青，何如我酒綠。"]'),
('89d9ed4c-3d0d-452b-9500-9fde0eec3e4e','彥博見和暑中之作殊有新功復用韻謝','李流謙','宋','宋诗','song-poetry','','[]','風雅有正宗，太山視丘垤。',180,'全唐诗/poet.song.125000.json','["風雅有正宗，太山視丘垤。", "識者了珉玉，不爾遠堯桀。", "咸韶久不作，日月遭薄蝕。", "空谷閉窈窕，市倡矜半額。", "誰知三百篇，學仙要仙骨。", "二南俱賢聖，展卷神已接。", "孝子或失愛，淑婦有不答。", "微言出宛轉，幽憤破藴結。", "側耳無絃音，策策風振葉。", "少陵乃冢嫡，豈止論瓜葛。", "涪翁異代友，俱作蟬蛻殻。", "鼓旗付後山，掌股戯孟獲。", "眼明見賢宗，我欲焚破篋。", "明珠不易得，收功在勤苶。", "一洗蛙與黽，騷壇許授職。"]'),
('c3e6bb2f-90ca-4e11-9994-b10e4f8575c4','次韻姚宣孺見寄','李流謙','宋','宋诗','song-poetry','','[]','作吏無好懷，寧食三年艾。',192,'全唐诗/poet.song.125000.json','["作吏無好懷，寧食三年艾。", "甚陋吾安之，所隸乃都會。", "文書如駡奴，吞噫不敢對。", "兩眉或小伸，獨有公等在。", "交臂露肝膽，不復事容態。", "月沼分賸馥，風軒共晴快。", "家餐聽相挽，盤筯及筍菜。", "但苦王事迫，數離每增慨。", "豈非造物意，物莫能兩大。", "况自摻裾別，至今胸憒憒。", "歸來未黔突，日月倏逾邁。", "書往得奇報，已恐責留債。", "丈夫志遠者，遑卹吠所怪。", "醉眼天不入，一飽真細碎。", "插貂與扶耒，此理本相代。", "持以敦薄夫，是事付我輩。"]'),
('cacf5905-a692-4e67-81f5-7168c6c8123a','次韻勾龍元應','李流謙','宋','宋诗','song-poetry','','[]','春歸知何時，庭草一尺長。',168,'全唐诗/poet.song.125000.json','["春歸知何時，庭草一尺長。", "風軟不起塵，薄日如秋陽。", "裘葛固異宜，單衣已疎凉。", "妍紅色事人，攬鏡無餘粧。", "青山只蒼然，久要自不忘。", "枯藤引我去，栗留囀幽篁。", "濯足江無波，照眼竹有光。", "展旗三伐鼓，騷壇起榛荒。", "垂髫伏窗几，抵掌談皇王。", "持之欲何施，海禽眩鏗鏘。", "風摇薜荔屋，塵集芙蓉堂。", "升斗尚何言，正比鈎餌香。", "投老遲問道，欲覓閑中忙。", "社成蓮亦花，歃血記此章。"]'),
('65633808-d0bd-4d94-88fe-c08e82ae49cc','偶連日食鷄夜夢有截一支者頗憐之有謂予言雞之被烹酷過於是驚覺作此詩以自警','李流謙','宋','宋诗','song-poetry','','[]','平生不喜殺，殺戒宿所欽。',204,'全唐诗/poet.song.125000.json','["平生不喜殺，殺戒宿所欽。", "累此多病身，蔬食慙未能。", "連日乏庖供，隻雞薦肴蒸。", "異夢發宵驚，截支血霪霪。", "旁立爲咨嗟，或人惠嘉音。", "見牛未見羊，盍不推此心。", "萬生均一愛，豈較人與禽。", "君看雞遭烹，楚痛甚斧砧。", "撫枕矍然悟，此豈神所箴。", "驚魂欲違幹，駭汗屢洒膺。", "內懼仍自欣，小差輒相懲。", "白璧護微疵，寧非憂之深。", "長平四十萬，一掃輕蟻蠅。", "暴殄置不問，天邪匪聾喑。", "稔惡侈後罰，幽誅毒炮燖。", "冥冥思昔愆，栗栗厲素襟。", "贖魚有前章，併以警侈淫。"]'),
('af7170c3-75de-4932-968b-c98ebd79ab38','以春草碧色分韻送朱師古知雒縣得色字','李流謙','宋','宋诗','song-poetry','','[]','二年客殊方，送君我鄉邑。',180,'全唐诗/poet.song.125000.json','["二年客殊方，送君我鄉邑。", "豈不念家山，對此好風月。", "何以慰羈旅，眼穿離鴻翼。", "寄聲賀父老，壺漿迓郊陌。", "令君臺閣人，九霄帝不隔。", "新書嚴入縣，驅驥就轅軛。", "手持朱絲絃，欲奏南風律。", "此意寧不佳，此事未易得。", "姑置馴桑雉，先辦繞床物。", "相顧一大笑，浮我當舉白。", "長魚隨鰍鰕，枯澤未容尺。", "驚雷忽破地，起視已無迹。", "春湖波如天，酒作鵝兒色。", "映君眉間黄，領此醉勿惜。", "明朝出門看，扁舟大江側。"]'),
('a1aae95e-bf40-4b31-b989-4c5a6511e23b','海棠未開對酒作此','李流謙','宋','宋诗','song-poetry','','[]','春以花故妍，花好不辱春。',120,'全唐诗/poet.song.125000.json','["春以花故妍，花好不辱春。", "漫山爛桃李，由求蓋具臣。", "國艷朝衆芳，此花當不名。", "芳園麗韶景，點檢能幾根。", "東風未披拂，萬紅藏杳冥。", "過客白眼看，遂與凡木隣。", "一朝吐華艷，天日爲之醺。", "綠樽有醇酌，及茲託慇懃。", "君看淮陰市，豈有國元勛。", "俗情傲未然，花笑當不嗔。"]'),
('52b5033f-e51b-4f05-ba74-6af40ee7863c','見蛛絲戲作','李流謙','宋','宋诗','song-poetry','','[]','一絲架空居，巧若出杼機。',108,'全唐诗/poet.song.125000.json','["一絲架空居，巧若出杼機。", "彌綸不知勞，終日周遭馳。", "相彼造爲艱，中有鴟鴞詩。", "豈獨考其室，爲罝陷羣飛。", "口腹共此累，坐嘆寧以疵。", "微我畋漁意，其端詎庖犧。", "雨過助浮妄，大小出琲璣。", "疾風輕羣脆，覷隙防藩籬。", "摩挲一寸腹，吾廬正于茲。"]'),
('7c0e67c3-f8b8-4c7b-b07c-99a0dbe03349','無害弟之官梓林伯氏無虧序送之極兄詔之義予言贅矣姑以其意而申言之','李流謙','宋','宋诗','song-poetry','','[]','吾家老仙一世師，挺特風槩老不衰。',320,'全唐诗/poet.song.125000.json','["吾家老仙一世師，挺特風槩老不衰。", "平生行己有本末，世人不知其天知。", "急流勇退人恨早，纖塵恐汙白玉姿。", "精神强健腰脚輕，鬖鬖白髮明鬢髭。", "盤谷亭前一幅巾，子掖孫携翁笑歖。", "無官一品錢滿屋，汝輩持底逃寒饑。", "指心一點物非物，向來所貯惟不欺。", "慇懃寶此徵後福，如印券契火灼龜。", "我勤樸斲爾塗堊，障護風雨期勿隳。", "庭前百拜領翁語，有毫髮愧非翁兒。", "季也才力百倍予，天之報翁或在茲。", "得其一體敏且强，遇事雹落雷電馳。", "莫嫌掾尉官職卑，正欲小試觀異時。", "弟兄贈言出寸丹，豈但趣和同兒嬉。", "伯氏有德君子哉，發言不妄如發機。", "敘文千字炯星日，是病苦者之神醫。", "願子銘几銘盤盂，驊騮萬里未易期。", "悲莫悲於生別離，鴈序可忍霜風吹。", "丈夫遠懷在門戶，正使蟻聚終奚爲。", "酒闌上馬飛鳥疾，我亦安能空鬰鬰。"]'),
('1295d018-8c2e-4f5a-af17-c760c2344c1a','陳彥博擢第後歸拜先墓作此送之','李流謙','宋','宋诗','song-poetry','','[]','霜風著林不停吹，天涯有客衣征衣。',384,'全唐诗/poet.song.125000.json','["霜風著林不停吹，天涯有客衣征衣。", "問客今歸有何得，一株老桂和根移。", "讀書作文四十載，浪走不啻萍在池。", "束書隨身乃封戶，睥睨一甑蒙蛛絲。", "傾囊千金勸少貶，掉頭一笑吾寧饑。", "學如木水有源本，朝販夕售顔忸怩。", "市倡青紅衒廛陌，窈窕深閉無由窺。", "清詩學自稟繩律，如嚼冰雪寒肝脾。", "平生交遊半豪俊，如此人物見者稀。", "每拈佳句對客誦，謂是古作非今爲。", "吾先君子壇級尊，子來談笑容攀躋。", "我從弱歲同硯几，如今攬鏡斑鬢髭。", "笑渠常遭俗眼白，短力不得相扶持。", "前日提筆試外省，我亦薄宦初來歸。", "口占程文問中否，强弩破葉劍截泥。", "十月十日夜漏盡，小奚驚夢來打扉。", "云有吉報可速起，倒穿衣裳喘而馳。", "賀者已滿坐無處，拍手怪我來何遲。", "淋漓一紙見名字，倉卒未省來其誰。", "喜歡不記語雜亂，但說老眼天不眵。", "明朝再拜酌酒賀，屋角一丈飛虹蜺。", "書生一第蛻骨耳，排風軼電方自茲。", "阿兄地下喚不應，門戶藉子扶寒衰。", "鄉閭朋舊夸地産，洗眼晝繡增嘆嘻。"]'),
('56ee1273-9b45-4540-8b72-b27ce07297ef','觀小兒甕戲','李流謙','宋','宋诗','song-poetry','','[]','五歲小兒初學步，絕藝亦知天所賦。',304,'全唐诗/poet.song.125000.json','["五歲小兒初學步，絕藝亦知天所賦。", "想見九牛可倒曳，已堪赤手擒猛虎。", "向來甕戲真偉觀，儻非目擊嗤浪語。", "器小猶須百斤重，挾以壯夫端恐仆。", "笑談拈取兩足上，電轉風旋疾如許。", "便令百試百不失，父兄從傍亦矜詡。", "市人駭嘆俱失聲，我自平生未曾覩。", "武陽盛氣蓋全燕，寄區狡謀踣二虜。", "論年固已一倍長，此兒誰肯噲等伍。", "虎變鷹揚看異時，經營一飽渾細事。", "世人稟賦有特異，常理未可求其故。", "相秦童子才毀齒，說項郎君方斷乳。", "拜歸懷中笑橘墮，羣戲道傍知李苦。", "登門已解敘通家，對客頗能嗔字父。", "劾鼠獄詞老吏服，汗簡清規乃翁沮。", "卓識有此更驚人，彼以力稱吾未與。", "行行三十成何事，但耗太倉如雀鼠。", "憮然自笑仍自憐，强說功名在遲暮。", "人言速成當不久，如我定應千萬壽。"]'),
('c31d4bc1-8405-4521-915b-ccd1eda5b610','文南朱使君葬其故人鈐兵李侯士大夫高其風義作詩美之亦賦一首','李流謙','宋','宋诗','song-poetry','','[]','翻手爲雲覆手雨，自昔嘗聞少陵語。',256,'全唐诗/poet.song.125000.json','["翻手爲雲覆手雨，自昔嘗聞少陵語。", "年來雅道更蕭颯，反眼朋游成越楚。", "便當續草絕交論，誰與重尋懷舊賦。", "一洗衰風振頹敗，我爲使君高此舉。", "故人流落死未葬，藁殯蕭蕭泣行路。", "破棺露骨沙草秋，紙錢號風白日暮。", "傷心重念百年交，洒涕親營一抔土。", "送喪不煩司隸傳，擇地當鄰烈士墓。", "龜趺大字日星煥，馬鬣新封鬼神護。", "恩流枯胔河海深，氣激頑夫金石沮。", "漬綿高義古所尚，掛劍初心吾敢負。", "張陳未死已相賊，笑彼安能保身後。", "九原可作定慨然，想見沾衿淚如注。", "清溝突起驚創見，繡被吹來自何許。", "區區論報未足道，此段徒能戲兒女。", "滄溟可涸山可磨，我詩自可傳千古。"]'),
('156127a8-0111-4ac3-9be6-0fa4739fb3d5','明月篇','李流謙','宋','宋诗','song-poetry','','[]','人言明月好，明月無私照。',88,'全唐诗/poet.song.125000.json','["人言明月好，明月無私照。", "海水深不測，明月照無極。", "九州浩茫茫，明月無遺光。", "誰家高樓三百尺，上有浮雲翳突兀。", "浮雲翳月月不知，樓頭美人空歎息。", "空歎息，何當赤手披雲師，放出清光如白日。"]'),
('7e4fe30c-804f-4c2e-8012-9be6429746b6','謝宇文正甫惠硯','李流謙','宋','宋诗','song-poetry','','[]','一硯能令一生足，感君投贈重金玉。',64,'全唐诗/poet.song.125000.json','["一硯能令一生足，感君投贈重金玉。", "人言當爲文字祥，夜夜燈花寒吐粟。", "提携不到白玉除，安能細碎箋蟲魚。", "爲君試草大鵬賦，九萬里風生須臾。"]'),
('5fc4bcad-44c7-4777-ada9-72621b6c5c04','題覺庵','李流謙','宋','宋诗','song-poetry','','[]','疾痛呻呼癢搔抑，人言是覺豈真覺。',128,'全唐诗/poet.song.125000.json','["疾痛呻呼癢搔抑，人言是覺豈真覺。", "問君非痛非癢時，覺何所之了不識。", "要知真覺無不覺，如日出海照萬國。", "雖然亦莫如是解，政恐雙睛翳金屑。", "扣庵欲覓住庵人，此人此庵何地著。", "蒲團紙帳睡未足，百蟲薨薨殘月白。", "六窗玲瓏境超廓，箇中自有真消息。", "兔走君前君不知，俊鶻豪鷹差一髮。"]'),
('f44a485d-72ce-4f38-8755-c37a303059b6','張周倚下第作此唁之','李流謙','宋','宋诗','song-poetry','','[]','將軍百戰摧驕虜，向來射石如射虎。',96,'全唐诗/poet.song.125000.json','["將軍百戰摧驕虜，向來射石如射虎。", "分封不得一丸土，晚歲功名成夢語。", "古來志士窮者多，唾壺擊碎奈命何。", "平生道力輕羣魔，巨艦豈肯摇微波。", "大千與我俱幻爾，是中無處容悲喜。", "西方仙人不可詆，破除憂患正須此。"]'),
('5c0a854b-7fee-47c2-8e61-f8d24483e111','送陰次公赴榮州學官','李流謙','宋','宋诗','song-poetry','','[]','撐腸萬卷不救饑，書生何苦攻書爲。',128,'全唐诗/poet.song.125000.json','["撐腸萬卷不救饑，書生何苦攻書爲。", "如烹太牢飲醇酒，無此肝肺無由知。", "陰侯把筆耕六籍，短檠熒熒照頭白。", "又携束書作官去，此生此債寧終極。", "大州小州疲征輸，文書急急如駡奴。", "家無二頃歸未可，泮宮水冷樂有餘。", "使君喜士比金玉，知子姓名吾所屬。", "定當屣履迎王符，勿憂廣文飯不足。"]'),
('6f5674d8-f214-4337-b5fd-8e64f5fe5544','中秋玩月以東坡詩不擇茅簷與市樓况我官居似蓬島爲韻得似字','李流謙','宋','宋诗','song-poetry','','[]','十年中秋不見月，譬之去國唯喜似。',368,'全唐诗/poet.song.125000.json','["十年中秋不見月，譬之去國唯喜似。", "朝來氛翳崩厥角，天公粲然一啟齒。", "夕月可占此其祥，枯龜未必知許事。", "黄昏天宇開琉璃，出雲微覘摶空勢。", "要人故自作遲遲，悵望豈知空歲歲。", "玉峰一掌開喬嶽，銀海千尋湧平地。", "光吞箕斗不自持，影薄魚龍無處避。", "烟林差差鳥未定，露草涓涓螢暗墜。", "唯我心源初不動，炯炯摩尼照濁水。", "四門宏開衆陰伏，六藝高懸百家廢。", "餘輝切勿丐老蚌，尤物溺人非所貴。", "何如美酒入詩腸，化作錦囊珠字字。", "南樓萬丈高切雲，彈壓山川據要會。", "當年老子興不淺，閒據胡床想風味。", "今人未必輸古人，况復我友半傑士。", "凌晨尺紙飛羽檄，一約而來羶集蟻。", "夜如何其不須問，酌盡滄溟放君起。", "酒酣起舞踏寒影，滿地瓊瑶驚破碎。", "仙娥手拊丹桂樹，裛裛天香落襟袂。", "洞天六六我所家，摩拍洪崖肩綺季。", "霞雲不著著青衫，生恐羣仙笑憔悴。", "旁人勸我聊爾耳，仙娥好意君勿阻。", "海鯨背穩風力强，看我轉頭三萬里。"]'),
('214cc7e1-5a30-4024-900e-37b3f16c4f7d','送兄長赴蓬州職官','李流謙','宋','宋诗','song-poetry','','[]','人家栽花爲春忙，我家種柏求蒼蒼。',128,'全唐诗/poet.song.125000.json','["人家栽花爲春忙，我家種柏求蒼蒼。", "柏生如蓋蔭百畝，癡紅騃紫無殘香。", "常言直道我家物，篋櫝于今藏手澤。", "拈來洒涕不忍看，分付伯兄金玉質。", "去天一尺古蓬州，綫路雲端客自愁。", "年來在處熬膏火，翻愛此地真瀛洲。", "同居患貧別則惡，苦心害性空悽惻。", "不及林中反哺烏，日暮歸來却同集。"]'),
('3caecbdb-cf98-4304-8b15-9a3758d8f3d5','石鈞父之官火井乞詩贈行','李流謙','宋','宋诗','song-poetry','','[]','君家嶙峋兩冰柱，黄塵漲天不敢汙。',144,'全唐诗/poet.song.125000.json','["君家嶙峋兩冰柱，黄塵漲天不敢汙。", "阿雲醉卧呼不譍，斷碑零落荒阡雨。", "君今去作火井縣，山中嬰兒待慈母。", "前日一旱不堪說，危喘僅存無半縷。", "祝君到官百不問，置酒先須酌田父。", "從來和氣致豐年，一笑能令粟盈庾。", "我方投犁學爲吏，人言未可紙上語。", "今人古人豈相遠，力行所知心自許。", "惟君可聞我可言，明日一尊黄鵠舉。"]'),
('647e82c9-7260-4cd0-aea9-6dd201bbb039','送虞提宮','李流謙','宋','宋诗','song-poetry','','[]','桃花未落春水生，百川合流如鏡平。',128,'全唐诗/poet.song.125000.json','["桃花未落春水生，百川合流如鏡平。", "江神約束蛟與鰐，東閣郎君將母行。", "一帆萬里無荆越，非霧非烟鎖雙闕。", "只今手持天下柄，相公身是稷與卨。", "潭潭大府琳琅都，翻翻㦸带纏金鋪。", "朝回坐對彩衣舞，天上應有人間無。", "相門出相古來有，周公在前魯公後。", "看君父子名一時，野人甘作扶犁手。"]'),
('e5f13082-0d13-4e24-a6c5-776e121701be','池上','李流謙','宋','宋诗','song-poetry','','[]','雨漲秋池三尺水，亦有秋風到池裏。',64,'全唐诗/poet.song.125000.json','["雨漲秋池三尺水，亦有秋風到池裏。", "荷花顔色不如故，零亂寒蘆并折葦。", "鸂鶒飛來依晚紅，蕩槳徐徐莫驚起。", "擘蓬截藕尚堪餐，一醉何辭碧筩美。"]'),
('10671a57-4a2a-40cb-b754-2f9774edef1d','挽王隠君','李流謙','宋','宋诗','song-poetry','','[]','仁田義鉏德其種，晚歲坐看苗幪幪。',272,'全唐诗/poet.song.125000.json','["仁田義鉏德其種，晚歲坐看苗幪幪。", "先生一去不可識，但喜郎君實麟鳳。", "一綫微言驚道喪，九鼎斯文頼君重。", "聖門濤瀾無畔岸，我嘗操舟怯奔湧。", "中流奪魄不敢進，亂流而濟渠甚勇。", "射鼷强弩勿妄發，彈雀明珠戒輕用。", "峩冠進之白玉堂，天高會借長風送。", "細尋耒耨竟誰力，銍艾猶傳掛丘壠。", "朝來示我幽宮刻，再拜整冠輒成誦。", "乃知先生一世士，學如荀揚文屈宋。", "四邊海宴中國尊，已嘆銅駝沒荒茸。", "轉頭飲馬長城下，共指先幾世爭竦。", "竟不一官止韋布，大澤深丘老梁棟。", "岷江濫觴固未快，末流與海爭澒洞。", "我聞天窮不再世，卜以郎君言必中。", "九京幽幽復何憾，一杯徑往澆餘痛。", "薤歌嗚咽不成聲，但覺風乾雲亦凍。"]'),
('bfd96dc3-143d-480b-9d56-9054aaac3cc2','挽王夫人','李流謙','宋','宋诗','song-poetry','','[]','維古女士都可見，過眼絕無一佳傳。',160,'全唐诗/poet.song.125000.json','["維古女士都可見，過眼絕無一佳傳。", "客來授我一編書，疾讀不知雙涕泫。", "夫人有子鳴斯文，吾從崑崙識河漢。", "胸中能貯百卷書，此豈只用裙襦看。", "前朝大老尊夫人，鬼蜮不量作兒玩。", "寒心仰屋竊嘆語，志士如今刀斫案。", "唐安治中祿不薄，十畝東湖紅爛漫。", "輕車在門忽折軸，恨如秋江盛不滿。", "史筆在手吾宗英，寧愛一詞沒彤管。", "人生八十善可書，好夢仍長不爲短。"]'),
('232045f7-b28e-4ad3-986e-4058da483b04','寄題天台臨海白鶴廟康濟泉爲顔魯子少卿作','李流謙','宋','宋诗','song-poetry','','[]','將軍射虎不射石，石作於菟能沒鏑。',128,'全唐诗/poet.song.125000.json','["將軍射虎不射石，石作於菟能沒鏑。", "翻然再控弓不力，俊鶻豪鷹眼前失。", "兩泉後先今抗行，何物使之令人驚。", "泉出在山流在地，却似只從方寸生。", "沉沉玉甃碧雙峙，旱爲甘霖渴爲醴。", "白鶴千年歸不歸，半夜空山泣神鬼。", "令君爲政無近名，天以斯泉印其清。", "泉邊有樹仍蔽芾，他日思君於此地。"]'),
('9ecebcdf-70b9-4819-a1b2-cd6ee4d37487','雲月篇','李流謙','宋','宋诗','song-poetry','','[]','雲在山，月在水，合和二物誰遣使。',144,'全唐诗/poet.song.125000.json','["雲在山，月在水，合和二物誰遣使。", "雲收但有千巑岏，月落惟餘一清泚。", "向來爲同復爲異，欲說誰鉗三尺喙。", "與君臨流共一笑，影墮澄泓實相似。", "故應拄杖偶然來，那得泉中覓居士。", "人間八月秋更老，桂樹無風波不滓。", "碧筩爲樽酌清醥，瓊瑶嗽腸雪冰齒。", "江妃爲予舞凌波，老鶴不眠亦孤唳。", "酒醒忽憶三峰游，目光已在鯨魚背。"]'),
('c4d97903-cb90-4072-b7a7-c6e5f2a1abc9','次韻張通甫見貽','李流謙','宋','宋诗','song-poetry','','[]','插架茫茫紛四部，莫向離騷泥蘅杜。',160,'全唐诗/poet.song.125000.json','["插架茫茫紛四部，莫向離騷泥蘅杜。", "文章何處如有神，心手相隨鷹搦兔。", "長卿醉死文君壚，渠輩但可折簡呼。", "淺慙入俚深入僻，纖麗惡淫寒則枯。", "欲張吾軍子可恃，楚璞呈前燕石恥。", "擘波飛去定神龍，汗血牽來真驥子。", "人物有此未易求，頗將擷英泛其流。", "朝來車從照人熱，乃肯訪我投林丘。", "詞華薄技無多道，少作吾今知悔早。", "相期聖處下工夫，一念超然蠲熱惱。"]'),
('d534ef4b-cbe3-481a-a1f7-c5fee54f99b5','次韻宋才夫','李流謙','宋','宋诗','song-poetry','','[]','麒麟丹青了無夢，香火因緣已成癖。',96,'全唐诗/poet.song.125000.json','["麒麟丹青了無夢，香火因緣已成癖。", "一堂風冷自分明，誰撮虛空强摹畫。", "蔬食鼎烹均一茹，笑取菅麻視繒帛。", "風幡自作此分別，蛛掛一絲猶可惜。", "大千元不一毫隔，何處往來勞轡策。", "冥鴻遠矣方控弦，一筯銀絲好看客。"]'),
('d63c6dc7-dfff-4d07-ae13-e1bb05ae7e8a','王子友示詩次其韻','李流謙','宋','宋诗','song-poetry','','[]','先生不憂窮到骨，唯惜修名易埃滅。',128,'全唐诗/poet.song.125000.json','["先生不憂窮到骨，唯惜修名易埃滅。", "平生窗几辛勤功，語及雲程輒嗚咽。", "冷曹晨炊有不續，遠道相從笑回曲。", "微言不足溫飽人，羨渠著斗量珠玉。", "風霜歲晚念慈母，黄葉翩翩積行路。", "烹鷄奉餐蔬自煮，繄我獨無悲此語。", "大厦千間要封植，期君當作垂天翼。", "朋友之樂可樂不，昔人願封萬戶侯。"]'),
('a5f3e061-9468-4b46-8ec4-2b2ec6e48c3c','送黄仲武尉青城','李流謙','宋','宋诗','song-poetry','','[]','書生一第如登天，如君何啻坂走圓。',96,'全唐诗/poet.song.125000.json','["書生一第如登天，如君何啻坂走圓。", "要知筆頭有河漢，向來元未窺微瀾。", "得官莫厭百僚底，水激三千從此始。", "白藤肩輿照路光，小慰當年擇鄰意。", "岷山勢壓西南坤，霞裾風袂潛仙靈。", "公餘有暇縱幽討，爲我一弔張白雲。"]'),
('54b65baa-3554-4c7b-b306-75e37e03354f','失題','李流謙','宋','宋诗','song-poetry','','[]','身長七尺面一尺，眼若電光鬢若棘。',96,'全唐诗/poet.song.125000.json','["身長七尺面一尺，眼若電光鬢若棘。", "腰間大羽不妄發，長空弦落鳥隨踣。", "漢家夫子方少年，東平月窟西酒泉。", "不須武陽兵十萬，不用都尉卒五千。", "願得君王一寸鐵，斷取樓蘭獻北闕。", "笑提金印歸去來，五湖茫茫波浸月。"]'),
('9e10f13a-8d9a-4105-b25e-5c57375e7f6b','送楊嗣清國錄出倅廣漢','李流謙','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','岱宗崢嶸乃爲嶽，丈夫可不志特達。',160,'全唐诗/poet.song.125000.json','["岱宗崢嶸乃爲嶽，丈夫可不志特達。", "平生論人每如此，楊子入眼吁可愕。", "清班突見頎而長，開口四坐薄曉霜。", "自言磈磊不可茹，正須一吐空肝腸。", "太學黄虀了殘業，又携束書去挈挈。", "偃㦸韜戈吾已衰，快刀斫案子甚决。", "古人作事令人驚，今人豈不如古人。", "折枝要是不爲爾，長劍在手無蛟鯨。", "楊子楊子吾所許，舉杯酌君肝膽露。", "期君直到黄髮時，無使英名一塵汙。"]'),
('d1287be8-793f-45b2-8d9a-d7c66d42194f','書薛公肅山齋','李流謙','宋','宋诗','song-poetry','','[]','愛山仍以山名齋，問山何許簷周回。',64,'全唐诗/poet.song.125000.json','["愛山仍以山名齋，問山何許簷周回。", "午窗睡足一笑起，風吹市聲不到耳。", "插貂鳴玉主人事，山不撩君君自戲。", "細思却合幽人居，分我半几來讀書。"]'),
('1ac515c4-f04d-4382-8132-b6bacfd88577','送楊元功','李流謙','宋','宋诗','song-poetry','','[]','判司碌碌塵埃間，可能老此橫海鱣，一朝雷雨插兩翰。',72,'全唐诗/poet.song.125000.json','["判司碌碌塵埃間，可能老此橫海鱣，一朝雷雨插兩翰。", "九江風高浪如屋，萬里扁舟帆一幅，夢魂先遶湖山綠。", "玉除有地容著身，且爲岷峨起斯文，莫來憔悴隨鷄羣。"]'),
('ccab735d-c035-42e2-a1d6-b2e7b9fad1e8','送王總卿','李流謙','宋','宋诗','song-poetry','','[]','北風號霜脫羣木，送客東門車萬軸。',208,'全唐诗/poet.song.125000.json','["北風號霜脫羣木，送客東門車萬軸。", "城中人家作兒啼，若爲四角生華轂。", "公今未上九天上，身雖去此猶在蜀。", "邊頭張頤萬虎兕，一食不飽吼振谷。", "况聞天驕屢窺瞰，往往危機生隠伏。", "欲寬九重宵旰念，分付若人一夔足。", "錢如流水粟如雨，指顧之間嘆神速。", "公方攬轡使一道，百吏毛寒頸仍縮。", "隳者振職汙者澄，如臨鬼神不敢瀆。", "峩冠置之一堂上，不勞折箠四夷服。", "天生此材必此用，楩楠本爲渠渠屋。", "孤生蒙庇逾歲月，况復鴒原辱甄錄。", "明年春風二三月，更看枯根回寸綠。"]'),
('1d246281-e0d0-41e1-a3c0-097acf717921','送樊漕移帥瀘南','李流謙','宋','宋诗','song-poetry','','[]','金龍直歲當玄冥，憶公剖竹江陽城。',304,'全唐诗/poet.song.125000.json','["金龍直歲當玄冥，憶公剖竹江陽城。", "碧鷄坊中駐千騎，裁詩餞送雙旌行。", "逢人到處說項斯，豈賤子故唯先盟。", "一官泮水謝推輓，挾策仍許從諸生。", "隻詞華衮豈易得，再以薦墨光姓名。", "一朝去我生怊悵，呱呱欲作啼雛嬰。", "向來宦海四十年，白首一節無斜傾。", "只今耆舊直可數，曷不往矣司機衡。", "詔書連年到西蜀，歸田奏上羣兒驚。", "西南夷蜑惟稽顙，男耕女織鼓不鳴。", "廟堂徹桑戒無事，正以卧護煩老成。", "犬羊腥羶亦人耳，悅安惡擾皆其情。", "不須談兵但飲酒，帥非爾帥乃父兄。", "秋光如水浸行色，牙纛獵獵風有聲。", "氈褐迎道沸羣獠，弓刀繞帳森千兵。", "丈夫未遂調燮事，華皓得此亦足榮。", "觀公畜德有餘地，如海既酌隨復盈。", "晚福衮衮蓋未艾，善頌何以歌簫笙。", "更須書考二十四，永與松鶴同堅清。"]'),
('65d9fc09-d7db-4c6e-9a29-644806936a62','王正卿爲作山水小軸作此促之','李流謙','宋','宋诗','song-poetry','','[]','王郎妙墨石剖璧，正爾不從著意得。',64,'全唐诗/poet.song.125000.json','["王郎妙墨石剖璧，正爾不從著意得。", "十日一水五日石，猶笑前人風雨疾。", "溪藤小幅白雪光，向來數筆衣不裳。", "濁河未清子未忙，但恐竟軸海變桑。"]'),
('56424ed6-dd17-4a80-b921-48184c93169a','送丁子昭左司湖南運副','李流謙','宋','宋诗','song-poetry','','[]','昔年九轉金精熒，鸞幢鵠節飛青冥。',128,'全唐诗/poet.song.125000.json','["昔年九轉金精熒，鸞幢鵠節飛青冥。", "偶同鷄犬舐殘粒，至今未脫塵中塵。", "平生不識紫芝面，邂逅天涯忻一見。", "安有斯人可棄捐，置身只合金鑾殿。", "急流勇退人所嘆，上書屢請色不難。", "浩然笑涉重湖去，一節映照清湘寒。", "人生分願各有賦，鳩鵬何必勞相慕。", "期君廊廟我巖壑，他日冰霜同晚暮。"]'),
('cd50a842-749e-4aa1-b20b-9291b53465c0','送樊眉州','李流謙','宋','宋诗','song-poetry','','[]','我先君子官于涪，一時賢僚今在不。',256,'全唐诗/poet.song.125000.json','["我先君子官于涪，一時賢僚今在不。", "唯公直節貫華皓，千尺壽檜橫霜秋。", "丈人靜聽請具陳，平生契義骨肉侔。", "簡池解組過鄉縣，劇飲不去公遮留。", "似是兄弟姓則殊，詩藁半破猶勤收。", "合行使符蔡山下，先後召杜騰民謳。", "吾家萬松蔭黄土，公方千騎驅華輈。", "十年不見此邂逅，窮冬雨雪寒颼飀。", "未明投刺候門下，老閽竊語來何求。", "柳州先友一一數，山陽鄰笛令人愁。", "岷峨氣象抗湖海，近日人物幾窮搜。", "如公當寘文石陛，一麾乃付近古州。", "蘇家名稱震戎夏，如崧降甫尼生丘。", "文獻可徵况美俗，黄堂坐嘯萬事休。", "公餘兵衛繞畫㦸，妙香一縷鈴齋幽。", "神交千載尚誰可，子韓子文著床頭。"]'),
('018326e3-a40a-4541-969f-36dede4a3dee','送蘇給事出知太平州','李流謙','宋','宋诗','song-poetry','','[]','一代文章有圖籙，天賜之履征九服。',160,'全唐诗/poet.song.125000.json','["一代文章有圖籙，天賜之履征九服。", "奉牲乞盟走珠玉，吳狂楚僭非此族。", "至今人望壇坫尊，風流文采被諸孫。", "丈人似是更酷似，大河一派來崑崙。", "華途不須移步到，憂國憂君心日老。", "匹馬朝行人避驄，短奏宵歸自焚藁。", "一朝倦拜青鎖門，分符端欲宣上恩。", "再拜願回批敕手，却與疲瘵豐雞豚。", "青絲絡頭甘半菽，丈夫出處不碌碌。", "我亦昨夜夢山靈，苦喚西歸理松菊。"]'),
('18ec9b6b-fa4b-4b97-815d-8eb30f780a9d','宣孺斫庭前蘆葦見山有薝蔔入坐中示詩次其韻','李流謙','宋','宋诗','song-poetry','','[]','扶摇何啻九萬里，盍不往作蛟螭騰。',112,'全唐诗/poet.song.125000.json','["扶摇何啻九萬里，盍不往作蛟螭騰。", "笑我真爲折腰尉，如君雅稱哦詩丞。", "輒班下寮愧連璧，屢愛新詩工琢冰。", "斫林與山出眉目，欲喚逋客招野僧。", "晚香入簾恨悒悒，坐恐瘦骨成稜稜。", "賞幽豈足廢官事，凈社久冷從公興。", "芙渠薝蔔一家耳，相看未易分級層。"]'),
('9aceb86c-b607-4bb4-86ef-b9cf0d4e3fd0','和錢大虛清映亭韻','李流謙','宋','宋诗','song-poetry','','[]','西風振槁如發蒙，危亭創見心眼工。',144,'全唐诗/poet.song.125000.json','["西風振槁如發蒙，危亭創見心眼工。", "融成水月一合相，有似猛火烹鉛銅。", "是時素節屬重九，喚客一醉萸菊同。", "夜深跳魚亂珂璧，起舞大叫騎鯨公。", "令君心瀾了不起，摩尼返照萬事通。", "拄頤但覺朝氣爽，繞腰未羨黄金重。", "高情偶與幽賞會，妙語倒瀉瓊瑰胸。", "誰將玉笛吹曉月，透袂冰濃禁不徹。", "歸來夢想通明觀，一片湖光眼中見。"]'),
('b8fb2e2e-84ff-4968-9bc9-590a8dd13099','送吳志行監稅','李流謙','宋','宋诗','song-poetry','','[]','乃翁儒林大宗匠，造化爲爐鑄卿相。',128,'全唐诗/poet.song.125000.json','["乃翁儒林大宗匠，造化爲爐鑄卿相。", "坐與文皇致太平，玉骨如塵汾水上。", "斯文未喪不須嗟，仍喜郎君書起家。", "等閒一第唾手得，以此報翁其未邪。", "判北門事首峩豸，歷階而升姑少待。", "斗米迫人成遠征，雲夢胸襟何足芥。", "霜風獵獵吹征衣，登山臨水傷別離。", "丈夫富貴恐不免，萬里扶摇方自茲。"]'),
('9b5fff7a-ef7e-48fc-a3c7-37ea525baf30','送王君弼寺丞出守臨邛','李流謙','宋','宋诗','song-poetry','','[]','昔人帝城願一入，君今翩翩去何亟。',192,'全唐诗/poet.song.125000.json','["昔人帝城願一入，君今翩翩去何亟。", "向來一念君親同，夜夢倚門人髮白。", "人生適意富貴齊，况是求歸真得歸。", "江風飽帆不可挽，恰恰春好花濃時。", "君於文字識源委，筆勢逼人殊亹亹。", "每來握臂相與言，我屢點頭興嘆喟。", "三年厭踏東華塵，聽鷄走馬常踆踆。", "黑頭使君豈不貴，腰間見綬我亦驚。", "蜀吳相望八千里，到家遥想慈顔喜。", "上堂跪觴下堂拜，應有輝光照庭戺。", "白鶴勝峰記昔游，醉墨淋漓在上頭。", "君行有暇試尋覓，不知已掃黄泥不。"]'),
('9805174f-a7e8-4bef-a8c0-783be33558a1','比觀仲結諸公課會皆勍敵也行就舉南宮作此贈之','李流謙','宋','宋诗','song-poetry','','[]','文章末流乃科舉，剽東掠西何等語。',208,'全唐诗/poet.song.125000.json','["文章末流乃科舉，剽東掠西何等語。", "得者矜誇失者羞，其中往往分賢否。", "一官垂涎儻不勉，譬之北轅求適楚。", "諸君堂堂萬騎將，折箠自足笞狂虜。", "收拾波瀾著盆盎，却恐蛟龍愁窘步。", "信手拈來即三昧，安用區區備先具。", "朝窗暮几不停綴，寶玉牽聯鬭奇富。", "論如過秦有古意，賦擬兩都多傑句。", "朝來次第出示我，兩耳卓槊驚咸濩。", "華歆便可置龍頭，牧之豈肯居第五。", "我駭虛弦痛方定，未暇相從執旗鼓。", "請君勿見小敵怯，一戰而霸在此舉。", "歸來凈洗科場業，別與斯文立門戶。"]'),
('1460a754-0201-4abc-b59a-a975de4cd223','送任漕赴召','李流謙','宋','宋诗','song-poetry','','[]','宋十一葉聖天子，有臣伊皋佐其理。',320,'全唐诗/poet.song.125000.json','["宋十一葉聖天子，有臣伊皋佐其理。", "鏖兵孽雛褫天戮，手把降幡屢摇尾。", "周宣功大心愈小，盈而持之甚持水。", "龍墀端笏拜疏言，有室大競唯多士。", "蒼蛟淵潛百鱗駭，乳兕林蹲樵牧止。", "臣舉所知匪臣私，取之鄉國大瑰偉。", "后皇曰嘻毋留行，奔雷將車電摇幟。", "先生捧詔色不動，在泰拔茅以其彙。", "向來輸寫萬瀆海，人笑一蠡測涯涘。", "古人成人責禮樂，房杜頳顔諸葛死。", "屠龍覓肝薦雕俎，不如河魴甘且旨。", "卑之試爲目睫論，欲識强羸占國勢。", "議和當有守和策，偃兵適恐造兵耳。", "焦頭常居曲突上，有言復吞胸磊碨。", "先生領略首屢肯，懸知不作三窟計。", "欣然拔劍爲公舞，舞罷颯颯回風起。", "孤生飄零踰歲月，感慨鰍蝦共泥滓。", "石田蝗蟊仍數熯，抱耒空山欲何俟。", "叔孫大猾誠謬妄，狗監文章亦巴鄙。", "黄金儻築燕人臺，爲問何如從隗始。"]'),
('034ba3af-017c-49bc-a5e1-e4bebd1998e7','代送陳都大赴召','李流謙','宋','宋诗','song-poetry','','[]','庭前梧葉西風起，三峽秋光凈如洗。',240,'全唐诗/poet.song.125000.json','["庭前梧葉西風起，三峽秋光凈如洗。", "仙帆一舸此入覲，靈鼉擊鼓馮夷喜。", "七閩山水天下奇，摧秀搴英瑞斯世。", "要知曠代乃一見，鳳巢阿閭麟游畤。", "彤庭紫闥足夷步，萬里西來將使指。", "西南榷牧古所重，陰削盜資寬國計。", "臺家選任皆偉人，遠極隴秦包越嶲。", "我公經略出咳唾，凜凜霜威肅頹靡。", "飛聲一日到冕旒，四輦促還不留轡。", "從來大材須大用，豈有如公才一使。", "東夷盟血猶未乾，豺豹固應防嚙噬。", "公歸爲國須遠謀，平躋兩禁躐三事。", "飄零孤翮得廣厦，晨啄暮栖方竊庇。", "驪駒清唱不忍聞，東望慨然增歎喟。", "他時黄閣未遐遺，猶願登堂拜簪履。"]'),
('d78ee666-b385-4af2-9d66-6150811f50e7','送張漢州赴召','李流謙','宋','宋诗','song-poetry','','[]','詔書揮翰日邊來，蜀有巨儒星杓魁。',320,'全唐诗/poet.song.125000.json','["詔書揮翰日邊來，蜀有巨儒星杓魁。", "胸中深博布河漢，舌底霹靂降霆雷。", "先天遡流得絕派，大物不敢藏胚胎。", "回薄一氣在籠絡，奇神怪魃生愁哀。", "十年縛屋蒼崖隈，脫幘擲去一笑咍。", "刺史驚呼失匕筯，遮道自挽封章回。", "先生閉門壁愈堅，高風一日興澆頹。", "矯然輕世豈我事，此學施用真難哉。", "行止在天不在我，風動水涌如挽推。", "嗣皇繼聖登禹稷，豈有此士遺蒿萊。", "二年勞公湖上行，看鵝酌酒春風臺。", "手摩嬰雛斧貪猾，蛟鰐半束角與顋。", "古人讀易元用易，羲文祕妙今寒灰。", "漢儒妖異陷荒闊，但與瞽史相喧豗。", "子雲晚出造根極，後生蜉撼輕嘲詼。", "安樂老翁獨稽首，玄鑰直付先生開。", "向來緒言見編簡，去去勳業看崔嵬。", "彌綸乃是第一手，下者乃取支崩摧。", "賓閣顧予若嗟異，贈語愧乏珠瓊瑰。", "眼看飛帆不得去，天涯逐食嗟徘徊。"]'),
('b92c560b-c083-43f6-a528-95ee18f007a0','送晁子西提刑赴召','李流謙','宋','宋诗','song-poetry','','[]','君家如河出崑崙，橫貫中國浮乾坤。',224,'全唐诗/poet.song.125000.json','["君家如河出崑崙，橫貫中國浮乾坤。", "鼎彜勳績爛星斗，編簡文字垂瑶琨。", "到海喧豗勢愈壯，約束蛟蜃驅鼉黿。", "略分涓流溉下土，草木蕃潤資其恩。", "先生繡衣吹霜風，一道生齒關寢飧。", "人家春園滿桃李，隨處秋社肥雞豚。", "智效一官可能爾，尚於勝處非所論。", "胸中人物自著眼，倀倀待相嗤彼昏。", "古人過人本如此，事業自是爲根元。", "我知先生在廊廟，定不碌碌爲澄渾。", "頗恨未識元魯山，一紙藻藉無媒援。", "只今相送九天去，風在下矣何軒軒。", "青雲託附可無意，欲兒女語吐復吞。", "浩歌一曲豁清思，援筆江海蛟龍奔。"]'),
('566da31e-33dd-4195-950b-40077ece8999','寄送梁子輔赴召','李流謙','宋','宋诗','song-poetry','','[]','山嶽自高百谷下，向來無物使之者。',336,'全唐诗/poet.song.125000.json','["山嶽自高百谷下，向來無物使之者。", "驊騮合奉鸞和車，豈與黔蹄同一駕。", "英奇絕代難小了，泥滓投之輒悲咤。", "一朝拔去不可扼，震地風雷怯凌跨。", "泮宮先生自超特，鼎甲聲稱低董賈。", "眼明奎畫照琬琰，萬喙夸呼海傾瀉。", "胡爲不即天上去，識者怪吁狂者駡。", "或傳鳳篆來日邊，流水爲車龍即馬。", "只應故是霄漢人，腐鼠未足鵷雛嚇。", "九江水暖桃花肥，風色不驚神所借。", "只今岷峨抗湖海，貫玉編珠炯相射。", "臺家議和不議戰，太平有象須藻藉。", "小却猶當白玉堂，縱步黄扉方食蔗。", "嗟予骯髒每自哂，蚤年謾想牛心炙。", "一官漫浪不可說，可能更索山人價。", "五年投閒食不飽，攬鏡顛毛輒生怕。", "道塗衆鬼同揶揄，口不能酬面空赭。", "人生升沉亦何恨，但喜龍虎新變化。", "異時擊壤爲幸民，一犁亦願從耕稼。", "金華夫子吾勝友，接武風雲共閒暇。", "未應厚祿絕來書，寄聲紙尾煩多謝。"]'),
('fbcdf1ac-5427-4046-b456-f2af8a84ca49','送何子應少卿赴召','李流謙','宋','宋诗','song-poetry','','[]','持竿野叟踏帝腹，太史占星驚變色。',336,'全唐诗/poet.song.125000.json','["持竿野叟踏帝腹，太史占星驚變色。", "白衣山人侍黄衣，軍中指點相嘆息。", "雲龍契遇固疇曩，千載一合非人力。", "羊裘眠沙竟何補，坐視生民自肥瘠。", "功成乞身香案前，歸侶松喬未爲失。", "我公學傳無盡翁，束髮英名撼區域。", "杲日潛光衆未覩，公獨扶輪上霄極。", "此時際會如二子，鼎鉉鈞衡本公物。", "若爲流落四十年，豈厭蓬壺薄瀛渤。", "龍飛天子第一載，收召耆俊誠汲汲。", "遥知問膳大明宮，論士到公先指屈。", "追鋒一日來劍外，破浪帆開矢離括。", "朝廷未漆月支首，抱戈虎旅衣生虱。", "嫠不卹緯憂宗周，寧有裙襦能念國。", "堂堂甲兵滿胸臆，可無奇謀寬旰食。", "我故人子得深知，平生一鏃未破鏑。", "欲隨公去邈楚越，恨不身邊插雙翮。", "叔孫區區進大猾，謬謂書生用奚益。", "古來萬里知戎情，何必縵胡半縫掖。", "願公入對明光宮，西南豪俊手推出。", "我非其人敢觖望，市駿千金先市骨。"]'),
('2afdb1be-f988-4c33-8172-7b2cfa7c8ff3','挽李子和知縣','李流謙','宋','宋诗','song-poetry','','[]','盤谷先生壇級尊，萬夫操槊輒歛魂。',224,'全唐诗/poet.song.125000.json','["盤谷先生壇級尊，萬夫操槊輒歛魂。", "黄堂晝嚴繞華㦸，往往君來客打門。", "高談錯起風襲塵，醉眼相視月照樽。", "歸來拊掌此快士，外無圭角中甚渾。", "吾家宰樹已拱把，君亦荒殯生棘榛。", "小阮弟兄吾所敬，霧谷養就虎豹文。", "銜君至恩深到骨，手書盛德表九原。", "遣奴持送急開讀，字字璀爛光瑶琨。", "兼金餽魚客何陋，寶玉圍腰吾敢嗔。", "九牛未可一毛數，大壑才以半缶論。", "嶄然二雛亦奇俊，造物兩眼如許明。", "由來孝弟動鬼神，宦學所自爲根源。", "向來施設本此耳，欲著吾說聽者驚。", "春風相送綠草野，爲君一慟河漢翻。"]'),
('b5ccddbe-16f9-4326-b0ef-fa83ffef49ad','送夔路費漕','李流謙','宋','宋诗','song-poetry','','[]','晚風酣酣吹柳花，長亭送客日欲斜。',256,'全唐诗/poet.song.125000.json','["晚風酣酣吹柳花，長亭送客日欲斜。", "春草春波兩愁極，雲馳千騎誰能遮。", "先生要是世所寶，大貝白璧金丹砂。", "生當龍墀侍黄繖，不爾鳳閣揮白麻。", "州麾再把亦何事，但見桃李春家家。", "后皇顧遠食每旰，一節又付夔與巴。", "荒山如石不可鑿，要看雨露滋槁芽。", "黄金作甌覆名字，軟蒲作輪駕輕車。", "調和元氣須此手，典謨勳烈非誕夸。", "小夫朽質謝鎸削，尺寸不能供負叉。", "馬羣一顧覺差異，便遣萬里奔風沙。", "阿房變色人未信，勉之霄漢參飛霞。", "僕夫在門輒休駕，揆力不足慙蟾蛙。", "雖然此意萬鈞重，自矢報稱其未邪。", "眼看帆檝不得去，縛以微官成嘆嗟。", "他時黄闥眷簪舄，猶幸姓氏塵頰牙。"]'),
('1a69c64e-1838-4df7-92fe-620429b21d95','代人上李制參生辰','李流謙','宋','宋诗','song-poetry','','[]','乾坤不許一塵隔，誰倒天河濯秋色。',144,'全唐诗/poet.song.125000.json','["乾坤不許一塵隔，誰倒天河濯秋色。", "鵠鷺心性冰雪魂，造物著意不倉卒。", "星斗並煥仰斯文，準繩不愆宗絕德。", "當年只作充閭喜，不知此人係邦國。", "錦囊名章小游戲，上公啟齒嘆孤出。", "太白要是天上人，少陵屢作諸侯客。", "朝來日照黄金巵，諸生登堂作生日。", "鳳麟媲德公厭聞，丹砂續年笑無益。", "試問公家白髮翁，五千微言不老術。"]'),
('6006337f-5acc-40a0-8228-0e6de3eb9856','挽安岳李令','李流謙','宋','宋诗','song-poetry','','[]','司馬家兒何等兒，家居令人撞壞之。',240,'全唐诗/poet.song.125000.json','["司馬家兒何等兒，家居令人撞壞之。", "長嘯羯奴一繩縻，校三十里嗟已遲。", "新亭收涕僅自支，下者朽棟當積危。", "君看黄髮掩面時，此殆天意非人爲。", "一時埃𡏖埋精奇，褐衣懷珍去而違。", "老樵携畚動嶽祇，委體氈廬玉投泥。", "向來捫虱氣吐霓，元子眼膜無金篦。", "縱狼山林血黔黎，慘澹萬古關河悲。", "先生異代論盛衰，使當若時未可知。", "指揮王謝驅羣鷄，狂童豈勞折箠笞。", "中興天子周宣齊，炳燿常武烝民詩。", "囊封未報九地歸，恨無偉烈光鐘彝。", "我思若人涕沾衣，太阿不如兩錢錐。", "魚復陣石存遺基，故智猶爲豎子窺。", "斯文未泯神所持，復有英雄發噓欷。"]'),
('80dd286d-6ee2-4651-8ccd-11d13a62539a','別臨邛知縣李允成','李流謙','宋','宋诗','song-poetry','','[]','周公山前傾蓋時，再歲通家同骨肉。',272,'全唐诗/poet.song.125000.json','["周公山前傾蓋時，再歲通家同骨肉。", "紫巖樓畔又從容，四方上下如相逐。", "別來每恨無見日，要見夙緣償未足。", "公來臨邛弄鳴琴，一官季氏仍寮末。", "移將遠期爲近期，天遣從公恐不速。", "尺書日夜苦相換，何止已多如笋束。", "淹留自春竟徂冬，出門如物縶兩脚。", "一朝决去水赴壑，夢魂先到鶴山側。", "下車一見開兩眼，喜色分時破愁頰。", "約我不來公即來，一日不見公不樂。", "將閒文書猛撥置，喚好朋友細款曲。", "疾邪憤世時抵掌，悵往悲今忽嚬蹙。", "狂吞壯飲無空樽，長句短章幾滿軸。", "尊賢下士公盛德，忘義忘年吾敢辱。", "百年四海幾知己，爲公悲歌起衰俗。", "明朝翩翩隨社燕，欲去暫留情最惡。", "黄花滿頭約重來，聞說床頭酒方熟。"]'),
('fc4cd9cf-650e-45bd-bf84-c9008c038127','送才夫之成都','李流謙','宋','宋诗','song-poetry','','[]','客有可人期不來，昔人抱恨長悠哉。',128,'全唐诗/poet.song.125000.json','["客有可人期不來，昔人抱恨長悠哉。", "可得宦遊同一處，家有如願令人猜。", "郊東郊西踏春色，醉舞淋浪花插額。", "門前紫騮嘶東風，却折垂楊供馬策。", "如君豈久居塵泥，好處人知天亦知。", "我非夔才識宮羽，此言欲驗須他時。", "長橋離愁濕烟雨，去日更將歸日數。", "從今把盞與題詩，故應半是思君語。"]'),
('5868f4f9-58b1-4e89-9128-c83a66f1dc11','白雲先生魯叶殿丞交之父有隠節其居徽考所賜旁爲魏高士守一庵高士上皇所賓禮庵亦賜地也高士亡矣而白雲之後至食不給過之慨然爲賦此篇','李流謙','宋','宋诗','song-poetry','','[]','白雲先生去何從，烟霞高人繼其蹤。',64,'全唐诗/poet.song.125000.json','["白雲先生去何從，烟霞高人繼其蹤。", "兩朝恩光照巖穴，映牆竹柏清陰同。", "高人已注丹臺籍，白雲子孫食不給。", "人生有累豈妻孥，生羨金門羽衣客。"]'),
('640ccb64-8104-44ea-81ba-1f292b3705b3','林夫體中不佳而能不廢翰墨且蒙以文軸見教其天性所嗜如此敬嘆不已既勿藥作詩賀之','李流謙','宋','宋诗','song-poetry','','[]','瓠肥不必緣糠覈，倒床鼾睡掀四壁。',144,'全唐诗/poet.song.125000.json','["瓠肥不必緣糠覈，倒床鼾睡掀四壁。", "飯山詩好自應瘦，騎省賦成髮先白。", "公子翩翩鍾鼎家，宜有騷人歌錦瑟。", "數從癯儒弄文字，坐令二豎喜投隙。", "藥裹關心始置之，往往呻吟出圭璧。", "由來物理論根種，虎生則斑鷹則擊。", "浣腸濯胃固佳手，愈風却痁非此力。", "東風吹園花正開，新禽向人語磔磔。", "疾來相就破除之，萬事可拚春可惜。"]'),
('cb669698-6f1c-4d78-a3ca-13f5c7bb017b','賀王制置敷學之除','李流謙','宋','宋诗','song-poetry','','[]','太霄傑觀凌空起，非霧非烟護珠蘂。',320,'全唐诗/poet.song.125000.json','["太霄傑觀凌空起，非霧非烟護珠蘂。", "萬靈操㦸夾危棟，中有丹書并綠字。", "走雲飛雨澤地産，合璧聯珠煥宸緯。", "堯圖羲墳共彪炳，禹訓湯銘角雄偉。", "岡陵松柏老如鐵，華榜丹青新若洗。", "論思欲侍聖天子，寓直正須真學士。", "一時盛選孰睥睨，百代耆儒屬宸倚。", "惟有我公瑞河嶽，早與靈鼇爭贔屭。", "絲綸飛藻傾兩禁，弓鉞專方雄萬騎。", "從容裘带凈岷隴，零落旗矛清筰嶲。", "疇庸王府侈三晝，告喜郵音傳一紙。", "升華祕宇階召拜，正位台符慰瞻徯。", "妄論斯文本神物，輕發其藏觸天恚。", "開物成務非翰墨，賁飾乾坤乃能事。", "周書九誥削邪叛，一品會昌夷僭詭。", "願公亟從衮舄歸，早就典謨垂萬世。", "迂愚把筆自齠齔，裂紙悲鳴蛩蚓比。", "酸寒一尉不可說，尺璧光陰分馬箠。", "待公勳業映彝鼎，勉葺巴蕪歌俊偉。", "絲麻雖美收蒯菅，尚冀風人採輿隸。"]'),
('1340d062-bd22-439a-99b7-ed06226c2879','文約用韻請別作此留之并柬簽判李丈','李流謙','宋','宋诗','song-poetry','','[]','平生心知我與君，餘子碌碌耳未聞。',128,'全唐诗/poet.song.125000.json','["平生心知我與君，餘子碌碌耳未聞。", "相思輒命嵇呂駕，醉飲仍開孟公門。", "山城牢落情易動，翻然便作思家夢。", "笑言伏臘未一有，歸辦黄虀三百甕。", "君才何止吞四溟，新詩誦過牙生津。", "猗那清廟復在眼，此作未許秦火焚。", "吾家丈人似居易，落筆成章了無諱。", "相從更作百篇詩，且盡中山千日醉。"]'),
('ab8967f9-5aa9-45ee-8755-2b58091f62da','留黄思忠','李流謙','宋','宋诗','song-poetry','','[]','可人如君不易致，惠然而來此天意。',112,'全唐诗/poet.song.125000.json','["可人如君不易致，惠然而來此天意。", "往往文字雜嘯歌，兒輩倚牆吾敢訶。", "向來邂逅無此款，曲水風流嗟未遠。", "愛君欲留君不留，一聞說歸我先愁。", "亦知主人無德戀，多情合覷青山面。", "况聞漲江浪翻雷，轂生四角若爲推。", "留君信自非人力，君雖欲去不可得。"]'),
('9bdf8cfa-f80b-4002-96d4-753e8ccc8002','壽仲秉侍郎','李流謙','宋','宋诗','song-poetry','','[]','今朝雲裾下星漢，明日冰輪十分滿。',128,'全唐诗/poet.song.125000.json','["今朝雲裾下星漢，明日冰輪十分滿。", "今朝海實薦蟠桃，明日潮頭千丈高。", "君才與月爭澄爽，君氣如潮同浩放。", "如何不著廊廟中，不是考槃巖壑樣。", "十年立朝兒輩驚，前日欲去親留行。", "我雖流落未足恨，世間那有此友生。", "躋堂奉觴祝耆耈，仙骨應須飲仙酒。", "潮聲不斷月長圓，歲歲來爲主人壽。"]'),
('a3ab9a19-34ed-4341-94c2-7c1dd68f50ff','挽張主簿','李流謙','宋','宋诗','song-poetry','','[]','嘗聞種德如種木，百年培壅猶不足。',176,'全唐诗/poet.song.125000.json','["嘗聞種德如種木，百年培壅猶不足。", "君看牛羊踐履地，豈有寸椽撐破屋。", "我方撮髮訪耆舊，已聞定國多陰德。", "崑峯薦璧淵出珠，天敕百靈介多福。", "後來源委誰導之，刊木濬川君有力。", "一官縛死不須說，天定勝人理則必。", "鵷鶵覽輝下其庭，一舉萬里羣鳥伏。", "我耕我穫我其食，夸者流涎疑者奪。", "桃李蔭繁春不留，瓊瑰夢斷月空白。", "煌煌貂冕侈殊渥，尚冀他時賁幽宅。", "死而不忘誰者是，嗚呼公乎妥沈魄。"]'),
('15abbd9c-cd2a-445d-bd2e-c9c4c62dbc44','青樓行','李流謙','宋','宋诗','song-poetry','','[]','踏空驕馬蹄鐵踣，萬里一鞭驚滅沒。',96,'全唐诗/poet.song.125000.json','["踏空驕馬蹄鐵踣，萬里一鞭驚滅沒。", "青樓美人顔如花，笑揭珠簾邀客入。", "小槽珠溜紅滴滴，左持瓊觴右瑶瑟。", "得君一笑妾願足，不用真珠量斗斛。", "歌聲未闋杯未擲，城上歸鴉带寒日。", "蒼頭進馬莫留連，別院笙歌擁門立。"]'),
('cb918f8b-2c10-4e3d-89af-74bad7231c55','紫薇花','李流謙','宋','宋诗','song-poetry','','[]','庭前紫薇初作花，容華婉婉明朝霞。',64,'全唐诗/poet.song.125000.json','["庭前紫薇初作花，容華婉婉明朝霞。", "何人得閒不耐事，聽取蜂蝶來喧譁。", "絲綸閣下文書靜，能與微郎破孤悶。", "一般草木有窮通，冷笑黄花伴陶令。"]'),
('c7d3293f-da14-4c80-842b-6606f25423ab','公歸行送王顯謨','李流謙','宋','宋诗','song-poetry','','[]','我從職方究區域，江漢滔滔紀南國。',336,'全唐诗/poet.song.125000.json','["我從職方究區域，江漢滔滔紀南國。", "厥田上上蓋名壤，其人落落亦代出。", "卧龍偉烈雄鼎峙，雛鳳英稱冠簪盍。", "峴山風流亙千祀，鹿門隠槩輕九牧。", "地靈不與人存亡，王脈依然鍾傑特。", "先生後出掩前哲，天公著手自斲削。", "如入宗廟識彝鼎，如開武庫見矛㦸。", "早以命士戰羣士，不怯小敵勇大敵。", "三年博士嗟洄沉，一等巍科登岌嶪。", "銅符千里小游戲，瑞節三川徧揚歷。", "欲歌德業愧蜩聒，妄覘設施歎蠡測。", "愛民如兒吏不擾，以身爲律人自服。", "恩波春醲疲瘵蘇，美最飈馳冕旒徹。", "賜環成命衆聽聳，總計優除羣論咽。", "公止一方爲福星，公歸天下作膏澤。", "一方天下有大小，公則不校我所惜。", "周公居東逾歲月，東人願留惜不發。", "西人衮舄待公歸，鴻飛遵渚歌九罭。", "君子所至民父母，在此無惡彼無斁。", "我雖東人願公歸，不敢自私笑其狹。", "援毫爲賦公歸行，明日羽旄風獵獵。"]'),
('e8bd0a9b-19de-45e8-bf5b-0be2ee1a0304','送孫遠仲知錄解官歸洪雅','李流謙','宋','宋诗','song-poetry','','[]','錦官碌碌牛馬走，邂逅僧廬欣握手。',128,'全唐诗/poet.song.125000.json','["錦官碌碌牛馬走，邂逅僧廬欣握手。", "嘗憶觀燈夜相過，一時勝輩同樽酒。", "孤雲岑絕西南陬，牢落重來說舊遊。", "不知宦情薄如紙，掉頭忽作商聲謳。", "蚤年提筆戰多士，晚歲功名夢相似。", "底事人生真足夸，華髮猶能彩衣戲。", "霜空木脫秋山明，高風駕帆秋浪輕。", "細雨重陽好天氣，紅萸紫菊正思君。"]'),
('f15da1fa-97a4-479a-b9fb-b5f564c51dba','用黎州梅字韻作詩送之','李流謙','宋','宋诗','song-poetry','','[]','西風舉扇揮浮埃，十年水曲并山隈。',160,'全唐诗/poet.song.125000.json','["西風舉扇揮浮埃，十年水曲并山隈。", "一朝尺一天上來，臺家擇才搜偉瑰。", "豫樟連雲誰手栽，梁千尺觀崢嶸哉。", "收拾虹蜺小低徊，如取萬海納一杯。", "濟時策略招譏詼，翳氛卷盡青天開。", "還如調鼎須鹽梅，衆星錯落環杓魁。", "欲談近事樹頰頦，旗矛委塵槍卧苔。", "禍生冥冥戒其胎，如公氣象天可回。", "高論疾如破山雷，毋使缾罄空耻罍。", "笑渠佩玉救焚煨，往矣急挽波之頹。"]'),
('74e94037-81c7-49e9-9da5-450fe86dd5d0','文約既行復作此送之','李流謙','宋','宋诗','song-poetry','','[]','登山臨水遠送君，征鴻掠天不堪聞。',128,'全唐诗/poet.song.125000.json','["登山臨水遠送君，征鴻掠天不堪聞。", "臨岐握手惜此別，車已載脂僕在門。", "驪歌未殘心欲動，剪燭夜談如昨夢。", "茂林已掃山陰迹，地黄猶注床頭甕。", "明朝咫尺隔滄溟，烟波渺渺迷羌津。", "我亦歸來念離索，孤坐手取柏子焚。", "君絕畛畦我平易，肝膽相傾無復諱。", "春風萬斛撒金蓮，遲君更作連宵醉。"]'),
('e62ae050-fcae-46a5-90a2-035122fa54aa','答何積中','李流謙','宋','宋诗','song-poetry','','[]','先生古心寄玄漠，老松矯矯石鑿鑿。',64,'全唐诗/poet.song.125000.json','["先生古心寄玄漠，老松矯矯石鑿鑿。", "已欣凈社得勝友，更枉高軒出奇作。", "山林軒冕無間然，造物從公意所便。", "决科縱未吞餘子，著書亦足垂千年。"]'),
('57a8e836-12a9-4846-b099-1d0310e8981d','宋文約有謁於邡江不遂而歸復用韻見貽以此答之','李流謙','宋','宋诗','song-poetry','','[]','中山老穎初得君，姬姓之毛遂無聞。',128,'全唐诗/poet.song.125000.json','["中山老穎初得君，姬姓之毛遂無聞。", "疏封新賜管城爵，待詔嘗趨金馬門。", "胡爲得此色爲動，引赴幽人春草夢。", "新詩更許窺豹管，淺識當憑發醯罋。", "生平雅懷吞八溟，赤脚欲踏河漢津。", "自慚不是虎頭相，未能逕取龍庭焚。", "談今說古吾所易，况值聖明初不諱。", "快書禮樂三千言，白獸先贏一樽醉。"]'),
('e36f1346-7dcc-4e7e-b2bf-f75b6d897efc','宋才夫作詩自言作縣之况以冷官爲可樂戲用韻答之','李流謙','宋','宋诗','song-poetry','','[]','雲霄自許當比肩，豈料坎壈逢針氈。',96,'全唐诗/poet.song.125000.json','["雲霄自許當比肩，豈料坎壈逢針氈。", "求魚乃欲從沮洳，吞舟見之定囅然。", "諸生但解笑便腹，好事誰肯與酒錢。", "吹寒固自乏暖律，使物又恨無神鞭。", "君方踏筵觀艷舞，我正閉戶甘草玄。", "閒忙亦復分苦樂，溫醲淡泊無非緣。"]'),
('51276229-34e9-482d-b754-075b63375def','立春日有感用彥博韻','李流謙','宋','宋诗','song-poetry','','[]','雙轂行天不停轡，世間那得西流水。',64,'全唐诗/poet.song.125000.json','["雙轂行天不停轡，世間那得西流水。", "麻姑昨夜呼我飲，笑說海塵飛幾幾。", "百年半見韶華濃，不妨老子頰仍紅。", "人生萬事有起伏，緩聽高歌酌春醁。"]'),
('89267486-eb64-42c5-83af-fec64b83f3fc','晚春有感答才夫上巳之作二首  其一','李流謙','宋','宋诗','song-poetry','','[]','牡丹猶欲扳春住，開到荼䕷春遂去。',64,'全唐诗/poet.song.125000.json','["牡丹猶欲扳春住，開到荼䕷春遂去。", "黄蜂白蝶太癡生，抵死嗔風復嗔雨。", "少年世味如蜜甜，邇來唯覺食無鹽。", "只應餘習掃未盡，一春病酒常厭厭。"]'),
('7a6565b7-fe54-4269-8dd3-9be6d532d07e','晚春有感答才夫上巳之作二首  其二','李流謙','宋','宋诗','song-poetry','','[]','劉郎愛花被花惱，玄都觀裏詩應好。',64,'全唐诗/poet.song.125000.json','["劉郎愛花被花惱，玄都觀裏詩應好。", "騷人從古多閒愁，仍是清樽破除了。", "禁詩如禁秋蟲鳴，止酒如止長淮傾。", "人生貴在適意爾，孰知蜾蠃與螟蛉。"]'),
('362a3184-e5c4-4f58-92d2-30307273820e','宋才夫解官作此送之','李流謙','宋','宋诗','song-poetry','','[]','與君異姓如兄弟，鴈塔相携有名字。',128,'全唐诗/poet.song.125000.json','["與君異姓如兄弟，鴈塔相携有名字。", "西來山城始傾蓋，北去塞垣仍握臂。", "渥洼來者天馬駒，八鸞六轡供皇輿。", "朝觴瑶池夕玄圃，豈願地下粒與芻。", "三年妙旨發徽軫，飽聽村村人說尹。", "政成通籍天上去，綠髮斑衣歸侍省。", "茜袍頳萼春怡融，堂上老人雙頰紅。", "渾家拜舞上翁壽，盡捲春風入樽酒。"]'),
('db4510cc-6a08-45b3-ade0-aeb35e5a11f9','夜飲彥博家歸而作此','李流謙','宋','宋诗','song-poetry','','[]','故人留飲歸夜深，銅缾唧唧蟲微吟。',64,'全唐诗/poet.song.125000.json','["故人留飲歸夜深，銅缾唧唧蟲微吟。", "一燈猶照讀書眼，半紙忽生懷古心。", "亦知所貴何必用，魚目驪珠自輕重。", "人間蟻穴小差殊，等是一場閒睡夢。"]'),
('f8ce58fc-60eb-4088-8123-0718d42f613c','醉時謠','李流謙','宋','宋诗','song-poetry','','[]','晴輒不閒閒輒雨，少神造物惡相阻。',96,'全唐诗/poet.song.125000.json','["晴輒不閒閒輒雨，少神造物惡相阻。", "我自意行無雨晴，翻倒滄溟儘從汝。", "青年一去不可招，紫烟漠漠三山暮。", "朝雲破峽忽歸來，從君欲覓高唐賦。", "向來似夢此非夢，轉盼仍從夢中去。", "夜深泥滑欲歸時，瘦馬遲遲堤上路。"]'),
('c0a5e0b1-34ec-4167-ad8a-43a2223d65ee','七夕','李流謙','宋','宋诗','song-poetry','','[]','火金鏖攻電雷擊，風從西來火折北。',272,'全唐诗/poet.song.125000.json','["火金鏖攻電雷擊，風從西來火折北。", "向來勝負吾已分，物極而顛勢其必。", "露盤清濯房櫳秋，冰壺冷浸乾坤骨。", "明河指點三星橫，天上靈期有幽約。", "寒機軋軋終年思，危橋納納萬山隔。", "不知今夕果何夕，洞房幽懽寸陰疾。", "仙人與世當異馳，一念蕭然證無極。", "情之所鍾豈其然，婉孌合匹此疑褻。", "巫娥神力造化通，撫摩神禹授祕策。", "百靈後先相開鑿，脫我蛟鰐骨再肉。", "楚大夫玉何人哉，枕茵誣之神所殛。", "姑置是事勿復問，一扇微凉萬金直。", "有景如此可小了，况復我友一世傑。", "其文如玉雅過之，共作清詩洗汙蔑。", "兒曹瓜果羅庭除，拜祈天孫巧可乞。", "何如侑我花前樽，得巧未必如得拙。", "君看鳴鳩安鵲巢，大勝狡兔營三窟。"]'),
('9df2550b-9512-4787-b4f0-afb1867fe80e','喜仲明西歸','李流謙','宋','宋诗','song-poetry','','[]','半載迢迢住利州，嘉陵江水日夜流。',160,'全唐诗/poet.song.125000.json','["半載迢迢住利州，嘉陵江水日夜流。", "安得却流關下去，載我唯須一葉舟。", "我歸未遠君隨至，燕鴻相避知何意。", "月巖四見月上弦，日日江頭望行李。", "庭柯一鵲鳴朝陽，人言君歸過石崗。", "明日拏舟入城去，劇喜重上君子堂。", "瘦骨稜稜衣表見，我亦鬢毛斑太半。", "談新說舊兩留連，紅燭燒殘無一寸。", "人生大抵如流萍，忽然相值飄然分。", "西風吹我又將去，預作一場離恨新。"]'),
('ff69802f-ee17-4f0c-b8db-9004aeedd8bd','飯客鎮驛見壁間書火池事異甚','李流謙','宋','宋诗','song-poetry','','[]','荒亭舊刻書火池，火從水出如燎脂。',64,'全唐诗/poet.song.125000.json','["荒亭舊刻書火池，火從水出如燎脂。", "五行生克謬常理，異事儻恍令人疑。", "居人只言數里近，驅車欲前僕夫慍。", "誰能博學辨癡龍，寄我此詩聊一問。"]'),
('2210ce1f-57fa-49ef-9ba2-2366f3ed42a3','宿永年鎮僧居','李流謙','宋','宋诗','song-poetry','','[]','風慘雲低月欲墮，路上荒村愁僻左。',64,'全唐诗/poet.song.125000.json','["風慘雲低月欲墮，路上荒村愁僻左。", "蕭條橫道屋三間，傴僂迎門僧一箇。", "夜深山鬼聲砉然，恐來吹燈不敢眠。", "明朝踏雪又西去，千疊萬重山屈盤。"]'),
('03e25055-2c8d-40f7-837a-c91fc2ffbe4b','錢元質飲客月巖前小亭酒半月上移席坐巖下四顧林塘景氣清絕眉山程進儒謂予不可無詩因作此','李流謙','宋','宋诗','song-poetry','','[]','兩山齊起屹雙闕，一巖突出刳寒月。',160,'全唐诗/poet.song.125000.json','["兩山齊起屹雙闕，一巖突出刳寒月。", "成行松桂自昭穆，入耳流泉間宮角。", "向來妙思發天藴，突兀小亭著能穩。", "漁郎撐舟更何之，不信武陵眉睫近。", "慇懃置酒臨清夜，主人不凡客殊野。", "酒酣燭暗月初上，却徙胡床坐巖下。", "疎疎林隙半輪懸，破碎寒塘萬珪璧。", "恐有仙人海上來，髣髴天風響環玦。", "蟇頤先生有矜色，索我題詩紀清絕。", "才薄將奈此景何，喚起吾家跨鯨白。"]'),
('2d9968b6-ee38-43e2-9312-41bbd9e83e32','拜嵩次山塔','李流謙','宋','宋诗','song-poetry','','[]','向來契分膠投漆，一日不見真若失。',112,'全唐诗/poet.song.125000.json','["向來契分膠投漆，一日不見真若失。", "那知遂作死生分，屈指五年飛鳥疾。", "詩人猶誦碧雲句，老衲來尋金鎖骨。", "亭亭孤塔蔽榛莽，下馬焚香涕橫集。", "烟林霧草不供愁，坐對青山搔短髮。", "亦知電露難把玩，但聽漚泡自生滅。", "歸來閉閣睡方美，杜宇一聲山月白。"]'),
('495a7400-5944-4a11-b93f-e766a80153ad','自登道來馬谿作','李流謙','宋','宋诗','song-poetry','','[]','朝暾拔山紅一丈，露草烟林氣蕭爽。',256,'全唐诗/poet.song.125000.json','["朝暾拔山紅一丈，露草烟林氣蕭爽。", "出門華構照新綠，並轡寶珂喧碎響。", "僮奴尚語林薄間，馬蹄勢已青雲上。", "琳宮百年傲風雨，氣象雄深挾千嶂。", "青山固是耐久交，老檜真成丈人行。", "山童候門驚馬嘶，道士疊爻知客訪。", "情親肯自摘嘉蔬，興發更遣沽村釀。", "未妨意行窮勝踐，不用心違嘆仙賞。", "雙峯喚我却西去，穿逕縈紆轉修蟒。", "荒橋下馬久竚立，孤塔懷人嘿惆悵。", "多謝山僧供湯餠，腹猶果然虛雅餉。", "只應探討盡老釋，坐覺仙凡絕天壤。", "碎礫誰參水底禪，飛蜺空閣雲間仗。", "凌霄固有飛霞珮，塵蒙濁骨何由往。", "歸來閉戶省初念，一炷爐香薰宿障。", "題詩聊復紀勝游，永與名山鎮龍藏。"]'),
('8e3ce0e2-efe4-4ebd-8bbe-c2f1bc1dc2ab','游秦園分韻得東字','李流謙','宋','宋诗','song-poetry','','[]','愛春春淺如稚童，愛晴連日無雨風。',112,'全唐诗/poet.song.125000.json','["愛春春淺如稚童，愛晴連日無雨風。", "閉門不出春笑儂，百年容易成老翁。", "山茶經霜尚能紅，小梅吹雪香正濃。", "盍不亟倒琉璃鍾，主人好意客亦同。", "粉牋乞句酬天公，筆端有氣如白虹。", "少年射虎南山中，于今塵土蒙琱弓。", "安得雷雨鞭蟄龍，拊髀浩氣亦欲東。"]'),
('d393fc99-f5a5-43a7-ae6d-eaad92934f47','安居道中','李流謙','宋','宋诗','song-poetry','','[]','上如躋雲下臨淵，亂石當道如防賢。',64,'全唐诗/poet.song.125000.json','["上如躋雲下臨淵，亂石當道如防賢。", "遥看一鳥轉絕壑，鳥已烟沉吾木末。", "晚風吹雪作雲飛，山中更添一尺泥。", "歲華如此猶浪走，梅花思人越消瘦。"]'),
('1a4790df-18fe-4db1-9f9f-e36eef0c28f2','同常和仲謁照老和仲有詩次其韻','李流謙','宋','宋诗','song-poetry','','[]','杏花一株凌曉寒，刮眼創見春風還。',144,'全唐诗/poet.song.125000.json','["杏花一株凌曉寒，刮眼創見春風還。", "天涯作客歸未得，主人好事客疎頑。", "鳴鳩喚雨綠野浄，遊絲掛空白日閒。", "祇園有僧坐隠几，柱杖與子來扣關。", "薰爐午篆轉輕縷，浄缾曉汲翻微瀾。", "禪僧不摇月照水，雄辯猝起雷破山。", "癡兒浪說三組貴，向我不博一笑懽。", "歸來妙語出頃刻，照坐綺縠紛斕斑。", "火急爲續永和帖，清景一失情易闌。"]'),
('008a8a97-ac15-4ec1-ab46-8959f7d0f4c4','東州行上費檢正','李流謙','宋','宋诗','song-poetry','','[]','東州十剎如西州，東州幽爽西喧湫。',192,'全唐诗/poet.song.125000.json','["東州十剎如西州，東州幽爽西喧湫。", "登臨在在有佳處，我來無事得縱游。", "望川致爽兩奇特，雲烟流通東與北。", "一爲清淑一曠遠，清者發興遠快目。", "城西三剎跨一牛，五百雲堂老比丘。", "捐金樂施到樵牧，不知願力何年修。", "鄧家名筆難再得，苦愛雍熙之兩壁。", "貴人摸搨不曾休，真是化身千百億。", "府公玉皇香案吏，帆薄三山風輒止。", "來蘇疲瘵十萬家，卷縮靈河一杯裏。", "野人冠服裹狙猿，曳裾更欲之何門。", "慙無杜老驚人句，空負陳蕃解榻恩。"]'),
('de7b24e9-9c10-4846-b700-8dccdaa19470','巖桂堂','李流謙','宋','宋诗','song-poetry','','[]','湘峯峩峩湘水碧，萬古魚龍護冰魄。',144,'全唐诗/poet.song.125000.json','["湘峯峩峩湘水碧，萬古魚龍護冰魄。", "荷衣芷佩凝秋霜，欲誦遺章髮先白。", "天生草木預何事，乃與騷人同一骨。", "今人古人共磨滅，惟有芬香埋不得。", "主人手植雙桂樹，寧爲嬖玩娛燕席。", "亦知蘭鮑隨所化，勉進修名比馨潔。", "繞除霏霏風襲予，欲參靈螭駕寥闃。", "陳辭重華弔屈賈，酌以芳辛起湮鬰。", "日暮美人期未來，霧濕烟低花蔌蔌。"]'),
('1b761343-3bb3-4528-888c-fc182eb67aeb','歲庚午予過來鳳驛觀壁間碑刻火池事嘗賦詩今歲甲午再過用前韻','李流謙','宋','宋诗','song-poetry','','[]','東西燕鴻長差池，二十五年車載脂。',64,'全唐诗/poet.song.125000.json','["東西燕鴻長差池，二十五年車載脂。", "觀河性在故應爾，化鶴人歸空自疑。", "年來於道覺差近，此心頗已忘欣慍。", "吾兒亦復能此詩，鑷白老人休更問。"]'),
('92db00e8-bb8d-4151-9df8-485a7c723f0f','慈雲壁間有楊皓明叔崇寧甲申所題詩和者甚衆','李流謙','宋','宋诗','song-poetry','','[]','浮花眩眼朱成碧，關渠何事愁寂寂。',64,'全唐诗/poet.song.125000.json','["浮花眩眼朱成碧，關渠何事愁寂寂。", "依舊漁竿入手來，老我江湖倦游客。", "徑須一醉拋青春，校量細故非高人。", "茂弘雅量本不爾，幾箑能障西風塵。"]'),
('0bd9a8e7-da72-4370-9bfa-576c569072ba','自拋渡未嘗驚恐次公安舟爲疾風倒吹幾不能返自江行未嘗阻風將次沙市風留三日','李流謙','宋','宋诗','song-poetry','','[]','常時拋渡如不知，公安浪高船倒吹。',64,'全唐诗/poet.song.125000.json','["常時拋渡如不知，公安浪高船倒吹。", "數月江程絕無阻，一舍沙頭風泊之。", "因行逢觸發深省，無事安平人不領。", "要知憂樂自相形，天馬擡頭見鞭影。"]'),
('fbba5df3-6d86-43fb-9d0b-3844bffb396d','劉蛻唐大中時人文塚在兜率寺予嘗讀孫樵自序其作云大中皇帝嘗有詔褒時之藝能凡三人而樵居其一曰孫樵有揚馬之文蛻既同時不應不在褒詔之列士之顯晦固有定分劉君獨未能忘此乎塚其文予蓋疑其有激也作此弔之','李流謙','宋','宋诗','song-poetry','','[]','詔書嘗下大中朝，不聞稱蛻但稱樵。',128,'全唐诗/poet.song.125000.json','["詔書嘗下大中朝，不聞稱蛻但稱樵。", "犠樽棄溝俱害性，此理要以達觀超。", "封文爲塚嬉笑怒，恚不人知防鬼妬。", "高岸爲谷谷爲陵，磨滅可無千載慮。", "向來述作等俳諧，傳與不傳何有哉。", "六經排孔諱服鄭，未勝咸陽一炬灰。", "虛名誤人箕斗爾，引調狙公嗔與喜。", "已嗤地下有修文，更笑樓成能作記。"]'),
('cea00fed-ed2e-4b95-8767-088163f11aa1','涵翠亭','李流謙','宋','宋诗','song-poetry','','[]','太華峯頭花十丈，十八韓翁語豪壯。',128,'全唐诗/poet.song.125000.json','["太華峯頭花十丈，十八韓翁語豪壯。", "法華會上如車輪，跨猊仙人妄與真。", "九州芒芒置勿問，萬柄秋塘插寒鏡。", "楚人裂裳緝爲衣，一塵涴之色不怡。", "孽童萬死劍斬馬，何物奴言似之者。", "觸花花恐怒且嗔，悲風獵獵吹白蘋。", "我來拊檻笑仍喟，欲挽清泠濯斯穢。", "主人囅然客罷休，一醉能銷千古愁。"]'),
('f2011ca8-5b27-457d-a7cb-2b08126cf72e','弔李允成知縣','李流謙','宋','宋诗','song-poetry','','[]','百年造化無遺力，霜雪十圍豈易得。',192,'全唐诗/poet.song.125000.json','["百年造化無遺力，霜雪十圍豈易得。", "盲工操斤選樸樕，銅柯石根棄如擲。", "嗚呼斯人何不淑，天畀之多人則嗇。", "白眼千百碌碌子，老虎可縛蛟可馘。", "神鋒屢染鷄鶩血，繞匣龍蛇夜悲泣。", "英靈不合世間著，蟻宮歷游無半席。", "不如收拾還山川，化爲球琳尚華國。", "意氣偶合肝腸傾，手栽檀欒食予實。", "至今歛翼蓬蒿中，不與燕雀同感激。", "霜風吹愁愁更濃，屈折長虹玉三尺。", "晨興攬衣發深省，古來精誠可裂石。", "玄堂文成許見不，魚與熊掌當取一。"]'),
('7d669985-114d-443b-9408-da7863d02b96','飛烏道中','李流謙','宋','宋诗','song-poetry','','[]','朝發江亭暮山驛，面顔塵埃手龜拆。',64,'全唐诗/poet.song.125000.json','["朝發江亭暮山驛，面顔塵埃手龜拆。", "弟兄相逐兩浮萍，一盞村醪慰愁寂。", "高堂老人念兒寒，兒念老人不得眠。", "慇懃祝付送書鴈，爲傳片字報平安。"]'),
('530f01b0-d37e-4b3d-b39c-8c87f83454c8','飛烏與正老相值蓋十月初見之夢兆云','李流謙','宋','宋诗','song-poetry','','[]','憶得初冬忘甲子，夜夢與師游破寺。',64,'全唐诗/poet.song.125000.json','["憶得初冬忘甲子，夜夢與師游破寺。", "明朝東望欲寄聲，我在紫巖師錦水。", "空山行役偶相逢，物色看來與夢同。", "當時夢覺疑非夢，今日翻疑是夢中。"]'),
('86b0ace5-18fd-4031-ab5f-a3823e091bde','山口阻風','李流謙','宋','宋诗','song-poetry','','[]','舟行常有性命憂，江風一動令人愁。',64,'全唐诗/poet.song.125000.json','["舟行常有性命憂，江風一動令人愁。", "盤渦倒帆日方午，又作賈胡終日留。", "淮山隔江看細小，淡掃修眉晚尤好。", "岷峩行盡此江來，可是愛山心未了。"]'),
('958f0f17-96f5-4418-97d3-adb588309d40','賦壽康海棠','李流謙','宋','宋诗','song-poetry','','[]','何許園林春最釅，海棠萬萬千千點。',224,'全唐诗/poet.song.125000.json','["何許園林春最釅，海棠萬萬千千點。", "不應惟是錦織成，正恐更將猩血染。", "未開半豆已欲滴，爛吐一庭尤瀲灧。", "窺月洗雨俱可玩，抹霧橫烟猝難掩。", "梓澤步障烘曉霞，溫泉粉玉臨秋鑑。", "相逢但欲酣且歌，目送誰言美而艷。", "桃花何處容面皮，欲笑春風無乃僭。", "光翻牖戶翠堆幄，濃逼須眉纈生臉。", "裹頭朝出常苦晚，燒燭夜看終未厭。", "見不數數夢來往，百斛可傾心獨欠。", "老來世味薄如紙，斬斷情根須一斂。", "隨身鼓笛本遊戲，過目埃氛亦俄暫。", "明朝風雨未可期，委地泥沙混真濫。", "憑君但向雪落時，箇裏直須勤點檢。"]'),
('b78cc481-bf0f-4dc4-9e46-c3f4b385f02e','峽中重九以菊有黄華分韻得菊字','李流謙','宋','宋诗','song-poetry','','[]','江湖浪走嗟碌碌，往往佳時忘記錄。',272,'全唐诗/poet.song.125000.json','["江湖浪走嗟碌碌，往往佳時忘記錄。", "今朝峽裏作重陽，節物雖同感殊俗。", "終日懸憂湍瀨間，何人爲唱黄花曲。", "尚喜樽罍餘舊醅，不然何以慰蕭索。", "每思在家天氣好，一甕床頭撥寒綠。", "欲熟未熟喚客飲，婦駡兒嘲醉不答。", "只今那能問甜澀，况是名樽難重得。", "晚行江干見籬落，小雨霏霏冒叢菊。", "若從主人覓數枝，金英未吐心亦足。", "歸插銅缾對清酌，營度肴蔬選橙栗。", "茱萸在手花在頭，起舞狂歌忘爲客。", "人情一種無貴賤，餘瀝猶能到僮僕。", "淵明固是羲皇人，腰不可折带難束。", "白衣大自勝督郵，千古因渠重斯節。", "我行四方亦何事，此腹能須幾圭撮。", "並頭鷄鶩不自厭，仰首高飛愧鴻鵠。", "酒闌獨誦歸來章，醉面如頳背如沃。"]'),
('2794f555-4cf9-431e-a8c4-b4ff73b6d823','枕上聞櫓聲','李流謙','宋','宋诗','song-poetry','','[]','勸君不須下瞿唐，順流從此道路長。',64,'全唐诗/poet.song.125000.json','["勸君不須下瞿唐，順流從此道路長。", "勸君早上瞿唐去，遡流雖艱近家鄉。", "我今出蜀幾寒暑，催歸苦念家人語。", "更煩舟子策全功，疾趁鳴鷄起摇櫓。"]'),
('2985cf71-95f3-44b8-9e0b-6b1951eb4aef','晚步江滸有得黿大如箕贖放之鄰叟言此家前數日已嘗得一煮之通夕旦發盎視之黿忽引首以水噴其面茲亦可驚異者作是詩以爲好殺者之戒','李流謙','宋','宋诗','song-poetry','','[]','卷帆江臯日西斜，散步聊縱腰脚麻。',240,'全唐诗/poet.song.125000.json','["卷帆江臯日西斜，散步聊縱腰脚麻。", "有黿如箕誰所得，繩貫四足尚喘呀。", "偶然相值不忍去，倚杖却立空咨嗟。", "客囊雖云甚羞澀，數金何惜死可賒。", "破筐解縛置池上，初猶不動如磔蛙。", "舟人共觀各呼舞，稍稍有力能爬沙。", "須臾一躍不復覩，去侶蛟鱷朋魚蝦。", "隣翁又傳可愕事，宜誌簡牘懲凶邪。", "近嘗得一付湯鼎，通夕爛煮勞薪葭。", "黎明發盎欲下箸，以水噴面摇其牙。", "此言聽者驚自倒，小人不戒愚何加。", "我今贖放豈爲德，逡巡得脫汝幸耶。", "不須叩門問長史，無用染指嗔子家。", "祝黿好去勿浪出，水有網罟陸有罝。", "作詩快讀不能寐，展轉屢見燈生花。"]'),
('ce587f80-b87c-462b-9920-9e4dedfd1913','放魚','李流謙','宋','宋诗','song-poetry','','[]','溪媼雙魚入手中，鬐鬛不摇猶眼紅。',64,'全唐诗/poet.song.125000.json','["溪媼雙魚入手中，鬐鬛不摇猶眼紅。", "咫尺波濤即胡越，不忍觳𧥆人心同。", "小舟自放清江側，爲龍何以報我德。", "只須旱歲活焦枯，不用明珠光的皪。"]'),
('a937a329-4281-4159-85ed-dcfc8f91d4dc','遂寧登舟','李流謙','宋','宋诗','song-poetry','','[]','江流不知幾曲折，但見遠樹合復分。',64,'全唐诗/poet.song.125000.json','["江流不知幾曲折，但見遠樹合復分。", "上灘下灘櫓聲急，眠沙白鷗如不聞。", "山行畏遲舟欲速，試較里程翻詰曲。", "都緣歸計失平章，端恐青山笑人俗。"]'),
('9b8bfcf8-2132-4dd9-a5d2-696364bbd003','舟著淺','李流謙','宋','宋诗','song-poetry','','[]','御風起帆如彍矢，不能萬里猶千里。',64,'全唐诗/poet.song.125000.json','["御風起帆如彍矢，不能萬里猶千里。", "中流浪頭屋高起，誤入淺洲舟閣底。", "愚公不量欲移山，篙人伎窮客長嘆。", "世言卒行好步難，何如一棹夷猶間。"]'),
('f01998d2-f5b7-4788-9a96-8d1526887b7f','鄂渚大風','李流謙','宋','宋诗','song-poetry','','[]','萬艘相銜繫江渚，夜半疾風來莫禦。',64,'全唐诗/poet.song.125000.json','["萬艘相銜繫江渚，夜半疾風來莫禦。", "舟輕力孱費支拄，大聲舂撞如臼杵。", "千金應有覓壺人，冤呼倉黄那忍聞。", "吾顔死灰魚鼈喜，公無渡河公不止。"]'),
('dcf10c1d-0ab2-4bca-be3e-18f59075d4a9','訪楊少虞得小詩併呈才夫','李流謙','宋','宋诗','song-poetry','','[]','坐遭飛埃瞇雙目，不應更到琅玕腹。',64,'全唐诗/poet.song.125000.json','["坐遭飛埃瞇雙目，不應更到琅玕腹。", "青山爲人作禦侮，對面亭亭削蒼玉。", "公子翩翩故自佳，我來空嘆駒局促。", "抱冰嚼雪豈能清，火裏芙蕖初出浴。"]'),
('06841ae5-14ef-46e3-a646-fad58542cae1','舟中夜讀蟠舟詩','李流謙','宋','宋诗','song-poetry','','[]','夜讀蟠舟詩，如共蟠舟語。',60,'全唐诗/poet.song.125000.json','["夜讀蟠舟詩，如共蟠舟語。", "五年別淚隔秋風，萬里孤舟泊寒渚。", "行盡諸方勘盡禪，此句逢人未曾舉。", "東坡老人喜流涎，荔丹元似江瑶柱。"]'),
('6323c1da-9c92-4ea7-bdae-9d1da47ec031','雜言二首  其一','李流謙','宋','宋诗','song-poetry','','[]','春來無處無芳草，但覺故園春更好。',64,'全唐诗/poet.song.125000.json','["春來無處無芳草，但覺故園春更好。", "海棠前日夢見之，今日看來渾未老。", "櫻桃紅杏相因依，梅陰吐芽青滿枝。", "世間亦有如意事，酒熟正是花開時。"]'),
('4aaf0a23-75aa-45c1-a4a8-1f48a0e722c0','雜言二首  其二','李流謙','宋','宋诗','song-poetry','','[]','一萍無根託瀰渺，分頭常多聚常少。',64,'全唐诗/poet.song.125000.json','["一萍無根託瀰渺，分頭常多聚常少。", "天涯碧草又傷心，况是一分春已了。", "啼禽飛來窺酒樽，樽中綠波吹鱗鱗。", "東君可只令人瘦，更在花邊冷笑人。"]'),
('1da55539-a48e-4aa2-b5a2-37a1a4f02b27','十八日同少虞才夫子友子西泛舟','李流謙','宋','宋诗','song-poetry','','[]','清江不知日夜長，前日平流吹作浪。',128,'全唐诗/poet.song.125000.json','["清江不知日夜長，前日平流吹作浪。", "得得來尋白鳥盟，仍喚津人操兩槳。", "殘紅漸稀綠漸多，苦留不住如春何。", "細看恰有三十日，我醉起舞君當歌。", "紫微玉堂九天上，人非仙骨何由往。", "舟中俱是斬蛟人，洗眼待觀龍虎榜。", "夜歸錯落北斗橫，轉枕喔喔塒鷄鳴。", "一春常嗟睡不足，幸無官事莫相驚。"]'),
('e02b5fc4-acdf-480a-94f8-fa258d898d46','次德茂湖中韻','李流謙','宋','宋诗','song-poetry','','[]','秋風早已來吹人，朝數暮數唯歸程。',64,'全唐诗/poet.song.125000.json','["秋風早已來吹人，朝數暮數唯歸程。", "白湖粘天行未了，單舸夜泊令人驚。", "更闌剪燭共愁語，酒醒彈鋏爲商聲。", "篙兒飯飽便熟睡，那識懷家去國情。"]'),
('93066317-1aa0-4f85-b319-5b7d50fc26f6','次德茂菱花韻','李流謙','宋','宋诗','song-poetry','','[]','菱葉寒陂收曉鏡，蕭蕭獨伴黄蘆暝。',64,'全唐诗/poet.song.125000.json','["菱葉寒陂收曉鏡，蕭蕭獨伴黄蘆暝。", "自同香草入騷吟，不羨玉臺春壓鬢。", "三四鳬雛傍母眠，盡付與秋秋亦領。", "更看細雨出魚兒，江上老翁漁未竟。"]'),
('43ff9ea7-1acc-4274-9b91-8ac1f71f69ff','萬安道上逢牧者','李流謙','宋','宋诗','song-poetry','','[]','暖日平崗牛數尾，短蓑破笠三四子。',64,'全唐诗/poet.song.125000.json','["暖日平崗牛數尾，短蓑破笠三四子。", "牛饑吃草渴飲水，牧兒仰卧不摇箠。", "人牛意閒俱不知，笑我駐車獨移時。", "薄暮騎牛却歸去，晚烟遥見隔林炊。"]'),
('2530387e-d641-4d7b-a76e-a86507a027b3','登無爲冠鰲亭分韻得山字','李流謙','宋','宋诗','song-poetry','','[]','岱嵩拆裂滄溟翻，驚魂去幹呼復還。',368,'全唐诗/poet.song.125000.json','["岱嵩拆裂滄溟翻，驚魂去幹呼復還。", "故人勸我勉自寬，聖貴揚名懲毀殘。", "十生導師超物先，誓言一拜蠲冤煩。", "曉暾破霽山雲搴，匹馬弄袖風翩翩。", "解鞍投寺日幾磚，莧蔬宜我詩腸酸。", "危亭飛出峯之巔，闍黎慇懃勸躋攀。", "我飽聞之意欣然，兩脚酸澀怯不前。", "清景一失矢縱弦，藜杖到手勿作難。", "萬杉夾逕穿蜿蜒，坦如康莊駕輕軿。", "山鬼作意發天慳，似求清詩藻幽妍。", "憑欄寸目攝大千，萬里碧玉圍青天。", "遠樹如髮山如拳，孤鴻滅沒昏蒼烟。", "九關上羾須臾還，以氣爲馬不用鞭。", "冠鼇榜亭固寓言，亦恐蓬嶠神作遷。", "雲旗往往來飛仙，切勿投餌憂崩騫。", "壯哉古邑雄兩川，眇然下瞰廼爾孱。", "可憐居人蟻紛闐，擾擾膏火日夜煎。", "强弱角鬭觸與蠻，豈知共住一指端。", "憑誰與此曠蕩觀，定當泚顙頳厥顔。", "向來學道窺微玄，妙諦與世殊越燕。", "空生大覺海一涓，而况此境空所緣。", "摩尼流光照八埏，試將此理攻堅頑。", "客言有句子未參，一杯滿酌澆青山。"]'),
('a74d4f81-0b96-4422-bdb9-58398228e43c','同馮縉雲游無爲以吾獨胡爲在泥滓分韻賦詩得泥字','李流謙','宋','宋诗','song-poetry','','[]','人言躍馬妨杖藜，世士不可污丹梯。',360,'全唐诗/poet.song.125000.json','["人言躍馬妨杖藜，世士不可污丹梯。", "人言解牛非割雞，豈信截玉如截泥。", "山林朝士弧矢睽，一物異用鵠之栖，妄生濤瀾分畛畦。", "我自局狹誰排擠，先生大千一手提。", "使握鼎鉉如扶犁，豈於喧寂心生翳。", "朝驅兩輪鹿護麛，暮閲千紙髮變黳。", "痛者手摩攣者携，蚊虻膚撓夕夢迷。", "餒蛟仄目初生羝，血牙未洗遭燖刲。", "天公付公爲旱霓，作三日雨徵可稽。", "詰朝棧路沿澗溪，籃輿軋軋勞攀躋。", "束縛繡斧揮金鼙，吏奉杖屨從小奚。", "指點山水窮坤倪，夜談隠具窺緗綈。", "曠然冥蒙徹甕醯，轉變前境塵却犀。", "我自嘆駭失徑蹊，公如大像頭小低。", "嗟乎太倉此一稊，不從公來噬其臍。", "是山冠冕川東西，二大老文光璇題。", "公不一語意慘悽，是以稽首拜馬蹄。", "欣然傾倒珠玻璃，飛天寶焰照栱枅。", "夢中櫂唱驚鳧鷖，挽衣不留恨空齋。", "悲願苦切哀黔黎，早縛渾厥臣羌氐。", "快讀大頌崖天齊，把茅歸謝黄金閨。", "收拾伊傅從阮嵇，爲公再歌歸來兮。"]'),
('5fec2649-3f9f-4b6d-8424-7b395e16cf12','遊溫湯','李流謙','宋','宋诗','song-poetry','','[]','丹雛振翰栖佛屋，蛟吻吐泉供客浴。',64,'全唐诗/poet.song.125000.json','["丹雛振翰栖佛屋，蛟吻吐泉供客浴。", "東華夢破軟紅飛，不肯隨人到岩谷。", "扣欄投餌魚羣喜，一鱗圉圉獨去之。", "萬里歸來狎鷗鳥，青波如鏡鬢如絲。"]'),
('ecd28897-6f05-44fd-8e1a-322f6be0ecf6','七月十七日游浮山值夜未快所觀急歸作詩','李流謙','宋','宋诗','song-poetry','','[]','田疇渺渺平一望，側嶺橫峯環四向。',240,'全唐诗/poet.song.125000.json','["田疇渺渺平一望，側嶺橫峯環四向。", "那知中有此巉巖，倚天削鐵三千丈。", "坤靈湧出薦地寶，方嶠飛來憩靈仗。", "我來暑濕未解圍，薄日烘烘雲盎盎。", "投鞭濯手趨深殿，稽首虛皇注遐想。", "黄昏食罷亟就枕，殷地鼻雷飜疊嶂。", "夜深風雨來萬騎，勢欲拔山投莽蒼。", "明朝幽徑一丈泥，淺猶沒屨深沒杖。", "仙游咫尺邈霄漢，但倚危欄嘿惆悵。", "琳宮危絕何由上，祕洞幽深倦探訪。", "獨尋荒碣考歲月，更覓遺民問疇曩。", "雲舄朝飛溪漲深，玄猿夜答空山響。", "過門初欲快雄嚼，染指誰能當大饗。", "會求靈藥插羽翮，未分風帆隔崑閬。", "詩作監盟神所臨，後約有期吾敢爽。"]'),
('46f90cd4-ff80-4a21-a5e4-d056b6833839','寄張珍甫殿院  其一','李流謙','宋','宋诗','song-poetry','','[]','自是清華選，嘗懷宿昔期。',48,'全唐诗/poet.song.125000.json','["自是清華選，嘗懷宿昔期。", "高名推不去，異産買無貲。", "一日風雲遇，千年簡牘隨。", "岷峩添岌嶪，袖裏著安危。"]'),
('2a23cae7-2f86-4f35-b9d0-6df782087f72','寄張珍甫殿院  其二','李流謙','宋','宋诗','song-poetry','','[]','江湖淹遠使，崑閬侶飛仙。',48,'全唐诗/poet.song.125000.json','["江湖淹遠使，崑閬侶飛仙。", "豸首承恩渥，龍墀接邇聯。", "豺狼莫當道，鵰鶚不空拳。", "黯惷猶冠見，驕王易縮肩。"]'),
('babeeda5-147a-4637-8c99-07869fbfe78c','寄張珍甫殿院  其三','李流謙','宋','宋诗','song-poetry','','[]','已贍經時策，仍輕許國身。',48,'全唐诗/poet.song.125000.json','["已贍經時策，仍輕許國身。", "攘戎先政事，强本即精神。", "禹貢山川闊，堯天日月新。", "至誠馴暴逆，玉笏動嚴宸。"]'),
('cd6a3fd9-e11f-47d4-be1a-c91e80dfc03d','寄張珍甫殿院  其四','李流謙','宋','宋诗','song-poetry','','[]','只有肝嘗露，初無舌悔捫。',48,'全唐诗/poet.song.125000.json','["只有肝嘗露，初無舌悔捫。", "法行功罪竦，令重闕庭尊。", "盡變媮諛俗，仍關佞倖門。", "書生在蓬蓽，此事付能言。"]'),
('0e433918-3e0e-483f-b06a-c640b12a882b','寄張珍甫殿院  其五','李流謙','宋','宋诗','song-poetry','','[]','定勝端相屬，飛騫已後時。',48,'全唐诗/poet.song.125000.json','["定勝端相屬，飛騫已後時。", "閲人盤谷老，具眼石麟兒。", "連茹才非匹，彈冠想自癡。", "讀書頭半白，萬一故人知。"]'),
('7abc5d31-c7b7-49af-a581-aeadef06d7f5','宿船家小舟中凡三日夜作此','李流謙','宋','宋诗','song-poetry','','[]','自昔說離亂，經時足嘆吁。',48,'全唐诗/poet.song.125000.json','["自昔說離亂，經時足嘆吁。", "何爲來曠野，端是辱泥塗。", "相國跛男子，封侯裸丈夫。", "未須多感慨，事業出艱虞。"]'),
('1036cec8-ab76-4bb5-b276-7207d7240337','遣興七首  其一','李流謙','宋','宋诗','song-poetry','','[]','僻處便身懶，閒居喜歲豐。',48,'全唐诗/poet.song.125000.json','["僻處便身懶，閒居喜歲豐。", "蟲絲轉窗日，鳥語度溪風。", "疎竹斬新綠，晚花隨分紅。", "高人莫相訪，不比卧隆中。"]'),
('e9ea6595-7594-4d08-acc9-06b0efb764ce','遣興七首  其二','李流謙','宋','宋诗','song-poetry','','[]','柳老淵明宅，蓬深仲蔚居。',48,'全唐诗/poet.song.125000.json','["柳老淵明宅，蓬深仲蔚居。", "病身須藥石，閒日足圖書。", "世念焚香了，禪心隠几餘。", "空鈎本無意，誰爲語游魚。"]'),
('2b8d8b53-9f5a-4e91-a5bf-f96954a8f93b','遣興七首  其三','李流謙','宋','宋诗','song-poetry','','[]','懷抱向誰盡，窮交苦不多。',48,'全唐诗/poet.song.125000.json','["懷抱向誰盡，窮交苦不多。", "相期慰岑寂，未厭數經過。", "濁酒隨斟酌，新詩聽講磨。", "吾今已三十，不擬問如何。"]'),
('cf733fd1-8f50-45fc-93f8-eb80c5f21a7d','遣興七首  其四','李流謙','宋','宋诗','song-poetry','','[]','倦倚枯株坐，起尋微逕行。',48,'全唐诗/poet.song.125000.json','["倦倚枯株坐，起尋微逕行。", "魚爲鑿坏遁，蟬作採薇清。", "彈指四時足，閉關羣動平。", "盡言殊未可，日用本分明。"]'),
('448cf7e6-04e5-4770-a5bd-06cbd29b6cb0','遣興七首  其五','李流謙','宋','宋诗','song-poetry','','[]','水竹扶疎地，前人卜築勞。',48,'全唐诗/poet.song.125000.json','["水竹扶疎地，前人卜築勞。", "草荒煩僕豎，果熟戒兒曹。", "穴蟻生涯陋，冥鴻境界高。", "洗心觀萬物，至理寓秋毫。"]'),
('46896928-27a0-44aa-b705-9c189efb2d45','遣興七首  其六','李流謙','宋','宋诗','song-poetry','','[]','舞空三尺雪，笑指玉如泥。',48,'全唐诗/poet.song.125000.json','["舞空三尺雪，笑指玉如泥。", "早日羞屠狗，窮途悔射鼷。", "挂心無妄念，省分有幽栖。", "舌在何須問，端憂愧老妻。"]'),
('80528ff6-e865-4020-85f6-3f0b0d42155d','遣興七首  其七','李流謙','宋','宋诗','song-poetry','','[]','一飽便滿意，百年才轉頭。',48,'全唐诗/poet.song.125000.json','["一飽便滿意，百年才轉頭。", "可憐空不合，爲問亦何求。", "黄卷仍舒卷，清樽自勸酬。", "弔湘兒輩事，何地著閒愁。"]'),
('702bb029-bb0a-427d-95d4-eef032bf2c37','山中遣興五首  其一','李流謙','宋','宋诗','song-poetry','','[]','數月携家住，幽栖引興長。',48,'全唐诗/poet.song.125000.json','["數月携家住，幽栖引興長。", "客中容懶散，夢裏過炎凉。", "收網覺魚賤，酌泉知酒香。", "主人真好事，詩債數能償。"]'),
('3a053f81-96fa-4b3f-ad1e-4f2a07962e34','山中遣興五首  其二','李流謙','宋','宋诗','song-poetry','','[]','爛飲無賢聖，高歌有鬼神。',48,'全唐诗/poet.song.125000.json','["爛飲無賢聖，高歌有鬼神。", "梵書渾味著，藥裹自心親。", "朋友居山少，知聞到市新。", "孤舟怯風浪，不出又經旬。"]'),
('317ddd6c-e81d-480c-9042-76dc332d36ce','山中遣興五首  其三','李流謙','宋','宋诗','song-poetry','','[]','游宦初聊爾，歸來亦暢然。',48,'全唐诗/poet.song.125000.json','["游宦初聊爾，歸來亦暢然。", "低回簿領縛，慚愧斗升牽。", "元亮八十日，哥奴十九年。", "人生重名節，富貴疾雲烟。"]'),
('3d438822-b650-458b-a4e4-ab663a1ff90b','山中遣興五首  其四','李流謙','宋','宋诗','song-poetry','','[]','日薄愔愔熱，江渾漫漫流。',48,'全唐诗/poet.song.125000.json','["日薄愔愔熱，江渾漫漫流。", "蟬爲合尖響，燕作摻裾愁。", "棗熟成羣打，禾登掃地收。", "展眉欣一飽，八月又防秋。"]'),
('bad01eb4-5620-40ac-a1d6-b0e6cb50d37a','山中遣興五首  其五','李流謙','宋','宋诗','song-poetry','','[]','嗣聖承堯禹，圖書未見之。',48,'全唐诗/poet.song.125000.json','["嗣聖承堯禹，圖書未見之。", "兵威輕破竹，天意决占龜。", "燕雀甘藜莠，蛟龍或沼池。", "但令無戰伐，貧賤亦何辭。"]'),
('ed9a1480-fcf8-4203-a08d-076e03fb6759','遣興示彥博  其一','李流謙','宋','宋诗','song-poetry','','[]','信脚隨藤杖，穿林復過橋。',48,'全唐诗/poet.song.125000.json','["信脚隨藤杖，穿林復過橋。", "聊休讀書眼，小縱坐禪腰。", "老木成陰徧，枯泉赴汲遥。", "龍孫吾手種，先我到雲霄。"]'),
('863e1f16-95af-46ee-a67a-ebb53956ccd3','遣興示彥博  其二','李流謙','宋','宋诗','song-poetry','','[]','尊酒誰相勸，詩篇子可酬。',48,'全唐诗/poet.song.125000.json','["尊酒誰相勸，詩篇子可酬。", "臨流驚老大，倚杖笑窮愁。", "雨足鳩初歇，風狂蝶未休。", "化工專一氣，俛首聽沉浮。"]'),
('97a10aa9-5921-46f0-b283-0b8154f968f8','遣興示彥博  其三','李流謙','宋','宋诗','song-poetry','','[]','可人子陳子，乃祖定元龍。',48,'全唐诗/poet.song.125000.json','["可人子陳子，乃祖定元龍。", "一寸悠悠梗，千章落落松。", "暗投初未擇，狂吠竟誰容。", "堅壘自銜璧，饑師不足攻。"]'),
('41a72325-f55e-4f9a-a879-ee8695b2b020','雨後有月江上作','李流謙','宋','宋诗','song-poetry','','[]','雨止夜色靜，漲生江浪浮。',48,'全唐诗/poet.song.125000.json','["雨止夜色靜，漲生江浪浮。", "碧雲度星漢，明月照汀洲。", "倏忽陰晴異，蒼茫意緒秋。", "微吟不須苦，下有未眠鷗。"]'),
('44f4833f-ad6b-469b-ac18-c8899389e56f','游東山  其一','李流謙','宋','宋诗','song-poetry','','[]','軒自岧嶢稱，欄因杳靄橫。',48,'全唐诗/poet.song.125000.json','["軒自岧嶢稱，欄因杳靄橫。", "客魂摇鳥影，醉耳入江聲。", "失喜過門屐，沾衿越席箏。", "東山懷謝傅，憂樂總關情。"]'),
('d3fca147-c132-423e-8137-10cf37cbdcd9','游東山  其二','李流謙','宋','宋诗','song-poetry','','[]','今日如人意，全家在翠微。',48,'全唐诗/poet.song.125000.json','["今日如人意，全家在翠微。", "葉齊才蔽樹，雲近欲生衣。", "樽酒蒲桃綠，盤蔬赤莧肥。", "不須聞杜宇，作客自思歸。"]'),
('8c8122b2-a842-47e6-b374-d5a4f05ff614','送五八姪歸二江','李流謙','宋','宋诗','song-poetry','','[]','清霜入短褐，送汝酌深杯。',48,'全唐诗/poet.song.125000.json','["清霜入短褐，送汝酌深杯。", "萬事不如學，千金難買才。", "關心門戶重，過眼歲時催。", "莫待收燈後，驅車望早來。"]'),
('e66d644a-b4a0-404e-a17f-c5c7abacf173','上牛頭山','李流謙','宋','宋诗','song-poetry','','[]','馬首多經歷，牛頭到未嘗。',48,'全唐诗/poet.song.125000.json','["馬首多經歷，牛頭到未嘗。", "平川成岌嶪，諸剎寄微茫。", "像設尊千古，香燈走四方。", "來陪僧粥飯，此願幾時償。"]'),
('04aa23bf-6f38-43b0-b3d9-6d266f5207ae','次韻朱飾之中秋翫月因以送之','李流謙','宋','宋诗','song-poetry','','[]','君理朝宗楫，吾乘上峽船。',48,'全唐诗/poet.song.125000.json','["君理朝宗楫，吾乘上峽船。", "此盃同此地，明月又明年。", "怕作凌晨別，貪看徹曉圓。", "眉間有黄氣，知近冕旒邊。"]'),
('4308a480-55c4-4881-85b4-6a0d65b7dd60','送謝天奇赴淮上之招','李流謙','宋','宋诗','song-poetry','','[]','今日論形勝，全淮正上流。',48,'全唐诗/poet.song.125000.json','["今日論形勝，全淮正上流。", "老成資畢召，俊異集枚鄒。", "共說從軍樂，休歌出塞愁。", "鄉邦饒杞梓，君已拔其尤。"]'),
('c7314694-b27f-4ec4-a23e-6fc5490ab96e','送尹仲求臨邛戶掾','李流謙','宋','宋诗','song-poetry','','[]','何必崑峯遠，天球自粹溫。',48,'全唐诗/poet.song.125000.json','["何必崑峯遠，天球自粹溫。", "掾曹甘蠖屈，僚侶總鯨吞。", "子去成三友，公餘寄一樽。", "滄溟有餘瀝，猶幸及鴒原。"]'),
('ac9fb885-d488-4ca6-bb77-08ebcae355b0','次韻秋日書懷  其一','李流謙','宋','宋诗','song-poetry','','[]','官共冰雪冷，身如鷗鷺閒。',48,'全唐诗/poet.song.125000.json','["官共冰雪冷，身如鷗鷺閒。", "更無人問字，只有分看山。", "莫厭蕭條裏，全勝洶湧間。", "秋來笋成束，匕筯未須慳。"]'),
('c1751c76-8827-4c48-9ba5-e7ed00fc1a71','次韻秋日書懷  其二','李流謙','宋','宋诗','song-poetry','','[]','微風吹葉脫，落日卷簾初。',48,'全唐诗/poet.song.125000.json','["微風吹葉脫，落日卷簾初。", "蠻榼行提酒，胡床卧讀書。", "友朋元總好，氣味不應踈。", "有暇須乘興，溪中足鯉魚。"]'),
('232a7606-7fee-41e1-a6e2-22bca3d84959','平都山二首  其一','李流謙','宋','宋诗','song-poetry','','[]','慇懃雪色鹿，報我上空濛。',48,'全唐诗/poet.song.125000.json','["慇懃雪色鹿，報我上空濛。", "老鶴三山客，蒼松百歲翁。", "洞雲浮地出，池水與江通。", "仙榼無多酌，逡巡兩頰紅。"]'),
('9bbed637-bce8-40fa-91eb-c523c8f61ad2','平都山二首  其二','李流謙','宋','宋诗','song-poetry','','[]','福地何蕭爽，真祠自杳冥。',48,'全唐诗/poet.song.125000.json','["福地何蕭爽，真祠自杳冥。", "棟梁傳曩昔，草木带仙靈。", "霧市朝仍合，雲扉夜不扃。", "天風吹玉磬，應是誦黄庭。"]'),
('0a3f6e3e-c0b1-4c1a-8551-9832a06c729e','過新津游修覺山','李流謙','宋','宋诗','song-poetry','','[]','舊聞修覺寺，葦岸却維舟。',48,'全唐诗/poet.song.125000.json','["舊聞修覺寺，葦岸却維舟。", "句法雄千古，山形盡數州。", "野寬仍據會，江合却分流。", "畏暑猶如此，吾方事遠遊。"]'),
('c3bf4ca7-640f-484d-964d-2dae17beb0f4','送史唐英二首  其一','李流謙','宋','宋诗','song-poetry','','[]','藉甚聞名久，惠然從我游。',48,'全唐诗/poet.song.125000.json','["藉甚聞名久，惠然從我游。", "敢云國士遇，每向古人求。", "一第娛親爾，高懷可意不。", "咸韶亂蛙吹，期子繼蘇歐。"]'),
('2b8de18f-5165-4e76-9b6b-6162cae2ef91','送史唐英二首  其二','李流謙','宋','宋诗','song-poetry','','[]','陰崖隕天末，朝日上團團。',48,'全唐诗/poet.song.125000.json','["陰崖隕天末，朝日上團團。", "稍覺岷峩近，絕知湖海寬。", "舜門元自闢，蜀道未應難。", "富貴風花耳，相看在歲寒。"]'),
('bcfd4983-1578-43a3-9490-b00cfd66ad28','送王景文','李流謙','宋','宋诗','song-poetry','','[]','相送復相送，生憎風景殊。',48,'全唐诗/poet.song.125000.json','["相送復相送，生憎風景殊。", "還家疑是夢，涉世誤爲儒。", "愛惜千金璧，遲回一束芻。", "亦思江海去，書札寄潜夫。"]'),
('c7813e4b-5ce8-4f84-97f2-39bb8b4106b5','送楊道父二首  其一','李流謙','宋','宋诗','song-poetry','','[]','骨清殊矯矯，氣老自沉沉。',48,'全唐诗/poet.song.125000.json','["骨清殊矯矯，氣老自沉沉。", "門戶託君重，江湖入夢深。", "功名須少壯，歲月惜侵尋。", "萬里相隨去，庭闈一寸心。"]'),
('a1e2bf16-a084-4f62-a092-b2d73adedf6f','送楊道父二首  其二','李流謙','宋','宋诗','song-poetry','','[]','遂决乘桴計，初無判袂愁。',48,'全唐诗/poet.song.125000.json','["遂决乘桴計，初無判袂愁。", "清樽聊把手，弱纜已開頭。", "懿戚今元老，鄉邦子俊流。", "等閒垂一臂，談笑上瀛洲。"]'),
('8a5001a5-3b4c-4d24-a5ea-a2c12a7ac793','重陽前一日仲明見過留之以州會辭作此示之','李流謙','宋','宋诗','song-poetry','','[]','黄菊金錢小，紅萸錦紐香。',48,'全唐诗/poet.song.125000.json','["黄菊金錢小，紅萸錦紐香。", "滯留成久客，邂逅作重陽。", "勝友幾相值，清尊聊共嘗。", "吾宗慣城府，幽興負滄浪。"]'),
('351e8978-9746-41d9-82ca-b44572b4d9ed','允成載酒見過作此示之','李流謙','宋','宋诗','song-poetry','','[]','乘興初非約，相過不作難。',48,'全唐诗/poet.song.125000.json','["乘興初非約，相過不作難。", "酒寬隨量飲，花好盡情看。", "春已無多子，人誰有此歡。", "明朝各行役，塵土上征鞍。"]'),
('036501a9-4864-4771-bf5c-d21af04a8508','離合州驛晚宿茆城驛','李流謙','宋','宋诗','song-poetry','','[]','稍喜川原豁，遥看草樹明。',48,'全唐诗/poet.song.125000.json','["稍喜川原豁，遥看草樹明。", "惡灘猶夢怖，平地始身輕。", "場圃收遺秉，溝塍勸早耕。", "得歸萬事好，漂泊豈人情。"]'),
('bd7272fb-3975-4566-b2dd-941deb6ac544','寄送石鈞父二首  其一','李流謙','宋','宋诗','song-poetry','','[]','鳳麟元德産，閲世自深根。',48,'全唐诗/poet.song.125000.json','["鳳麟元德産，閲世自深根。", "士豈無公論，人宜有達尊。", "三山聊袖手，九折未驚魂。", "瓦礫看珠貝，先聲到塞垣。"]'),
('199e5952-3339-45c5-b7d0-b66ed9b63774','寄送石鈞父二首  其二','李流謙','宋','宋诗','song-poetry','','[]','再見非無分，相逢自昔緣。',48,'全唐诗/poet.song.125000.json','["再見非無分，相逢自昔緣。", "牛峯留滿歲，鶴嶠別經年。", "師友今尤惜，書題遠尚傳。", "蔡山連越巂，細認落鴻邊。"]'),
('4723eb73-1007-4cc2-ac37-e6390b9c10c5','送程叔虞監稅','李流謙','宋','宋诗','song-poetry','','[]','吾來真漫爾，識面喜周旋。',48,'全唐诗/poet.song.125000.json','["吾來真漫爾，識面喜周旋。", "兩月連牆住，孤帆別袂牽。", "人生同宇宙，官學各風烟。", "把酒知何日，臨流一惘然。"]'),
('b25e5d22-550e-4fee-b4d8-0a37cc1e1e7e','豐都驛呈任子厚詩二首  其一','李流謙','宋','宋诗','song-poetry','','[]','三家笑荒陋，十日寄蕭條。',48,'全唐诗/poet.song.125000.json','["三家笑荒陋，十日寄蕭條。", "破戶無人掩，寒爐折竹燒。", "青燈不廢卷，白酒未空瓢。", "伴我能於此，他年定久要。"]'),
('45f1232d-7e06-46e0-b604-fb3192384a41','豐都驛呈任子厚詩二首  其二','李流謙','宋','宋诗','song-poetry','','[]','書壞無全牘，衣濡有裂繒。',48,'全唐诗/poet.song.125000.json','["書壞無全牘，衣濡有裂繒。", "倦梳晨起髮，祗曲晝眠肱。", "客路行將了，家山喚得譍。", "焚香謝僊佛，宵夢已先憑。"]'),
('66f61d23-504b-4489-909a-b5e2536babaa','書事  其一','李流謙','宋','宋诗','song-poetry','','[]','飽飯將何適，携筇登翠微。',48,'全唐诗/poet.song.125000.json','["飽飯將何適，携筇登翠微。", "江長仍曲折，樹遠欲依稀。", "煮井未休汲，田家初掩扉。", "驚心崖路險，隔岸喚船歸。"]'),
('45eb7c1c-569c-4db0-9770-c71efe442c44','書事  其二','李流謙','宋','宋诗','song-poetry','','[]','唯有江郊好，能消畏日長。',48,'全唐诗/poet.song.125000.json','["唯有江郊好，能消畏日長。", "晚杯荷露重，午枕竹風凉。", "溪鷺閒無敵，庭萱恨易忘。", "翩翩孤蝶意，只是託幽香。"]'),
('60afd6b1-80d3-4348-a387-147c5153d7f0','書事  其三','李流謙','宋','宋诗','song-poetry','','[]','能閒無健羨，可飽即珍烹。',48,'全唐诗/poet.song.125000.json','["能閒無健羨，可飽即珍烹。", "成我耕桑計，欣兒課誦聲。", "橫戈真不武，歛袂亦難平。", "苦欲勞工宰，此生無我生。"]'),
('02887ddd-3998-48ac-84de-afb4d195049c','書事  其四','李流謙','宋','宋诗','song-poetry','','[]','塞色旌旗薄，邊聲皷角喧。',48,'全唐诗/poet.song.125000.json','["塞色旌旗薄，邊聲皷角喧。", "三軍正悲憤，中國固雄尊。", "障戍爭襟險，朝廷護本根。", "古來挾策者，談笑整乾坤。"]'),
('d72b2c60-9364-4c23-ad05-65b83ab32f8f','陸使君祠二首  其一','李流謙','宋','宋诗','song-poetry','','[]','山爲一案峙，水恰面前流。',48,'全唐诗/poet.song.125000.json','["山爲一案峙，水恰面前流。", "自是神靈宅，非從槁殻謀。", "風聲分井絡，雲氣接瀛邱。", "炯炯誰相領，焚香髮半秋。"]'),
('47c4b85c-af15-4798-864f-0100f22bd712','陸使君祠二首  其二','李流謙','宋','宋诗','song-poetry','','[]','梁初奄巴蜀，仍有渡瀘人。',48,'全唐诗/poet.song.125000.json','["梁初奄巴蜀，仍有渡瀘人。", "汲直餘蒸簡，蕭翁亦聚塵。", "傑魂猶念沛，遠夢不歸秦。", "幻化元超忽，何勞問大鈞。"]'),
('56c9ae5b-378d-44c2-9a95-a89802010409','出郊','李流謙','宋','宋诗','song-poetry','','[]','頗愛晚凉出，適當秋霽初。',48,'全唐诗/poet.song.125000.json','["頗愛晚凉出，適當秋霽初。", "豐年田父語，喬木野人廬。", "畦稻根根直，池荷葉葉疎。", "冷官無事業，歸舍了殘書。"]'),
('8047c8be-a2be-4dcd-904a-7abc11c2c305','晚泊','李流謙','宋','宋诗','song-poetry','','[]','薄霧初迷岸，微風早繫舟。',48,'全唐诗/poet.song.125000.json','["薄霧初迷岸，微風早繫舟。", "山青只欲遠，江闊不勝流。", "取酒深深酌，將詩緩緩謳。", "去家萬餘里，聊此散千憂。"]'),
('c68576aa-401b-46dc-abc2-dd65b7d22df1','送王伯董入總幕  其一','李流謙','宋','宋诗','song-poetry','','[]','几窗纏結習，翰墨錄殊勛。',48,'全唐诗/poet.song.125000.json','["几窗纏結習，翰墨錄殊勛。", "未入三山直，當空萬馬羣。", "俛眉聊綠水，展脚是青雲。", "五十頭如漆，功名不放君。"]'),
('acd16c94-4c66-4f03-8105-2a3b39bd616f','送王伯董入總幕  其二','李流謙','宋','宋诗','song-poetry','','[]','昔爲萬里別，歸送北征鴻。',48,'全唐诗/poet.song.125000.json','["昔爲萬里別，歸送北征鴻。", "近接何曾數，深期本自同。", "遠眸眵霧嶂，短箠滑霜風。", "更說無窮樂，懷中雙橘紅。"]'),
('4f6414e4-1f40-4ebc-9748-c0d17c7fa70e','送王景文入制幕二首  其一','李流謙','宋','宋诗','song-poetry','','[]','著眼分明見，論心委曲知。',48,'全唐诗/poet.song.125000.json','["著眼分明見，論心委曲知。", "負排閶闔氣，有泣鬼神詩。", "世故從料理，人材屬盛衰。", "浮雲多變化，寧憶路傍時。"]'),
('e1f8f50c-cb43-4d99-aae0-2de5299c764d','送王景文入制幕二首  其二','李流謙','宋','宋诗','song-poetry','','[]','繾綣聯名第，飄零共塞垣。',48,'全唐诗/poet.song.125000.json','["繾綣聯名第，飄零共塞垣。", "自知此事勝，更覺斯文尊。", "欲別言尤苦，相期意略存。", "成都萬事好，只合近清樽。"]'),
('51a59774-8dda-49c4-ab82-ba3aca7591fe','入峽聞灘聲','李流謙','宋','宋诗','song-poetry','','[]','山稠知峽近，今夜聽灘聲。',48,'全唐诗/poet.song.125000.json','["山稠知峽近，今夜聽灘聲。", "燈映舟人語，江空宿鳥驚。", "不眠共展轉，獨語記平生。", "自覺無多愧，微堪答父兄。"]'),
('2e54c31b-5261-459a-b563-0238ca36c474','懷李仲明  其一','李流謙','宋','宋诗','song-poetry','','[]','地曠空凝結，江清悅見聞。',48,'全唐诗/poet.song.125000.json','["地曠空凝結，江清悅見聞。", "娟娟初上月，漠漠未歸雲。", "魚樂能忘釣，鷗閒故念羣。", "桂旗風不度，却立詠湘君。"]'),
('28ae6fdf-a6fd-47fd-a45f-f55680ea94ac','懷李仲明  其二','李流謙','宋','宋诗','song-poetry','','[]','斜暉放船好，晚吹得凉多。',48,'全唐诗/poet.song.125000.json','["斜暉放船好，晚吹得凉多。", "星斗窺深酌，魚龍答浩歌。", "乾坤身半老，湖海意如何。", "夙昔紉蘭約，遲君肯重過。"]'),
('a15d48e4-35d6-41dd-b074-da6b22d377c7','謁無盡墓','李流謙','宋','宋诗','song-poetry','','[]','飛動少年意，如今推達尊。',48,'全唐诗/poet.song.125000.json','["飛動少年意，如今推達尊。", "何人窺畛域，投老見根源。", "草沒碑無字，林深木有孫。", "只須說廉藺，猶足褫諛魂。"]'),
('fe83425a-8c3a-40ca-951a-a93b71959e6f','五百羅漢洞','李流謙','宋','宋诗','song-poetry','','[]','五百雲霞侶，同胞生佛家。',48,'全唐诗/poet.song.125000.json','["五百雲霞侶，同胞生佛家。", "不貪三昧酒，共駕一乘車。", "猿餽霜餘果，僧烹粥後茶。", "我來無供養，唯讀妙蓮華。"]'),
('b832e6da-8e0b-48dc-8f6a-4415776b69c6','枕上','李流謙','宋','宋诗','song-poetry','','[]','欲問更長短，江村無鼓鼙。',48,'全唐诗/poet.song.125000.json','["欲問更長短，江村無鼓鼙。", "客懷如酒病，秋夜與年齊。", "被冷失孤蝶，霜清聞遠鷄。", "終年爲蕩子，尺紙愧山妻。"]'),
('2049918e-35b2-4bb6-ad48-b25f6b72ab58','射洪道中二首  其一','李流謙','宋','宋诗','song-poetry','','[]','曉色仍過雨，殘鈎不掛天。',48,'全唐诗/poet.song.125000.json','["曉色仍過雨，殘鈎不掛天。", "空霏漫野迥，浄綠浸江鮮。", "何自有靈鵲，誰言無杜鵑。", "倚風搔首意，窈窕若爲傳。"]'),
('bed11444-cdc2-4e6f-b462-71ccf92941f0','射洪道中二首  其二','李流謙','宋','宋诗','song-poetry','','[]','遠墟行藹藹，滯緒豁欣欣。',48,'全唐诗/poet.song.125000.json','["遠墟行藹藹，滯緒豁欣欣。", "挾翠山能潤，矜晴草自薰。", "墮鳶那及嘆，飛鷺可堪羣。", "欲共江流說，滔滔故不聞。"]'),
('390c7740-a42c-4c04-95c9-50a6daed523b','仲明兄弟訪別郊居','李流謙','宋','宋诗','song-poetry','','[]','眼遠孤帆沒，臨流一悵然。',48,'全唐诗/poet.song.125000.json','["眼遠孤帆沒，臨流一悵然。", "分携惜此日，作惡驗中年。", "惟有加餐祝，仍期得句傳。", "相看俱四十，香火好因緣。"]'),
('d6e8067d-a8eb-45a6-a31c-0941890fd731','次懷安骨肉自簡池來會','李流謙','宋','宋诗','song-poetry','','[]','來往金澗道，尋常不隔年。',48,'全唐诗/poet.song.125000.json','["來往金澗道，尋常不隔年。", "異方何契闊，渾舍此團圓。", "老子風埃甚，孫兒玉雪娟。", "妻孥勞行役，爭勸吸長川。"]'),
('98081a09-58f3-46e8-8b78-01edc7df9c96','吳波亭相對數峰極可愛','李流謙','宋','宋诗','song-poetry','','[]','吳波波上亭，一面列山屏。',48,'全唐诗/poet.song.125000.json','["吳波波上亭，一面列山屏。", "雨雨晴晴好，朝朝暮暮青。", "倦身無處著，醉眼爲渠醒。", "便欲携歸去，全勝腰萬釘。"]'),
('12b8f7ca-8b51-4adb-a4e3-d12c20bce226','寄彥博二首  其一','李流謙','宋','宋诗','song-poetry','','[]','聞道陳夫子，年來學更工。',48,'全唐诗/poet.song.125000.json','["聞道陳夫子，年來學更工。", "幾人曾著眼，聖處已收功。", "老驥思長路，潜鯤待疾風。", "何當問奇字，載酒過揚雄。"]'),
('c237c237-1d46-4901-8d5d-cf78aaf863ba','寄彥博二首  其二','李流謙','宋','宋诗','song-poetry','','[]','世途今若此，吾道竟何如。',48,'全唐诗/poet.song.125000.json','["世途今若此，吾道竟何如。", "學古疑無用，謀身忌太疎。", "引杯空慷慨，看鏡獨躊躇。", "千萬胸中語，因人略寄書。"]'),
('110dc178-3a69-41c8-86db-fe7c1093a117','七曲祠','李流謙','宋','宋诗','song-poetry','','[]','天生絕代英，夢想見儀形。',48,'全唐诗/poet.song.125000.json','["天生絕代英，夢想見儀形。", "桂殿風凝綠，苔宮雨護青。", "雲雷通翕忽，洞穴閟陰靈。", "只有丹心苦，聊將託杳冥。"]'),
('1c51124f-6f4b-4580-88e6-66b557a55726','夔子岸下水作頹沙裂岸轉舟避之','李流謙','宋','宋诗','song-poetry','','[]','狂流作平地，別渚轉輕橈。',48,'全唐诗/poet.song.125000.json','["狂流作平地，別渚轉輕橈。", "岸斷石出沒，雲虛山動摇。", "奔湍長澒洞，杯酒且逍遥。", "可待然犀照，潜鱗意自驕。"]'),
('f85d5361-c823-42ef-aff2-a10ba0c82a57','仲明留少城未還予將歸矣留詩別之','李流謙','宋','宋诗','song-poetry','','[]','判袂四十日，望君君不來。',48,'全唐诗/poet.song.125000.json','["判袂四十日，望君君不來。", "過門先問訊，立馬屢徘徊。", "正坐牽歸夢，無緣把別杯。", "鶴山果西去，會面更悠哉。"]'),
('b0ddce33-cffd-4776-be81-75d289526b10','別元質  其一','李流謙','宋','宋诗','song-poetry','','[]','鷗輕家泛泛，梗短路悠悠。',48,'全唐诗/poet.song.125000.json','["鷗輕家泛泛，梗短路悠悠。", "妙句能留客，澄江可散愁。", "長年資浩歎，秋色動商謳。", "故有先疇在，歸爲鴈鶩謀。"]'),
('2bcd2e1b-eb93-48be-9eb8-4bd22ec20414','別元質  其二','李流謙','宋','宋诗','song-poetry','','[]','遠夢燈頻照，羈懷酒重傾。',48,'全唐诗/poet.song.125000.json','["遠夢燈頻照，羈懷酒重傾。", "啼烏翻夕露，歸鴈占秋晴。", "此地豐魚稻，如君好弟兄。", "語離亦怊悵，松檟獨關情。"]'),
('cb8631a3-0085-4188-b5e1-4d3c50cdbdef','送錢太虛同年','李流謙','宋','宋诗','song-poetry','','[]','不隔同年面，真情本弟兄。',48,'全唐诗/poet.song.125000.json','["不隔同年面，真情本弟兄。", "人能純白備，交自始終成。", "測管才窺豹，傾江試吸鯨。", "吾言蓍蔡驗，决矣看飛鳴。"]'),
('6649bd73-0fac-4410-86d1-7cea0434e7b6','次趙惟直韻','李流謙','宋','宋诗','song-poetry','','[]','山合失空曠，江奔成溯洄。',48,'全唐诗/poet.song.125000.json','["山合失空曠，江奔成溯洄。", "陽臺鏁雲雨，楚澤貯風雷。", "白鳥背人去，青帘明眼來。", "舊醅寧得厭，聊共客中杯。"]'),
('6d6c3490-facc-4098-b63e-d13798b3eada','次韻仲秉見寄二首  其一','李流謙','宋','宋诗','song-poetry','','[]','別後年仍換，詩來語更工。',48,'全唐诗/poet.song.125000.json','["別後年仍換，詩來語更工。", "音書恨不數，魂夢却相通。", "草木春風後，關河夕照中。", "飛鴻不可倩，此意付筠筒。"]'),
('088177e3-47a5-4ee0-bcf7-4aa3cf097ef9','次韻仲秉見寄二首  其二','李流謙','宋','宋诗','song-poetry','','[]','讀書空有癖，學道苦無工。',48,'全唐诗/poet.song.125000.json','["讀書空有癖，學道苦無工。", "散策羣峯近，穿溪小逕通。", "此身猶客裏，野性合山中。", "春水添新浪，煩君理釣筒。"]'),
('78724b39-5886-4cd0-a14b-ed28e80b62d9','次仲甄韻二首  其一','李流謙','宋','宋诗','song-poetry','','[]','大用不堅壁，等閒憂患侵。',48,'全唐诗/poet.song.125000.json','["大用不堅壁，等閒憂患侵。", "平生知學道，萬事付無心。", "露莧鉏晨甲，烟篁步夕陰。", "陶然宇宙內，魚鳥聽浮沈。"]'),
('7d04425b-b109-4acd-9adc-c95d8de510e4','次仲甄韻二首  其二','李流謙','宋','宋诗','song-poetry','','[]','惻剝風枝恨，若爲開我顔。',48,'全唐诗/poet.song.125000.json','["惻剝風枝恨，若爲開我顔。", "索居詩社廢，多病酒杯慳。", "本自便三逕，何曾夢九關。", "臨溪問魚樂，知我是青山。"]'),
('bd219029-de90-47b2-83c3-920e27bd099f','益昌道中次兄長韻二首  其一','李流謙','宋','宋诗','song-poetry','','[]','聚頭閒日月，逐日信東西。',48,'全唐诗/poet.song.125000.json','["聚頭閒日月，逐日信東西。", "夜泊驚逢虎，晨餐倦乞醯。", "燈青千嶂夢，月白五更鷄。", "耐老前山路，長年送馬蹄。"]'),
('fd41b080-399d-4c52-b5e5-23b9d36ba76a','益昌道中次兄長韻二首  其二','李流謙','宋','宋诗','song-poetry','','[]','木杪著郵亭，山行未飽經。',48,'全唐诗/poet.song.125000.json','["木杪著郵亭，山行未飽經。", "已成身挈挈，恐失鬢青青。", "老樹霞烘幄，陰崖雪糝屏。", "冰霜先訓在，敢負舊趨庭。"]'),
('13071626-f2a1-45be-81c2-02fe098a6e93','投晁子止制置三首  其一','李流謙','宋','宋诗','song-poetry','','[]','讀書萬卷破，轉物一機神。',48,'全唐诗/poet.song.125000.json','["讀書萬卷破，轉物一機神。", "道德欣爲御，文章妙斲輪。", "聖賢同一處，天地要彌綸。", "汗簡窺千古，從來只數人。"]'),
('2b178063-bddd-40ea-858d-d7288f43eaf5','投晁子止制置三首  其二','李流謙','宋','宋诗','song-poetry','','[]','吳甸七千里，坤垠六十州。',48,'全唐诗/poet.song.125000.json','["吳甸七千里，坤垠六十州。", "宸心寬北闕，老子在西樓。", "召伯出分陝，衛公歸相周。", "衮衣人愜意，重爲雪山愁。"]'),
('96eaacad-9546-45af-a2b5-e82fb12643fb','投晁子止制置三首  其三','李流謙','宋','宋诗','song-poetry','','[]','西南雄節制，人物妙鑪錘。',48,'全唐诗/poet.song.125000.json','["西南雄節制，人物妙鑪錘。", "舐鼎非無意，登門獨恨遲。", "正期雲觸石，會見菌成芝。", "不信酬恩事，君看左顧時。"]'),
('f69aac55-f725-4e1d-a98c-9223259aca86','送查總卿三首  其一','李流謙','宋','宋诗','song-poetry','','[]','事業參亭毒，人才兆廢興。',48,'全唐诗/poet.song.125000.json','["事業參亭毒，人才兆廢興。", "百年爭鳳睹，一遇慨河澄。", "手到無盤錯，旁觀有級層。", "夜來春夢好，先已上觚稜。"]'),
('8cec789d-56f1-4b2b-96b7-67bddcad6dcd','送查總卿三首  其二','李流謙','宋','宋诗','song-poetry','','[]','御爐薰隔夜，清蹕響凌晨。',48,'全唐诗/poet.song.125000.json','["御爐薰隔夜，清蹕響凌晨。", "對罷天顔喜，朝回賜服新。", "自期宜棟幹，小却尚絲綸。", "此論由來久，周行萬搢紳。"]'),
('7dfba5dd-3fb8-48dc-94e2-36b63a310aac','送查總卿三首  其三','李流謙','宋','宋诗','song-poetry','','[]','臘雪千江浪，春風萬里船。',48,'全唐诗/poet.song.125000.json','["臘雪千江浪，春風萬里船。", "相依身健在，遠送意茫然。", "公近此三接，吾驚失一天。", "相君如辱問，願報已歸田。"]'),
('469df829-8d71-4eed-8cd8-53a655d2733a','夜坐呈王子友  其一','李流謙','宋','宋诗','song-poetry','','[]','無氈殊未覺，有興亦難忘。',48,'全唐诗/poet.song.125000.json','["無氈殊未覺，有興亦難忘。", "小雨寒微就，孤燈話儘長。", "疎凉湯煮豉，淡泊菜含霜。", "爲問王夫子，如何共肺腸。"]'),
('07ab5632-3861-4043-9078-95be19ca4b07','夜坐呈王子友  其二','李流謙','宋','宋诗','song-poetry','','[]','晴山見歷歷，遠水聽颼颼。',48,'全唐诗/poet.song.125000.json','["晴山見歷歷，遠水聽颼颼。", "宇宙不知大，關河空復愁。", "孤雲游子夢，滯穗野翁謳。", "我與鴉俱息，烟林晚共投。"]'),
('a13df4c4-42f5-41f1-8247-e4546f86be22','晚歸','李流謙','宋','宋诗','song-poetry','','[]','漁子艤舟待，山童負笈窺。',48,'全唐诗/poet.song.125000.json','["漁子艤舟待，山童負笈窺。", "數峯銜日盡，百丈逆灘遲。", "去住初隨意，夷猶獨誦詩。", "不妨歸更晚，正見月生時。"]'),
('d51413e9-fc15-46c8-ae24-d5391a11679f','宇文氏莊觀海棠時海棠未甚開而余旦夕歸矣賦此','李流謙','宋','宋诗','song-poetry','','[]','雨猛幾終夕，風狂遂徹朝。',48,'全唐诗/poet.song.125000.json','["雨猛幾終夕，風狂遂徹朝。", "眼緣春色醉，魂爲客愁消。", "澤國空留滯，山房恐寂寥。", "平蕪烟一望，鄉夢太迢遥。"]'),
('431e53ae-a7f1-4846-9b0b-abbc33a6686d','即事','李流謙','宋','宋诗','song-poetry','','[]','山路仍多雨，秋天最易陰。',48,'全唐诗/poet.song.125000.json','["山路仍多雨，秋天最易陰。", "呼舟亂灘響，倚杖俯溪潯。", "風力憑江橫，雲容隠樹深。", "一寒遽如許，料理欲歸心。"]'),
('ddaaac23-9b50-4b5a-be72-89ca9b6f3cba','錢氏隠居三首  其一','李流謙','宋','宋诗','song-poetry','','[]','高棲俛氛穢，華屋照滄浪。',48,'全唐诗/poet.song.125000.json','["高棲俛氛穢，華屋照滄浪。", "列岫带修竹，小池環海棠。", "晚盃魚蟹富，春筯蕨薇香。", "涉世真無意，吾今號漫郎。"]'),
('71a350c0-ebff-4a45-b184-7ebb000fe7de','錢氏隠居三首  其二','李流謙','宋','宋诗','song-poetry','','[]','野水瑩心碧，春山入骨清。',48,'全唐诗/poet.song.125000.json','["野水瑩心碧，春山入骨清。", "去穿雲際屐，來卧竹間亭。", "鳥語風嘲哲，花枝日杳冥。", "晚來江上笛，客裏不須聽。"]'),
('f5eb12eb-276a-4a76-ba88-f251b1833240','錢氏隠居三首  其三','李流謙','宋','宋诗','song-poetry','','[]','遠樹高低見，清溪曲折流。',48,'全唐诗/poet.song.125000.json','["遠樹高低見，清溪曲折流。", "草眠耕後犢，波泛狎餘鷗。", "醒醉無人管，登臨各自愁。", "扁舟大如葉，爛漫作春游。"]'),
('051d6d64-d371-4c78-a73c-6b52b378dd93','偶失一丹瓢戲書','李流謙','宋','宋诗','song-poetry','','[]','誰取一瓢去，虛勞九轉功。',48,'全唐诗/poet.song.125000.json','["誰取一瓢去，虛勞九轉功。", "徵杯驚羽化，開畫嘆幮空。", "已墮寧論甑，雖亡未失弓。", "人間閒得喪，盡付綠樽中。"]'),
('4d42c176-df90-4839-924f-5419198bfe96','次韻德茂待仲甄巨卿未至','李流謙','宋','宋诗','song-poetry','','[]','飄零一月住，日望北來船。',48,'全唐诗/poet.song.125000.json','["飄零一月住，日望北來船。", "眼冷傳書鯉，腸空吸露蟬。", "夢魂孤枕側，行李畏途邊。", "堅守蒲人信，嗟予苦未賢。"]'),
('c8e6bb49-0d3f-4795-afc1-b6f427acf950','抵家','李流謙','宋','宋诗','song-poetry','','[]','何地非吾土，故鄉情未忘。',48,'全唐诗/poet.song.125000.json','["何地非吾土，故鄉情未忘。", "掀眉對兄弟，酌酒話行藏。", "拜墓色不愧，逢人語更狂。", "梅花相待發，好在細思量。"]'),
('6180de01-211f-4120-ad8e-6bb0a8ec04d3','郭及之僉判招飲雅安同僚也','李流謙','宋','宋诗','song-poetry','','[]','江來從此合，我上爾東行。',48,'全唐诗/poet.song.125000.json','["江來從此合，我上爾東行。", "節物驚心地，主人留客情。", "霧花摇老眼，霜燭灧深觥。", "醉恐清歌斷，應須更數聲。"]'),
('848fc7ee-cedf-43ea-b2c0-e9864e5d26fd','送牟孔錫之官敘南二首  其一','李流謙','宋','宋诗','song-poetry','','[]','凌雲高鵠峙，擲地響金渾。',48,'全唐诗/poet.song.125000.json','["凌雲高鵠峙，擲地響金渾。", "蟾窟聲名早，鰲峯氣象尊。", "十年才一試，萬里正孤騫。", "勿說居夷陋，吾師有格言。"]'),
('90fa87fb-eba2-4259-aaf0-67873061d83c','送牟孔錫之官敘南二首  其二','李流謙','宋','宋诗','song-poetry','','[]','得朋宦游樂，不覺在山中。',48,'全唐诗/poet.song.125000.json','["得朋宦游樂，不覺在山中。", "慣住家鄉似，頻過骨肉同。", "憑欄但烟樹，振袂忽霜風。", "遠別無窮意，君歸我已東。"]'),
('606de574-1634-410e-8f5b-b7be834fc5ea','送李仁甫運判赴召三首  其一','李流謙','宋','宋诗','song-poetry','','[]','嵩岱國之鎮，鳳麟天所生。',48,'全唐诗/poet.song.125000.json','["嵩岱國之鎮，鳳麟天所生。", "有人占寶氣，無耳著修名。", "斯道自神聖，爾曹聊重輕。", "晉書定一付，一代聽權衡。"]'),
('76940062-78e4-4661-8a55-36552cf04a53','送李仁甫運判赴召三首  其二','李流謙','宋','宋诗','song-poetry','','[]','累歲徵賢詔，于今始一來。',48,'全唐诗/poet.song.125000.json','["累歲徵賢詔，于今始一來。", "已令人意滿，更著驛書催。", "白璧有成價，蛾眉無巧媒。", "經綸夙昔事，吾駕不須回。"]'),
('36943d21-efc7-4341-86a5-d07a5a1010fc','送李仁甫運判赴召三首  其三','李流謙','宋','宋诗','song-poetry','','[]','瞿塘六月浪，如馬亦安流。',48,'全唐诗/poet.song.125000.json','["瞿塘六月浪，如馬亦安流。", "舟楫魚龍喜，藜蒿虎豹憂。", "低回嗟薄宦，慷慨動商謳。", "門戶今如綫，非爲粱稻謀。"]'),
('8d535258-9f0c-4c32-8eed-87e49f911e58','江上晚眺書所見','李流謙','宋','宋诗','song-poetry','','[]','雲鎔金錯落，月挂玉盤盂。',48,'全唐诗/poet.song.125000.json','["雲鎔金錯落，月挂玉盤盂。", "水退岸全缺，烟陳山欲無。", "沙晴鷗併集，林暝鳥爭呼。", "不必求摩詰，分明是畫圖。"]'),
('f0cd2244-f43b-463e-bd6f-8ad440909283','舟中','李流謙','宋','宋诗','song-poetry','','[]','欲買一江碧，不知須幾錢。',48,'全唐诗/poet.song.125000.json','["欲買一江碧，不知須幾錢。", "舟輕故款款，酒好但涓涓。", "雲脚他州雨，波光別岸天。", "漁謳與樵唱，同和小山篇。"]'),
('eb60db6b-14d8-4b51-8c8a-ea83fbfa199c','小息','李流謙','宋','宋诗','song-poetry','','[]','倦征當日午，小息散腰頑。',48,'全唐诗/poet.song.125000.json','["倦征當日午，小息散腰頑。", "索酒初隨意，題詩自破顔。", "不須通姓字，聊欲賞江山。", "放蕩郊園樂，于茲稍稍還。"]'),
('e62339f1-daff-4e5b-b627-123b12cfe858','贈白道人','李流謙','宋','宋诗','song-poetry','','[]','天涯隻影隨，百結身上衣。',48,'全唐诗/poet.song.125000.json','["天涯隻影隨，百結身上衣。", "有術沒人買，無家何處歸。", "自言窮亦好，未與道相違。", "酌汝一盃酒，醒來萬事非。"]'),
('16080be2-a679-4ee6-95d2-88b3c3f89dce','贈藍元一道人','李流謙','宋','宋诗','song-poetry','','[]','我聞方外士，見面照人明。',48,'全唐诗/poet.song.125000.json','["我聞方外士，見面照人明。", "筆幻歲寒友，琴彈太古聲。", "侯門知遇重，真館笑談清。", "茗椀聊相對，清風兩腋生。"]'),
('11867828-b766-445e-bc7f-6e35e545be95','次韻宋德器春晚即事五首  其一','李流謙','宋','宋诗','song-poetry','','[]','室空超衆止，理妙契無同。',48,'全唐诗/poet.song.125000.json','["室空超衆止，理妙契無同。", "簾卷半規日，香吹一綫風。", "草晴唯欲碧，花晚尚能紅。", "老我閒居興，清應到小童。"]'),
('a539b076-d1cb-4f2e-a0ff-f8ab34d189de','次韻宋德器春晚即事五首  其二','李流謙','宋','宋诗','song-poetry','','[]','久習成衰怯，何方療闊疎。',48,'全唐诗/poet.song.125000.json','["久習成衰怯，何方療闊疎。", "柴車窮巷客，貝葉長年書。", "每愧沾沾喜，寧甘鬰鬰居。", "蓍神吾未暇，堅意聽盈虛。"]'),
('5f09bbba-83cd-47c7-aae0-16229d4630fd','次韻宋德器春晚即事五首  其三','李流謙','宋','宋诗','song-poetry','','[]','靈明觀自己，糾錯漫殊途。',48,'全唐诗/poet.song.125000.json','["靈明觀自己，糾錯漫殊途。", "睨柱誇完璧，探懷失繫珠。", "封侯真不願，作佛尚堪圖。", "解我無還語，根塵法本粗。"]'),
('80f999e4-c3bb-4041-8f9f-5bae0726f86f','次韻宋德器春晚即事五首  其四','李流謙','宋','宋诗','song-poetry','','[]','樓迥支筇久，庭閒轉榻頻。',48,'全唐诗/poet.song.125000.json','["樓迥支筇久，庭閒轉榻頻。", "松衰無直幹，竹好但新筠。", "漫仕慚逋客，躬耕羨野人。", "可能千里意，端的爲吳蓴。"]'),
('70b02dd4-273d-4874-bf94-7624008ec5db','次韻宋德器春晚即事五首  其五','李流謙','宋','宋诗','song-poetry','','[]','柳老陰陰密，榴繁灼灼明。',48,'全唐诗/poet.song.125000.json','["柳老陰陰密，榴繁灼灼明。", "持杯了醒醉，拊檻置枯榮。", "谷曠簫笙雜，江空鏡像呈。", "澄心著老眼，物物見真情。"]'),
('26017b13-5ac6-4e0f-8039-49001c7a3604','元質苦留過重陽且約泛舟觀泉二首  其一','李流謙','宋','宋诗','song-poetry','','[]','舟行十里遠，山出一泉清。',48,'全唐诗/poet.song.125000.json','["舟行十里遠，山出一泉清。", "爲景尋幾徧，將詩賭欲贏。", "江清渾玩著，酒好易支撐。", "半世無功業，狂歌任性情。"]'),
('d3720e76-8a05-4038-8e8e-e6caf708bceb','元質苦留過重陽且約泛舟觀泉二首  其二','李流謙','宋','宋诗','song-poetry','','[]','久客相看好，思歸得去不。',48,'全唐诗/poet.song.125000.json','["久客相看好，思歸得去不。", "深慚楚醴設，更作賈胡留。", "歲閏菊花早，霜清竹葉秋。", "尊前聞見在，不擬說閒愁。"]'),
('d8477a8f-671a-4945-bad8-08ad547c5ef2','早飯白崖鋪凈果院','李流謙','宋','宋诗','song-poetry','','[]','久客諳人事，身能到處安。',48,'全唐诗/poet.song.125000.json','["久客諳人事，身能到處安。", "爐深紅一聚，竹瘦碧千竿。", "祗作臨深恐，何辭行路難。", "幾成晚來雪，唯有不勝寒。"]'),
('56b49fb1-b1db-4410-8cc6-02f49d71a48c','用仲秉韻貽照老','李流謙','宋','宋诗','song-poetry','','[]','來問維摩疾，幽人有宿盟。',48,'全唐诗/poet.song.125000.json','["來問維摩疾，幽人有宿盟。", "浮漚非實性，鬭蟻是虛聲。", "廟冷香誰爇，城空賊自平。", "老師家裏事，無壞亦無成。"]'),
('bedea3f0-6510-4239-afae-98d0684a9272','贈照老','李流謙','宋','宋诗','song-poetry','','[]','舊矣聞名熟，欣然識面初。',48,'全唐诗/poet.song.125000.json','["舊矣聞名熟，欣然識面初。", "只求一轉語，不用五車書。", "出屋茶烟密，臨溪樹影疎。", "地偏吾所愛，庭草不須鋤。"]'),
('217abfc1-d9f3-476b-a7aa-be5309f1c152','照老用韻謝復作','李流謙','宋','宋诗','song-poetry','','[]','了了三生事，寥寥一念初。',48,'全唐诗/poet.song.125000.json','["了了三生事，寥寥一念初。", "未忘牛背約，端憶籠中書。", "塵劫空相隔，交情本不疎。", "焚香咨勝義，驕色已先鋤。"]'),
('eb0c884a-af39-4f7f-bba0-ec480207d04d','用前韻呈照老','李流謙','宋','宋诗','song-poetry','','[]','吏部稱文暢，愚溪進浩初。',48,'全唐诗/poet.song.125000.json','["吏部稱文暢，愚溪進浩初。", "深慚詆佛奏，更著廣交書。", "情契遠猶合，義乖隣亦疎。", "詫予無騃習，固自起犁鋤。"]'),
('de9e3d91-f101-474b-b7cf-29b97a6374ba','泛舟呈元質照老  其一','李流謙','宋','宋诗','song-poetry','','[]','扁舟載我去，身世兩悠然。',48,'全唐诗/poet.song.125000.json','["扁舟載我去，身世兩悠然。", "暝靄無窮樹，春江不盡天。", "阮嵇真酒伴，李郭即神仙。", "孤唱君須和，風流漢晉前。"]'),
('854c47bd-63ce-46c8-855d-6e5118a3de9a','泛舟呈元質照老  其二','李流謙','宋','宋诗','song-poetry','','[]','落日清江闊，臨流一慨然。',48,'全唐诗/poet.song.125000.json','["落日清江闊，臨流一慨然。", "斷鴻烟際渚，雌霓雨餘天。", "照海珠成市，騎鯨客是仙。", "輕風借帆力，送我玉妃前。"]'),
('6f5c9d63-9891-494f-96ed-8aac04c33667','僕盡半月之力僅得五詩而和仲落筆成十章俊哉予所甚畏也勉作二章答和仲三章述懷庶滿其數云  其一','李流謙','宋','宋诗','song-poetry','','[]','向來得祕藏，著意國風初。',48,'全唐诗/poet.song.125000.json','["向來得祕藏，著意國風初。", "一字嘔心出，十篇隨手書。", "天成新句熟，月煅古人疎。", "長鎩非君敵，區區恃棘鋤。"]'),
('f52a1be5-3b16-411c-ab4f-2fc7a85eafc9','僕盡半月之力僅得五詩而和仲落筆成十章俊哉予所甚畏也勉作二章答和仲三章述懷庶滿其數云  其二','李流謙','宋','宋诗','song-poetry','','[]','慷慨揮毫際，倉黄展卷初。',48,'全唐诗/poet.song.125000.json','["慷慨揮毫際，倉黄展卷初。", "少寬誅寇檄，已草納降書。", "恃勝防君失，輸籌笑我疎。", "班龍落誰手，芝草費人鋤。"]'),
('8547eebf-bb04-4837-9d76-9119522dbdd7','用韵答王子蒼','李流謙','宋','宋诗','song-poetry','','[]','聖道灰秦燎，殘編出漢初。',48,'全唐诗/poet.song.125000.json','["聖道灰秦燎，殘編出漢初。", "混茫千古意，破碎百家書。", "中鏑無多語，操戈亦太疎。", "升堂得玄解，伴子带經鋤。"]'),
('d1563373-72da-492f-8681-0ac070a34e0b','答李仲明仍用鋤字韻','李流謙','宋','宋诗','song-poetry','','[]','月白星稀後，歌殘雅奏初。',48,'全唐诗/poet.song.125000.json','["月白星稀後，歌殘雅奏初。", "剽聞先破膽，欲見疾開書。", "孔翠仙毛爛，珊瑚海樹疎。", "好詩如好畫，黑瘦未容鋤。"]'),
('b37c4bea-a733-42be-8dc5-f86a3a582113','李允成次彥博韻見示仍用韻答之三首  其一','李流謙','宋','宋诗','song-poetry','','[]','花氣濃熏塢，藤稍密蔭橋。',48,'全唐诗/poet.song.125000.json','["花氣濃熏塢，藤稍密蔭橋。", "但須樽有酒，未問印垂腰。", "芳草晚尤碧，好山晴更遥。", "太阿真寶劍，不必夜干霄。"]'),
('61da0fe9-41be-4fff-93e7-b496424c5f06','李允成次彥博韻見示仍用韻答之三首  其二','李流謙','宋','宋诗','song-poetry','','[]','吾家老仙伯，白璧半錢酬。',48,'全唐诗/poet.song.125000.json','["吾家老仙伯，白璧半錢酬。", "杖屨窮幽地，禽魚替客愁。", "可能百世出，閒却一生休。", "念舊須公等，年來嘆俗浮。"]'),
('cebcada9-ce9b-45ef-aee9-ca12873cf7ab','李允成次彥博韻見示仍用韻答之三首  其三','李流謙','宋','宋诗','song-poetry','','[]','俛眉聊卓魯，高步故夔龍。',48,'全唐诗/poet.song.125000.json','["俛眉聊卓魯，高步故夔龍。", "倦翮閒霜鶚，蒼稜老澗松。", "只應安小試，正自恥先容。", "泚筆書三異，他山玉可攻。"]'),
('a0924777-5693-4083-ac41-d9d6e2e3bcc0','以雙筆贈照老用前韻','李流謙','宋','宋诗','song-poetry','','[]','三窟驅除後，千毫束縛初。',48,'全唐诗/poet.song.125000.json','["三窟驅除後，千毫束縛初。", "得封才五等，進位合中書。", "炯炯銀鈎粲，翩翩薤葉疎。", "惡詩同遣贈，荒類要君鋤。"]'),
('03f25402-c734-403e-aa48-a2adb65b27b9','宿離相院','李流謙','宋','宋诗','song-poetry','','[]','客到蒼苔寺，僧鳴暝色鐘。',48,'全唐诗/poet.song.125000.json','["客到蒼苔寺，僧鳴暝色鐘。", "古檠挑焰澀，疎屋透霜濃。", "吾道元迂闊，中年雅倦慵。", "誰令背猿鶴，自酌不須攻。"]'),
('7ab8b6f0-6c6b-4aac-8b51-d40318268dfb','遊靈鷲院','李流謙','宋','宋诗','song-poetry','','[]','人說招提好，來游稱所聞。',48,'全唐诗/poet.song.125000.json','["人說招提好，來游稱所聞。", "雲烟四山合，草樹一溪分。", "瘦馬催歸晚，闍黎館客勤。", "荒墳有郎宿，夜夜粲天文。"]'),
('e701861b-a679-45d6-b53e-c96951dccb9c','游水東院  其一','李流謙','宋','宋诗','song-poetry','','[]','暝角傳風遠，昏帆到浦遲。',48,'全唐诗/poet.song.125000.json','["暝角傳風遠，昏帆到浦遲。", "草猶矜晚翠，麥正及春饑。", "客鴈無留意，殘雲有去思。", "濁醪不禁醉，聊藉晚風吹。"]'),
('faa94777-cf13-49df-863a-6986248d0208','游水東院  其二','李流謙','宋','宋诗','song-poetry','','[]','虛檻橫空闊，平郊入望賒。',48,'全唐诗/poet.song.125000.json','["虛檻橫空闊，平郊入望賒。", "樓臺萬家邑，桃李一川花。", "鷄犬非人世，樵漁亦相家。", "閒思十年事，倚杖獨咨嗟。"]'),
('4db14fb7-1c10-4282-b074-fb4bb62079eb','次黄仲甄峽中韻','李流謙','宋','宋诗','song-poetry','','[]','峽水清一線，峽山赭千層。',48,'全唐诗/poet.song.125000.json','["峽水清一線，峽山赭千層。", "禹力不到處，蜀靈用功深。", "蛟龍改窟穴，日暮聞微吟。", "遥想風雨夕，扁舟繫楓林。"]'),
('6b9082c9-0611-4428-af9e-0531d06e7704','石洞二首  其一','李流謙','宋','宋诗','song-poetry','','[]','春夢斷不記，春游誰與同。',48,'全唐诗/poet.song.125000.json','["春夢斷不記，春游誰與同。", "竹斜過午日，池皺晚來風。", "柳已都齊綠，桃猶約略紅。", "流鶑啼未了，又過短牆東。"]'),
('7e714a90-bbd3-41b1-a1ec-eab718b1763d','石洞二首  其二','李流謙','宋','宋诗','song-poetry','','[]','香霧團成蓋，茶花白勝酥。',48,'全唐诗/poet.song.125000.json','["香霧團成蓋，茶花白勝酥。", "對書閒境界，覓句靜工夫。", "客信因魚得，歸程約鴈俱。", "庭前海棠樹，尚及一看無。"]'),
('d5ab2873-0ce5-48f4-a7b8-a75e055976ab','送何子聞使君之行在','李流謙','宋','宋诗','song-poetry','','[]','繫舟鄰近渚，索酒共清斟。',48,'全唐诗/poet.song.125000.json','["繫舟鄰近渚，索酒共清斟。", "契闊十年事，飄零萬里心。", "大門元赫赫，要路正駸駸。", "去國吾何恨，看君上禁林。"]'),
('3d43fe3d-fb55-43c3-a676-c6bc68d741a0','挽費檢正  其一','李流謙','宋','宋诗','song-poetry','','[]','鈎深三古學，遇合百年機。',48,'全唐诗/poet.song.125000.json','["鈎深三古學，遇合百年機。", "垂上青雲去，仍完白璧歸。", "功名身易老，豪傑意多違。", "鼎臠留餘啖，蒸青有發揮。"]'),
('6e7a971c-685d-4a63-b2f4-38c7b6e13f97','挽費檢正  其二','李流謙','宋','宋诗','song-poetry','','[]','瑶墀隣近侍，華㦸老方州。',48,'全唐诗/poet.song.125000.json','["瑶墀隣近侍，華㦸老方州。", "閉閤人無訟，凝香歲自秋。", "凶衰乘鵩集，涕淚感麟休。", "古佛知公恨，涪江不盡流。"]'),
('a0ed8995-e193-4714-a341-c6cd0bd0f7ab','挽費檢正  其三','李流謙','宋','宋诗','song-poetry','','[]','憶作荆州客，多慚鮑叔知。',48,'全唐诗/poet.song.125000.json','["憶作荆州客，多慚鮑叔知。", "蒼黄懸榻地，慟絕盖棺時。", "映睫餘殘淚，親膚有近期。", "空山那得去，倚杖鬢如絲。"]'),
('c1b32ccd-2411-48b9-8042-2559b6148a36','挽張主簿  其一','李流謙','宋','宋诗','song-poetry','','[]','百里桑麻地，春風鼓舞中。',48,'全唐诗/poet.song.125000.json','["百里桑麻地，春風鼓舞中。", "隨軒一犁潤，折獄片言功。", "小試已無敵，晚成應不同。", "他年循吏傳，亦足慰途窮。"]'),
('15ba3549-fcda-46e9-a228-aad803b8aa20','挽張主簿  其二','李流謙','宋','宋诗','song-poetry','','[]','楚楚桐孫秀，願交慚不量。',48,'全唐诗/poet.song.125000.json','["楚楚桐孫秀，願交慚不量。", "新詩吾退舍，前輩子登堂。", "刮目鯨掀海，經年驥伏箱。", "斯言儻不驗，我欲罪穹蒼。"]'),
('a2920cc6-c1d2-4de7-ab6e-4cd1b801f5da','挽秦國夫人  其一','李流謙','宋','宋诗','song-poetry','','[]','鸞衿榮翠栝，璇魄媚方流。',48,'全唐诗/poet.song.125000.json','["鸞衿榮翠栝，璇魄媚方流。", "慶襲高華出，賢供窈窕求。", "靈光分婺照，靜質肖坤柔。", "閨闥關何事，風人美造周。"]'),
('9f4a3643-a49b-426d-a380-08011d9804c6','挽秦國夫人  其二','李流謙','宋','宋诗','song-poetry','','[]','賚說端由帝，生申未許崧。',48,'全唐诗/poet.song.125000.json','["賚說端由帝，生申未許崧。", "神功資鍊石，吉夢託占熊。", "赫赫扶天業，堂堂浴日忠。", "芝麟昭聖瑞，何力贊元工。"]'),
('26d96379-61e0-4285-8eb4-0948c323596a','挽秦國夫人  其三','李流謙','宋','宋诗','song-poetry','','[]','華笄諧淑配，綠髮負平生。',48,'全唐诗/poet.song.125000.json','["華笄諧淑配，綠髮負平生。", "桃李春如寄，鷗鷳夢不驚。", "周婺慚絕識，蜀寡讓孤情。", "口授天人學，寒窗伴短檠。"]'),
('5069db6a-9ae6-42b3-84e5-c88b84c28f14','挽秦國夫人  其四','李流謙','宋','宋诗','song-poetry','','[]','伴渙方興日，憂危未决前。',48,'全唐诗/poet.song.125000.json','["伴渙方興日，憂危未决前。", "僞書知莽詐，新歷斷周延。", "冰作羣疑泮，風從一語傳。", "龜靈無此識，上智炳機先。"]'),
('487985cd-d0ed-4b4a-b2cb-884dbe84d5d2','挽秦國夫人  其五','李流謙','宋','宋诗','song-poetry','','[]','露蓮秋沼瑩，霜月曉潭空。',48,'全唐诗/poet.song.125000.json','["露蓮秋沼瑩，霜月曉潭空。", "褕翟翻經外，塵泡隠几中。", "禪心安瘴嶠，結習謝雲櫳。", "五頌分明說，癡人耳自聾。"]'),
('b4f046a5-dfaf-4ede-9e05-780887da6db6','挽秦國夫人  其六','李流謙','宋','宋诗','song-poetry','','[]','久矣鴻飛渚，翩然鴈字峯。',48,'全唐诗/poet.song.125000.json','["久矣鴻飛渚，翩然鴈字峯。", "九重疏異渥，萬里合幽封。", "引柩烏銜壤，馴阡鹿護松。", "他時人下馬，有子是夔龍。"]'),
('4c711770-3220-454e-9fac-52f6f9576770','杜少陵祠','李流謙','宋','宋诗','song-poetry','','[]','赤紱銀章玉骨寒，焚香再拜淚汍瀾。',64,'全唐诗/poet.song.125000.json','["赤紱銀章玉骨寒，焚香再拜淚汍瀾。", "黄花郪縣仍羞見，好月鄜州只獨看。", "可是一生長客路，故應千古恨儒官。", "蚤知涉世元如此，悔不霜林斫釣竿。"]'),
('c0c8c018-7008-4752-95cc-d41eaf82436c','草堂','李流謙','宋','宋诗','song-poetry','','[]','浣花溪上得閒來，石刻摩挲病眼開。',64,'全唐诗/poet.song.125000.json','["浣花溪上得閒來，石刻摩挲病眼開。", "短策多時臨水立，紅塵半路與風回。", "乞靈伎薄裳爲带，驚世名言海納盃。", "相對只今真夢寐，數椽茅屋老蒼苔。"]'),
('f3b5e735-5969-4d2a-8b7c-be3d20fcc7d8','宿魏城驛用羅江東韻懷李仲明','李流謙','宋','宋诗','song-poetry','','[]','昔年漂泊記曾游，碧樹蟬聲又带秋。',64,'全唐诗/poet.song.125000.json','["昔年漂泊記曾游，碧樹蟬聲又带秋。", "滑滑泥行青嶂路，翩翩風倚夕陽樓。", "人誇馴雉碑猶在，書託文鱗水漫流。", "天遣此來相近傍，伴君牢落向邊州。"]'),
('c54dee14-8e63-46b2-9c38-a61b0d180dfe','題重興寺','李流謙','宋','宋诗','song-poetry','','[]','陌上橫流浸作泥，行人步穩方一移。',64,'全唐诗/poet.song.125000.json','["陌上橫流浸作泥，行人步穩方一移。", "春雲將雨遶山去，社燕營巢貼地飛。", "憩僕且須投古寺，閒懷猶喜論禪機。", "中宵瞥起胡床念，回首家山幾日歸。"]'),
('039b3492-ca33-4365-a64b-50847d6a6361','游龍角山福志院','李流謙','宋','宋诗','song-poetry','','[]','招提未到只聞名，乘興來游意最真。',64,'全唐诗/poet.song.125000.json','["招提未到只聞名，乘興來游意最真。", "出郭都無三十里，同行恰有兩三人。", "入門竹逕能明眼，隨處禪房可著身。", "莫怪山僧拙言語，十年已不踏紅塵。"]'),
('6abfc3a4-4aa6-4efa-b006-1e681c754706','忠州','李流謙','宋','宋诗','song-poetry','','[]','井邑雲根一聚村，尋詩來掃壁間塵。',64,'全唐诗/poet.song.125000.json','["井邑雲根一聚村，尋詩來掃壁間塵。", "此州惟有斷頭將，聖世初無棄梗人。", "楓葉晚林終日醉，梅花臘嶠幾時春。", "不愁過客當年淚，尊酒黄堂是舊隣。"]'),
('95d12cc2-ac7b-4b90-a17a-22ae36aac92c','自三池一日過靈池十五里頭宿山險盡矣','李流謙','宋','宋诗','song-poetry','','[]','壠頭停轡望龜城，元有夷途似掌平。',64,'全唐诗/poet.song.125000.json','["壠頭停轡望龜城，元有夷途似掌平。", "厭把五更供客夢，猛將一日了山程。", "樹連新綠千林暗，日轉斜紅半野明。", "稚子別來應念我，候門深喜馬蹄聲。"]'),
('fad03b48-47d5-4a66-84a0-b99c81b5b5a1','抵簡池呈元質進孺二首  其一','李流謙','宋','宋诗','song-poetry','','[]','持此迂愚漫浪身，忍慙一出竟何營。',64,'全唐诗/poet.song.125000.json','["持此迂愚漫浪身，忍慙一出竟何營。", "枕邊客意兼寒意，門外溪聲似雨聲。", "易辦蓬蒿三畝宅，可無藜莧一杯羹。", "青衫豈是官人樣，白鳥私憂說敗盟。"]'),
('2016c8af-9e75-4781-a270-05c54d931560','抵簡池呈元質進孺二首  其二','李流謙','宋','宋诗','song-poetry','','[]','竹生稚子鶴生雛，重到君家舊隠居。',64,'全唐诗/poet.song.125000.json','["竹生稚子鶴生雛，重到君家舊隠居。", "病後苦無多酌酒，別來唯有自鈔書。", "身方逐食從飄蕩，學久師心恐闊疎。", "慚愧故人相念意，欲行爲我少躊躇。"]'),
('8ae829d0-94dc-4e1b-a1d6-d3afbdd6a485','呈德茂','李流謙','宋','宋诗','song-poetry','','[]','秋入羈懷勞我思，愁兼歸夢到家遲。',64,'全唐诗/poet.song.125000.json','["秋入羈懷勞我思，愁兼歸夢到家遲。", "有人來得平安字，無事編成酬唱詩。", "相伴幾經江月照，同行更賞峽山奇。", "祗應便把州麾去，還有三年不見時。"]'),
('3e70a2a4-a6a5-4330-a4e0-0e5626478ab3','十月十五日同黄大博出城','李流謙','宋','宋诗','song-poetry','','[]','休沐來尋九里松，故因晴日覺春容。',64,'全唐诗/poet.song.125000.json','["休沐來尋九里松，故因晴日覺春容。", "寒餘淺水紅衣盡，淡抹輕烟紫翠重。", "倦向山僧談白葉，歸從逋客醉黄封。", "塵埃瞇目成深省，何處招提鳴曉鐘。"]'),
('5a5ce44e-e5e3-4cc6-9eb9-6325a3114c7a','送張仲山守唐安二首  其一','李流謙','宋','宋诗','song-poetry','','[]','六十專城髮未斑，更於何地覓三山。',64,'全唐诗/poet.song.125000.json','["六十專城髮未斑，更於何地覓三山。", "不妨談笑催科裏，正頼清凉熱惱間。", "到日紅梅留臘在，公餘翠杓酌春慳。", "胡床有月堪乘興，客到南樓不下關。"]'),
('c90e36c3-df47-4b19-b5d9-b7480f93d324','送張仲山守唐安二首  其二','李流謙','宋','宋诗','song-poetry','','[]','南浦波輕草色微，蹇馿遥路獨依依。',64,'全唐诗/poet.song.125000.json','["南浦波輕草色微，蹇馿遥路獨依依。", "暖風旌旆春隨去，細雨犁鉏麥正肥。", "驛騎蚤聞催迅召，邊屯猶未解重圍。", "謝家父子名江左，折屐行看破賊歸。"]'),
('8f96d968-72fd-41cb-8aef-0865e8e6d7cb','送崔子淵祕丞出守小益二首  其一','李流謙','宋','宋诗','song-poetry','','[]','寶峯山下識君初，豈但聲華在石渠。',64,'全唐诗/poet.song.125000.json','["寶峯山下識君初，豈但聲華在石渠。", "海上三山元咫尺，人生五馬少躊躇。", "鼎鍾事業那能免，丘壑情懷自覺疎。", "安得一帆相逐去，故園春雨長新蔬。"]'),
('cfd783eb-2ebf-4e8f-9204-b6fdc79cd74a','送崔子淵祕丞出守小益二首  其二','李流謙','宋','宋诗','song-poetry','','[]','晉公幕府總豪英，末至非才愧長卿。',64,'全唐诗/poet.song.125000.json','["晉公幕府總豪英，末至非才愧長卿。", "已去化爐金尚躍，更分客袂涕空橫。", "早催劍棧迎千騎，更借湖山勸一觥。", "水自嘉陵流到海，尺書應有故人情。"]'),
('28d7676d-d9f0-49c5-9156-b7a4257e3375','送孫賓老守三池二首  其一','李流謙','宋','宋诗','song-poetry','','[]','自藝心田歲自收，天翁兩眼月臨秋。',64,'全唐诗/poet.song.125000.json','["自藝心田歲自收，天翁兩眼月臨秋。", "近臣薦鶚方成表，吉夢逢刀遂得州。", "吏術無多非問馬，機心已盡不驚鷗。", "三溪便是桃源路，更欲武陵何處求。"]'),
('d4758d93-fedf-4a4e-8620-8273051b8de9','送孫賓老守三池二首  其二','李流謙','宋','宋诗','song-poetry','','[]','百萬貔貅尚枕戈，將軍未復舊山河。',64,'全唐诗/poet.song.125000.json','["百萬貔貅尚枕戈，將軍未復舊山河。", "非干使者徵求急，正柰窮邊餉輓何。", "頗願有言先牧養，不妨自署拙催科。", "公餘儻暇尋遺事，塵鎖荒祠望刮摩。"]'),
('8b60c62d-3c60-470f-ae83-3ac11b4120d2','送魏德源守普慈二首  其一','李流謙','宋','宋诗','song-poetry','','[]','一毫不露見全身，德覘徵符捷若神。',64,'全唐诗/poet.song.125000.json','["一毫不露見全身，德覘徵符捷若神。", "嵩岱自高元地勢，球琳非琢本天真。", "出山聊作無心潤，著物應名有脚春。", "喚作使君猶未解，豈知游戲兩朱輪。"]'),
('5dfedf71-7471-477b-8d22-17d77867bd81','送魏德源守普慈二首  其二','李流謙','宋','宋诗','song-poetry','','[]','東梓名州最普州，蟆頤相望氣橫秋。',64,'全唐诗/poet.song.125000.json','["東梓名州最普州，蟆頤相望氣橫秋。", "青衿胄子迎高朕，竹馬兒童識細侯。", "只有愛民心尚在，可能憂國淚空流。", "摩挲疲瘵無多事，綠野家家劍換牛。"]'),
('7a3aea68-5bc8-446c-9bd3-f317511adae1','送黄仲秉侍郎出守鎮江  其一','李流謙','宋','宋诗','song-poetry','','[]','十年朝露厭鳴珂，華髮蕭蕭奈倦何。',64,'全唐诗/poet.song.125000.json','["十年朝露厭鳴珂，華髮蕭蕭奈倦何。", "鸞翮九霄穿日月，龍驤萬斛飽風波。", "古人不見吾猶夢，直道能行恨亦多。", "駟馬錦衣兒輩事，只須持此答岷峨。"]'),
('1afe4e8d-b646-4ef3-9207-325c57774907','送黄仲秉侍郎出守鎮江  其二','李流謙','宋','宋诗','song-poetry','','[]','遥看北固海門秋，千騎東方占上頭。',64,'全唐诗/poet.song.125000.json','["遥看北固海門秋，千騎東方占上頭。", "去國尚多憂國淚，送君那免別君愁。", "風遲宴閣清香凝，月滿兜零晚穟收。", "北府名樽天下說，亦知能到故人不。"]'),
('4884faf3-656a-44d4-96ad-20255e49fc78','次黄仲甄峽中韻','李流謙','宋','宋诗','song-poetry','','[]','九江度盡惡風波，峽口窺天一握多。',64,'全唐诗/poet.song.125000.json','["九江度盡惡風波，峽口窺天一握多。", "亦愛吾廬覺歸好，數乘此險奈親何。", "響迎濤瀨將愁上，青惜峯巒等夢過。", "不管行人聽不得，暝猿和雨嘯雲蘿。"]'),
('97cfafee-8556-4e06-a962-6ade1346da2e','十月二十五日失舟','李流謙','宋','宋诗','song-poetry','','[]','船頭飽飯看揚舲，忽作翻漿不反瓶。',64,'全唐诗/poet.song.125000.json','["船頭飽飯看揚舲，忽作翻漿不反瓶。", "萬死一生真是幸，九江三峽未嘗經。", "尚收棄物乾坤大，薄恃陰功祖考靈。", "憂患偶來須理遣，可能爲汝更星星。"]'),
('c93e6572-8cc4-49b8-9e38-6e39091d0d83','泊采石二首  其一','李流謙','宋','宋诗','song-poetry','','[]','何時便有此山川，真宰懸知恐偶然。',64,'全唐诗/poet.song.125000.json','["何時便有此山川，真宰懸知恐偶然。", "唳鶴驚風前日事，落漚斜照晚來天。", "燬犀無用撩幽怪，洗醆先應酹謫僊。", "暝角吹殘吾欲老，五陵佳氣隔疎烟。"]'),
('dad312bd-207f-4c41-be19-aa703665cde3','泊采石二首  其二','李流謙','宋','宋诗','song-poetry','','[]','江頭楊柳淺於金，澤國餘寒春未深。',64,'全唐诗/poet.song.125000.json','["江頭楊柳淺於金，澤國餘寒春未深。", "才見桃花能慰眼，便同躑躅每傷心。", "瓊枝璧月自惆悵，山色潮聲無古今。", "閒訪闍黎倒戈地，正應漢德有謳吟。"]'),
('7a50f4c6-2818-4304-beae-420a82454cb9','舟中','李流謙','宋','宋诗','song-poetry','','[]','一舸乘凉載夕暉，晚來白汗稍停揮。',64,'全唐诗/poet.song.125000.json','["一舸乘凉載夕暉，晚來白汗稍停揮。", "近人初月當頭照，趁宿輕鷗直下飛。", "江國有天須恣買，岫雲無雨莫空歸。", "新秋漸到灘頭樹，先遣蓑童問釣磯。"]'),
('c79c5136-bec1-4823-a6fc-391b9ca04b36','月夜江上作','李流謙','宋','宋诗','song-poetry','','[]','月與清湍一樣流，不妨夜色尚淹留。',64,'全唐诗/poet.song.125000.json','["月與清湍一樣流，不妨夜色尚淹留。", "已將船作青天坐，安得江爲大白浮。", "恐有幽人釣寒渚，正須橫吹起危樓。", "年來身世無拘管，便是波間一葉舟。"]'),
('9510980a-67be-4e9f-919f-ca9be9936a04','水後過淮安金堂皆非舊路','李流謙','宋','宋诗','song-poetry','','[]','向來茅屋半驚湍，嘆息流亡久未還。',64,'全唐诗/poet.song.125000.json','["向來茅屋半驚湍，嘆息流亡久未還。", "已覺重行非故道，只應無恙是青山。", "旋藍偃嶽元常事，深谷爲陵亦等閒。", "衲被蒙頭都莫問，未當居士一分頑。"]'),
('fc07a911-31d2-4f71-abe2-49ccd8495353','焦山漢末焦光隠於此是日乃其生日土人會者甚衆','李流謙','宋','宋诗','song-poetry','','[]','桂樹蘭叢藹宿薰，楚辭一曲送迎神。',64,'全唐诗/poet.song.125000.json','["桂樹蘭叢藹宿薰，楚辭一曲送迎神。", "豈聞鈎黨能留漢，故有桃源可避秦。", "欲記曾來終草草，多慙浪走祇踆踆。", "却尋揚子江頭路，依舊楊花愁殺人。"]'),
('eeb6ccd5-720a-4a00-8def-b780c56a812a','連日陰雨未及一到金焦二山病中得梁文佳句枕上吟哦不能自已復次韻','李流謙','宋','宋诗','song-poetry','','[]','雲滿長空雨漲沙，金焦一望去非賒。',64,'全唐诗/poet.song.125000.json','["雲滿長空雨漲沙，金焦一望去非賒。", "擬拋塵網尋僧舍，更著烟蓑訪釣家。", "北固江山仍壯麗，南徐風物尚繁華。", "只愁病客難登檻，且待金烏出海涯。"]'),
('d49f173c-1b78-4492-b137-b5e55437af30','再遊蔣山  其一','李流謙','宋','宋诗','song-poetry','','[]','繫馬松門竟日留，一燈深殿炯清幽。',64,'全唐诗/poet.song.125000.json','["繫馬松門竟日留，一燈深殿炯清幽。", "杖頭猶識齊梁讖，屐齒曾經王謝游。", "瑟瑟新毛吃老樹，娟娟瞇目破紅榴。", "風鈴塔上知何語，應使行人估客愁。"]'),
('66f2560a-2c70-4616-b0a4-d1eaacf1c70e','再遊蔣山  其二','李流謙','宋','宋诗','song-poetry','','[]','江南春晚見芳菲，雪白梨花照客衣。',64,'全唐诗/poet.song.125000.json','["江南春晚見芳菲，雪白梨花照客衣。", "步步來求諸佛記，塵塵全現祖師機。", "不禁戰伐山河老，猶說經綸俎豆非。", "共飲名園那惜醉，落紅故故傍愁飛。"]'),
('a7a4af62-b38b-4ac3-84a8-e709411a442d','久留蕪湖待巨卿仲甄不至','李流謙','宋','宋诗','song-poetry','','[]','吳波晴浸夕陽紅，一語丁寧北去鴻。',64,'全唐诗/poet.song.125000.json','["吳波晴浸夕陽紅，一語丁寧北去鴻。", "頗覺淹留添髮白，不妨羞澀剩囊空。", "枕頭靠睡禁長日，舸背占旗惜便風。", "想得家山俱在夢，亦應煩悶略相同。"]'),
('82caebbd-59f5-4800-86c0-52f1faaa7f04','蕪湖晚步','李流謙','宋','宋诗','song-poetry','','[]','迥陂積水長蒲蔣，散步郊原借夕涼。',64,'全唐诗/poet.song.125000.json','["迥陂積水長蒲蔣，散步郊原借夕涼。", "塵袖風巾嗟久旅，稻畦柘逕似吾鄉。", "蛙聲月色當空曠，爨火人家在莽蒼。", "望合碧雲人未至，滯留愧客問行藏。"]'),
('388b0daf-edab-495b-b298-69620cf16e61','遊長蘆','李流謙','宋','宋诗','song-poetry','','[]','他年天眼識褕褘，千柱如今鏁夕暉。',64,'全唐诗/poet.song.125000.json','["他年天眼識褕褘，千柱如今鏁夕暉。", "笑說老禪操一葦，戲呼靈媼授三歸。", "波濤嚙岸蛟龍惡，荻竹抽萌鱠縷肥。", "曲水流觴記今日，晚風直欲透人衣。"]'),
('beb2f7da-a854-4c61-9427-8cf62c9d2746','金陵二首  其一','李流謙','宋','宋诗','song-poetry','','[]','龍蟠虎踞帝王州，屢歎降旗出石頭。',64,'全唐诗/poet.song.125000.json','["龍蟠虎踞帝王州，屢歎降旗出石頭。", "不惜家居撞壞了，可因歌舞破除休。", "露桃滴滴啼宮井，風柳條條絆客舟。", "春水一江流未盡，不禁更問幾多愁。"]'),
('ac5b936d-b718-4132-8d06-6e1f65f6be8a','金陵二首  其二','李流謙','宋','宋诗','song-poetry','','[]','江城疊鼓晚停撾，游子翩翩念歲華。',64,'全唐诗/poet.song.125000.json','["江城疊鼓晚停撾，游子翩翩念歲華。", "水底乾坤浮日夜，沙邊鷗鷺老烟霞。", "漁人能說陳隋事，燕子猶尋王謝家。", "南北自分仍自合，不應全殢後庭花。"]'),
('a746741b-4ae4-482d-99ec-8f603fd784c6','午飯高橋院','李流謙','宋','宋诗','song-poetry','','[]','招提下馬憩逡巡，野飯親烹澗底芹。',64,'全唐诗/poet.song.125000.json','["招提下馬憩逡巡，野飯親烹澗底芹。", "二月韶華聽啼鳥，百年心事信行雲。", "不禁烈日花光薄，更抹微烟草色薰。", "老衲未知風木恨，向人猶說故將軍。"]'),
('2d5410ce-e40c-469b-9e62-03a8e0cbc8bf','游虎丘次仲甄韻','李流謙','宋','宋诗','song-poetry','','[]','逢山到處爲遲留，行到東南第幾州。',64,'全唐诗/poet.song.125000.json','["逢山到處爲遲留，行到東南第幾州。", "終古香燈憑像教，可人軒戶稱山丘。", "苔封鐵色千尋壁，日麗雲章百尺樓。", "脚底全吳何足小，待將八極恣浮游。"]'),
('1f691352-3717-497d-8cdc-d1e2b6f172a8','人日同諸公自馬谿登道宿無爲','李流謙','宋','宋诗','song-poetry','','[]','塵埃瞇目浸填胸，日日青山在夢中。',64,'全唐诗/poet.song.125000.json','["塵埃瞇目浸填胸，日日青山在夢中。", "改歲人家無一事，並游文社有諸公。", "招提夜語驚山鬼，野店春沽醉病翁。", "綠塢紅村誰境界，自憑好句占東風。"]'),
('fcc1ce37-ff89-4aac-8e31-9595cfcda0cb','次韻彥博游無爲馬谿併呈孫隆州','李流謙','宋','宋诗','song-poetry','','[]','塊處無人語合頭，出門猝猝又還休。',64,'全唐诗/poet.song.125000.json','["塊處無人語合頭，出門猝猝又還休。", "縛茅晚歲欣同社，並轡名峯得勝游。", "松下一筇真可老，山中五月已如秋。", "未應斗粟全關念，更爲先生幾日留。"]'),
('87a42a34-6c20-4047-a409-fe8f3d1fe656','又次韻彥博游無爲寺二首  其一','李流謙','宋','宋诗','song-poetry','','[]','靈蛻巋然謝垢埃，焚香却立嘆奇哉。',64,'全唐诗/poet.song.125000.json','["靈蛻巋然謝垢埃，焚香却立嘆奇哉。", "自從新歲門常掩，不見青山眼懶開。", "飛觀千楹孤鳥墮，齋盂萬指曉鯨催。", "亦知空劫已前事，浪說十生曾去來。"]'),
('f684dad4-e1cc-44bb-87af-99d7ac70c6a0','又次韻彥博游無爲寺二首  其二','李流謙','宋','宋诗','song-poetry','','[]','東風力弱未揚埃，密泛叢蘭有意哉。',64,'全唐诗/poet.song.125000.json','["東風力弱未揚埃，密泛叢蘭有意哉。", "可是伸眉須酒滿，只應彈指又花開。", "吹毛句妙無人領，擊鉢詩工著底催。", "照水只愁羞冕紱，勳名蓋世亦時來。"]'),
('dcadf001-9ee2-4d9d-8340-bddbe236a7c1','游長松聞捷音','李流謙','宋','宋诗','song-poetry','','[]','十里登山訪定身，衣邊猶带簿書塵。',64,'全唐诗/poet.song.125000.json','["十里登山訪定身，衣邊猶带簿書塵。", "僧厨筍蕨隨齋鉢，禪窟香燈話宿因。", "便可扶犁老岷蜀，已聞傳檄定咸秦。", "家家釵釧何須惜，難買堯眉一笑春。"]'),
('af0629c5-2ac3-40a1-82fd-6b0829db021a','次韻何子聞安靜觀  其一','李流謙','宋','宋诗','song-poetry','','[]','翩然逸想九霞間，仍是霓衣與鹿冠。',64,'全唐诗/poet.song.125000.json','["翩然逸想九霞間，仍是霓衣與鹿冠。", "塵劫三山元自近，神官一字固應難。", "雲烟萬瓦虹榱壯，冰雪千幢鵠輦寒。", "堪笑木强韓吏部，如何容易撮靈丹。"]'),
('14e16121-9c57-457c-a515-db2c23931497','次韻何子聞安靜觀  其二','李流謙','宋','宋诗','song-poetry','','[]','日壓茅簷醉擁蓑，靜聽寒溜奏雲和。',64,'全唐诗/poet.song.125000.json','["日壓茅簷醉擁蓑，靜聽寒溜奏雲和。", "深藏本自身全露，瞪眎元知語不多。", "紫府地嚴須一到，蒼崖文古要重磨。", "新宮固是叢霄樣，應有胎禽憶舊柯。"]'),
('cefce3c0-6ff7-453a-80ea-6d862de5e251','郊行至天王院','李流謙','宋','宋诗','song-poetry','','[]','郊行不欲經城市，厭見塵沙漠漠黄。',64,'全唐诗/poet.song.125000.json','["郊行不欲經城市，厭見塵沙漠漠黄。", "響樹蜩螗憑晚吹，遶陂鳬鶩占殘陽。", "青山與世久相絕，修竹於人未易忘。", "下馬招提揖僧話，始知塵境有仙鄉。"]'),
('a4ef86c4-bc27-4209-b4a1-b196c271ca0a','挽張雅州  其一','李流謙','宋','宋诗','song-poetry','','[]','酣飽風烟德有芽，從來三㦸是張家。',64,'全唐诗/poet.song.125000.json','["酣飽風烟德有芽，從來三㦸是張家。", "翩翩羣從同時貴，落落高門一世華。", "人自不欺寧用忍，身如可贖但空嗟。", "路人泣指飛丹旐，猶憶雙旌卷暝霞。"]'),
('b1fc0e63-4876-4505-bc0c-ddc6af0a38f8','挽張雅州  其二','李流謙','宋','宋诗','song-poetry','','[]','三年流落塞垣春，雪屋冰廬樂藻芹。',64,'全唐诗/poet.song.125000.json','["三年流落塞垣春，雪屋冰廬樂藻芹。", "司業頗知憐鄭老，薛宣能不吏朱雲。", "鶚牋重剡新如昨，蟻壤高眠喚不聞。", "一掬壠頭知己泪，霜風吹墮白楊墳。"]'),
('f121c1a3-7c23-4733-9f10-c36bb30b0e52','自少城解職事還邑二首  其一','李流謙','宋','宋诗','song-poetry','','[]','塵埃一出竟何爲，白竹依然晝掩扉。',64,'全唐诗/poet.song.125000.json','["塵埃一出竟何爲，白竹依然晝掩扉。", "只應爲客重爲客，便欲得歸寧得歸。", "獨鶴靜臨寒沼立，遊蜂閒趁落花飛。", "東君老大人消瘦，憑仗清樽一解圍。"]'),
('09ca1f40-c4a1-4697-9104-04c115c14fb3','自少城解職事還邑二首  其二','李流謙','宋','宋诗','song-poetry','','[]','胡床卯飲带餘酲，身世如天行白雲。',64,'全唐诗/poet.song.125000.json','["胡床卯飲带餘酲，身世如天行白雲。", "竹簡讀殘聊一嘆，水沉燒盡更三薰。", "癡心久絕臨淵羨，老手唯便植杖芸。", "自有此生須自斷，豈能曲折問靈氛。"]'),
('7599612c-93ba-476d-819b-cf74021246a6','送劉元圭','李流謙','宋','宋诗','song-poetry','','[]','犯寒過我喜仍驚，節物崢嶸更遠程。',64,'全唐诗/poet.song.125000.json','["犯寒過我喜仍驚，節物崢嶸更遠程。", "劇飲投車輕十日，細談剪燭易三更。", "故人高義千鈞重，久客歸心一夜生。", "爲語溪翁好相念，時將蓑笠曬春晴。"]'),
('e7150d6e-72ea-4edf-bb35-9c5a23c63310','弔無爲照老三首  其一','李流謙','宋','宋诗','song-poetry','','[]','彈指超然一念初，從儒從佛兩蘧廬。',64,'全唐诗/poet.song.125000.json','["彈指超然一念初，從儒從佛兩蘧廬。", "十年身走半天下，萬卷人稱行祕書。", "故自高懷嫌入俗，不妨兒輩共憎渠。", "臨行半偈如何道，裂轉虛空最起予。"]'),
('0d3b632c-edc4-4d5a-b93c-d8b1b4e8001d','弔無爲照老三首  其二','李流謙','宋','宋诗','song-poetry','','[]','記得三溪溪上春，瘦筇容我夜敲門。',64,'全唐诗/poet.song.125000.json','["記得三溪溪上春，瘦筇容我夜敲門。", "一生幾見此人物，十日九從師笑言。", "閒得得來非有意，冷湫湫去若爲論。", "西山第一烟雲窟，好駐高人雪月魂。"]'),
('eb260ff8-4661-44f4-868b-7c6678613a68','弔無爲照老三首  其三','李流謙','宋','宋诗','song-poetry','','[]','六尺巖巖鐵石姿，可憐一病不支持。',64,'全唐诗/poet.song.125000.json','["六尺巖巖鐵石姿，可憐一病不支持。", "荒榛半壠獨歸處，暝靄數峯無見時。", "未割塵緣聊洒涕，欲尋陳迹但哦詩。", "蕭蕭秋雨山中夜，負我他年對榻期。"]'),
('5580a805-68cf-4920-bcab-5c0c5463f2c8','和葉六舅','李流謙','宋','宋诗','song-poetry','','[]','李杜主盟詩有聲，文推韓柳著章程。',64,'全唐诗/poet.song.125000.json','["李杜主盟詩有聲，文推韓柳著章程。", "二三子者皆人傑，五百年來並世生。", "但見詞源倒三峽，豈知武庫足千兵。", "勉君須把分陰惜，莫問紅塵雨共晴。"]'),
('58822da3-4475-41aa-a909-a79d1d2a3e20','費文達除夔漕作此賀之三首  其一','李流謙','宋','宋诗','song-poetry','','[]','分明餘潤徹眉間，道德根源固曄然。',64,'全唐诗/poet.song.125000.json','["分明餘潤徹眉間，道德根源固曄然。", "寶篆印泥初不著，神機貫札自無前。", "絲綸新渥榮三晝，鼎鉉深知眇一涓。", "兩禁只今誰妙手，岷峨人物半吳天。"]'),
('4a9b9647-4307-45ba-88a0-c09299d5afd6','費文達除夔漕作此賀之三首  其二','李流謙','宋','宋诗','song-poetry','','[]','吉音一紙疾郵傳，白帝城頭勸著鞭。',64,'全唐诗/poet.song.125000.json','["吉音一紙疾郵傳，白帝城頭勸著鞭。", "楚樹已沾新雨露，蜀江行換好風烟。", "政須急拯溝中瘠，不用多流地上錢。", "一節故應關象緯，向來兩使動星躔。"]'),
('156b4644-43d4-4e35-a7c8-f18bc7083d41','費文達除夔漕作此賀之三首  其三','李流謙','宋','宋诗','song-poetry','','[]','刻鵠工夫愧不量，弓裘遺緒可能忘。',64,'全唐诗/poet.song.125000.json','["刻鵠工夫愧不量，弓裘遺緒可能忘。", "一廛未遂耕桑計，半世空磨翰墨場。", "桐燼偶收非有意，璧瑕誤指亦何傷。", "霜松不學閒桃李，報答東君日月長。"]'),
('3811284f-ba99-4bbb-9cde-5ef7f266356d','同邑寮飲望錦亭','李流謙','宋','宋诗','song-poetry','','[]','小亭挈榼共登臨，濯錦城高隔暝陰。',64,'全唐诗/poet.song.125000.json','["小亭挈榼共登臨，濯錦城高隔暝陰。", "元有乾坤堪著眼，却因身世苦驚心。", "碧山已盡天猶闊，黄葉欲殘秋更深。", "已把安危屬王謝，酒闌不必淚沾襟。"]'),
('f47be1d2-c6c3-4961-9ba3-d25c57ed8461','獨步','李流謙','宋','宋诗','song-poetry','','[]','凍殻藏龜太窘生，驚心已覺歲崢嶸。',64,'全唐诗/poet.song.125000.json','["凍殻藏龜太窘生，驚心已覺歲崢嶸。", "倦慵把易床頭看，獨自尋梅樹下行。", "溪面冰花寒更結，屋顛雪意晚將成。", "一生與物無深分，竹葉相看合有情。"]'),
('8f0918ff-3ab1-4ec3-ad6b-fa3d344b05a4','書事','李流謙','宋','宋诗','song-poetry','','[]','五十光陰兩歲過，頭顱閒處自摩挲。',64,'全唐诗/poet.song.125000.json','["五十光陰兩歲過，頭顱閒處自摩挲。", "隔籬山影誰招去，滿樹梅花獨占多。", "物色年華同我老，蜂情蝶思柰渠何。", "少時一劍明秋水，放在塵中久不磨。"]'),
('c4df4f25-770e-42c6-b283-327a4cbc75c6','偶成  其一','李流謙','宋','宋诗','song-poetry','','[]','早年種竹作漁竿，笠澤煙波夢未闌。',64,'全唐诗/poet.song.125000.json','["早年種竹作漁竿，笠澤煙波夢未闌。", "已向塵根消縛脫，猶將文字校甘酸。", "風松自有閒宮徵，溪鷺初無俗肺肝。", "最愛少游平日語，墮鳶跕跕遣心寒。"]'),
('2b0429de-c513-44ef-80f6-5d3d4053a8c8','偶成  其二','李流謙','宋','宋诗','song-poetry','','[]','人生偶爾竟何須，點檢閒身一事無。',64,'全唐诗/poet.song.125000.json','["人生偶爾竟何須，點檢閒身一事無。", "可笑戰蝸猶曳甲，不妨夢蟻却分符。", "夜凉白月誰相過，酒盡清樽可更沽。", "作箇生涯若箇是，步兵不擬哭窮途。"]'),
('af78d02a-8005-4445-97ec-45aa27af5c13','偶成  其三','李流謙','宋','宋诗','song-poetry','','[]','離家記得臘前時，吹盡飛花了不知。',64,'全唐诗/poet.song.125000.json','["離家記得臘前時，吹盡飛花了不知。", "傍枕厭聽連曉雨，援毫愁賦送春詩。", "百年直好平章看，萬事仍須爛熟思。", "臣朔不堪當世用，唯應索米救朝饑。"]'),
('54345a20-7173-4a90-baaa-0a9689931f09','偶成  其四','李流謙','宋','宋诗','song-poetry','','[]','獨行飽飯腹屢捫，欲出未出星縱橫。',64,'全唐诗/poet.song.125000.json','["獨行飽飯腹屢捫，欲出未出星縱橫。", "梅花於人遠近好，月色隨我東西明。", "香來適與鼻觀會，夜久忽遣毛骨驚。", "急須喚取陳夫子，欲與平章此段清。"]'),
('467c8139-87a3-4ae8-94d9-da94ff410cf4','即事  其一','李流謙','宋','宋诗','song-poetry','','[]','懶步東阡與北溪，一春心賞苦多違。',64,'全唐诗/poet.song.125000.json','["懶步東阡與北溪，一春心賞苦多違。", "墮紅藉藉癡蜂醉，稚綠陰陰乳燕飛。", "去國三年應自笑，封侯萬里不如歸。", "門前車馬能來否，午睡醒來獨掩扉。"]'),
('701891bd-8fe1-4b96-bbed-eac73ffe3e9b','即事  其二','李流謙','宋','宋诗','song-poetry','','[]','愛春未得一錢酬，獨倚東風搔白頭。',64,'全唐诗/poet.song.125000.json','["愛春未得一錢酬，獨倚東風搔白頭。", "花影入簾情苒苒，竹風挨枕夢悠悠。", "黄鸝欲下無誰語，碧草相看始欲愁。", "老大別無新伎倆，只憑詩句寫風流。"]'),
('ee99eb08-430d-4ffd-8bab-6d4b4917544c','即事  其三','李流謙','宋','宋诗','song-poetry','','[]','雪巘雲林共莽然，世間那有此江天。',64,'全唐诗/poet.song.125000.json','["雪巘雲林共莽然，世間那有此江天。", "曉檣攙日何時到，夜柁鳴風幾夕眠。", "閒卜家書燈似粟，略開旅抱酒如泉。", "輕鷗飛下仍飛去，汝在江湖是散仙。"]'),
('540b97f3-d481-4652-b18f-bfddf40fa21a','仲甄見和復用韻','李流謙','宋','宋诗','song-poetry','','[]','坎止流行亦漫然，斯文未喪本關天。',64,'全唐诗/poet.song.125000.json','["坎止流行亦漫然，斯文未喪本關天。", "冥鴻雲外知誰報，怨鶴山中不得眠。", "連榻故人非楚越，杖藜幽約在林泉。", "盛詞終日供吟諷，骨換元知久學仙。"]'),
('dc654ab4-16d7-4d31-a571-2255c4eb0d1c','即事','李流謙','宋','宋诗','song-poetry','','[]','清江與我共天涯，若到滄溟始是家。',64,'全唐诗/poet.song.125000.json','["清江與我共天涯，若到滄溟始是家。", "曉渡換舟驚宿鴈，暮林繫馬散栖鴉。", "山童老木才餘骨，潮落寒汀半露沙。", "只恐行人不著眼，一川秋色在蘆花。"]'),
('47de57c2-2a94-4030-a412-f630d3457cf9','次韻楊文甫監茶名山新建學橋二首  其一','李流謙','宋','宋诗','song-poetry','','[]','高棟浮空插萬甍，來游誰是魯諸生。',64,'全唐诗/poet.song.125000.json','["高棟浮空插萬甍，來游誰是魯諸生。", "規模要識鳴絃意，土苴猶消擊柱爭。", "馴壠雉驕佳氣象，集林鴞惡好音聲。", "白頭老令能知此，莞爾相撩意未平。"]'),
('487acbfb-5fd3-4091-abeb-73a07d778fd5','次韻楊文甫監茶名山新建學橋二首  其二','李流謙','宋','宋诗','song-poetry','','[]','赤欄畫柱水光中，更愛豐碑筆吐虹。',64,'全唐诗/poet.song.125000.json','["赤欄畫柱水光中，更愛豐碑筆吐虹。", "霧市溟濛鼇闖首，雪花錯落馬行空。", "關門近接俱天險，溪水平流亦海通。", "執朴笑渠憂詛者，不知說豫坐收功。"]'),
('634acb7f-0716-47dc-8e28-a05c9a4a8acc','元質携客渡江飲於村店','李流謙','宋','宋诗','song-poetry','','[]','一篙寒碧碎鱗鱗，數尺孤舟僅著身。',64,'全唐诗/poet.song.125000.json','["一篙寒碧碎鱗鱗，數尺孤舟僅著身。", "江水煮魚還地脈，瓦盆盛酒見天真。", "頗容老子賒閒日，聊與青山作主人。", "不用樽前羅粉黛，遠峯元解作眉顰。"]'),
('00d5b983-c027-4a01-b02f-0196b35dcbc9','招黄太博飲','李流謙','宋','宋诗','song-poetry','','[]','從來官職慣如冰，便是青衫行脚僧。',64,'全唐诗/poet.song.125000.json','["從來官職慣如冰，便是青衫行脚僧。", "去歲離家今日是，故人招隠幾時能。", "早衰鬚鬢逢人問，太拙形模引世憎。", "均在客中誰作伴，如何不共醉騰騰。"]'),
('c9ee27b4-c001-4347-8c76-6246575d5a93','夜興','李流謙','宋','宋诗','song-poetry','','[]','疲筋弱骨畏歊蒸，頗欲清言濯肺膺。',64,'全唐诗/poet.song.125000.json','["疲筋弱骨畏歊蒸，頗欲清言濯肺膺。", "風亂飛螢光細碎，露團幽篠醉懵騰。", "只應愛月癡猶在，更覺憎蚊忿未懲。", "竹屋紙窗風雨夜，幾時書冊近青燈。"]'),
('3cffcf9f-8b37-4ec4-a59b-ef25137096e2','次韻大人江上秋興','李流謙','宋','宋诗','song-poetry','','[]','織水輕烟擘不開，晚峯濃翠積成堆。',64,'全唐诗/poet.song.125000.json','["織水輕烟擘不開，晚峯濃翠積成堆。", "吹殘黄葉風猶舞，飛盡青天鳥却回。", "萬古關河空拊髀，半天風雨獨持杯。", "欲將直道干侯印，政恐舟從陸地推。"]'),
('b79ec7c9-7a37-4a42-a66e-b910e73cf27b','書懷  其一','李流謙','宋','宋诗','song-poetry','','[]','靜閲膠膠擾擾身，細從物理究虧成。',64,'全唐诗/poet.song.125000.json','["靜閲膠膠擾擾身，細從物理究虧成。", "一人譽復一人毀，五鼎食仍五鼎烹。", "怪木莫題居士字，修篁合著此君名。", "西風又起塵千斛，望拜生憎白羽橫。"]'),
('91b3e449-fb1f-4c1a-9f52-9a524bfac760','書懷  其二','李流謙','宋','宋诗','song-poetry','','[]','衫似荷枯嫌絆縛，屋如斗大費支撐。',64,'全唐诗/poet.song.125000.json','["衫似荷枯嫌絆縛，屋如斗大費支撐。", "寒蔬日日同僧飯，拄杖時時伴鶴行。", "聊託蓴鱸非厚味，漫言松菊本真情。", "山中亦有閒田地，可惜離家久不耕。"]'),
('65989142-a080-49c4-a2bc-6d204817fec6','次韻大人書懷  其一','李流謙','宋','宋诗','song-poetry','','[]','萬鈞筆力等閒扛，占斷溪山福已龐。',64,'全唐诗/poet.song.125000.json','["萬鈞筆力等閒扛，占斷溪山福已龐。", "撲鼻寒梅香樹樹，照人新釀綠缸缸。", "大嚴浄社誰投足，小恕詩壇肯納降。", "莫爲不侯空嘆息，將軍才氣自無雙。"]'),
('53fb5f2a-6771-492b-8cc7-94c1ac298770','次韻大人書懷  其二','李流謙','宋','宋诗','song-poetry','','[]','雲翻雨覆不須論，捫虱何妨坐對溫。',64,'全唐诗/poet.song.125000.json','["雲翻雨覆不須論，捫虱何妨坐對溫。", "政恐移文邀俗駕，可能垂箔走高門。", "寒松卧雪不知老，脫葉經霜無幾存。", "醉著錦袍堪一笑，翰林風月我諸孫。"]'),
('c663af41-a669-46ad-9863-c573e6f0854b','次韻大人書懷  其三','李流謙','宋','宋诗','song-poetry','','[]','何如莫莫與休休，分付烟波一釣裘。',64,'全唐诗/poet.song.125000.json','["何如莫莫與休休，分付烟波一釣裘。", "心向青山貪未了，夢隨白鳥去無由。", "閒雲猶閣爲霖潤，野水空橫濟物舟。", "安得杜陵詩老在，從渠每日醉江頭。"]'),
('ae6d753f-883f-4409-87c2-1fa2feaf9a87','次韻程進孺書懷','李流謙','宋','宋诗','song-poetry','','[]','寸梗悠悠寄一城，主人留客亦多情。',64,'全唐诗/poet.song.125000.json','["寸梗悠悠寄一城，主人留客亦多情。", "目窮斷鴈投空影，耳著清江徹曉聲。", "濁酒半樽心易醉，遠書一字眼偏明。", "無家更甚無魚苦，付與先生好細評。"]'),
('3253c223-f0c1-4895-89cd-cbfcaa34c602','次韻樞相雪中之什','李流謙','宋','宋诗','song-poetry','','[]','空明無際了寒天，戍堠消鋒弩絕拳。',64,'全唐诗/poet.song.125000.json','["空明無際了寒天，戍堠消鋒弩絕拳。", "平白萬方包險穢，清泠一片起沉綿。", "山登姑射欣逢歲，賊破淮西欲問年。", "更長嘉陵千尺浪，春風穩送五湖船。"]'),
('52c7124f-311e-4ff6-a101-39f6d17f7d9c','譙允蹈知縣和予所作二詩復用韻答之  其一','李流謙','宋','宋诗','song-poetry','','[]','向來沮洳懶扶竿，獨有詩情久未闌。',64,'全唐诗/poet.song.125000.json','["向來沮洳懶扶竿，獨有詩情久未闌。", "把菊風流元曠蕩，紉蘭氣骨自辛酸。", "賞音定許推夔足，知味寧論食馬肝。", "勝日從公窺祕藏，珠星璧月照人寒。"]'),
('b169ef03-7df4-487a-a94d-18942c2d382d','譙允蹈知縣和予所作二詩復用韻答之  其二','李流謙','宋','宋诗','song-poetry','','[]','窮年斗粟亦時須，清坐那能論有無。',64,'全唐诗/poet.song.125000.json','["窮年斗粟亦時須，清坐那能論有無。", "洗我破樽傾竹葉，覓君佳句寫桃符。", "種瓜晚計應先定，畫餠空名不擬沽。", "辦取芒鞋山裏去，羊腸縱險是夷途。"]'),
('5391c3b2-b910-4f9d-8d50-47cc93e95e03','次大人韻二首  其一','李流謙','宋','宋诗','song-poetry','','[]','盤礡誰知畫史真，向來唯有宋元君。',64,'全唐诗/poet.song.125000.json','["盤礡誰知畫史真，向來唯有宋元君。", "試除學道有底事，爲問决科何等文。", "棋罷玉枰收碎雹，香殘金鴨轉微雲。", "獨騎一馬悠悠去，閒訪江頭白鷺羣。"]'),
('3b65d877-0f10-410c-a5db-38570750c6e1','次大人韻二首  其二','李流謙','宋','宋诗','song-poetry','','[]','六品官資叵厭卑，高懷自不入時宜。',64,'全唐诗/poet.song.125000.json','["六品官資叵厭卑，高懷自不入時宜。", "却尋清渭歸垂釣，猶向鈞天憶射麋。", "長日只憑詩遣悶，暮年全藉酒扶衰。", "早將鵩賦胸中了，賈誼何憂絳灌疑。"]'),
('f5408d52-14f7-473f-b592-9329753ae2b0','又次大人韻','李流謙','宋','宋诗','song-poetry','','[]','卜築城南幾歲華，滿川煙雨富桑麻。',64,'全唐诗/poet.song.125000.json','["卜築城南幾歲華，滿川煙雨富桑麻。", "武陵未用逃秦俗，盤谷從來屬李家。", "橫拓小溪通畫檝，剩栽疎竹間梅花。", "更饒一斗詩千首，不信閒居樂可涯。"]'),
('8a34029f-6be0-4a91-9e22-006d1cbf525f','遊安樂次句龍元應韻','李流謙','宋','宋诗','song-poetry','','[]','得友何妨並轡行，眼明木末數峯橫。',64,'全唐诗/poet.song.125000.json','["得友何妨並轡行，眼明木末數峯橫。", "真游與世寥寥隔，滯念逢僧稍稍平。", "不復定身懷故宅，空餘遺像閟荒坑。", "莫教學道傷遲暮，世路低回已半生。"]'),
('9b9ccb4f-4726-430d-ab23-c0d5212465ff','次元尉伯言韻','李流謙','宋','宋诗','song-poetry','','[]','燭影紅餘僕屢更，不知飛霰集前榮。',64,'全唐诗/poet.song.125000.json','["燭影紅餘僕屢更，不知飛霰集前榮。", "終年客有刀頭恨，半夜春從酒面生。", "華髮風埃羞漫仕，廢疇煙雨負深耕。", "誦君好句迎新歲，更醉屠酥最後觥。"]'),
('ce5a5e76-2d2f-4efe-90f6-c41abd175d9a','譙丈復見貽仍次韻答之二首  其一','李流謙','宋','宋诗','song-poetry','','[]','筆陣旗開豹繞竿，敢持一鏃傍門闌。',64,'全唐诗/poet.song.125000.json','["筆陣旗開豹繞竿，敢持一鏃傍門闌。", "朅來戲作鳬飛舄，老去嫌爲蚋聚酸。", "塵土簿書慵掛眼，瓊瑶文字喜彫肝。", "寄牋閶闔誰相問，九虎近人毛骨寒。"]'),
('9e8b1aa6-7bc9-461b-9e4b-351fa1a3a783','譙丈復見貽仍次韻答之二首  其二','李流謙','宋','宋诗','song-poetry','','[]','只得公詩百不須，萬金人有此應無。',64,'全唐诗/poet.song.125000.json','["只得公詩百不須，萬金人有此應無。", "可容輕易秦庭璧，已戒牢藏晉鄙符。", "慣客鳬鷗迎野步，及時菘韮薦村沽。", "幽棲爲問能來否，朝市山林自兩途。"]'),
('09cc2651-7bb8-4c9b-854d-0a7d734a3740','再賡佳什已致牽羊之請又辱不鄙垂教蓋大巫困小巫欲眎其顛踣爲戲耳輒作二章以足小成之數  其一','李流謙','宋','宋诗','song-poetry','','[]','鱗鱗新綠漲篙竿，飛鴈聲中歲已闌。',64,'全唐诗/poet.song.125000.json','["鱗鱗新綠漲篙竿，飛鴈聲中歲已闌。", "梅蘂尚能供冷淡，酒杯那復問甜酸。", "徵招不入幽人夢，節物空驚壯士肝。", "趁取芳菲行樂去，麗詞妍唱暖春寒。"]'),
('f076b783-3520-453a-adb5-095d8b9eb747','再賡佳什已致牽羊之請又辱不鄙垂教蓋大巫困小巫欲眎其顛踣爲戲耳輒作二章以足小成之數  其二','李流謙','宋','宋诗','song-poetry','','[]','講摩師友我尤須，此道今人已絕無。',64,'全唐诗/poet.song.125000.json','["講摩師友我尤須，此道今人已絕無。", "頗欲相從問奇字，故應未暇注陰符。", "竹嫌影薄乘春種，酒怕樽空带雪沽。", "杖屨往來憂不數，恐公早晚躡華途。"]'),
('15c55f2d-19bf-49e5-8945-cb144904416c','宇文德濟約游崇慶值客不果從德濟有詩次韻二首  其一','李流謙','宋','宋诗','song-poetry','','[]','午枕風輕睡足時，起來閒掩竹間扉。',64,'全唐诗/poet.song.125000.json','["午枕風輕睡足時，起來閒掩竹間扉。", "登山劇欲君聯臂，出戶那堪客挽衣。", "失脚半生沈世網，掀髯一笑見天機。", "青山好去應須去，蘧瑗于今已覺非。"]'),
('2d7d6f23-ad2c-4a90-b21f-debcf2e55645','宇文德濟約游崇慶值客不果從德濟有詩次韻二首  其二','李流謙','宋','宋诗','song-poetry','','[]','跨海仙人安在哉，幽尋款款不須催。',64,'全唐诗/poet.song.125000.json','["跨海仙人安在哉，幽尋款款不須催。", "雲蘿有約遽相失，杖屨幾時能獨來。", "半日清談容易廢，百年幽抱若爲開。", "新詩小慰參差恨，快讀聊將勸一杯。"]'),
('33bdde0d-7190-499d-a9e7-6caa2d720ecc','次韻楊師仁見贈','李流謙','宋','宋诗','song-poetry','','[]','鴻鴈行中接俊游，不將千戶比荆州。',64,'全唐诗/poet.song.125000.json','["鴻鴈行中接俊游，不將千戶比荆州。", "自于種種推先手，可但區區放一頭。", "揚馬不妨生絕代，鄒枚未肯老諸侯。", "天寒翠袖愁如織，應念塵侵季子裘。"]'),
('462f0b7b-8891-40f3-b4b8-6f4eb6be1cf6','師仁再用韻復作一首','李流謙','宋','宋诗','song-poetry','','[]','室中元自有天游，海內如何止九州。',64,'全唐诗/poet.song.125000.json','["室中元自有天游，海內如何止九州。", "送老只憑書萬卷，傳家不用橘千頭。", "便當野服從逋客，未暇巍冠伴沐猴。", "一動天文兒戲耳，苦煩天子訪羊裘。"]'),
('2b77026a-be66-435f-b280-3f2a54141b04','王正卿何道夫和嘉字韻詩至數十道夫贈予數篇晉卿亦贈一篇因次其韻凡六首  其一','李流謙','宋','宋诗','song-poetry','','[]','從君未省涉津涯，白璧明珠屢拜嘉。',64,'全唐诗/poet.song.125000.json','["從君未省涉津涯，白璧明珠屢拜嘉。", "一吸湖江真大國，僅除風雨亦寒家。", "簿書笑我忙官事，筆硯饒君管物華。", "世味可能爭腊毒，餒蛟饞兕漫摇牙。"]'),
('26257ee3-22ff-4b35-a512-9048027544f2','王正卿何道夫和嘉字韻詩至數十道夫贈予數篇晉卿亦贈一篇因次其韻凡六首  其二','李流謙','宋','宋诗','song-poetry','','[]','放浪山顛與水涯，藜羹有味薦珍嘉。',64,'全唐诗/poet.song.125000.json','["放浪山顛與水涯，藜羹有味薦珍嘉。", "根塵要識元非我，言語懸知未到家。", "霜渚澄波空漲潦，風林脫木浄浮華。", "公明領取休論價，處事何須更作牙。"]'),
('c3f85a3b-95a1-44dc-9d81-30d97da46b27','王正卿何道夫和嘉字韻詩至數十道夫贈予數篇晉卿亦贈一篇因次其韻凡六首  其三','李流謙','宋','宋诗','song-poetry','','[]','清言元論極邊涯，南渡風流繼永嘉。',64,'全唐诗/poet.song.125000.json','["清言元論極邊涯，南渡風流繼永嘉。", "中散一生慵作吏，淵明無日不思家。", "悠悠官路降胸臆，苒苒年光侮鬢華。", "人說亂蛙勝鼓吹，欲將藜杖比高牙。"]'),
('13f8ffd6-bb8a-4536-859b-00c3d70e9a26','王正卿何道夫和嘉字韻詩至數十道夫贈予數篇晉卿亦贈一篇因次其韻凡六首  其四','李流謙','宋','宋诗','song-poetry','','[]','戲論無涯與有涯，委心沖漠固清嘉。',64,'全唐诗/poet.song.125000.json','["戲論無涯與有涯，委心沖漠固清嘉。", "衣裳草木元非織，窟宅雲霞豈是家。", "瞪眎恐同高長史，神交宜伴老南華。", "只應一念超塵劫，安用神漿夜繞牙。"]'),
('30ad79a1-a2bb-45ba-89c7-b71525f08743','王正卿何道夫和嘉字韻詩至數十道夫贈予數篇晉卿亦贈一篇因次其韻凡六首  其五','李流謙','宋','宋诗','song-poetry','','[]','越王飛觀插天涯，小異何人識孟嘉。',64,'全唐诗/poet.song.125000.json','["越王飛觀插天涯，小異何人識孟嘉。", "別後文章尤造理，向來學術自成家。", "諸生薦士皆時論，此道逢辰固國華。", "行脫羈銜謝拘迫，雲窗歸理萬籤牙。"]'),
('7324a382-182b-41fb-82e3-f4085de37e66','王正卿何道夫和嘉字韻詩至數十道夫贈予數篇晉卿亦贈一篇因次其韻凡六首  其六','李流謙','宋','宋诗','song-poetry','','[]','洗甲傾河漸可涯，北征猶記宋元嘉。',64,'全唐诗/poet.song.125000.json','["洗甲傾河漸可涯，北征猶記宋元嘉。", "石劉姓字非圖籙，軒嚳乾坤自我家。", "原上鼓旗寒朔吹，日邊詔令掞春華。", "舞干元是吾皇事，不必將軍號虎牙。"]'),
('757102a1-0cc7-4281-995c-21bb6f4f7edd','樞相游吳園再用前韻','李流謙','宋','宋诗','song-poetry','','[]','等閒驅雪作晴天，夾道從公立萬弮。',64,'全唐诗/poet.song.125000.json','["等閒驅雪作晴天，夾道從公立萬弮。", "白甚自矜梅淡竚，青回稍覺麥芊綿。", "不知今夕真何夕，共說明年是好年。", "舐鼎恐無雞犬分，一江還我捕魚船。"]'),
('b15956a9-6f5b-49c1-843b-cf0992cf0300','任德廣通判拉游長松以詩見貽次其韻  其一','李流謙','宋','宋诗','song-poetry','','[]','稽首頭陀問八還，揚眉應已破玄關。',64,'全唐诗/poet.song.125000.json','["稽首頭陀問八還，揚眉應已破玄關。", "苦無骨相侯千戶，薄有生涯屋數間。", "笑讀道書蒙絳帕，喜澆茗椀酌青山。", "從公一瓣薰知見，谷霧無心澤豹斑。"]'),
('7c85ea96-2a9f-41ab-a53b-b96c1fe44c3d','任德廣通判拉游長松以詩見貽次其韻  其二','李流謙','宋','宋诗','song-poetry','','[]','鷺行鴛列幾時還，虎豹何曾限九關。',64,'全唐诗/poet.song.125000.json','["鷺行鴛列幾時還，虎豹何曾限九關。", "雜沓羣公半天上，婆娑老子但塵間。", "平戎正倚二三策，招隠休論大小山。", "浯水斷崖磨欲盡，憑君染筆續彪斑。"]'),
('a83212f9-039f-4b94-896a-7e8be1ab2603','任德廣通判拉游長松以詩見貽次其韻  其三','李流謙','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','已成倦鳥不知還，碌碌無奇合抱關。',64,'全唐诗/poet.song.125000.json','["已成倦鳥不知還，碌碌無奇合抱關。", "五斗未供雞鶩飽，一身長占簿書間。", "何妨使我留東閣，久自從公仰泰山。", "佳句傳來渾舍喜，亟將病目洗斕斑。"]'),
('18bc8190-9646-40c1-a16e-715dfcef3a77','德廣至中途再示詩次其韻','李流謙','宋','宋诗','song-poetry','','[]','肩輿又作带星還，騎氣遥瞻晚度關。',64,'全唐诗/poet.song.125000.json','["肩輿又作带星還，騎氣遥瞻晚度關。", "已覺勝游同夢裏，不知秀色尚眉間。", "鞭鯨浪欲浮滄海，賣鶴猶堪買好山。", "幾日褰衣扣黄閣，雲腴重試鷓鴣斑。"]'),
('27f1e9c3-feb8-4188-8b5d-e83aee310b8e','次子友竿字韻','李流謙','宋','宋诗','song-poetry','','[]','百戰殘兵但揭竿，每聞風鶴意先闌。',64,'全唐诗/poet.song.125000.json','["百戰殘兵但揭竿，每聞風鶴意先闌。", "懷中鼠腊元非璞，味外鹽梅不止酸。", "細讀知君應掩口，苦吟笑我已刳肝。", "中天赫日臨無際，一點螢飛宿草寒。"]'),
('4a049ff5-2161-430b-839c-7820ca3499ce','次韻仲甄見貽','李流謙','宋','宋诗','song-poetry','','[]','向來出處有心期，未厭雲霄戢翼飛。',64,'全唐诗/poet.song.125000.json','["向來出處有心期，未厭雲霄戢翼飛。", "留滯兼旬空悵望，逡巡半路偶同歸。", "却欣夜語仍連榻，尚憶朝回日典衣。", "里閈齊年班又接，世間如我與君希。"]'),
('9171a684-5cf5-43ff-97b4-090efa01e87e','長蘆次德茂韻','李流謙','宋','宋诗','song-poetry','','[]','捲雪奇觀千丈瀾，詩情撩動未應慳。',64,'全唐诗/poet.song.125000.json','["捲雪奇觀千丈瀾，詩情撩動未應慳。", "却收浙右三年夢，仍對淮南數尺山。", "靴板隨人元自漫，田園覓去正須閒。", "風檣獨立看飛燕，家在孤雲落照間。"]'),
('5e2dbb7e-f30e-4421-b259-13702ee05a2a','送馮夏卿','李流謙','宋','宋诗','song-poetry','','[]','再見三池已舊遊，向來交臂錦江頭。',64,'全唐诗/poet.song.125000.json','["再見三池已舊遊，向來交臂錦江頭。", "味融實際冰河泮，心印微言水月秋。", "雖作燕鴻猶邂逅，故應蓬梗合漂浮。", "相思別後才餘夢，身在刀州望梓州。"]'),
('28df4587-525e-49cd-baec-352f2811440b','有感','李流謙','宋','宋诗','song-poetry','','[]','眼看燕雀閙雲間，塌翼蓬榛笑孔鸞。',64,'全唐诗/poet.song.125000.json','["眼看燕雀閙雲間，塌翼蓬榛笑孔鸞。", "未暇持竿釣渭水，却因採菊見南山。", "床頭有酒三冬足，案上無書一日閒。", "世路只今難著脚，定當何地置疎頑。"]'),
('084655ab-d658-4171-ac3a-44955a05e1b8','飲文氏園是日鵲噪于庭坐上燭花無數就試者凡五人','李流謙','宋','宋诗','song-poetry','','[]','虎變龍騰各有心，諸公高宴盍朋簪。',64,'全唐诗/poet.song.125000.json','["虎變龍騰各有心，諸公高宴盍朋簪。", "爛開數對迎祥燭，合噪仍來報喜禽。", "人似月娥元自近，酒名天祿莫辭深。", "坐中五客聯登去，他日華堂榜桂林。"]'),
('a5c0ead2-292a-4c79-b1d7-e449c76bee99','次韻陳彥博梅飲之什','李流謙','宋','宋诗','song-poetry','','[]','又向疎梅檢校春，乾坤浩蕩日趨新。',64,'全唐诗/poet.song.125000.json','["又向疎梅檢校春，乾坤浩蕩日趨新。", "一樽樹下喚深酌，數歲天涯思遠人。", "正倚交情論晚暮，直因臭味作疎親。", "淵明嗜酒嵇康懶，只覺年來此是真。"]'),
('358e15ee-12a9-4b99-9ea0-11c18e37968c','送李閬州二首  其一','李流謙','宋','宋诗','song-poetry','','[]','耳熟才名四十年，憂民憂國兩華顛。',64,'全唐诗/poet.song.125000.json','["耳熟才名四十年，憂民憂國兩華顛。", "不妨銅竹仍三剖，要是金門竟九遷。", "連歲爐錘專造化，諸生岐路託飛騫。", "餘丹乞與閒雞犬，亦許身隨絳闕僊。"]'),
('7e81f859-2487-4208-a68a-945f4388499a','送李閬州二首  其二','李流謙','宋','宋诗','song-poetry','','[]','少陵曾賦閬州詩，苦說城南天下稀。',64,'全唐诗/poet.song.125000.json','["少陵曾賦閬州詩，苦說城南天下稀。", "鈴閤訟閒簾半卷，胡床客好麈頻揮。", "著鞭尚及春耕勸，促詔應隨曉仗歸。", "他日遺簪猶在念，端容杖策扣黄扉。"]'),
('c2fee9d2-56cf-4751-b9ac-b7f89b9b461d','再用魏城驛韻貽白綿州','李流謙','宋','宋诗','song-poetry','','[]','多病相如故倦游，歸逢清潤麥天秋。',64,'全唐诗/poet.song.125000.json','["多病相如故倦游，歸逢清潤麥天秋。", "回頭漸遠將軍幕，飛夢先登帝子樓。", "磊落聲稱元古郡，醉吟家世自詩流。", "此身只擬春中老，莫問君平住益州。"]'),
('c66bedd1-7585-4d8e-b05c-59e206356a9a','貽白綿州','李流謙','宋','宋诗','song-poetry','','[]','曾陪芍藥醉春風，轉首三年似夢中。',64,'全唐诗/poet.song.125000.json','["曾陪芍藥醉春風，轉首三年似夢中。", "誰使衝泥千里去，又欣剪燭一樽同。", "名章越好供妍唱，舊學全疎愧近功。", "莫怪分符少留滯，此邦曾客少陵翁。"]'),
('5c2177d8-4cad-4030-a09f-4cc19a4caefc','寄送張雅州二首  其一','李流謙','宋','宋诗','song-poetry','','[]','融和盎盎上雙眉，曠度真成萬頃陂。',64,'全唐诗/poet.song.125000.json','["融和盎盎上雙眉，曠度真成萬頃陂。", "岱華自高元地勢，球琳不琢本天姿。", "地方千里我無事，春滿萬家人不知。", "預作去思無限意，攀轅送處似迎時。"]'),
('ad3667e3-97ee-492a-b6ba-62ef91d38e54','寄送張雅州二首  其二','李流謙','宋','宋诗','song-poetry','','[]','二年學舍冷如冰，岌嶪龍門許屢登。',64,'全唐诗/poet.song.125000.json','["二年學舍冷如冰，岌嶪龍門許屢登。", "可但不遭官長駡，只應獨愧小人乘。", "身留紫塞天一角，目斷朱輪山幾層。", "爲問何時到牆仞，清宵遠夢故堪憑。"]'),
('2dab0243-3ae8-492d-9e0d-a0103fa4f8bd','七夕馬逸已而獲之','李流謙','宋','宋诗','song-poetry','','[]','門外喧呼驚失馬，天邊未暇問牽牛。',64,'全唐诗/poet.song.125000.json','["門外喧呼驚失馬，天邊未暇問牽牛。", "報恩不作雀銜玉，快意遂爲鷹脫韝。", "他日盖帷吾已許，暮年繩勒汝應羞。", "故知多憶橫門道，定厭青絲久絡頭。"]'),
('9f58eb00-2cfe-4f2a-b248-5007cb252722','送魏德源倅永康','李流謙','宋','宋诗','song-poetry','','[]','晚歲從誰覓賞音，浪將孤興託瑶琴。',64,'全唐诗/poet.song.125000.json','["晚歲從誰覓賞音，浪將孤興託瑶琴。", "聊爲風月平分客，莫起山林獨往心。", "碧草但能供別恨，黄花却解勸清斟。", "我猶未制思親淚，更聽離歌定不禁。"]'),
('a6b85157-f1b0-4d1a-be86-ad4a5ae14732','別趙惟直','李流謙','宋','宋诗','song-poetry','','[]','邂逅都城一笑休，却來萬里共羈游。',64,'全唐诗/poet.song.125000.json','["邂逅都城一笑休，却來萬里共羈游。", "關河地迥仍分首，桃李春深已放舟。", "詩卷長留開倦目，酒杯盡嚼豁離憂。", "追風健筆兼豪氣，期子蓬山更上頭。"]'),
('4af58c77-440e-4d77-acf5-e8ea56615f33','秋懷次黄仲甄韻  其一','李流謙','宋','宋诗','song-poetry','','[]','畏日全無客到門，一溪閒與白鷗分。',64,'全唐诗/poet.song.125000.json','["畏日全無客到門，一溪閒與白鷗分。", "遶樓山色時時見，抱葉蟬聲處處聞。", "戰罷碁枰無宿恨，夢回茗椀有殊勳。", "力田尚可持門戶，我欲歸耕谷口雲。"]'),
('1aca1fd3-c73f-4493-b671-8ea042bdcd7f','秋懷次黄仲甄韻  其二','李流謙','宋','宋诗','song-poetry','','[]','破曉庭皋一葉風，年華苒苒笑羈窮。',64,'全唐诗/poet.song.126000.json','["破曉庭皋一葉風，年華苒苒笑羈窮。", "獨携拄杖行溪曲，恐有挐音出葦叢。", "世界大千塵偶集，人生三十日方中。", "只須飽飯隨緣過，矰繳何曾到塞鴻。"]'),
('bb8aa4a8-70a7-42e7-b6b5-c46d4dc15ee2','喜晴','李流謙','宋','宋诗','song-poetry','','[]','一秋今日是新晴，晚稻懸知有幾分。',64,'全唐诗/poet.song.126000.json','["一秋今日是新晴，晚稻懸知有幾分。", "抱濕庭蕪猶靡靡，傍暄溪卉欲欣欣。", "顛風料理丹楓樹，返照留連白鷺羣。", "摇落只供騷客恨，故應長倚醉醺醺。"]'),
('bd1e8404-2b60-4419-adcf-cdc2d32ce1fb','重陽偶成','李流謙','宋','宋诗','song-poetry','','[]','百尺危樓倚瘦藤，輕陰小令正秋深。',64,'全唐诗/poet.song.126000.json','["百尺危樓倚瘦藤，輕陰小令正秋深。", "山雲洗刷供晴眺，杯酒飄浮笑淺斟。", "漠北烽煙空抵掌，水南松竹每經心。", "紅萸紫菊誇强健，醉帽無人獨自簪。"]'),
('eaa2c46b-c29a-4a7d-af8a-15fa7deedc98','宿高橋懷仲明','李流謙','宋','宋诗','song-poetry','','[]','闌干投晚俯煙霏，全不支梧酒力微。',64,'全唐诗/poet.song.126000.json','["闌干投晚俯煙霏，全不支梧酒力微。", "沙鳥犯寒猶獨立，林烏趁暝已先歸。", "繚愁亦笑溪爲带，障遠端疑樹合圍。", "歲晏客天無好夢，最憐清露漬人衣。"]'),
('6521c9d4-931c-4532-b1f6-bc4e02c24ca7','太平宮','李流謙','宋','宋诗','song-poetry','','[]','一馬騰騰上翠微，松風瑟瑟解吹衣。',64,'全唐诗/poet.song.126000.json','["一馬騰騰上翠微，松風瑟瑟解吹衣。", "故宮亂後仍華壯，使者年來果是非。", "何日身能牀蘂笈，只今心自託金徽。", "兩林不到猶遺恨，落照銜山勸客歸。"]'),
('80c5cede-283c-4756-8b49-c3bdd6631c7d','送家連父解綿竹丞','李流謙','宋','宋诗','song-poetry','','[]','猿臂將軍數自奇，白頭州縣竟何爲。',64,'全唐诗/poet.song.126000.json','["猿臂將軍數自奇，白頭州縣竟何爲。", "斲墁未盡成風巧，測管才窺澤霧姿。", "流水繞除空日日，西山拄笏謾時時。", "一杯相送貧無力，剩有新詩說去思。"]'),
('b9b3a0e1-8853-48d5-860d-88ee986628e1','送計祖仁雒縣丞','李流謙','宋','宋诗','song-poetry','','[]','青青楊柳灞橋斜，滿酌清樽莫嘆嗟。',64,'全唐诗/poet.song.126000.json','["青青楊柳灞橋斜，滿酌清樽莫嘆嗟。", "可是因循成別緒，只應咫尺便天涯。", "未論流水千竿竹，且看春風一縣花。", "渺渺故園情最苦，不知歸夢屬誰家。"]'),
('f80ed46f-00c0-4a08-a7a7-916dbd6c5db7','次韻彥博中秋不見月','李流謙','宋','宋诗','song-poetry','','[]','露華浸竹冷娟娟，想象嫦娥能少年。',64,'全唐诗/poet.song.126000.json','["露華浸竹冷娟娟，想象嫦娥能少年。", "萬事只堪搔短髮，一杯不擬問高天。", "駸駸夜色投書幌，的的心期在釣船。", "可笑薄雲工料理，何曾遮却一分圓。"]'),
('1d3564ec-c03c-4914-9061-2b1483a190ab','學中曝御書次少虞韻','李流謙','宋','宋诗','song-poetry','','[]','晴暾煜煜眩晨光，洗眼來窺雲漢章。',64,'全唐诗/poet.song.126000.json','["晴暾煜煜眩晨光，洗眼來窺雲漢章。", "身拜玉階元夕夢，手披金笈有天香。", "風翔鳳翼尤妍媚，雲捲奎躔不覆藏。", "尚想承平閒氣象，從臣鵠立侍君王。"]'),
('86ce68fe-68b3-40c4-ae8b-bae890d3b80e','李花','李流謙','宋','宋诗','song-poetry','','[]','春寒怪底一分加，元是東君雪作花。',64,'全唐诗/poet.song.126000.json','["春寒怪底一分加，元是東君雪作花。", "已後殘梅矜夜魄，强隨飛絮舞朝霞。", "霜葩薦斚何人共，碧實堆盤儘客誇。", "爲汝泫然應有意，騷人端是感年華。"]'),
('111d19b1-d20e-47c1-83a5-77c9c5d400ec','井上即事','李流謙','宋','宋诗','song-poetry','','[]','九陌黄塵涴客裾，隨人亦恐到茅廬。',64,'全唐诗/poet.song.126000.json','["九陌黄塵涴客裾，隨人亦恐到茅廬。", "朝朝山色供憑檻，夜夜溪聲伴讀書。", "可要功名驚宇宙，分知骨相合樵漁。", "晚來小艇衝煙出，江上有人爭賣魚。"]'),
('07385841-72ba-4347-b094-3102f7ea3761','挽郭敦復','李流謙','宋','宋诗','song-poetry','','[]','太少城中斂板初，識公鸞鵠自清癯。',64,'全唐诗/poet.song.126000.json','["太少城中斂板初，識公鸞鵠自清癯。", "持心要是忠厚者，遇事决非章句儒。", "豺豹欲前終落爪，參辰無地可彎弧。", "他年白鶴同歸否，猶有髯龍老未枯。"]'),
('8d37c997-7e57-4d4b-b925-67fd20502bfc','送王和叟赴果州','李流謙','宋','宋诗','song-poetry','','[]','芝蘭祇合在階庭，公子翩翩更老成。',64,'全唐诗/poet.song.126000.json','["芝蘭祇合在階庭，公子翩翩更老成。", "白日朱門三列㦸，黑頭華轂再專城。", "一樽別酌心先醉，萬里歸橈夢易驚。", "欲問樓高高幾許，跨渠僊鶴到瑶京。"]'),
('0be6b92a-b6f7-4159-9bb5-f73d265b8ea5','晚飲趙惟直以果薦知所從來酌以一大杯','李流謙','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','猶带枝頭淡淡黄，飽經十月洞庭霜。',64,'全唐诗/poet.song.126000.json','["猶带枝頭淡淡黄，飽經十月洞庭霜。", "且傾蜀客千杯酒，頗記吳姬三日香。", "可得一餐逢玉屑，故應百感爲瓊漿。", "此江幸自東流去，何不和根移取將。"]'),
('580823e3-8b24-4b1e-8726-34fb60f8c000','送張子勤九隴尉','李流謙','宋','宋诗','song-poetry','','[]','老鳳高棲雛鳳飛，山林鍾鼎各相宜。',64,'全唐诗/poet.song.126000.json','["老鳳高棲雛鳳飛，山林鍾鼎各相宜。", "出門馬首亭亭去，斂板胸中落落奇。", "頗憶濁醪過我夜，正愁碧草送君時。", "如何數日中年味，恰是今朝聞子規。"]'),
('11f8bc40-3cc2-417a-b96a-23f55571d2af','貽長松寺慈禪師','李流謙','宋','宋诗','song-poetry','','[]','一年山色好相看，欲去仍來倍黯然。',64,'全唐诗/poet.song.126000.json','["一年山色好相看，欲去仍來倍黯然。", "大士初無留客意，幽人更結住山緣。", "梨花村落清明後，梅子園林五月前。", "我已到家春亦老，酒杯猶足趁流年。"]'),
('ea7df499-710f-45f9-8fff-da828bf5e866','用宇文龍圖韻贈龍華印老','李流謙','宋','宋诗','song-poetry','','[]','少年一口吸西江，聖處端能走季咸。',64,'全唐诗/poet.song.126000.json','["少年一口吸西江，聖處端能走季咸。", "浄觀清泠橫一水，遠懷孤秀揖千巖。", "溪雲卧久看頻度，山日談餘訝半銜。", "便欲瘦筇來問訊，上方應恐隔僊凡。"]'),
('926bb785-d75e-4b79-993e-837b642bebf4','再用韻送印老','李流謙','宋','宋诗','song-poetry','','[]','抖擻孤懷十日談，不將幽憤託巫咸。',64,'全唐诗/poet.song.126000.json','["抖擻孤懷十日談，不將幽憤託巫咸。", "別來斷雁虛秋信，夢破驚猿憶曉巖。", "脫葉趁風聲互答，歸鴉赴日影相銜。", "臨分半偈無多惜，濁骨憑師爲點凡。"]'),
('b9bf677b-8be2-43ba-a5b6-8e726c38dd8d','挽楊彥序','李流謙','宋','宋诗','song-poetry','','[]','長憶君家得雋多，庭前桂樹想婆娑。',64,'全唐诗/poet.song.126000.json','["長憶君家得雋多，庭前桂樹想婆娑。", "岱雲觸石才膚寸，溟浸稽天但一波。", "頗欲弛韝觀縱擊，可堪伏櫪起悲歌。", "人生泡焰都難據，惟有豐碑屹不磨。"]'),
('a5bc611b-fcd9-48a0-b9f6-dc52fe674b4c','閏重陽有感次宋景文公韻','李流謙','宋','宋诗','song-poetry','','[]','濛濛煙雨濕閒愁，往燕來鴻共遠遊。',64,'全唐诗/poet.song.126000.json','["濛濛煙雨濕閒愁，往燕來鴻共遠遊。", "引滿白醪欣再熟，儘開黄菊耐深秋。", "眼前節物重憑檻，醉裏商歌緩擊甌。", "苦愛佳名歎塵爵，淵明高興轉悠悠。"]'),
('5a20eebb-f166-4181-8053-cf38f4ba640d','寄李仲明','李流謙','宋','宋诗','song-poetry','','[]','夜床風雨憶相過，節物驚人奈老何。',64,'全唐诗/poet.song.126000.json','["夜床風雨憶相過，節物驚人奈老何。", "只有孤鴻知我意，每因明月爲君歌。", "千山夢去無由到，一字書來已覺多。", "餘耳向來真義合，不知底處便容戈。"]'),
('cafceb85-f98c-4bef-a084-46755de87505','寄劉德父','李流謙','宋','宋诗','song-poetry','','[]','解携仍是一年餘，本自情親聽迹疎。',64,'全唐诗/poet.song.126000.json','["解携仍是一年餘，本自情親聽迹疎。", "子去合登青瑣闥，人言方駕短轅車。", "向來花月空餘夢，近日詩文定起予。", "塞鴈若知懷遠意，寄書聊爲問何如。"]'),
('35d1851e-5c0e-4cb0-994b-8f5ca607b8f4','別費檢正二首  其一','李流謙','宋','宋诗','song-poetry','','[]','香案前頭自乞歸，歸心先逐鴈西飛。',64,'全唐诗/poet.song.126000.json','["香案前頭自乞歸，歸心先逐鴈西飛。", "豈關松菊吾身重，偶託蓴鱸此意微。", "行樂不妨千騎擁，照人何必萬釘圍。", "兒曹悵惜先生笑，付與醇醪定是非。"]'),
('31b8c994-0af3-4490-8ba1-4407856be80a','別費檢正二首  其二','李流謙','宋','宋诗','song-poetry','','[]','主人愛客客留連，敢比荆州遇仲宣。',64,'全唐诗/poet.song.126000.json','["主人愛客客留連，敢比荆州遇仲宣。", "親奉綺談逾十日，空勞清夢隔三年。", "未能輕去田園樂，那得長居几杖前。", "真約賞音無幾箇，故應感激易潸然。"]'),
('da5fb407-6427-405c-89e8-ae3aa2ff209f','桃花','李流謙','宋','宋诗','song-poetry','','[]','自然穠臉與深唇，一味繁紅也絕倫。',64,'全唐诗/poet.song.126000.json','["自然穠臉與深唇，一味繁紅也絕倫。", "滄海浪傳千歲種，武陵應有四時春。", "去年崔護詩仍在，前度劉郎意獨親。", "亦要清樽相料理，可能但倚筆如神。"]'),
('e9c1172a-df73-4687-b961-ce5a8e070652','即事','李流謙','宋','宋诗','song-poetry','','[]','寒食已過風日好，城郭稍背郊原幽。',64,'全唐诗/poet.song.126000.json','["寒食已過風日好，城郭稍背郊原幽。", "雙扉晝閉亦何事，一杖携春仍浪游。", "但覺桃花成老大，不知楊柳尚風流。", "霜螯臘蟻君須醉，細雨疎簾罷遣愁。"]'),
('cc3a8b02-a731-40fb-81dc-5697bdb81aa6','游野航次元應韻三首  其一','李流謙','宋','宋诗','song-poetry','','[]','平地坐我帆檣中，翠峯出沒工爲容。',64,'全唐诗/poet.song.126000.json','["平地坐我帆檣中，翠峯出沒工爲容。", "輕鷗舞晴沙照影，蒼蛟吼浪雪薄胸。", "漁舠繫月江一曲，樵斧斫雲山幾重。", "詩翁忽來吐佳句，物色才情元一宗。"]'),
('3feaef85-6bb8-413d-b310-671343d3839d','游野航次元應韻三首  其二','李流謙','宋','宋诗','song-poetry','','[]','日落未落空明中，琉璃夜色開天容。',64,'全唐诗/poet.song.126000.json','["日落未落空明中，琉璃夜色開天容。", "一江不浣清浄目，百榼能平碨磊胸。", "神山在前若可到，江妃去人無數重。", "錦袍酌酒醉起舞，跨鯨僊人乃吾宗。"]'),
('d6c85c53-f841-45a3-85c6-fdf008bd7dfe','游野航次元應韻三首  其三','李流謙','宋','宋诗','song-poetry','','[]','掛起西窗橫笛中，白鷺亦有佳客容。',64,'全唐诗/poet.song.126000.json','["掛起西窗橫笛中，白鷺亦有佳客容。", "江風脫幘吹短髮，明月入戶窺愁胸。", "只須茅茨補疎漏，安用樓觀相複重。", "人生趣尚各天性，古人願識韓朝宗。"]'),
('231604ff-5a36-4542-a143-81dc7e0d7d7f','遣興  其一','李流謙','宋','宋诗','song-poetry','','[]','不於蝸角更稱兵，放下諸緣即太平。',64,'全唐诗/poet.song.126000.json','["不於蝸角更稱兵，放下諸緣即太平。", "但有千篇足傳世，不須二頃可謀生。", "盤餐麤糲聖賢事，門巷蕭條千古情。", "緩炷爐熏引輕吹，道人心念一絲橫。"]'),
('c26960a4-b059-4705-a666-ca9bc79bf7be','遣興  其二','李流謙','宋','宋诗','song-poetry','','[]','邂逅成功一世驚，不知元逐衆人耕。',64,'全唐诗/poet.song.126000.json','["邂逅成功一世驚，不知元逐衆人耕。", "結茅容我庇風雨，識字教兒記姓名。", "閒輒吟詩真苦相，醉能遣客即真情。", "晚來溪月延微步，浴鷺浮鷗俱眼明。"]'),
('c39c053e-3655-4400-9c7a-e93fc81bf995','遣興  其三','李流謙','宋','宋诗','song-poetry','','[]','翛翛楊柳倚門斜，客至遥疑靖節家。',64,'全唐诗/poet.song.126000.json','["翛翛楊柳倚門斜，客至遥疑靖節家。", "半世功名閒日月，百年生理仰桑麻。", "只知上將元屠狗，不信通侯亦種瓜。", "靜想升沉堪一笑，清樽且趁未殘花。"]'),
('8d081ec9-d9e1-43c1-9114-5e5127c442e0','遣興  其四','李流謙','宋','宋诗','song-poetry','','[]','向來穴紙笑癡蠅，猶覺文章是小乘。',64,'全唐诗/poet.song.126000.json','["向來穴紙笑癡蠅，猶覺文章是小乘。", "四壁圖書聊隠几，半窗風雨屢挑燈。", "卑枝早厭鳴岡鳳，尺水難留跨海鵬。", "未試屠龍一分手，可能問舍愧陳登。"]'),
('3ebd53b7-d9f6-42a2-8320-e8fb9daf0b66','遣興  其五','李流謙','宋','宋诗','song-poetry','','[]','疎疎簾色映蒼苔，屋角諸峯曉翠開。',64,'全唐诗/poet.song.126000.json','["疎疎簾色映蒼苔，屋角諸峯曉翠開。", "蝶護殘花癡不去，鳥爭餘食慣仍來。", "向來棲遁初無意，從古經綸別有才。", "抱杖風前一長嘯，破愁安得即時杯。"]'),
('ed2c3fd2-5a88-4723-8c7b-bf1fd5bd6850','遣興  其六','李流謙','宋','宋诗','song-poetry','','[]','小窗日影轉悠悠，卷盡殘書却到頭。',64,'全唐诗/poet.song.126000.json','["小窗日影轉悠悠，卷盡殘書却到頭。", "香茗半甌輕列鼎，好詩千首勝封侯。", "朱絃無復人三歎，白璧空慙我屢投。", "酒好但宜供客醉，癡兒可忍換涼州。"]'),
('7204e7a1-8431-42af-a24b-36336ad4862e','遣興  其七','李流謙','宋','宋诗','song-poetry','','[]','楚客近添蘭九畹，渭川新長竹千尋。',64,'全唐诗/poet.song.126000.json','["楚客近添蘭九畹，渭川新長竹千尋。", "叵堪多病侵豪氣，猶喜長閒契宿心。", "滿眼圖書吾事定，杜門香火佛緣深。", "海波倒立風霆峻，未省鱣鯨竟陸沉。"]'),
('08c64cf7-b9ac-43d1-94c4-82a13b3e6599','江月二首  其一','李流謙','宋','宋诗','song-poetry','','[]','秋江與秋月，誰遣恰相和。',24,'全唐诗/poet.song.126000.json','["秋江與秋月，誰遣恰相和。", "借我蓑衣著，三人亦未多。"]'),
('4189bbf7-403d-4b10-a0d6-7b8c6e555168','江月二首  其二','李流謙','宋','宋诗','song-poetry','','[]','皎皎映澄漪，千尋沒到時。',24,'全唐诗/poet.song.126000.json','["皎皎映澄漪，千尋沒到時。", "篙師輕轉櫓，可惜碧琉璃。"]'),
('56219eac-b577-4bf9-92f2-860f23dfc4f0','姚和中母夫人年八十二殊增獨無之嘆因遺小罌使歸爲壽副以一絕','李流謙','宋','宋诗','song-poetry','','[]','舍肉增長嘆，分甘助淺斟。',24,'全唐诗/poet.song.126000.json','["舍肉增長嘆，分甘助淺斟。", "贈君椒柏酒，慰我蓼莪心。"]'),
('d706f129-61fa-46aa-bad8-0fb2cc412825','長灘','李流謙','宋','宋诗','song-poetry','','[]','乍脫驚濤恐，猶爲曲木看。',24,'全唐诗/poet.song.126000.json','["乍脫驚濤恐，猶爲曲木看。", "昔人憎勝母，吾亦畏長灘。"]'),
('3ba1ef29-4ef7-4c8e-8c05-80c09b8613bc','雲莊耕者','李流謙','宋','宋诗','song-poetry','','[]','莘野樂堯舜，谷口豈真卿。',24,'全唐诗/poet.song.126000.json','["莘野樂堯舜，谷口豈真卿。", "自是不可掩，區區非近名。"]'),
('44311885-a582-4acc-9927-b63231c10f65','過東州境見耕','李流謙','宋','宋诗','song-poetry','','[]','驅牛耕側坡，牛困人柰何。',24,'全唐诗/poet.song.126000.json','["驅牛耕側坡，牛困人柰何。", "我念田家苦，東州苦更多。"]'),
('51f58ef9-78df-447d-ac26-8725ed9dcc70','偶題  其一','李流謙','宋','宋诗','song-poetry','','[]','小溝溶漾可涉，彩舫夷猶不驚。',28,'全唐诗/poet.song.126000.json','["小溝溶漾可涉，彩舫夷猶不驚。", "晚酌忽逢名酒，當時打破愁城。"]'),
('91cc4f04-b778-46f5-b953-ed7f8eca9a64','偶題  其二','李流謙','宋','宋诗','song-poetry','','[]','遥岑數寸斜日，楊柳一江晚烟。',28,'全唐诗/poet.song.126000.json','["遥岑數寸斜日，楊柳一江晚烟。", "追恨風拘雨阻，那知鴈後花前。"]'),
('8e0f95b6-65b7-49f1-ae11-972bb96a86f0','關王祠  其一','李流謙','宋','宋诗','song-poetry','','[]','諸葛張陳已上，將軍未數黥韓。',28,'全唐诗/poet.song.126000.json','["諸葛張陳已上，將軍未數黥韓。", "暝夜險途風雨，令人懸想辛酸。"]'),
('f1a0ea57-d374-4d80-8b86-ce7f1deb0ecd','關王祠  其二','李流謙','宋','宋诗','song-poetry','','[]','萬人傑誰可敵，千載名終不磨。',28,'全唐诗/poet.song.126000.json','["萬人傑誰可敵，千載名終不磨。", "此地晚鐘晨梵，生前鐵馬金戈。"]'),
('4b99f904-fb62-47c1-a37a-fd393b6dfb54','先公三池祠室學官相傳占爲公署同年李南才毅然欲復其舊貽以四絕句  其一','李流謙','宋','宋诗','song-poetry','','[]','老僊有力在斯文，廩士餘糧但一塵。',32,'全唐诗/poet.song.126000.json','["老僊有力在斯文，廩士餘糧但一塵。", "列屋誦絃知所自，杏壇今秀幾株春。"]'),
('02cad113-9175-4820-9aa3-47415d4eb880','先公三池祠室學官相傳占爲公署同年李南才毅然欲復其舊貽以四絕句  其二','李流謙','宋','宋诗','song-poetry','','[]','末俗何由到古人，傷心祠室漫名存。',32,'全唐诗/poet.song.126000.json','["末俗何由到古人，傷心祠室漫名存。", "風榱雨棟那堪說，石刻汙漫像設昏。"]'),
('2880b513-6e18-4ab3-b5da-bcbefa52e77d','先公三池祠室學官相傳占爲公署同年李南才毅然欲復其舊貽以四絕句  其三','李流謙','宋','宋诗','song-poetry','','[]','一椽不得留遺愛，百世寧能保奉嘗。',32,'全唐诗/poet.song.126000.json','["一椽不得留遺愛，百世寧能保奉嘗。", "豚犢無稱益先美，碎碑伐樹亦尋常。"]'),
('1e590c00-26ec-4960-93ff-6fa7282bda12','先公三池祠室學官相傳占爲公署同年李南才毅然欲復其舊貽以四絕句  其四','李流謙','宋','宋诗','song-poetry','','[]','一念愛親無彼此，向來情義篤年家。',32,'全唐诗/poet.song.126000.json','["一念愛親無彼此，向來情義篤年家。", "稍伸九地幽幽恨，此事期君可咄嗟。"]'),
('bcd39b03-8f22-443a-a2e5-8d9ccbc591af','次韻嘲落梅代梅答二絕  其一','李流謙','宋','宋诗','song-poetry','','[]','不是春愁減素肌，從來鶴骨可能肥。',32,'全唐诗/poet.song.126000.json','["不是春愁減素肌，從來鶴骨可能肥。", "便將夢裏一般看，恐是幽人作蝶飛。"]'),
('0ba8aec3-6a35-4198-ab71-048033d506bf','次韻嘲落梅代梅答二絕  其二','李流謙','宋','宋诗','song-poetry','','[]','吹開吹落本無心，萬物自秋還自春。',32,'全唐诗/poet.song.126000.json','["吹開吹落本無心，萬物自秋還自春。", "若把穠花校枯寂，本無諸妄亦無真。"]'),
('d6ec158b-5850-438f-b01c-1dad37590455','彥博歸自劍陽其家梅已半落作詩見示因次其韻  其一','李流謙','宋','宋诗','song-poetry','','[]','爲問春從何處歸，晚村烟雨細絲絲。',32,'全唐诗/poet.song.126000.json','["爲問春從何處歸，晚村烟雨細絲絲。", "從來漏洩冤庭柳，點檢分明是此枝。"]'),
('a6983e5c-3a6b-4d66-b2c5-1e2a95fc97ca','彥博歸自劍陽其家梅已半落作詩見示因次其韻  其二','李流謙','宋','宋诗','song-poetry','','[]','溪水泠泠欲雪天，風鬟霧鬢不勝寒。',32,'全唐诗/poet.song.126000.json','["溪水泠泠欲雪天，風鬟霧鬢不勝寒。", "定同子美鄜州月，應恨閨中只獨看。"]'),
('2853ba22-9684-492b-bfc0-93ccf3180e2a','彥博歸自劍陽其家梅已半落作詩見示因次其韻  其三','李流謙','宋','宋诗','song-poetry','','[]','愛惜濃香恐過時，劉郎何事苦歸遲。',32,'全唐诗/poet.song.126000.json','["愛惜濃香恐過時，劉郎何事苦歸遲。", "只應昨夜幽窗夢，飛到君邊未可知。"]'),
('08ae2247-a5b8-4a54-adf8-8ad9f440d5c6','梅花  其一','李流謙','宋','宋诗','song-poetry','','[]','昨夜臨溪一樹開，人言應與鴈俱回。',32,'全唐诗/poet.song.126000.json','["昨夜臨溪一樹開，人言應與鴈俱回。", "霜葩只在寒梢上，却是春風自去來。"]'),
('94f31465-c8ad-4ca8-bfab-0eab58e7fa62','梅花  其二','李流謙','宋','宋诗','song-poetry','','[]','殷勤蝶障與蜂遮，一點幽香不許賒。',32,'全唐诗/poet.song.126000.json','["殷勤蝶障與蜂遮，一點幽香不許賒。", "歲歲相逢只如此，問花羞我我羞花。"]'),
('77f0d80c-6185-4def-86b3-d00a274f02ef','梅花  其三','李流謙','宋','宋诗','song-poetry','','[]','照影月斜寒瀨淺，吹香風細夜簾疎。',32,'全唐诗/poet.song.126000.json','["照影月斜寒瀨淺，吹香風細夜簾疎。", "萼綠華來誰得見，借君雲珮與霞裾。"]'),
('cb20061a-0e3c-4423-b62a-205c2ab2f90c','梅花  其四','李流謙','宋','宋诗','song-poetry','','[]','似嫌潔白太清寒，故著微紅略破顔。',32,'全唐诗/poet.song.126000.json','["似嫌潔白太清寒，故著微紅略破顔。", "俯仰聊同閒草木，不妨游戲住人間。"]'),
('6698f9ef-34db-4926-8997-c06c0d5d23ab','梅花  其五','李流謙','宋','宋诗','song-poetry','','[]','道人一味著幽禪，誰遣天花到眼邊。',32,'全唐诗/poet.song.126000.json','["道人一味著幽禪，誰遣天花到眼邊。", "亂插銅缾看盡日，向人終是好因緣。"]'),
('a70f270a-31c3-4d75-a94e-6c9fc5bc4ef4','戲贈智淵師二偈  其一','李流謙','宋','宋诗','song-poetry','','[]','芙蕖元不植高原，插向紅爐色更鮮。',32,'全唐诗/poet.song.126000.json','["芙蕖元不植高原，插向紅爐色更鮮。", "拖取門前擔糞漢，滿堂金玉富熏天。"]'),
('c6ab978d-bb21-4665-b482-5fbe498acdc4','戲贈智淵師二偈  其二','李流謙','宋','宋诗','song-poetry','','[]','江北江南喧世界，陪了草鞋多少錢。',32,'全唐诗/poet.song.126000.json','["江北江南喧世界，陪了草鞋多少錢。", "嚇得小兒成底事，何如參我竹匕禪。"]'),
