('c3589e5e-927d-4b4a-9fb7-448ef81d4167','秋日漫興二首  其一','洪邁','宋','宋诗','song-poetry','','[]','江湖久客日思家，坐覺微霜上鬢華。',64,'全唐诗/poet.song.126000.json','["江湖久客日思家，坐覺微霜上鬢華。", "節序又催秋後鴈，風光爭發雨前花。", "倦遊已夢莊生蝶，不飲何憂廣客蛇。", "怪底朝來衣袖薄，一川白露下蒹葭。"]'),
('97e10429-831c-4f7a-8796-dee40b276d41','秋日漫興二首  其二','洪邁','宋','宋诗','song-poetry','','[]','一夕西風木葉飛，畫梁落月淡餘輝。',64,'全唐诗/poet.song.126000.json','["一夕西風木葉飛，畫梁落月淡餘輝。", "銀燈夜照還家夢，金剪親裁寄遠衣。", "霜信早隨新鴈至，素書深訝故人稀。", "無因爲謝東曹掾，鱸熟蓴香莫便歸。"]'),
('53a4c90a-2e10-421c-b7ce-facff99769f4','庚戌正月十四日同友人丁晉年王蔚之謁普照塔','洪邁','宋','宋诗','song-poetry','','[]','孤塔騖霄漢，晴影金碧眩。',192,'全唐诗/poet.song.126000.json','["孤塔騖霄漢，晴影金碧眩。", "重來得寓目，歸枕尾殘汴。", "緬懷何姓人，哀禱傾淮甸。", "是身如皎月，有水著處現。", "彈指遍大千，何止數鄉縣。", "惟應因緣地，聊爾共流轉。", "顛危悔勒馬，善涉悟覓扇。", "君看悔與悟，只在一轉盼。", "至人獨何心，示此禍福變。", "當知夙緣定，莫作邪道見。", "哀哉衆生愚，積惡稔天譴。", "云何一朝急，頼此香火薦。", "我來適燈夕，寶蠟明邃殿。", "還揩客眼塵，重睹浮屠面。", "朝來塔上鈴，告我風色便。", "平淮一回首，岸容失葱蒨。"]'),
('c68727ba-9689-4f65-a99c-bde1eafe4cf9','曉過吳縣','洪邁','宋','宋诗','song-poetry','','[]','舟行有嚴程，越國常曉發。',48,'全唐诗/poet.song.126000.json','["舟行有嚴程，越國常曉發。", "雙艪兀殘夢，起坐窺落月。", "人家岸野水，霧雨籠邃闥。", "遥憐瑣窗人，欹枕聽嘔軋。"]'),
('e12547ef-0a89-46ac-b5a3-9457a14a24b7','陪餘杭張無垢先生飲','洪邁','宋','宋诗','song-poetry','','[]','先生結屋在人境，門巷蕭蕭作冰冷。',128,'全唐诗/poet.song.126000.json','["先生結屋在人境，門巷蕭蕭作冰冷。", "紛紛入眼不入意，坐客千言不相領。", "叩關聞我倒屣迎，重解舊榻塵埃生。", "向來妙處久不吐，一挽天漢崑崙傾。", "共說別來經世事，我言所向皆兒戲。", "胸中磈礧不用澆，便有清愁說無地。", "士林師範六一翁，先生合在伯仲中。", "願言終賜指歸處，爲君敬作曾南豐。"]'),
('526f1a09-5a65-475f-b6c4-8cec698ee962','於潛道中','洪邁','宋','宋诗','song-poetry','','[]','山行厭犖确，理策扶敧危。',72,'全唐诗/poet.song.126000.json','["山行厭犖确，理策扶敧危。", "綠野三兩家，一息知可期。", "冉冉晴林端，炊烟裊晴暉。", "居民豐且樂，恐是太古遺。", "那知都邑間，百索困鞭笞。", "繁華今何有，半作道旁羸。"]'),
('567885ff-2bde-4d23-b137-9c0ad8b431f9','度芙蓉嶺','洪邁','宋','宋诗','song-poetry','','[]','幽泉端爲誰，放溜雜琴筑。',96,'全唐诗/poet.song.126000.json','["幽泉端爲誰，放溜雜琴筑。", "山深春未老，泛泛亂蕊馥。", "娟娟菖蒲花，可玩不可觸。", "靈根盤翠崖，老作蛙蚓蹙。", "褰裳踏下流，濯此塵土足。", "何當餌香節，浄洗心眼肉。", "餘功到方書，萬卷不再讀。", "晚歲窮名山，靈苗縱穿斸。"]'),
('7234143e-3bfa-4ceb-8f0d-2532bac30a87','信州禪月臺上','洪邁','宋','宋诗','song-poetry','','[]','玉峯點寥廓，霄漢疑可梯。',156,'全唐诗/poet.song.126000.json','["玉峯點寥廓，霄漢疑可梯。", "玉水環城陰，灧灧方拍隄。", "層臺擅二美，吾策時一携。", "何當蠟我屐，更欲照以犀。", "塵勞不相赦，竟類窮途迷。", "吾生麋鹿爾，不羨駕輅驪。", "向來丘壑懷，語發人所詆。", "長安黑頭公，玉勒朝金閨。", "山林出戲言，廣己無端倪。", "誰收遮日手，歸把耕雨犁。", "紛紛塵土中，等是舞甕雞。", "頗聞山水間，幽子飯藿藜。", "行當踐此語，絕境同攀躋。"]'),
('8e2522ae-97e2-4c07-9588-5e508eca68e6','送禪師往妙香寺元住雲溪','洪邁','宋','宋诗','song-poetry','','[]','道人捨幽居，誰管溪上雲。',108,'全唐诗/poet.song.126000.json','["道人捨幽居，誰管溪上雲。", "此身白雲耳，遑暇南北分。", "頗聞妙香山，天花雨繽紜。", "宴坐丈室間，歷亂舊衲紋。", "山前路悠悠，山後水沄沄。", "應觀川途客，念我奔走勤。", "豈無香火緣，他年往相羣。", "飽食跛鐺飯，稀摘幽澗芹。", "當令枕花臺，白社掩前薰。"]'),
('dc10e03c-2fdf-4731-82cc-b53182e9fb6f','坐睡','洪邁','宋','宋诗','song-poetry','','[]','坐久睡屢兀，手失未了書。',96,'全唐诗/poet.song.126000.json','["坐久睡屢兀，手失未了書。", "清風脫然至，心醒得我娛。", "起看孤隙光，了不移錙銖。", "云何短夢中，萬境生須臾。", "嗟彼市朝子，百巧營其軀。", "安知非夢役，過眼滅無餘。", "至人有達觀，那與世賢愚。", "不須無言子，同上崑崙墟。"]'),
('9426db44-e620-44b7-9d3b-8aec882e4847','游山光寺','洪邁','宋','宋诗','song-poetry','','[]','寺藏兩山腹，路轉百步陰。',96,'全唐诗/poet.song.126000.json','["寺藏兩山腹，路轉百步陰。", "登高試病脚，掬冷清煩襟。", "敗壁龕石刻，歲月不可尋。", "惟應查公石，俯仰閲古今。", "屋古囷枝挂，摧頹力難任。", "何當咄嗟辦，嗣彼鐘梵音。", "興衰豈關吾，得酒且滿斟。", "歸路有溪月，攬之醒吾心。"]'),
('8ee626be-b80d-45e9-9c3e-445d37f37c8b','送建州徐生','洪邁','宋','宋诗','song-poetry','','[]','人羈天地間，誰非一浮萍。',72,'全唐诗/poet.song.126000.json','["人羈天地間，誰非一浮萍。", "泛然偶相值，便有離合情。", "君家武夷下，歸路塵眼明。", "我生愛山者，夢寐秀色橫。", "秋風送客去，把手更心傾。", "爾逢山中人，爲我寄此聲。"]'),
('c323690e-1212-48f2-89da-6b058616dfc0','贈覺師','洪邁','宋','宋诗','song-poetry','','[]','覺師儒門秀，脫屣世故早。',132,'全唐诗/poet.song.126000.json','["覺師儒門秀，脫屣世故早。", "那知軒冕味，夙悟心已槁。", "惟餘章句習，心境時相惱。", "如人生於齊，而即楚鄉老。", "雖遭楚人咻，微音或清好。", "固無益生死，亦未妨至道。", "家山亦何有，骯髒衣間窖。", "叢林選佛場，一擲想盆倒。", "云何慰故居，俛仰待華皓。", "他年空手歸，子語吾爲老。", "幸分曹溪水，萬刼付一澡。"]'),
('05ba37b6-289d-4aa1-bee5-95f02b5a2d1a','休寧村落間有奇石如彈子渦所出宜養石菖蒲程德藻許以餽我以詩督之','洪邁','宋','宋诗','song-poetry','','[]','君家綠溪上，岸曲溪成渦。',84,'全唐诗/poet.song.126000.json','["君家綠溪上，岸曲溪成渦。", "渦間石無數，水蹙相蕩磨。", "誰嘗掬而戲，一一印指螺。", "我欲往取之，擁此菖蒲窠。", "石罌注新汲，幽姿發清哦。", "夫子許餉我，往督書已多。", "願言速寄與，起此泉石痾。"]'),
('360ad418-523b-4abe-ae24-ebf832d881ef','效淵明','洪邁','宋','宋诗','song-poetry','','[]','人生本無事，况我麋鹿姿。',96,'全唐诗/poet.song.126000.json','["人生本無事，况我麋鹿姿。", "一墮世網中，永與林壑辭。", "此行獨何事，豈不爲寒饑。", "弱歲慕古人，頗覺世好卑。", "那知齒髮邁，終然此心違。", "春風到山澤，魚鳥亦知時。", "我行何日休，流目瞻長岐。", "且用陶翁言，一觴聊可揮。"]'),
('5db6b5a1-9849-4fcb-93cc-bbdcbeb2a578','酬馬退翁見示之什','洪邁','宋','宋诗','song-poetry','','[]','我家大江左，江水日夜東。',132,'全唐诗/poet.song.126000.json','["我家大江左，江水日夜東。", "遥瞻發源處，乃在西南窮。", "相望邈異境，正北一水通。", "故令我與子，迹遠心自同。", "我生寡所諧，强顔紅塵中。", "倦飛矯歸翮，饑吟咽寒蛩。", "獨欣得吾子，萬慮一笑空。", "時時出秀句，醒我如風松。", "當知山澤臞，不鄙犀角豐。", "彈冠實伊始，此生各飛蓬。", "卜鄰應未必，即事聊從容。"]'),
('9fbe6ea0-f3c7-43bd-8e6c-71d3c1cceedd','戲答胡汝能','洪邁','宋','宋诗','song-poetry','','[]','吾生苦中狹，與世枘鑿乖。',132,'全唐诗/poet.song.126000.json','["吾生苦中狹，與世枘鑿乖。", "平生素心人，耿耿不滿懷。", "汝能伯始後，遊世如嬰孩。", "相逢握手語，便作塤篪諧。", "時時笑謂我，如子患未涯。", "執古以規今，求合誠難哉。", "涉世幸未遠，子車尚可回。", "我介足怨忌，君通絕嫌猜。", "不見山巨源，雍容居鼎台。", "不見嵇中散，絕交自可哀。", "賢愚心自了，短韻共一咍。"]'),
('f2ea351b-1fe3-495f-b84a-690c3d914518','謁吳公路許借論衡復留一日戲作','洪邁','宋','宋诗','song-poetry','','[]','幽獨不自得，駕言款齋廬。',72,'全唐诗/poet.song.126000.json','["幽獨不自得，駕言款齋廬。", "殷勤主人情，投轄恐回車。", "轄亦不須投，此去將焉如。", "惟憂酒錢盡，使吾詩腸枯。", "會合曾幾何，可復自作疎。", "更當留一夕，帳中搜異書。"]'),
('b908dda3-3712-414c-b762-3d6a236b8ddc','新秋','洪邁','宋','宋诗','song-poetry','','[]','幽人無與娛，耳冷百不聞。',48,'全唐诗/poet.song.126000.json','["幽人無與娛，耳冷百不聞。", "新米熟未知，但覺市酒醇。", "滄洲散秋色，山水逾清新。", "一醉不忍獨，念我存故人。"]'),
('fc430445-78f4-443a-9e02-fa162f9f78e0','道中得雨','洪邁','宋','宋诗','song-poetry','','[]','吾行田野間，吁嗟連數村。',48,'全唐诗/poet.song.126000.json','["吾行田野間，吁嗟連數村。", "千山收宿雨，谿作黄梅渾。", "漸看風葉底，一洗龜坼痕。", "餘功被行客，稍壓旱塵昏。"]'),
('cb70edea-f419-49cf-8b51-0ced94236871','道中','洪邁','宋','宋诗','song-poetry','','[]','驕陽久自殺，一雨蕩龜坼。',144,'全唐诗/poet.song.126000.json','["驕陽久自殺，一雨蕩龜坼。", "田夫夢亦好，翻隴已幽咽。", "朝來喜相晤，一飽心已决。", "翻翻風葉亂，嫋嫋露芒出。", "去年禾欲秀，積潦滿秋澤。", "今年豈堪旱，束手就溝壑。", "我生拙謀口，藜藿甘如蜜。", "向來真過計，憂民豈吾職。", "赤子天可憐，嗟人獨何力。", "何須事兒戲，合沓來賀客。", "稍欣新稻熟，社酒行可覓。", "當同扶路翁，醉歸舞南陌。"]'),
('5c5549cb-d4d0-4e98-83e5-74b44806896b','無題','洪邁','宋','宋诗','song-poetry','','[]','前年溪上秋風時，主人酒熟烹黄雞。',128,'全唐诗/poet.song.126000.json','["前年溪上秋風時，主人酒熟烹黄雞。", "歸來醉倒睡便著，父老喚起牛羊蹊。", "此生一醉寧易得，未辨身爲貴人客。", "征西將軍爾何人，那用尊前驚墮幘。", "朅來閩越再經秋，聞道軒名涎已流。", "懸知得酒推不去，此客有轄何須投。", "今我正爲奔走役，空想題詩滿高壁。", "若逢落魄姓回人，爲問何時定相覓。"]'),
('7753eac9-2079-4363-bbdd-00d774238fc5','書窗對月','洪邁','宋','宋诗','song-poetry','','[]','天公自厭雨，一夕開寒晴。',96,'全唐诗/poet.song.126000.json','["天公自厭雨，一夕開寒晴。", "霜風浄曠野，鴻落有餘聲。", "饑鴉得林靜，霽月素窗生。", "慰開睡眼色，一洗空花橫。", "故人千里餘，壺濁誰與傾。", "遥知勸影杯，共此通夕情。", "今冬有奇事，三見飛玉英。", "明年溪上路，誰餉雨中耕。"]'),
('fa3693d8-0f2d-46a9-814f-94a1d188ff83','宿野人家','洪邁','宋','宋诗','song-poetry','','[]','夢裏滄波摇一葉，覺時正受肩輿兀。',64,'全唐诗/poet.song.126000.json','["夢裏滄波摇一葉，覺時正受肩輿兀。", "人家一宿晚可投，新席槁梧香更滑。", "霜前䆉稏收百畝，稚子新能牧鵝鴨。", "我生本是个中人，挾策久矣猶能說。"]'),
('0a0294a8-a87b-4fab-9622-975ecac355bf','度石棟嶺','洪邁','宋','宋诗','song-poetry','','[]','我行欲安適，策馬踰山樊。',96,'全唐诗/poet.song.126000.json','["我行欲安適，策馬踰山樊。", "谷深不可瞬，危磴爭猱猨。", "坡陀兩山間，寂歷三家村。", "茅簷青裙婦，蓬髮薪烟昏。", "敲冰那可飲，分我一掬溫。", "郎樵晚未歸，客至不與言。", "不奉沙頭巵，肯投柳下門。", "作詩配國風，行者式其藩。"]'),
('939033a2-9666-4e89-a2f6-6d789f938373','用退之韻賦新霽','洪邁','宋','宋诗','song-poetry','','[]','春泥窘幽步，苔上屐痕少。',72,'全唐诗/poet.song.126000.json','["春泥窘幽步，苔上屐痕少。", "新晴一褰衣，綠葉藏啼鳥。", "方塘灧宿漲，古鏡窺清曉。", "華顛忽自笑，綵羽墮驚矯。", "瞻言雲中耕，縹緲穹脊繞。", "歸把東皋犁，此念何日了。"]'),
('08f6492d-c5e1-4d33-a83b-c70bff847290','送金確然歸弋陽','洪邁','宋','宋诗','song-poetry','','[]','昔我雲溪居，送子雲溪濆。',120,'全唐诗/poet.song.126000.json','["昔我雲溪居，送子雲溪濆。", "重來問何如，笑指溪上雲。", "一別四周星，坐此世故紛。", "衰顔兩非昔，華髮粲可耘。", "我纏風樹悲，終日無一欣。", "子乃菽水憂，尚此奔走勤。", "對牀語未終，懸知便離分。", "霜風吹客袂，別意如絲棼。", "子歸葛陂上，去路接鄉枌。", "歸夢尚隨子，何當歎離羣。"]'),
('6a4a9a85-2b8e-4cf7-9247-1bae5a720de8','至節日建州會詹士元','洪邁','宋','宋诗','song-poetry','','[]','嗟予身百憂，佳節過倥傯。',120,'全唐诗/poet.song.126000.json','["嗟予身百憂，佳節過倥傯。", "客愁隨綫增，歸思與灰動。", "當年從子日，未覺百慮重。", "高堂遶牀呼，一擲有餘勇。", "那知客天涯，相對寒骨聳。", "歲月曾幾何，鬢絲今種種。", "忍饑山藥煮，附煖地爐擁。", "深藏斷往還，衰病脫拜拱。", "興言望鄉關，雲物方鬰滃。", "空餘相屬意，杯酒久不捧。"]'),
('7c357f27-fbef-4c1f-8e4b-ff4a4ab43696','用前韻答翁子靜','洪邁','宋','宋诗','song-poetry','','[]','客心既岑寂，節物亦倥傯。',120,'全唐诗/poet.song.126000.json','["客心既岑寂，節物亦倥傯。", "幽籬菊初暗，深壑梅已動。", "古人微尺璧，顧謂寸陰重。", "欲從夫子遊，掣肘媿不勇。", "松高節磊砢，鶴老格清聳。", "當知山澤臞，誰羨將相種。", "一官戲人間，叢書以自擁。", "微言聞緒餘，三歎手輒拱。", "青天本寥廓，不受雲霧滃。", "願言瞻清明，茗椀不辭捧。"]'),
('562e4f69-b65d-4f72-8fcc-088184ce2f10','微雨','洪邁','宋','宋诗','song-poetry','','[]','端居身百憂，况乃貧病俱。',72,'全唐诗/poet.song.126000.json','["端居身百憂，况乃貧病俱。", "天公頗相愛，相愛雨我蔬。", "藥區曉晴新，日薄生意蘇。", "衛生固未必，一飽行可圖。", "故園天一涯，茆荆誰爲鋤。", "崢嶸歲云晚，此念當何如。"]'),
('02376d39-5f83-45cc-ac08-40f2990c2562','寄題叔父池亭','洪邁','宋','宋诗','song-poetry','','[]','一壑久藏勝，數椽忽開亭。',120,'全唐诗/poet.song.126000.json','["一壑久藏勝，數椽忽開亭。", "方塘蔭瓦影，浄見魴鯉行。", "主人有嘉招，轉柁失高城。", "不知幾摇兀，杙舟上崢嶸。", "尊酒酌芳醁，園蔬煮柔青。", "翩翩射鴨弓，一笑翻綵翎。", "那知海陬姪，斗粟忘歸耕。", "餘生信萍梗，歸夢識林坰。", "漲水有回波，故鄉豈無情。", "一醉會有日，因之濯我纓。"]'),
('6217f4f0-432e-4233-b3f7-0d9f33753bd4','贈謝彥翔','洪邁','宋','宋诗','song-poetry','','[]','我本世味薄，寸田足自營。',120,'全唐诗/poet.song.126000.json','["我本世味薄，寸田足自營。", "年來荆棘盡，稍有梨棗萌。", "但恐骨相凡，未敢希長生。", "陳留達人後，未齔犀角盈。", "舊游記三山，幽夢徹九清。", "邇來三十年，但覺膏粱腥。", "幽尋飯綠髓，默卧誦黄庭。", "顧我塵土中，深慰夙心傾。", "仙人吳門卒，解后煩寄聲。", "相期朝金闕，鶴馭何時征。"]'),
('a947bec3-bea3-4ab0-b003-11490652f94b','考亭陳國器以家釀餉吾友人卓民表民表以飲予香味色皆清絕不可名狀因爲製名曰武夷仙露仍賦一首','洪邁','宋','宋诗','song-poetry','','[]','二年飲水閩中村，忽見玉醴傾蠻尊。',160,'全唐诗/poet.song.126000.json','["二年飲水閩中村，忽見玉醴傾蠻尊。", "涓涓醍醐灌熱腦，耿耿沆瀣明朝暾。", "旱塵久漲塵市暗，渴夢欲挽江湖吞。", "何人遠致雙鯉信，知我來扣羅雀門。", "不須邀月已清絕，尚恐熨齒當微溫。", "要從華池吸真液，豈獨玄鬢薅愁根。", "微茫已識投轄客，娬眉似返當壚魂。", "奇功誰續伯倫頌，妙意要與淵明論。", "胸中我自有涇渭，筆下君已傾崑崙。", "詩成寄與約他日，飲君與我空瓶盆。"]'),
('23e33940-68da-40e4-98e4-c421790204fa','久旱新歲乃雨','洪邁','宋','宋诗','song-poetry','','[]','高田土可籭，下田不受犁。',144,'全唐诗/poet.song.126000.json','["高田土可籭，下田不受犁。", "遺蝗憂插啄，况乃麥未齊。", "赤子天自憐，溝壑忍見擠。", "雨逐新歲來，停雲忽凄凄。", "莫辭三日霖，爲作一尺泥。", "汪汪既沒膝，灧灧仍拍隄。", "漸看蓑笠出，笑語喧畛畦。", "我欲與寓目，父老同攀躋。", "此身羣萬生，擾擾舞甕雞。", "曾亦無幾求，脫粟配羹藜。", "永言故隴耕，老眼路凄迷。", "好收歛手版，鋤耰歸自携。"]'),
('2def76b2-58ba-4b57-89fe-4fa9633c754f','春日與卓民表陳國器步出北郊','洪邁','宋','宋诗','song-poetry','','[]','灼灼桃吐華，濯濯柳垂縷。',96,'全唐诗/poet.song.126000.json','["灼灼桃吐華，濯濯柳垂縷。", "芳菲挽人出，春力乃如許。", "嗟余閉門客，佳節過不數。", "不因可人呼，那得幽步舉。", "客如山陰勝，詩作斜川語。", "誰言一尊酒，妙處合千古。", "歸來讀殘書，耿耿霜月苦。", "空餘流落心，三歎非吾土。"]'),
('93ff72ca-1c6b-4055-8526-45bfaec6365c','蔬飯','洪邁','宋','宋诗','song-poetry','','[]','蕨拳嬰兒手，笋解籜龍蛻。',120,'全唐诗/poet.song.126000.json','["蕨拳嬰兒手，笋解籜龍蛻。", "薦羞杞菊間，采斸烟雨外。", "嗟余飯藜藿，咽塞舟泝瀨。", "朝來二尾魚，一飽良已泰。", "充腸我誠足，染指客應嘅。", "平生食肉相，蕭瑟何足頼。", "王郎催牛炙，韓老憶鯨鱠。", "俠氣信雄夸，戲語亦狡獪。", "吾師魯顔子，陋巷翳蓬艾。", "執瓢不可從，一取清泉漱。"]'),
('d747a1a1-198c-43e9-8a23-840427dc7e18','戲贈吳知伯','洪邁','宋','宋诗','song-poetry','','[]','條侯得劇孟，吳楚坐可馘。',168,'全唐诗/poet.song.126000.json','["條侯得劇孟，吳楚坐可馘。", "我知無能爲，失此一敵國。", "偉哉奇男子，俠氣橫八極。", "書生復何者，骯髒老筆墨。", "刺口論安危，事往竟何益。", "匹夫嘯空野，驚塵一方塞。", "區區空有意，浩蕩洗鋒鏑。", "何如吳王孫，語輒面浮赤。", "交游得朱亥，負販鄙膠鬲。", "腰間鐵絲箭，上鏃紫塞翮。", "笑指蛇豕區，滅此而後食。", "諸公未備知，欲薦恨無力。", "明日我過君，烹牛啖社客。", "當書游俠傳，令子姓名白。"]'),
('db59b76d-0f2b-47a5-b01e-4ff9d5ad8648','送僧','洪邁','宋','宋诗','song-poetry','','[]','空中世界紛河沙，不知底處爲天涯。',128,'全唐诗/poet.song.126000.json','["空中世界紛河沙，不知底處爲天涯。", "乾坤百億在指掌，觸處與子同一家。", "云何猶作去來想，千里一跌毫釐差。", "坐令契闊費星紀，嶺雲欲寄山川遐。", "撥眉相對此何日，丈室浄掃餘天花。", "詩毫辨舌久投閣，萬竅寂歷風無譁。", "爲君游戲出三昧，妙處那復相聱牙。", "往將妙響應空谷，一任飛錫凌蒼霞。"]'),
('f3e6894b-0ee4-4f02-bdad-d312978f247f','書僧房','洪邁','宋','宋诗','song-poetry','','[]','陸續流泉自成句，來擁紅爐聽山雨。',64,'全唐诗/poet.song.126000.json','["陸續流泉自成句，來擁紅爐聽山雨。", "道人更有深深處，語曲如珠蟻絲度。", "几硯無塵寒欲霧，雕盤篆破孤螢吐。", "味如嚼蠟那禁咀，茶甘未回君莫去。"]'),
('2ef0628b-7761-45e2-ac49-83259a7d1a52','題蘆鴈屏','洪邁','宋','宋诗','song-poetry','','[]','征鴻坐何事，天遣南北飛。',108,'全唐诗/poet.song.126000.json','["征鴻坐何事，天遣南北飛。", "蕭然如旅人，無情自相依。", "孤葦吹欲折，秋風不勝威。", "冥冥一孤鶱，空費弋者機。", "寒聲落烟渚，相應不我違。", "嗟吾識此情，手納空嘆欷。", "安知丹青師，落筆乃庶幾。", "畫形孰不工，畫意識者稀。", "他時因吾句，購此千金揮。"]'),
('7f00c7ae-3ead-41e3-b5e0-72601b0a3393','題臨賦軒','洪邁','宋','宋诗','song-poetry','','[]','蒼山圍岑寂，下有一水奔。',132,'全唐诗/poet.song.126000.json','["蒼山圍岑寂，下有一水奔。", "閉戶卧風雨，束蒿翳籬藩。", "寥哉祇樹人，心遠忘世喧。", "此身自蘧廬，長物餘此軒。", "鳥語幽夢斷，香橫經帙翻。", "未成借路行，自要窺潺湲。", "遠師淵明意，不媿靈澈魂。", "月度了無迹，風行偶成痕。", "心境兩清妙，尺喙何由吞。", "賦詩安所取，碧雲未足論。", "何當揣朱絲，窈眇絃我言。"]'),
('00199d2d-d12f-46c4-ad0e-4c23cd6854a0','答併安江師送米','洪邁','宋','宋诗','song-poetry','','[]','不見道人久，天涯歲云除。',144,'全唐诗/poet.song.126000.json','["不見道人久，天涯歲云除。", "朝來食指動，忽接送米書。", "念師折脚鐺，五合未省餘。", "雖無覆餗禍，尚有乞食逋。", "云何憐孤客，日受饑火驅。", "未曾貸監河，矧肯索胡奴。", "誰言斗升意，矯矯超萬夫。", "嗟予事筆耕，輕棄南畝鋤。", "慁煩方外客，此計良已疎。", "何時事粗了，歸葺五畝居。", "生涯寄綿竹，豈即非良圖。", "不爲泉壤蚓，願學江湖魚。"]'),
('0e7711fe-d17a-45c6-9a1e-fc93c75146b5','陳德瑞饋新茶','洪邁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','空山冥冥雲霧窗，春風好夢敧殘缸。',96,'全唐诗/poet.song.126000.json','["空山冥冥雲霧窗，春風好夢敧殘缸。", "朝來果得故人書，微凸而么犀鍔雙。", "貴人爭買百瓔珞，此心兒女久已降。", "坐觀市井起攘袂，念之使我心紛龐。", "領君此意九鼎重，我雖有力安能扛。", "何時來施三昧手，慰我渴夢思長江。"]'),
('1bb67af4-fb95-46c0-a20f-8e1da39de350','次韻希旦喜雨','洪邁','宋','宋诗','song-poetry','','[]','驕陽挾酷暑，何啻虎而翼。',180,'全唐诗/poet.song.126000.json','["驕陽挾酷暑，何啻虎而翼。", "高田土可籭，況乃耕與植。", "風伯真可訟，雲合吹復拆。", "那知下土民，糟粕配橡實。", "古佛栖巖隈，旱沴豈我責。", "應緣賢令尹，閔雨丐法力。", "積陰暝山谷，流潤凄几格。", "朝來賀客散，置酒浣愁疾。", "古詩成雲外，險句動潛蟄。", "旋看蓑笠出，競喜溝澮溢。", "誰言令與佛，念我一何悉。", "嗟吾困蒿藜，最覺民可恤。", "何當問牛喘，免使訴魚失。", "九關虎豹守，懷此欲安適。", "誰哉此心同，吾飽將何日。"]'),
('5ac955c0-9618-41a2-9d93-e781f07a841e','古風二首寄汪明道  其一','洪邁','宋','宋诗','song-poetry','','[]','紫蘭初茁芽，深壑終自秀。',48,'全唐诗/poet.song.126000.json','["紫蘭初茁芽，深壑終自秀。", "骯髒蕭艾中，不采則誰咎。", "兒曹逐紛華，壯士保窮陋。", "應知此詞同，萬世無先後。"]'),
('3129a86c-6ffb-4a97-97f3-296eeabf4c0a','古風二首寄汪明道  其二','洪邁','宋','宋诗','song-poetry','','[]','俗士白人眼，從誰明此心。',48,'全唐诗/poet.song.126000.json','["俗士白人眼，從誰明此心。", "不欲故人見，訶我車轍深。", "蕭然江上廬，客卧詩書林。", "得句不相寄，誰賞氣駸駸。"]'),
('d11e6005-a6c8-44b2-9520-6f1d7fbad01b','建安道中','洪邁','宋','宋诗','song-poetry','','[]','吾生意行初不謀，汎汎何啻波中鷗。',128,'全唐诗/poet.song.126000.json','["吾生意行初不謀，汎汎何啻波中鷗。", "携家來作閩海夢，三年客食天南陬。", "我先人廬在何許，大江之左道阻修。", "奉新家有手足愛，隻身歸掃先梧楸。", "旋當來此營斗粟，南北顛倒無時休。", "此心轉與世事左，自作磨蟻將誰尤。", "安知不滿達者笑，窮達一戲如觀優。", "咄哉吾語亦已墮，且與造物同浮游。"]'),
('48e9399a-28c4-443d-9476-5d087d3c27f6','書事呈元聲如愚起莘三兄','洪邁','宋','宋诗','song-poetry','','[]','隠吏朱墨暇，飽眠北窗風。',144,'全唐诗/poet.song.126000.json','["隠吏朱墨暇，飽眠北窗風。", "時呼方外客，逃暑尊酒中。", "寂寞杜拾遺，四壁口不供。", "坐取盤餐款，哀哉豈天窮。", "何如平生友，磁鐵間不容。", "每懷千里駕，今作五斗逢。", "吏行散鳬鶩，楸局收鸞龍。", "共話十年舊，事往如飛蓬。", "浮榮真一戲，何者爲窮通。", "應須河漢語，浄洗芥蒂胸。", "僕夫適在門，客醉尊亦空。", "更爲後日約，及此芙蓉紅。"]');
